// CONFIGURACIÓN DE API DE TRANSCRIPCIÓN
// ======================================================
const API_TRANSCRIPCION_URL = 'http://localhost:5001/api/transcripcion';

// ======================================================
// MATRICES DE EVALUACIÓN POR FECHA
// ======================================================
const MATRIZ_ANTIGUA = {
    nombre: "Original (30|30|40)",
    fecha_limite: "2026-05-31",  // Hasta esta fecha inclusive
    pesos: { ENC: 30, ECUF: 30, ECN: 40 }
};

const MATRIZ_NUEVA = {
    nombre: "Nueva (15|15|70)",
    fecha_limite: null,  // A partir del 2026-06-01
    pesos: { ENC: 15, ECUF: 15, ECN: 70 }
};

// Función para saber qué matriz usar según la fecha
function getMatrizByFecha(fechaEvaluacion) {
    if (!fechaEvaluacion) return MATRIZ_NUEVA;
    
    const fechaLimite = new Date(MATRIZ_ANTIGUA.fecha_limite);
    const fechaEval = new Date(fechaEvaluacion);
    
    if (fechaEval <= fechaLimite) {
        return MATRIZ_ANTIGUA;
    } else {
        return MATRIZ_NUEVA;
    }
}

// Función para calcular nota como porcentaje según la matriz
function calcularNotaPorcentaje(evaluacion, pesos) {
    const pctENC = Math.min(((evaluacion.totalENC || 0) / pesos.ENC) * 100, 100);
    const pctECUF = Math.min(((evaluacion.totalECUF || 0) / pesos.ECUF) * 100, 100);
    const pctECN = Math.min(((evaluacion.totalECN || 0) / pesos.ECN) * 100, 100);
    
    // Promedio simple de los tres porcentajes
    return (pctENC + pctECUF + pctECN) / 3;
}

function obtenerPesosPorEvaluacion(evaluacion) {
    const fecha = obtenerFechaEvaluacion(evaluacion);
    const matriz = getMatrizByFecha(fecha);
    return matriz.pesos;
}

// Devuelve los pesos aplicables al conjunto filtrado (si todas las evaluaciones comparten matriz),
// o valores por defecto si no hay matriz dominante.
function obtenerPesosActuales() {
    const evaluaciones = window.evaluacionesFiltradasGlobal || window.evaluacionesGlobales || [];
    const m = obtenerMatrizDominante(evaluaciones);
    return m ? m.pesos : { ENC: 30, ECUF: 30, ECN: 40 };
}

function calcularPorcentajeMotivo(evaluacion, motivo) {
    const pesos = obtenerPesosPorEvaluacion(evaluacion);
    const total = evaluacion[`total${motivo}`] || 0;
    const pesoMax = pesos[motivo] || 100;
    return Math.min((total / pesoMax) * 100, 100);
}

function calcularPromediosMotivosPorcentaje(evaluaciones) {
    if (!evaluaciones || evaluaciones.length === 0) return { promedioENC: 0, promedioECUF: 0, promedioECN: 0 };
    let sumaENC = 0, sumaECUF = 0, sumaECN = 0;
    for (const e of evaluaciones) {
        sumaENC += calcularPorcentajeMotivo(e, 'ENC');
        sumaECUF += calcularPorcentajeMotivo(e, 'ECUF');
        sumaECN += calcularPorcentajeMotivo(e, 'ECN');
    }
    const total = evaluaciones.length;
    return {
        promedioENC: (sumaENC / total).toFixed(1),
        promedioECUF: (sumaECUF / total).toFixed(1),
        promedioECN: (sumaECN / total).toFixed(1)
    };
}

function contarMotivosPorDebajoDePeso(evaluaciones) {
    let conENC = 0, conECUF = 0, conECN = 0;
    for (const e of evaluaciones) {
        const pesos = obtenerPesosPorEvaluacion(e);
        if ((e.totalENC || 0) < pesos.ENC) conENC++;
        if ((e.totalECUF || 0) < pesos.ECUF) conECUF++;
        if ((e.totalECN || 0) < pesos.ECN) conECN++;
    }
    return { conENC, conECUF, conECN };
}

function obtenerMatrizDominante(evaluaciones) {
    if (!evaluaciones || evaluaciones.length === 0) return null;
    const primera = getMatrizByFecha(obtenerFechaEvaluacion(evaluaciones[0]));
    for (const e of evaluaciones) {
        const m = getMatrizByFecha(obtenerFechaEvaluacion(e));
        if (m.nombre !== primera.nombre) return null;
    }
    return primera;
}

function obtenerPesosPorEvaluacion(evaluacion) {
    const fecha = obtenerFechaEvaluacion(evaluacion);
    const matriz = getMatrizByFecha(fecha);
    return matriz.pesos;
}

function calcularPorcentajeMotivo(evaluacion, motivo) {
    const pesos = obtenerPesosPorEvaluacion(evaluacion);
    const total = evaluacion[`total${motivo}`] || 0;
    const pesoMax = pesos[motivo] || 100;
    return Math.min((total / pesoMax) * 100, 100);
}

function calcularPromediosMotivosPorcentaje(evaluaciones) {
    if (!evaluaciones || evaluaciones.length === 0) {
        return { promedioENC: 0, promedioECUF: 0, promedioECN: 0 };
    }

    let sumaENC = 0;
    let sumaECUF = 0;
    let sumaECN = 0;

    for (const evaluacion of evaluaciones) {
        sumaENC += calcularPorcentajeMotivo(evaluacion, 'ENC');
        sumaECUF += calcularPorcentajeMotivo(evaluacion, 'ECUF');
        sumaECN += calcularPorcentajeMotivo(evaluacion, 'ECN');
    }

    const total = evaluaciones.length;
    return {
        promedioENC: (sumaENC / total).toFixed(1),
        promedioECUF: (sumaECUF / total).toFixed(1),
        promedioECN: (sumaECN / total).toFixed(1)
    };
}

function contarMotivosPorDebajoDePeso(evaluaciones) {
    let conENC = 0;
    let conECUF = 0;
    let conECN = 0;

    for (const evaluacion of evaluaciones) {
        const pesos = obtenerPesosPorEvaluacion(evaluacion);
        if ((evaluacion.totalENC || 0) < pesos.ENC) conENC++;
        if ((evaluacion.totalECUF || 0) < pesos.ECUF) conECUF++;
        if ((evaluacion.totalECN || 0) < pesos.ECN) conECN++;
    }

    return { conENC, conECUF, conECN };
}

function obtenerMatrizDominante(evaluaciones) {
    if (!evaluaciones || evaluaciones.length === 0) return null;

    const primeraMatriz = getMatrizByFecha(obtenerFechaEvaluacion(evaluaciones[0]));
    for (const evaluacion of evaluaciones) {
        const matriz = getMatrizByFecha(obtenerFechaEvaluacion(evaluacion));
        if (matriz.nombre !== primeraMatriz.nombre) {
            return null;
        }
    }
    return primeraMatriz;
}

// ======================================================
// SISTEMA DE CUARTILES (FUTURO-PROOF) - VERSIÓN POSTGRESQL
// ======================================================

// Variables de caché
let cacheCuartiles = null;
let cacheCuartilesTimestamp = null;
const CACHE_CUARTILES_DURACION = 5 * 60 * 1000;

// Criterios por defecto (fallback)
function obtenerCriteriosPorDefecto() {
    return [
        { cuartil: 'Q1', nombre: 'Excelente', limite_inferior: 97, limite_superior: 100, color_hex: '#1a7f37', icono: '🏆', orden: 1 },
        { cuartil: 'Q2', nombre: 'Bueno', limite_inferior: 90, limite_superior: 96.99, color_hex: '#019DF4', icono: '📈', orden: 2 },
        { cuartil: 'Q3', nombre: 'Regular', limite_inferior: 85, limite_superior: 89.99, color_hex: '#f39c12', icono: '⚠️', orden: 3 },
        { cuartil: 'Q4', nombre: 'Riesgo', limite_inferior: 0, limite_superior: 84.99, color_hex: '#d93025', icono: '🔴', orden: 4 }
    ];
}

// Obtener criterios desde PostgreSQL
async function obtenerCriteriosCuartiles(forzarRecarga = false) {
    const ahora = Date.now();
    
    // Usar caché si es válido
    if (!forzarRecarga && cacheCuartiles && cacheCuartilesTimestamp && 
        (ahora - cacheCuartilesTimestamp) < CACHE_CUARTILES_DURACION) {
        console.log('📦 Usando caché de criterios de cuartiles');
        return cacheCuartiles;
    }
    
    try {
        const token = localStorage.getItem('meca_token');
        if (!token) {
            console.warn('⚠️ No hay token, usando criterios por defecto');
            return obtenerCriteriosPorDefecto();
        }
        
        // 🔴 CONSULTA - SIN orderBy (igual que en el diagnóstico que funcionó)
        const response = await fetch('/api/query', {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${token}`,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                table: 'criterios_cuartiles',
                operation: 'select',
                selectFields: '*',
                filters: [
                    { type: 'eq', column: 'activo', value: true }
                ]
                // 🔴 SIN orderBy - lo hacemos en JavaScript
            })
        });
        
        if (!response.ok) {
            const error = await response.json();
            console.warn('⚠️ Error consultando criterios:', error);
            return obtenerCriteriosPorDefecto();
        }
        
        const result = await response.json();
        let data = result.data || [];
        
        if (data.length === 0) {
            console.warn('⚠️ No hay criterios en BD, usando defecto');
            return obtenerCriteriosPorDefecto();
        }
        
        // 🔴 ORDENAR EN JAVASCRIPT por 'orden'
        data = data.sort((a, b) => {
            const ordenA = parseInt(a.orden) || 0;
            const ordenB = parseInt(b.orden) || 0;
            return ordenA - ordenB;
        });
        
        // Filtrar por fecha de vigencia en JavaScript
        const hoy = new Date().toISOString().split('T')[0];
        const filtrados = data.filter(c => {
            if (!c.fecha_vigencia_hasta) return true;
            return c.fecha_vigencia_hasta >= hoy;
        });
        
        if (filtrados.length === 0) {
            console.warn('⚠️ No hay criterios vigentes, usando defecto');
            return obtenerCriteriosPorDefecto();
        }
        
        cacheCuartiles = filtrados;
        cacheCuartilesTimestamp = ahora;
        console.log(`✅ ${filtrados.length} criterios de cuartiles cargados desde PostgreSQL`);
        console.log('📋 Criterios:', filtrados.map(c => `${c.cuartil}: ${c.limite_inferior}-${c.limite_superior}`).join(', '));
        return filtrados;
        
    } catch (error) {
        console.error('Error cargando criterios de cuartiles:', error);
        return obtenerCriteriosPorDefecto();
    }
}

// Obtener cuartil por nota
async function obtenerCuartilPorNota(nota, criterios = null) {
    if (!criterios) {
        criterios = await obtenerCriteriosCuartiles(false);
    }
    
    for (const criterio of criterios) {
        if (nota >= criterio.limite_inferior && nota <= criterio.limite_superior) {
            return {
                cuartil: criterio.cuartil,
                nombre: criterio.nombre,
                color: criterio.color_hex,
                icono: criterio.icono,
                limite_inferior: criterio.limite_inferior,
                limite_superior: criterio.limite_superior
            };
        }
    }
    
    return {
        cuartil: 'Q4',
        nombre: 'Riesgo',
        color: '#d93025',
        icono: '🔴',
        limite_inferior: 0,
        limite_superior: 84.99
    };
}

// Obtener cuartil (versión async)
async function obtenerCuartil(nota) {
    const resultado = await obtenerCuartilPorNota(nota, null);
    return resultado.cuartil;
}

// Calcular cuartil individual
async function calcularCuartilIndividual(promedio) {
    const resultado = await obtenerCuartilPorNota(promedio, null);
    return resultado.cuartil;
}

// Invalidar caché
function invalidarCacheCuartiles() {
    cacheCuartiles = null;
    cacheCuartilesTimestamp = null;
    console.log('🗑️ Caché de cuartiles invalidada');
}

