// ======================================================
async function verificarSesionSupervisor() {
    const token = localStorage.getItem('meca_token');
    const usuarioGuardado = localStorage.getItem('meca_usuario');
    
    console.log('🔍 [SUPERVISOR] Token encontrado:', token ? 'SÍ' : 'NO');
    
    if (!token || !usuarioGuardado) {
        console.log('⚠️ [SUPERVISOR] No hay sesión, redirigiendo a login');
        window.location.href = '/login';
        return false;
    }
    
    try {
        usuarioActual = JSON.parse(usuarioGuardado);
        console.log('✅ [SUPERVISOR] Usuario restaurado:', usuarioActual.nombre_completo);
        console.log('✅ [SUPERVISOR] Rol:', usuarioActual.rol);
        
        // Verificar que el rol sea válido para supervisor (no AUDITOR)
        if (usuarioActual.rol === 'AUDITOR') {
            console.log('⚠️ [SUPERVISOR] Auditor no puede acceder al sistema de supervisión');
            window.location.href = '/auditor';
            return false;
        }
        
        mostrarInterfazSupervisor();
        return true;
        
    } catch (error) {
        console.error('❌ [SUPERVISOR] Error:', error);
        window.location.href = '/login';
        return false;
    }
}
// ======================================================
// MOSTRAR INTERFAZ DE SUPERVISOR
// ======================================================
function mostrarInterfazSupervisor() {
    console.log('👤 Mostrando interfaz para supervisor:', usuarioActual?.nombre_completo);
    
    // Ocultar login
    const loginOverlay = document.getElementById('loginOverlay');
    if (loginOverlay) loginOverlay.style.display = 'none';

    // Mostrar info del usuario en el header
    const userInfo = document.getElementById('userInfo');
    const userName = document.getElementById('userName');
    const userRol = document.getElementById('userRol');

    if (userInfo) userInfo.style.display = 'flex';
    if (userName) userName.textContent = usuarioActual?.nombre_completo || 'Usuario';
    if (userRol) userRol.textContent = usuarioActual?.rol_nombre || usuarioActual?.rol || '';

    // Mostrar el contenido principal
    const container = document.querySelector('.container');
    if (container) container.style.display = 'block';

    // Generar las pestañas según el rol
    generarTabsSupervisor();
}

// ======================================================
// GENERAR PESTAÑAS DEL SUPERVISOR (DESDE BASE DE DATOS)
// ======================================================
async function generarTabsSupervisor() {
    console.log('🔧 Generando pestañas dinámicas para supervisor...');
    
    const tabsContainer = document.getElementById('tabsHeaderContainer');
    if (!tabsContainer) {
        console.error('❌ No se encontró el contenedor de pestañas');
        return;
    }
    
    tabsContainer.innerHTML = '';
    
    try {
        const token = localStorage.getItem('meca_token');
        
        if (!token) {
            console.error('❌ No hay token');
            mostrarPestanasFallback(tabsContainer);
            return;
        }
        
        // 🔴 USAR /api/pestanas (ya filtra por rol usando el token)
        const response = await fetch('/api/pestanas', {
            headers: {
                'Authorization': `Bearer ${token}`,
                'Content-Type': 'application/json'
            }
        });
        
        if (!response.ok) {
            throw new Error(`HTTP ${response.status}`);
        }
        
        const pestanas = await response.json();
        console.log('📋 Pestañas desde /api/pestanas:', pestanas);
        
        if (pestanas.length === 0) {
            console.warn('⚠️ No hay pestañas para este rol');
            tabsContainer.innerHTML = '<div style="padding: 20px; text-align: center;">No tiene acceso a ningún módulo</div>';
            return;
        }
        
        // Crear botones
        pestanas.forEach(pestana => {
            const button = document.createElement('button');
            button.className = 'tab-button';
            button.innerHTML = `${pestana.icono || '📄'} ${pestana.nombre}`;
            button.setAttribute('data-tab', pestana.codigo);
            button.onclick = (event) => showTab(pestana.codigo, event);
            tabsContainer.appendChild(button);
        });
        
        // Activar primera pestaña
        const primerBoton = tabsContainer.querySelector('.tab-button');
        if (primerBoton) {
            primerBoton.classList.add('active');
            const primeraPestana = primerBoton.getAttribute('data-tab');
            if (primeraPestana && typeof showTab === 'function') {
                showTab(primeraPestana, null);
            }
        }
        
        console.log(`✅ Generadas ${tabsContainer.children.length} pestañas`);
        
    } catch (error) {
        console.error('❌ Error generando pestañas:', error);
        mostrarPestanasFallback(tabsContainer);
    }
}

function mostrarPestanasFallback(tabsContainer) {
    const pestanasBasicas = [
        { codigo: 'reportes', nombre: '📊 Reportes', icono: '📊' },
        { codigo: 'historialAgente', nombre: '📋 Avance Gestores', icono: '📋' }
    ];
    
    pestanasBasicas.forEach(pestana => {
        const button = document.createElement('button');
        button.className = 'tab-button';
        button.innerHTML = `${pestana.icono} ${pestana.nombre}`;
        button.setAttribute('data-tab', pestana.codigo);
        button.onclick = (event) => showTab(pestana.codigo, event);
        tabsContainer.appendChild(button);
    });
    
    const primerBoton = tabsContainer.querySelector('.tab-button');
    if (primerBoton) {
        primerBoton.classList.add('active');
        const primeraPestana = primerBoton.getAttribute('data-tab');
        if (primeraPestana) showTab(primeraPestana, null);
    }
}


// ======================================================
// LOGOUT UNIFICADO
// ======================================================
function cerrarSesion(event) {
    if (event) {
        event.preventDefault();
        event.stopPropagation();
    }
    
    if (confirm('¿Cerrar sesión?')) {
        localStorage.removeItem('meca_token');
        localStorage.removeItem('meca_usuario');
        localStorage.clear();
        sessionStorage.clear();
        window.location.href = '/login';
    }
}


// ======================================================
// INICIALIZAR EVENTO DE CARGA DE AGENTES
// ======================================================
function inicializarEventoAgentes() {
    const fileInput = document.getElementById('fileAgentes');
    console.log('🔧 [INIT] Buscando fileAgentes:', fileInput);
    
    if (!fileInput) {
        console.warn('⚠️ [INIT] fileAgentes no encontrado aún, reintentando...');
        setTimeout(inicializarEventoAgentes, 500);
        return;
    }
    
    const nuevoInput = fileInput.cloneNode(true);
    fileInput.parentNode.replaceChild(nuevoInput, fileInput);
    
    nuevoInput.addEventListener('change', function(e) {
        console.log('🎉 [EVENT] CAMBIO DETECTADO');
        const file = e.target.files[0];
        if (!file) return;
        
        console.log('📁 [EVENT] Archivo:', file.name);
        
        const reader = new FileReader();
        reader.onload = function(e) {
            console.log('📖 [EVENT] Archivo leído, procesando...');
            const data = new Uint8Array(e.target.result);
            const workbook = XLSX.read(data, { type: 'array' });
            const primeraHoja = workbook.Sheets[workbook.SheetNames[0]];
            const jsonData = XLSX.utils.sheet_to_json(primeraHoja, { defval: "" });
            
            console.log('📊 [EVENT] Filas encontradas:', jsonData.length);
            console.log('📋 [EVENT] Columnas detectadas:', Object.keys(jsonData[0] || {}));
            
            // ======================================================
            // MAPEO DE COLUMNAS (COPIADO DE TU CÓDIGO ORIGINAL)
            // ======================================================
            const mapeoColumnas = {
                id: ['id', 'ID'],
                nombre: ['nombre', 'Nombre', 'NOMBRE', 'Nombre y Apellidos', 'NOMBRE Y APELLIDOS', 'agente', 'Agente'],
                dni: ['dni', 'DNI', 'Dni'],
                carnet: ['carnet', 'CARNET', 'Carnet'],
                correo: ['correo', 'CORREO', 'email', 'Email', 'EMAIL'],
                estado: ['estado', 'Estado', 'ESTADO'],
                lider_2026: ['lider_2026', 'LIDER_2026', 'lider', 'Lider', 'LÍDER', 'líder'],
                ubicacion: ['ubicacion', 'UBICACION', 'ubicación', 'Ubicación'],
                localidad: ['localidad', 'LOCALIDAD', 'Localidad'],
                categoria_label: ['categoria_label', 'CATEGORIA_LABEL', 'categoria', 'Categoria', 'CATEGORÍA', 'categoría'],
                funciones: ['funciones', 'FUNCIONES', 'Funciones'],
                horario_marzo: ['horario_marzo', 'HORARIO_MARZO', 'horarioMarzo'],
                horario_marzo_v1: ['horario_marzo_v1', 'HORARIO_MARZO_V1', 'horarioMarzoV1'],
                canal_tobe_1ra_activ_marzo: ['canal_tobe_1ra_activ_marzo', 'CANAL_TOBE_1RA_ACTIV_MARZO', 'canalTobe'],
                '1ra_actividad_marzo_v1': ['1ra_actividad_marzo_v1', '1RA_ACTIVIDAD_MARZO_V1', 'actividadMarzoV1'],
                created_at: ['created_at', 'CREATED_AT', 'fecha_creacion', 'Fecha Creación'],
                updated_at: ['updated_at', 'UPDATED_AT', 'fecha_actualizacion', 'Fecha Actualización']
            };
            
            function obtenerValor(row, posiblesNombres) {
                for (const nombre of posiblesNombres) {
                    if (row[nombre] !== undefined && row[nombre] !== null && row[nombre] !== '') {
                        let valor = row[nombre];
                        if (typeof valor === 'string') valor = valor.trim();
                        return valor;
                    }
                }
                return '';
            }
            
            const agentes = [];
            const errores = [];
            
            for (let i = 0; i < jsonData.length; i++) {
                const row = jsonData[i];
                const agente = {};
                
                for (const [campo, posibles] of Object.entries(mapeoColumnas)) {
                    agente[campo] = obtenerValor(row, posibles);
                }
                
                if (!agente.nombre || agente.nombre === '') {
                    errores.push(`Fila ${i + 2}: Nombre vacío o no encontrado`);
                    continue;
                }
                
                agente.nombre = agente.nombre.toString().toUpperCase();
                
                if (agente.estado) {
                    let estadoLimpio = agente.estado.toString().toUpperCase();
                    estadoLimpio = estadoLimpio.replace(/[^A-Z\s]/gi, '').trim();
                    if (estadoLimpio.includes('ACTIV')) agente.estado = 'ACTIVO';
                    else if (estadoLimpio.includes('INACTIV')) agente.estado = 'INACTIVO';
                    else if (estadoLimpio.includes('DM') || estadoLimpio.includes('PROLONG')) agente.estado = 'DM PROLONGADO';
                    else agente.estado = 'ACTIVO';
                } else {
                    agente.estado = 'ACTIVO';
                }
                
                if (agente.lider_2026 && typeof agente.lider_2026 === 'string') {
                    agente.lider_2026 = agente.lider_2026.toUpperCase();
                }
                if (agente.ubicacion && typeof agente.ubicacion === 'string') {
                    agente.ubicacion = agente.ubicacion.toUpperCase();
                }
                if (agente.localidad && typeof agente.localidad === 'string') {
                    agente.localidad = agente.localidad.toUpperCase();
                }
                if (agente.categoria_label && typeof agente.categoria_label === 'string') {
                    agente.categoria_label = agente.categoria_label.toUpperCase();
                }
                if (agente.funciones && typeof agente.funciones === 'string') {
                    agente.funciones = agente.funciones.toUpperCase();
                }
                
                agentes.push(agente);
            }
            
            console.log('📢 [EVENT] Agentes procesados:', agentes.length);
            
            if (agentes.length === 0) {
                alert('⚠️ No se encontraron agentes válidos en el archivo.\nAsegúrese de tener una columna llamada "nombre" o "Nombre y Apellidos"');
                return;
            }
            
            // ======================================================
            // MOSTRAR VISTA PREVIA
            // ======================================================
            const vistaPrevia = document.getElementById('vistaPreviaContenido');
            let previewHtml = `
                <div style="max-height: 300px; overflow-x: auto;">
                    <table style="width: 100%; font-size: 11px; border-collapse: collapse;">
                        <thead>
                            <tr>
                                <th>#</th>
                                <th>Nombre</th>
                                <th>DNI</th>
                                <th>Estado</th>
                                <th>Líder</th>
                            </tr>
                        </thead>
                        <tbody>
            `;
            
            agentes.slice(0, 10).forEach((a, i) => {
                previewHtml += `<tr>
                    <td>${i + 1}</td>
                    <td>${escapeHtml(a.nombre)}</td>
                    <td>${escapeHtml(a.dni || '-')}</td>
                    <td>${a.estado}</td>
                    <td>${escapeHtml(a.lider_2026 || '-')}</td>
                </tr>`;
            });
            
            if (agentes.length > 10) {
                previewHtml += `<tr><td colspan="5" style="text-align: center;">... y ${agentes.length - 10} más<\/td><\/tr>`;
            }
            
            previewHtml += `</tbody><\/table><\/div>`;
            
            if (errores.length > 0) {
                previewHtml += `<div style="margin-top: 10px; color: var(--danger); font-size: 11px;">
                    <strong>⚠️ Advertencias:</strong><br>
                    ${errores.slice(0, 5).join('<br>')}
                    ${errores.length > 5 ? `<br>... y ${errores.length - 5} más` : ''}
                </div>`;
            }
            
            vistaPrevia.innerHTML = previewHtml;
            document.getElementById('vistaPreviaAgentes').style.display = 'block';
            
            // ======================================================
            // ASIGNAR A VARIABLE GLOBAL Y HABILITAR BOTÓN
            // ======================================================
            window.agentesPendientesGuardarMasivo = agentes;
            console.log('📢 [EVENT] window.agentesPendientesGuardarMasivo asignado con:', window.agentesPendientesGuardarMasivo.length);
            
            const btnGuardar = document.getElementById('btnGuardarAgentesMasivo');
            if (btnGuardar) {
                btnGuardar.disabled = false;
                btnGuardar.style.opacity = '1';
                btnGuardar.style.cursor = 'pointer';
                console.log('✅ [EVENT] Botón guardar habilitado');
            }
        };
        reader.readAsArrayBuffer(file);
    });
    
    console.log('✅ [INIT] Evento change registrado correctamente');
}

// Ejecutar cuando el DOM esté listo
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', inicializarEventoAgentes);
} else {
    inicializarEventoAgentes();
}


// ========================================================================================
// BLOQUE 1: CONEXIÓN BD, LOGIN, SESIÓN Y ACTUALIZACIONES (13 funciones)
// ========================================================================================        
    
    // ===== 3. INICIO FUNCIÓN: Verificar sesión ==============================
    async function verificarSesion() {
    const sesion = sessionStorage.getItem('usuario_actual_supervisor');
    if (!sesion) return false;

    try {
        const datos = JSON.parse(sesion);

        // Validar expiración (8 horas máximo)
        const ahora = Date.now();
        const expiracion = datos.timestamp || 0;
        const horasTranscurridas = (ahora - expiracion) / (1000 * 60 * 60);

        if (horasTranscurridas > 8) {
            console.log('⏰ Sesión expirada por tiempo');
            sessionStorage.removeItem('usuario_actual_supervisor');
            sessionStorage.removeItem('session_token_actual');
            return false;
        }

        // Validar que tenga los campos mínimos necesarios
        if (!datos.id || !datos.rol_id) {
            console.log('❌ Sesión inválida (faltan campos)');
            sessionStorage.removeItem('usuario_actual_supervisor');
            return false;
        }

        // 🔴 🔴 🔴 NUEVO: Verificar en BD si la sesión sigue activa 🔴 🔴 🔴
        const sessionToken = sessionStorage.getItem('session_token_actual');
        if (sessionToken) {
            const db = getDB();
            if (db) {
                const { data: sesionBD, error } = await db
                    .from('sesiones_activas')
                    .select('estado')
                    .eq('session_token', sessionToken)
                    .maybeSingle();
                
                if (!error && sesionBD && sesionBD.estado !== 'activa') {
                    console.log(`⚠️ Sesión en BD está: ${sesionBD.estado}. Invalidando sesión local.`);
                    sessionStorage.removeItem('usuario_actual_supervisor');
                    sessionStorage.removeItem('session_token_actual');
                    sessionStorage.removeItem('session_inicio');
                    sessionStorage.removeItem('ultima_actividad');
                    return false;
                }
            }
        }

        usuarioActual = datos;
        return true;

    } catch (e) {
        console.error('Error parseando sesión:', e);
        sessionStorage.removeItem('usuario_actual_supervisor');
        return false;
    }
}

    // ===== NUEVA FUNCIÓN: Verificar si la sesión actual sigue activa en BD =====
    async function verificarSesionEnBD() {
        const sessionToken = sessionStorage.getItem('session_token_actual');
        if (!sessionToken) return false;
        
        const db = getDB();
        if (!db) return false;
        
        try {
            // Verificar si el token sigue activo en la BD
            const { data: sesion, error } = await db
                .from('sesiones_activas')
                .select('id, estado, usuario_id, fecha_inicio')
                .eq('session_token', sessionToken)
                .eq('estado', 'activa')
                .single();
            
            if (error || !sesion) {
                console.log('❌ Sesión no encontrada o inactiva en BD');
                return false;
            }
            
            // Verificar que el usuario en sesión coincide
            if (usuarioActual && sesion.usuario_id !== usuarioActual.id) {
                console.log('❌ Conflicto: usuario en sesión no coincide con BD');
                return false;
            }
            
            return true;
            
        } catch (error) {
            console.error('Error verificando sesión en BD:', error);
            return false;
        }
    }
    // ===== FIN FUNCIÓN: verificarSesion =====================================

    // ===== NUEVA FUNCIÓN: Validar y bloquear múltiples sesiones del mismo usuario
    async function validarYBloquearMultiplesSesiones(usuarioId, sessionTokenNuevo) {
        console.log(`🔒 Validando sesiones activas para usuario ID: ${usuarioId}`);
        
        const db = getDB();
        if (!db) {
            console.error('❌ Base de datos no disponible');
            return false;
        }
        
        try {
            // Verificar si la tabla sesiones_activas existe
            const { error: checkError } = await db
                .from('sesiones_activas')
                .select('id', { count: 'exact', head: true })
                .limit(1);
            
            // Si la tabla no existe, permitir login (para desarrollo)
            if (checkError && checkError.message.includes('does not exist')) {
                console.warn('⚠️ Tabla sesiones_activas no existe. Omitiendo control de sesiones múltiples.');
                return true;
            }
            
            // Buscar sesiones activas de este usuario (excluyendo la nueva que estamos creando)
            const { data: sesionesActivas, error } = await db
                .from('sesiones_activas')
                .select('*')
                .eq('usuario_id', usuarioId)
                .eq('estado', 'activa');
            
            if (error) throw error;
            
            if (sesionesActivas && sesionesActivas.length > 0) {
                console.log(`⚠️ Usuario ya tiene ${sesionesActivas.length} sesión(es) activa(s). Procediendo a cerrarlas...`);
                
                // Cerrar TODAS las sesiones activas anteriores
                for (const sesion of sesionesActivas) {
                    // Si la sesión tiene el mismo token que el nuevo, saltar (no debería ocurrir)
                    if (sesion.session_token === sessionTokenNuevo) continue;
                    
                    const { error: updateError } = await db
                        .from('sesiones_activas')
                        .update({
                            estado: 'cerrada',
                            fecha_fin: new Date().toISOString(),
                            motivo_cierre: 'Nuevo login desde otro dispositivo/navegador'
                        })
                        .eq('id', sesion.id);
                    
                    if (updateError) {
                        console.error(`Error cerrando sesión ${sesion.id}:`, updateError);
                    } else {
                        console.log(`✅ Sesión anterior cerrada: ID ${sesion.id} (token: ${sesion.session_token?.slice(-8)})`);
                        
                        // Registrar en historial de login (opcional)
                        await registrarHistorialLogin(
                            usuarioId,
                            usuarioActual?.usuario || 'Usuario',
                            'sesion_cerrada_por_nuevo_login',
                            sesion.ip_address || '0.0.0.0',
                            sesion.dispositivo || 'Desconocido',
                            `Sesión cerrada automáticamente por nuevo inicio de sesión`
                        );
                    }
                }
                
                console.log(`✅ Se cerraron ${sesionesActivas.length} sesión(es) anterior(es).`);
                return true;
            }
            
            console.log('✅ No hay sesiones activas previas. Login permitido.');
            return true;
            
        } catch (error) {
            console.error('❌ Error en validación de sesiones:', error);
            // En caso de error, permitir el login (no bloquear al usuario)
            return true;
        }
    }
    
    // ======================================================
    // SISTEMA DE GESTIÓN DE SESIONES - VERSIÓN CORREGIDA
    // ======================================================

    // Generar token único de sesión
    function generarSessionToken() {
        return 'ses_' + Date.now() + '_' + Math.random().toString(36).substr(2, 16) + '_' + crypto.randomUUID();
    }

    // Obtener información del dispositivo
    function obtenerInfoDispositivo() {
        const ua = navigator.userAgent;
        let dispositivo = 'Desktop';
        
        if (/(tablet|ipad|playbook|silk)|(android(?!.*mobi))/i.test(ua)) {
            dispositivo = 'Tablet';
        } else if (/Mobile|Android|iP(hone|od)|IEMobile|BlackBerry|Kindle|Silk-Accelerated|(hpw|web)OS|Opera M(obi|ini)/.test(ua)) {
            dispositivo = 'Móvil';
        }
        
        let so = 'Desconocido';
        if (ua.indexOf('Windows') !== -1) so = 'Windows';
        else if (ua.indexOf('Mac') !== -1) so = 'Mac';
        else if (ua.indexOf('Linux') !== -1) so = 'Linux';
        else if (ua.indexOf('Android') !== -1) so = 'Android';
        else if (ua.indexOf('iOS') !== -1 || ua.indexOf('iPhone') !== -1 || ua.indexOf('iPad') !== -1) so = 'iOS';
        
        let navegador = 'Desconocido';
        if (ua.indexOf('Chrome') !== -1 && ua.indexOf('Edg') === -1) navegador = 'Chrome';
        else if (ua.indexOf('Firefox') !== -1) navegador = 'Firefox';
        else if (ua.indexOf('Safari') !== -1 && ua.indexOf('Chrome') === -1) navegador = 'Safari';
        else if (ua.indexOf('Edg') !== -1) navegador = 'Edge';
        else if (ua.indexOf('Opera') !== -1 || ua.indexOf('OPR') !== -1) navegador = 'Opera';
        
        return `${dispositivo} - ${so} / ${navegador}`;
    }

    // Obtener IP pública
    async function obtenerIpPublica() {
        try {
            const response = await fetch('https://api.ipify.org?format=json');
            const data = await response.json();
            return data.ip;
        } catch (error) {
            console.warn('No se pudo obtener IP pública:', error);
            return '0.0.0.0';
        }
    }

    // Registrar historial de login
    async function registrarHistorialLogin(usuarioId, usuario, evento, ip, dispositivo, detalles = '') {
        const db = getDB();
        if (!db) return;
        
        try {
            await db
                .from('historial_login')
                .insert({
                    usuario_id: usuarioId,
                    usuario: usuario,
                    evento: evento,
                    ip_address: ip || '0.0.0.0',
                    user_agent: navigator.userAgent,
                    dispositivo: dispositivo,
                    detalles: detalles,
                    created_at: new Date().toISOString()
                });
            console.log(`✅ Historial registrado: ${evento} para ${usuario}`);
        } catch (error) {
            console.error('Error registrando historial:', error);
        }
    }

    // Crear sesión activa
    async function crearSesionActiva(usuarioId, sessionToken, ip, dispositivo) {
        console.log('🔧 crearSesionActiva - Iniciando...');
        console.log('📝 Parámetros:', { usuarioId, sessionToken, ip, dispositivo });
        
        const db = getDB();
        if (!db) {
            console.error('❌ Base de datos no disponible');
            return false;
        }
        
        try {
            // 🔴 PASO 1: Verificar si la tabla existe
            const { error: checkError } = await db
                .from('sesiones_activas')
                .select('id', { count: 'exact', head: true })
                .limit(1);
            
            // Si la tabla no existe, crearla automáticamente
            if (checkError && checkError.message.includes('does not exist')) {
                console.warn('⚠️ Tabla sesiones_activas no existe. Creándola...');
                const creada = await crearTablaSesionesActivas();
                if (!creada) {
                    console.error('❌ No se pudo crear la tabla');
                    return false;
                }
            }
            
            // 🔴 PASO 2: Verificar si hay una sesión activa anterior
            const { data: sesionesExistentes, error: findError } = await db
                .from('sesiones_activas')
                .select('id')
                .eq('usuario_id', usuarioId)
                .eq('estado', 'activa');
            
            if (!findError && sesionesExistentes && sesionesExistentes.length > 0) {
                console.log(`⚠️ Usuario tiene ${sesionesExistentes.length} sesión(es) activa(s). Cerrando...`);
                
                // Cerrar sesiones anteriores
                for (const sesion of sesionesExistentes) {
                    await db
                        .from('sesiones_activas')
                        .update({ 
                            estado: 'cerrada', 
                            fecha_fin: new Date(),
                            motivo_cierre: 'Nuevo inicio de sesión'
                        })
                        .eq('id', sesion.id);
                }
                console.log(`✅ ${sesionesExistentes.length} sesión(es) anterior(es) cerrada(s)`);
            }
            
            // 🔴 PASO 3: Insertar NUEVA sesión con los nombres de columna CORRECTOS
            const ahora = new Date();
            
            const nuevaSesion = {
                usuario_id: usuarioId,
                session_token: sessionToken,  // ← ¡ATENCIÓN! Debe ser 'session_token' (con 's')
                ip_address: ip,
                user_agent: navigator.userAgent,
                dispositivo: dispositivo,
                fecha_inicio: ahora,
                ultima_actividad: ahora,
                estado: 'activa'
            };
            
            console.log('📤 Insertando sesión en la base de datos:', nuevaSesion);
            
            const { data, error } = await db
                .from('sesiones_activas')
                .insert(nuevaSesion)
                .select();
            
            if (error) {
                console.error('❌ Error detallado al insertar:', error);
                console.error('🔍 Código de error:', error.code);
                console.error('📝 Mensaje:', error.message);
                console.error('📋 Detalles:', error.details);
                
                // Si el error es por columna faltante, mostrar qué columna falta
                if (error.message.includes('column')) {
                    console.error('⚠️ Posiblemente falta una columna en la tabla. Verifica la estructura.');
                }
                return false;
            }
            
            console.log('✅ Sesión insertada correctamente. ID:', data?.[0]?.id);
            console.log('📦 Datos guardados:', data?.[0]);
            
            // Guardar token en sessionStorage para verificación futura
            sessionStorage.setItem('session_token_actual', sessionToken);
            sessionStorage.setItem('session_inicio', Date.now().toString());
            sessionStorage.setItem('ultima_actividad', Date.now().toString());
            
            return true;
            
        } catch (error) {
            console.error('❌ Error inesperado en crearSesionActiva:', error);
            console.error('Stack trace:', error.stack);
            return false;
        }
    }

    // ======================================================
    // GUARDAR ROL (crear o actualizar)
    // ======================================================
    async function guardarRol(event) {
        event.preventDefault();
        
        const id = document.getElementById('rolId')?.value;
        const codigo = document.getElementById('rolCodigo')?.value.trim().toUpperCase();
        const nombre = document.getElementById('rolNombre')?.value.trim();
        const activo = document.getElementById('rolActivo')?.value === 'true';
        
        if (!codigo || !nombre) {
            alert('⚠️ Complete los campos obligatorios: Código y Nombre');
            return;
        }
        
        // Obtener pestañas seleccionadas
        const pestanasSeleccionadas = [];
        document.querySelectorAll('#formRol input[type="checkbox"]:checked').forEach(cb => {
            pestanasSeleccionadas.push(cb.value);
        });
        
        try {
            if (id) {
                // Actualizar rol existente
                await API.actualizarRol(id, { codigo, nombre, activo, pestanas: pestanasSeleccionadas });
                alert(`✅ Rol "${nombre}" actualizado correctamente`);
            } else {
                // Crear nuevo rol
                await API.crearRol({ codigo, nombre, activo, pestanas: pestanasSeleccionadas });
                alert(`✅ Rol "${nombre}" creado correctamente`);
            }
            
            // Recargar lista de roles
            if (typeof cargarRoles === 'function') {
                await cargarRoles();
            }
            
            // Cerrar modal
            cerrarModalRol();
            
        } catch (error) {
            console.error('❌ Error guardando rol:', error);
            alert(`❌ Error al guardar: ${error.message}`);
        }
    }

    // Verificar validez de sesión
    async function verificarValidezSesion() {
        const sessionToken = sessionStorage.getItem('session_token_actual');
        const sessionInicio = parseInt(sessionStorage.getItem('session_inicio'));
        const ultimaActividad = parseInt(sessionStorage.getItem('ultima_actividad'));
        
        if (!sessionToken || !sessionInicio) {
            console.log('⚠️ No hay session_token guardado');
            return false;
        }
        
        const db = getDB();
        if (!db) {
            console.error('❌ Base de datos no disponible');
            return false;
        }
        
        try {
            const ahora = Date.now();
            const duracionMaximaMs = 8 * 60 * 60 * 1000; // 8 horas
            const inactividadMaximaMs = 30 * 60 * 1000; // 30 minutos
            
            // Verificar duración máxima
            if (ahora - sessionInicio > duracionMaximaMs) {
                console.log('⏰ Sesión expirada por tiempo máximo (8 horas)');
                await cerrarSesionPorExpiracion(sessionToken);
                return false;
            }
            
            // Verificar inactividad
            if (ultimaActividad && (ahora - ultimaActividad > inactividadMaximaMs)) {
                console.log('⌛ Sesión expirada por inactividad (30 minutos)');
                await cerrarSesionPorInactividad(sessionToken);
                return false;
            }
            
            // 🔴 VERIFICAR EN BASE DE DATOS
            // Usar 'session_token' (con 's') para consultar
            const { data: sesion, error } = await db
                .from('sesiones_activas')
                .select('id, estado, fecha_inicio, ultima_actividad')
                .eq('session_token', sessionToken)
                .maybeSingle();
            
            if (error) {
                console.error('❌ Error consultando sesión:', error);
                // Si hay error, permitir continuar pero registrar
                return true;
            }
            
            if (!sesion) {
                console.log('⚠️ Sesión no encontrada en base de datos');
                return false;
            }
            
            if (sesion.estado !== 'activa') {
                console.log(`⚠️ Sesión en estado: ${sesion.estado}`);
                return false;
            }
            
            // Actualizar última actividad en base de datos
            await db
                .from('sesiones_activas')
                .update({ ultima_actividad: new Date() })
                .eq('id', sesion.id);
            
            return true;
            
        } catch (error) {
            console.error('❌ Error verificando sesión:', error);
            return true; // En caso de error, permitir continuar
        }
    }

    // Actualizar última actividad
    function actualizarUltimaActividad() {
        sessionStorage.setItem('ultima_actividad', Date.now().toString());
        
        const sessionToken = sessionStorage.getItem('session_token');
        if (!sessionToken) return;
        
        const db = getDB();
        if (!db) return;
        
        // Verificar si la tabla existe antes de actualizar
        db.from('sesiones_activas')
            .select('id', { count: 'exact', head: true })
            .limit(1)
            .then(({ error }) => {
                if (!error || !error.message.includes('does not exist')) {
                    db
                        .from('sesiones_activas')
                        .update({ ultima_actividad: new Date().toISOString() })
                        .eq('session_token', sessionToken)
                        .eq('estado', 'activa')
                        .catch(e => console.warn('Error actualizando actividad:', e));
                }
            });
    }

    // Cerrar sesión por expiración
    async function cerrarSesionPorExpiracion(sessionToken) {
        const db = getDB();
        if (db) {
            try {
                await db
                    .from('sesiones_activas')
                    .update({ estado: 'expirada', fecha_fin: new Date().toISOString() })
                    .eq('session_token', sessionToken);
            } catch(e) { console.warn(e); }
        }
        alert('⏰ Su sesión ha expirado. Por favor, inicie sesión nuevamente.');
        cerrarSesion();
    }

    // Cerrar sesión por inactividad
    async function cerrarSesionPorInactividad(sessionToken) {
        const db = getDB();
        if (db) {
            try {
                await db
                    .from('sesiones_activas')
                    .update({ estado: 'expirada', fecha_fin: new Date().toISOString() })
                    .eq('session_token', sessionToken);
            } catch(e) { console.warn(e); }
        }
        alert('⏳ Su sesión ha sido cerrada por inactividad.');
        cerrarSesion();
    }

    // ===== INICIO FUNCIÓN: IniciarMonitorSesion =============================
    function iniciarMonitorSesion() {
        console.log('🔧 [GLOBAL] iniciarMonitorSesion - EJECUTADA');
        
        // Limpiar monitor existente si lo hay
        if (window.monitorIntervalSesion) {
            console.log('🔧 Limpiando monitor existente...');
            clearInterval(window.monitorIntervalSesion);
            window.monitorIntervalSesion = null;
        }
        
        if (!usuarioActual) {
            console.log('⚠️ No hay usuario actual, monitor no iniciado');
            return false;
        }
        
        console.log('🟢 INICIANDO MONITOR DE SESIÓN (cada 10 segundos)');
        
        window.monitorIntervalSesion = setInterval(async () => {
            const sessionToken = sessionStorage.getItem('session_token_actual');
            if (!sessionToken) return;
            
            const db = getDB();
            if (!db) return;
            
            try {
                const { data: sesion, error } = await db
                    .from('sesiones_activas')
                    .select('estado')
                    .eq('session_token', sessionToken)
                    .maybeSingle();
                
                if (error) return;
                
                if (!sesion || sesion.estado !== 'activa') {
                    console.log('⚠️ Sesión cerrada remotamente');
                    alert('⚠️ Su sesión ha sido cerrada por un administrador o por inicio de sesión en otro dispositivo');
                    sessionStorage.clear();
                    location.reload();
                }
            } catch(e) {
                console.error('Monitor error:', e);
            }
        }, 10000);
        
        console.log('✅ Monitor creado con ID:', window.monitorIntervalSesion);
        return true;
    }
    // ===== FIN FUNCIÓN: iniciarMonitorSesion ================================

