    // ===== 10. INICIO FUNCIÓN: HashPassword (ENCRIPTAR CONTRASEÑA) ==========
    async function hashPassword(password) {
        const encoder = new TextEncoder();
        const data = encoder.encode(password);
        const hashBuffer = await crypto.subtle.digest('SHA-256', data);
        const hashArray = Array.from(new Uint8Array(hashBuffer));
        const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
        return hashHex;
    }
    // ===== FIN FUNCIÓN: hashPassword ========================================
    
    // ===== 11. INICIO FUNCIÓN: CargarPermisosUsuarioDesdeBD =================
    async function cargarPermisosUsuarioDesdeBD() {
        if (!usuarioActual || !usuarioActual.id) return null;

        const db = getDB();
        if (!db) return null;

        try {
            const { data, error } = await db
                .from('usuarios')
                .select(`
                    id,
                    activo,
                    roles:rol_id (
                        id,
                        codigo,
                        nombre
                    )
                `)
                .eq('id', usuarioActual.id)
                .single();

            if (error) {
                console.error('Error consultando permisos:', error);
                return null;
            }

            if (!data || !data.activo) {
                console.log('❌ Usuario inactivo o no encontrado');
                cerrarSesion();
                return null;
            }

            if (!data.roles) {
                console.log('❌ Usuario sin rol asignado');
                cerrarSesion();
                return null;
            }

            // ✅ Ya no usamos la columna permisos
            return {
                rol_id: data.roles.id,
                rol_codigo: data.roles.codigo,
                rol_nombre: data.roles.nombre,
                permisos: { pestanas: [] } // vacío, ya no se usa
            };

        } catch (error) {
            console.error('Error cargando permisos:', error);
            return null;
        }
    }
