    // ===== 12. INICIO FUNCIÓN: MostrarInterfazPorRolSeguro ==================
    async function mostrarInterfazPorRolSeguro() {
        console.log('👤 Configurando interfaz dinámica para usuario...');

        const permisosUsuario = await cargarPermisosUsuarioDesdeBD();

        if (!permisosUsuario) {
            cerrarSesion();
            return false;
        }

        if (usuarioActual) {
            usuarioActual.rol_codigo = permisosUsuario.rol_codigo;
            usuarioActual.rol_nombre = permisosUsuario.rol_nombre;
            usuarioActual.rol_id = permisosUsuario.rol_id;
            console.log('📦 usuarioActual actualizado:', usuarioActual);
        }

        // Mostrar información del usuario en el header
        const userInfo = document.getElementById('userInfo');
        const userName = document.getElementById('userName');
        const userRol = document.getElementById('userRol');

        if (userInfo) userInfo.style.display = 'flex';
        if (userName && usuarioActual) userName.textContent = usuarioActual?.nombre_completo || 'Usuario';
        if (userRol && permisosUsuario) userRol.textContent = permisosUsuario.rol_nombre || permisosUsuario.rol_codigo;

        // 🔴 🔴 🔴 ESTO ES LO QUE FALTA - GENERAR LAS PESTAÑAS 🔴 🔴 🔴
        console.log('📦 Llamando a generarTabsDinamicos...');
        await generarTabsDinamicos();
        console.log('📦 generarTabsDinamicos completado');

        console.log(`✅ Interfaz configurada para rol: ${permisosUsuario.rol_codigo}`);
        return true;
    }
