    // 1. Cargar todas las pestañas disponibles desde la base de datos
    async function cargarPestanasDisponibles() {
        const db = getDB();
        if (!db) return [];
        
        try {
            const { data: pestanas, error } = await db
                .from('pestanas_sistema')
                .select('*')
                .eq('visible', true)
                .order('orden', { ascending: true });
            
            if (error) {
                console.warn('Error cargando pestañas:', error);
                return obtenerPestanasFallback(); // Fallback por si la tabla no existe
            }
            return pestanas || [];
        } catch (error) {
            console.warn('Error en cargarPestanasDisponibles:', error);
            return obtenerPestanasFallback();
        }
    }

    // 2. Obtener pestañas permitidas para un rol específico
    async function obtenerPestanasPorRol(rolId) {
        const db = getDB();
        if (!db || !rolId) return [];
        
        try {
            // Intentar obtener desde la tabla rol_pestanas
            const { data, error } = await db
                .from('rol_pestanas')
                .select('pestana_codigo')
                .eq('rol_id', rolId);
            
            if (error) {
                console.warn('Error obteniendo permisos de pestañas:', error);
                // Fallback: usar permisos antiguos del JSON
                return obtenerPestanasDesdePermisosAntiguos();
            }
            return data.map(r => r.pestana_codigo);
        } catch (error) {
            console.warn('Error en obtenerPestanasPorRol:', error);
            return obtenerPestanasDesdePermisosAntiguos();
        }
    }

    // Fallback para compatibilidad con roles que aún tienen permisos en JSON
    function obtenerPestanasDesdePermisosAntiguos() {
        const rolCodigo = usuarioActual?.rol_codigo;
        console.log('🔍 Fallback para rol:', rolCodigo);
        
        if (rolCodigo === 'ADMIN') {
            return ['reportes', 'historialAgente', 'gestionPDA', 'productividad', 'gestionEscuchas', 'gestionAgentes', 'gestionUsuarios', 'estadoBD', 'versiones'];
        }
        if (rolCodigo === 'SUPERVISOR') {
            return ['reportes', 'historialAgente', 'gestionPDA', 'productividad', 'gestionEscuchas', 'gestionAgentes', 'estadoBD'];
        }
        if (rolCodigo === 'GERENTE') {
            return ['reportes', 'historialAgente'];
        }
        // AUDITOR no debería llegar aquí porque se bloquea en login
        return ['reportes']; // Guest mínimo
    }

    // 3. Generar dinámicamente los botones de pestañas
    async function generarTabsDinamicos() {
        console.log('🔧 generarTabsDinamicos - INICIANDO...');
        
        const todasLasPestanas = await cargarPestanasDisponibles();
        console.log('📦 todasLasPestanas:', todasLasPestanas);
        
        const rolId = usuarioActual?.rol_id;
        console.log('📦 rolId:', rolId);
        
        if (!rolId) {
            console.warn('⚠️ No hay rol_id para generar pestañas');
            return;
        }
        
        const pestanasPermitidas = await obtenerPestanasPorRol(rolId);
        console.log('📦 pestanasPermitidas:', pestanasPermitidas);
        
        const tabsContainer = document.getElementById('tabsHeaderContainer');
        console.log('📦 tabsContainer encontrado:', !!tabsContainer);
        
        if (!tabsContainer) {
            console.error('❌ No se encontró #tabsHeaderContainer');
            // 🔴 CREAR EL CONTENEDOR SI NO EXISTE
            const tabsHeader = document.querySelector('.tabs-header');
            if (tabsHeader && !tabsHeader.id) {
                tabsHeader.id = 'tabsHeaderContainer';
                console.log('✅ Se asignó id al .tabs-header existente');
            }
            return;
        }
        
        // Limpiar pestañas existentes
        tabsContainer.innerHTML = '';
        console.log('📦 tabsContainer limpiado');
        
        // Generar cada pestaña
        todasLasPestanas.forEach(pestana => {
            const estaPermitida = pestanasPermitidas.includes(pestana.codigo);
            console.log(`📦 Pestaña ${pestana.codigo}: permitida=${estaPermitida}`);
            
            if (estaPermitida) {
                const button = document.createElement('button');
                button.className = 'tab-button';
                button.innerHTML = `${pestana.icono} ${pestana.nombre}`;
                button.setAttribute('data-tab', pestana.codigo);
                button.onclick = (event) => showTab(pestana.codigo, event);
                tabsContainer.appendChild(button);
                console.log(`✅ Botón creado: ${pestana.nombre}`);
            }
        });
        
        // Activar la primera pestaña por defecto
        const primerBoton = tabsContainer.querySelector('.tab-button');
        if (primerBoton && !document.querySelector('.tab-button.active')) {
            primerBoton.classList.add('active');
            const primeraPestana = primerBoton.getAttribute('data-tab');
            if (primeraPestana) {
                showTab(primeraPestana, null);
            }
        }
        
        console.log(`✅ Generadas ${tabsContainer.children.length} pestañas`);
    }

