    // ===== 1. INICIO FUNCIÓN: CargarEvaluacionesDesdePostgreSQL (join) =======
    async function cargarEvaluacionesDesdePostgreSQL() {
        console.log('🔄 Cargando evaluaciones desde PostgreSQL...');
        
        try {
            // 🔴 USAR LA FUNCIÓN QUE YA FUNCIONA: API.getEvaluacionesConDetalles()
            // Esta función ya hace el mapeo snake_case → camelCase correctamente
            const evaluacionesConDetalles = await API.getEvaluacionesConDetalles();
            
            if (!evaluacionesConDetalles || evaluacionesConDetalles.length === 0) {
                console.log('📭 No hay evaluaciones en la BD');
                window.evaluacionesGlobales = [];
                return [];
            }

            console.log(`✅ Cargadas ${evaluacionesConDetalles.length} evaluaciones desde API.getEvaluacionesConDetalles()`);
            
            // 🔴 Los datos YA VIENEN en el formato correcto (camelCase)
            // Solo necesitamos asegurar que los números sean números
            const evaluacionesFormateadas = evaluacionesConDetalles.map(evalItem => {
                // Los detalles ya vienen mapeados desde la API
                const detalles = (evalItem.detalles_evaluacion || []).map(det => ({
                    bloque: det.bloque || '',
                    atributo: det.atributo || '',
                    submotivo: det.submotivo || '',
                    peso: Number(det.peso) || 0,
                    cumple: det.cumple === true || det.cumple === 1 || det.cumple === 'true'
                }));
                
                return {
                    id: evalItem.id,
                    timestamp: evalItem.timestamp,
                    fechaOriginal: evalItem.fecha_formateada || evalItem.fecha,
                    fecha: evalItem.fecha_formateada || evalItem.fecha,
                    ticketPSI: evalItem.ticket_psi || '',
                    agente: evalItem.agente || '',
                    evaluador: evalItem.evaluador || '',
                    idLlamada: evalItem.id_llamada || '',
                    fechaDescarga: evalItem.fecha_descarga || null,
                    // Asegurar que sean números
                    notaFinal: Number(evalItem.nota_final) || 0,
                    rango: evalItem.rango || '',
                    totalENC: Number(evalItem.total_enc) || 0,
                    totalECUF: Number(evalItem.total_ecuf) || 0,
                    totalECN: Number(evalItem.total_ecn) || 0,
                    tiempoAuditoria: evalItem.tiempo_auditoria || '',
                    tiempoAuditoriaFormateado: evalItem.tiempo_auditoria_formateado || '',
                    detalles: detalles
                };
            });

            window.evaluacionesGlobales = evaluacionesFormateadas;
            
            const conDetalles = evaluacionesFormateadas.filter(e => e.detalles && e.detalles.length > 0).length;
            console.log(`✅ ${window.evaluacionesGlobales.length} evaluaciones cargadas`);
            console.log(`📋 Evaluaciones con detalles: ${conDetalles}`);
            console.log('📊 Ejemplo notaFinal (como número):', window.evaluacionesGlobales[0]?.notaFinal, typeof window.evaluacionesGlobales[0]?.notaFinal);
            
            return window.evaluacionesGlobales;
            
        } catch (error) {
            console.error('❌ Error cargando evaluaciones:', error);
            window.evaluacionesGlobales = [];
            return [];
        }
    }
    // ===== FIN FUNCIÓN: cargarEvaluacionesDesdePostgreSQL =====================

    // ===== 2. INICIO FUNCIÓN: obtenerEvaluacionesConCache ==================
    async function obtenerEvaluacionesConCache(forzarRecarga = false) {
        const ahora = Date.now();
        const cacheValido = cacheEvaluaciones.data &&
            (ahora - cacheEvaluaciones.timestamp) < CACHE_DURACION &&
            !forzarRecarga;

        if (cacheValido) {
            console.log('✅ Usando caché de evaluaciones');
            return cacheEvaluaciones.data;
        }

        console.log('🔄 Obteniendo evaluaciones con detalles desde API...');
        
        // 🔴 Usar la función corregida que llama a API.getEvaluacionesConDetalles()
        const datos = await cargarEvaluacionesDesdePostgreSQL();
        
        if (!datos || datos.length === 0) {
            console.warn('⚠️ No se obtuvieron evaluaciones');
            return [];
        }
        
        console.log(`✅ Datos normalizados: ${datos.length} evaluaciones`);
        console.log('📊 Ejemplo - cantidad de detalles:', datos[0]?.detalles?.length || 0);

        cacheEvaluaciones = {
            data: datos,
            timestamp: ahora,
            hash: calcularHashEvaluaciones()
        };

        return datos;
    }
    // ===== FIN FUNCIÓN: obtenerEvaluacionesConCache =========================

