    // Obtener meses disponibles en la BD
    async function obtenerMesesDisponiblesDinamicos() {
        try {
            const meses = await API.getMesesDisponibles();
            return meses.map(m => ({
                valor: m.valor || `${m.anio}-${String(m.mes).padStart(2, '0')}`,
                label: m.label,
                anio: m.anio,
                mes: m.mes
            }));
        } catch (error) {
            console.error('Error obteniendo meses:', error);
            return [];
        }
    }
    
    // Obtener trimestres disponibles de los meses
    async function obtenerTrimestresDisponiblesDinamicos() {
        try {
            const meses = await API.getMesesDisponibles();
            const trimestres = new Map();
            
            meses.forEach(m => {
                const trim = Math.floor((m.mes - 1) / 3) + 1;
                const trimKey = `${m.anio}-Q${trim}`;
                if (!trimestres.has(trimKey)) {
                    trimestres.set(trimKey, {
                        valor: trimKey,
                        label: `Q${trim} ${m.anio}`,
                        anio: m.anio,
                        trimestre: trim
                    });
                }
            });
            
            return Array.from(trimestres.values()).sort();
        } catch (error) {
            console.error('Error obteniendo trimestres:', error);
            return [];
        }
    }
    
    // Obtener años disponibles de los meses
    async function obtenerAniosDisponiblesDinamicos() {
        try {
            const meses = await API.getMesesDisponibles();
            const anios = new Map();
            
            meses.forEach(m => {
                if (!anios.has(m.anio)) {
                    anios.set(m.anio, {
                        valor: m.anio.toString(),
                        label: m.anio.toString(),
                        anio: m.anio
                    });
                }
            });
            
            return Array.from(anios.values()).sort((a, b) => a.anio - b.anio);
        } catch (error) {
            console.error('Error obteniendo años:', error);
            return [];
        }
    }
    
    // Obtener días disponibles de la BD
    async function obtenerDiasDisponiblesDinamicos() {
        try {
            const evaluaciones = await obtenerEvaluacionesConCache();
            const dias = new Map();
            
            evaluaciones.forEach(eval => {
                const fecha = obtenerFechaEvaluacion(eval);
                if (fecha) {
                    const diaStr = formatDateForInput(fecha);
                    if (!dias.has(diaStr)) {
                        dias.set(diaStr, {
                            valor: diaStr,
                            label: formatDateToDisplay(diaStr),
                            fecha: fecha
                        });
                    }
                }
            });
            
            return Array.from(dias.values()).sort((a, b) => a.fecha - b.fecha);
        } catch (error) {
            console.error('Error obteniendo días:', error);
            return [];
        }
    }
    
