    // ===== 10. INICIO FUNCIÓN: filtrarEvaluacionesPorMes ====================
    function filtrarEvaluacionesPorMes(evaluaciones, mesKey) {
        if (mesKey === 'todos') return evaluaciones;
        
        const [anioFiltro, mesFiltro] = mesKey.split('-');
        
        return evaluaciones.filter(eval => {
            // Usar fecha_formateada que tiene formato DD/MM/YYYY HH:MM
            let fechaStr = eval.fecha_formateada || '';
            if (!fechaStr) return false;
            
            // Extraer DD/MM/YYYY
            const fechaParte = fechaStr.split(' ')[0];
            const partes = fechaParte.split('/');
            if (partes.length !== 3) return false;
            
            const dia = partes[0];
            const mes = partes[1];
            const anio = partes[2];
            
            return anio === anioFiltro && mes === mesFiltro;
        });
    }
    // ===== FIN FUNCIÓN: filtrarEvaluacionesPorMes ===========================

