    // ===== 13. INICIO FUNCIÓN: preprocesarDatosParaGraficos =================
    async function preprocesarDatosParaGraficos(evaluaciones) {
        if (!evaluaciones || evaluaciones.length === 0) return null;

        // Crear hash para saber si los datos cambiaron
        let hash = '';
        for (let i = 0; i < Math.min(evaluaciones.length, 50); i++) {
            hash += `${evaluaciones[i].id}|${evaluaciones[i].notaFinal}|`;
        }
        hash += `len:${evaluaciones.length}`;

        // Si los datos no cambiaron, devolver los preprocesados
        if (datosPreprocesados.hashEvaluaciones === hash && datosPreprocesados.ultimaActualizacion) {
            console.log('✅ Usando datos preprocesados para gráficos');
            return datosPreprocesados;
        }

        console.log('🔄 Preprocesando datos para gráficos (una sola vez)...');

        const porFecha = {};
        const porSemana = {};
        const porMes = {};
        const porTrimestre = {};
        const porAnio = {};

        // Mapeo de submotivos a frentes
        const mapaFrentes = {
            'Cumple_Speech': 'cliente', 'Cliente_corta_llamada': 'cliente',
            'Especifica_Motivo_Llamada': 'cliente', 'Menciona_Numero_Servicio': 'cliente',
            'No_Interrumpe_Dialogo': 'cliente', 'No_Omite_Preguntas_del_Cliente': 'cliente',
            'No_Deja_en_Espera_al_Cliente': 'cliente', 'No_Usa_Jergas': 'cliente',
            'Transmite_Seguridad/confianza': 'cliente', 'Tono_de_Voz/ Vocalizacion': 'cliente',
            'No_Corta_Llamada': 'negocio', 'No_Genera_conflicto_con_cliente': 'negocio',
            'Amabilidad': 'negocio', 'Brinda_informacion_correcta': 'negocio',
            'No_Repite_Información': 'negocio', 'Informa_Campañas': 'negocio',
            'Identifica_Responsable_de_Pago': 'proceso', 'Valida_Pago_de_Deuda': 'proceso',
            'Genera_Compromiso_de_Pago': 'proceso', 'Maneja_Objeciones': 'proceso',
            'Resuelve_dudas': 'proceso', 'Pregunta_motivo_no_pago': 'proceso',
            'Prioriza_pagos_APP_Digitales': 'proceso', 'Prioriza_pagos_Bancos/Agentes': 'proceso',
            'Confirma_Compromiso_de_Pago': 'proceso', 'Cierre_correcto': 'proceso',
            'No_Perjudica_imagen_Movistar': 'proceso', 'No_Compara_con_otros_clientes': 'proceso',
            'No_Induce Baja/Reclamo': 'proceso', 'Tipificacion_correcta': 'proceso'
        };

        // Procesar cada evaluación UNA SOLA VEZ
        for (const evalItem of evaluaciones) {
            // Obtener fecha
            let fechaStr = evalItem.fechaOriginal || evalItem.fecha || '';
            let fechaSolo = '';
            if (fechaStr.includes(' ')) fechaSolo = fechaStr.split(' ')[0];
            else if (fechaStr.includes('T')) {
                const [anio, mes, dia] = fechaStr.split('T')[0].split('-');
                fechaSolo = `${dia}/${mes}/${anio}`;
            } else fechaSolo = fechaStr;

            if (!fechaSolo) continue;

            // Parsear fecha para agrupación
            const [dia, mes, anio] = fechaSolo.split('/');
            const fechaObj = new Date(anio, mes - 1, dia);
            const semana = getWeekNumber(fechaObj);
            const trimestre = Math.floor((parseInt(mes) - 1) / 3) + 1;

            const claveDia = fechaSolo;
            const claveSemana = `${anio}-S${semana}`;
            const claveMes = `${anio}-${mes}`;
            const claveTrimestre = `${anio}-T${trimestre}`;
            const claveAnio = anio;

            // Inicializar estructuras
            [porFecha, porSemana, porMes, porTrimestre, porAnio].forEach(agrupador => {
                const clave = agrupador === porFecha ? claveDia :
                    agrupador === porSemana ? claveSemana :
                        agrupador === porMes ? claveMes :
                            agrupador === porTrimestre ? claveTrimestre : claveAnio;

                if (!agrupador[clave]) {
                    agrupador[clave] = {
                        fecha: claveDia,
                        label: agrupador === porFecha ? `${dia}/${mes}` :
                            agrupador === porSemana ? `Sem ${semana}` :
                                agrupador === porMes ? `${mes}/${anio}` :
                                    agrupador === porTrimestre ? `T${trimestre} ${anio}` : anio,
                        count: 0,
                        sumaNotas: 0,
                        cliente: { pesoTotal: 0, pesoObtenido: 0 },
                        negocio: { pesoTotal: 0, pesoObtenido: 0 },
                        proceso: { pesoTotal: 0, pesoObtenido: 0 },
                        quiebres: 0,
                        fallasPorAtributo: {},
                        fallasPorSubmotivo: {}
                    };
                }
            });

        // Agregar datos a cada nivel de agregación
        const estructuras = [
            { dict: porFecha, clave: claveDia },
            { dict: porSemana, clave: claveSemana },
            { dict: porMes, clave: claveMes },
            { dict: porTrimestre, clave: claveTrimestre },
            { dict: porAnio, clave: claveAnio }
        ];

        for (const { dict, clave } of estructuras) {
            const item = dict[clave];
            item.count++;
            item.sumaNotas += evalItem.notaFinal || 0;

            if ((evalItem.notaFinal || 0) < 85) item.quiebres++;

            // Procesar detalles para frentes y fallas
            if (evalItem.detalles && evalItem.detalles.length > 0) {
                for (const det of evalItem.detalles) {
                    const cumple = det.cumple === true || det.cumple === 'true' || det.cumple === 1;
                    const peso = det.peso || 0;
                    const submotivo = det.submotivo;
                    const atributo = det.atributo;
                    const frente = mapaFrentes[submotivo];

                    if (frente === 'cliente') {
                        item.cliente.pesoTotal += peso;
                        if (cumple) item.cliente.pesoObtenido += peso;
                    } else if (frente === 'negocio') {
                        item.negocio.pesoTotal += peso;
                        if (cumple) item.negocio.pesoObtenido += peso;
                    } else if (frente === 'proceso') {
                        item.proceso.pesoTotal += peso;
                        if (cumple) item.proceso.pesoObtenido += peso;
                    }

                    if (!cumple && submotivo) {
                        item.fallasPorAtributo[atributo] = (item.fallasPorAtributo[atributo] || 0) + 1;
                        item.fallasPorSubmotivo[submotivo] = (item.fallasPorSubmotivo[submotivo] || 0) + 1;
                    }
                }
            }
        }
    }
    
        // ======================================================
        // ## 03. Preprocesamiento y gráficos rápidos globales
        // ======================================================
            // Calcular porcentajes
            const procesarPorcentajes = (agrupador) => {
                for (const clave in agrupador) {
                    const item = agrupador[clave];
                    item.promedioNota = item.count > 0 ? (item.sumaNotas / item.count).toFixed(1) : 0;
                    item.porcentajeQuiebres = item.count > 0 ? (item.quiebres / item.count) * 100 : 0;

                    // Calcular porcentajes de frentes
                    item.cliente.pct = item.cliente.pesoTotal > 0 ?
                        Math.round((item.cliente.pesoObtenido / item.cliente.pesoTotal) * 100) : 100;
                    item.negocio.pct = item.negocio.pesoTotal > 0 ?
                        Math.round((item.negocio.pesoObtenido / item.negocio.pesoTotal) * 100) : 100;
                    item.proceso.pct = item.proceso.pesoTotal > 0 ?
                        Math.round((item.proceso.pesoObtenido / item.proceso.pesoTotal) * 100) : 100;
                }
            };

            procesarPorcentajes(porFecha);
            procesarPorcentajes(porSemana);
            procesarPorcentajes(porMes);
            procesarPorcentajes(porTrimestre);
            procesarPorcentajes(porAnio);

            // Ordenar por fecha
            const ordenarPorFecha = (agrupador) => {
                return Object.values(agrupador).sort((a, b) => {
                    const [diaA, mesA, anioA] = a.fecha.split('/');
                    const [diaB, mesB, anioB] = b.fecha.split('/');
                    return new Date(anioA, mesA - 1, diaA) - new Date(anioB, mesB - 1, diaB);
                });
            };

            datosPreprocesados = {
                porFecha: ordenarPorFecha(porFecha),
                porSemana: ordenarPorFecha(porSemana),
                porMes: ordenarPorFecha(porMes),
                porTrimestre: ordenarPorFecha(porTrimestre),
                porAnio: ordenarPorFecha(porAnio),
                ultimaActualizacion: Date.now(),
                hashEvaluaciones: hash,
                evaluacionesOriginales: evaluaciones
            };

            console.log(`✅ Datos preprocesados: ${datosPreprocesados.porFecha.length} días, ${datosPreprocesados.porSemana.length} semanas, ${datosPreprocesados.porMes.length} meses`);

            return datosPreprocesados;
    }
    // ===== FIN FUNCIÓN: preprocesarDatosParaGraficos ========================
    
    // ===== 14. INICIO FUNCIÓN: CalcularHashEvaluaciones =====================            
    function calcularHashEvaluaciones() {
        // Solo verificamos si hay nuevos registros en la base de datos
        // Esto es ligero porque no descarga datos
        return window.ultimoTimestampEvaluaciones || 'init';
    }
    // ===== FIN FUNCIÓN: CalcularHashEvaluaciones ========================

    // ===== 15. INICIO FUNCIÓN: cargarEvaluacionesConOptimizacion =================⚠️ Redundante
    async function cargarEvaluacionesConOptimizacion() {
    return await obtenerEvaluacionesConCache(false);
    }
    // ===== FIN FUNCIÓN: cargarEvaluacionesConOptimizacion ===================

// =============================CIERRE BLOQUE 2==========================================

// ======================================================================================
// BLOQUE 3: PESTAÑA "REPORTES" (Gráficos, KPIs, Filtros, Líderes) (45 funciones)
