    function mostrarMensajeSinDatosEnGraficos() {
        const canvasIds = [
            'chartEvolutivoAudios',
            'chartDistribucionRangos',
            'chartEvolutivoAtributos',
            'chartEvolutivoQuiebres',
            'chartComparativa',
            'chartEvolutivoFrentes',
            'chartAuditoriasPorAuditor',
            'chartEvolutivoAuditorias'
        ];

        canvasIds.forEach(id => {
            const canvas = document.getElementById(id);
            if (canvas) {
                const ctx = canvas.getContext('2d');
                if (ctx) {
                    destruirGraficoPorCanvas(id);
                    canvas.width = canvas.clientWidth;
                    canvas.height = canvas.clientHeight;
                    ctx.clearRect(0, 0, canvas.width, canvas.height);
                    ctx.font = '14px sans-serif';
                    ctx.fillStyle = '#6c757d';
                    ctx.textAlign = 'center';
                    ctx.fillText('📊 No hay datos en el período seleccionado', canvas.width / 2, canvas.height / 2);
                }
            }
        });
    }
