    // ===== FIN FUNCIÓN: renderizarEvolutivoConDatosFiltrados ================
    
    // ===== 18. INICIO FUNCIÓN: procesarDatosEvolutivosConEvaluaciones =======
    function procesarDatosEvolutivosConEvaluaciones(evaluaciones) {
        // 🔴 CORREGIDO: Verificar el parámetro recibido, NO usar window.evaluacionesGlobales
        if (!evaluaciones || evaluaciones.length === 0) {
            console.log('⚠️ procesarDatosEvolutivosConEvaluaciones: No hay evaluaciones recibidas');
            return [];
        }

        console.log(`📊 Procesando ${evaluaciones.length} evaluaciones para datos evolutivos`);

        const mapaFrentes = {
            // ======================================================
            // FRENTE CLIENTE (ENC)
            // ======================================================
            'Cumple_Speech': 'cliente',
            'Cliente_corta_llamada': 'cliente',
            'Especifica_Motivo_Llamada': 'cliente',
            'Menciona_Numero_Servicio': 'cliente',
            'No_Interrumpe_Dialogo': 'cliente',
            'No_Omite_Preguntas_del_Cliente': 'cliente',
            'No_Deja_en_Espera_al_Cliente': 'cliente',
            'No_Usa_Jergas': 'cliente',
            'Transmite_Seguridad/confianza': 'cliente',
            'Tono_de_Voz/ Vocalizacion': 'cliente',
            // ======================================================
            // FRENTE NEGOCIO (ECUF)
            // ======================================================
            'No_Corta_Llamada': 'negocio',
            'No_Genera_conflicto_con_cliente': 'negocio',
            'Amabilidad': 'negocio',
            'Brinda_informacion_correcta': 'negocio',
            'No_Repite_Información': 'negocio',
            'Informa_Campañas': 'negocio',
            // ======================================================
            // FRENTE PROCESO (ECN)
            // ======================================================
            'Identifica_Responsable_de_Pago': 'proceso',
            'Valida_Pago_de_Deuda': 'proceso',
            'Genera_Compromiso_de_Pago': 'proceso',
            'Maneja_Objeciones': 'proceso',
            'Resuelve_dudas': 'proceso',
            'Pregunta_motivo_no_pago': 'proceso',
            'Prioriza_pagos_APP_Digitales': 'proceso',
            'Prioriza_pagos_Bancos/Agentes': 'proceso',
            'Confirma_Compromiso_de_Pago': 'proceso',
            'Cierre_correcto': 'proceso',
            'No_Perjudica_imagen_Movistar': 'proceso',
            'No_Compara_con_otros_clientes': 'proceso',
            'No_Induce Baja/Reclamo': 'proceso',
            'Tipificacion_correcta': 'proceso'
        };

        const agrupadoPorFecha = {};

        evaluaciones.forEach(eval => {
            let fechaCompleta = eval.fechaOriginal || eval.fecha || '';
            let fechaSoloDia = '';

            if (fechaCompleta.includes(' ')) {
                fechaSoloDia = fechaCompleta.split(' ')[0];
            } else if (fechaCompleta.includes('T')) {
                const partes = fechaCompleta.split('T')[0];
                const [anio, mes, dia] = partes.split('-');
                fechaSoloDia = `${dia}/${mes}/${anio}`;
            } else {
                fechaSoloDia = fechaCompleta;
            }

            if (!fechaSoloDia) return;

            if (!agrupadoPorFecha[fechaSoloDia]) {
                agrupadoPorFecha[fechaSoloDia] = {
                    fecha: fechaSoloDia,
                    cliente: { pesoTotal: 0, pesoObtenido: 0 },
                    negocio: { pesoTotal: 0, pesoObtenido: 0 },
                    proceso: { pesoTotal: 0, pesoObtenido: 0 }
                };
            }

            if (eval.detalles && eval.detalles.length > 0) {
                eval.detalles.forEach(det => {
                    const submotivo = det.submotivo;
                    const peso = Number(det.peso) || 0;
                    const cumple = String(det.cumple).toLowerCase() === 'true';
                    const pesoObtenido = cumple ? peso : 0;
                    const frente = mapaFrentes[submotivo];

                    if (frente === 'cliente') {
                        agrupadoPorFecha[fechaSoloDia].cliente.pesoTotal += peso;
                        agrupadoPorFecha[fechaSoloDia].cliente.pesoObtenido += pesoObtenido;
                    } else if (frente === 'negocio') {
                        agrupadoPorFecha[fechaSoloDia].negocio.pesoTotal += peso;
                        agrupadoPorFecha[fechaSoloDia].negocio.pesoObtenido += pesoObtenido;
                    } else if (frente === 'proceso') {
                        agrupadoPorFecha[fechaSoloDia].proceso.pesoTotal += peso;
                        agrupadoPorFecha[fechaSoloDia].proceso.pesoObtenido += pesoObtenido;
                    }
                });
            }
        });

        const resultados = Object.values(agrupadoPorFecha).map(item => {
            const clientePct = item.cliente.pesoTotal > 0
                ? (item.cliente.pesoObtenido / item.cliente.pesoTotal) * 100
                : 100;
            const negocioPct = item.negocio.pesoTotal > 0
                ? (item.negocio.pesoObtenido / item.negocio.pesoTotal) * 100
                : 100;
            const procesoPct = item.proceso.pesoTotal > 0
                ? (item.proceso.pesoObtenido / item.proceso.pesoTotal) * 100
                : 100;

            return {
                fecha: item.fecha,
                cliente: Math.round(clientePct * 10) / 10,
                negocio: Math.round(negocioPct * 10) / 10,
                proceso: Math.round(procesoPct * 10) / 10
            };
        });

        resultados.sort((a, b) => {
            const [diaA, mesA, anioA] = a.fecha.split('/');
            const [diaB, mesB, anioB] = b.fecha.split('/');
            const fechaA = new Date(anioA, mesA - 1, diaA);
            const fechaB = new Date(anioB, mesB - 1, diaB);
            return fechaA - fechaB;
        });

        console.log(`✅ Datos evolutivos procesados: ${resultados.length} fechas`);
        return resultados;
    }
    // ===== FIN FUNCIÓN: procesarDatosEvolutivosConEvaluaciones ==============
    
    // ===== 19. INICIO FUNCIÓN: cambiarVistaAtributos (VERSIÓN CORREGIDA - MANTIENE PERÍODO) =====
    function cambiarVistaAtributos(vista) {
        console.log(`🖱️ cambiarVistaAtributos: ${vista}`);
        
        const btnGeneral = document.getElementById('btnViewAtributosGeneral');
        const btnQuiebres = document.getElementById('btnViewAtributosQuiebres');

        // Actualizar estado visual de los botones
        if (vista === 'general') {
            vistaAtributosActual = 'general';
            if (btnGeneral) btnGeneral.classList.add('active');
            if (btnQuiebres) btnQuiebres.classList.remove('active');
        } else if (vista === 'quiebres') {
            vistaAtributosActual = 'quiebres';
            if (btnQuiebres) btnQuiebres.classList.add('active');
            if (btnGeneral) btnGeneral.classList.remove('active');
        }

        // Obtener evaluaciones filtradas actuales
        let evaluacionesParaGrafico = null;
        
        // Prioridad 1: Evaluaciones filtradas por líder (si existen)
        if (window.evaluacionesFiltradasPorLider && window.evaluacionesFiltradasPorLider.length > 0) {
            evaluacionesParaGrafico = window.evaluacionesFiltradasPorLider;
            console.log(`📊 Usando evaluaciones filtradas por líder: ${evaluacionesParaGrafico.length}`);
        } 
        // Prioridad 2: Evaluaciones filtradas globales (por período)
        else if (window.evaluacionesFiltradasGlobal && window.evaluacionesFiltradasGlobal.length > 0) {
            evaluacionesParaGrafico = window.evaluacionesFiltradasGlobal;
            console.log(`📊 Usando evaluaciones filtradas globales: ${evaluacionesParaGrafico.length}`);
        } 
        // Prioridad 3: Todas las evaluaciones globales
        else if (window.evaluacionesGlobales && window.evaluacionesGlobales.length > 0) {
            evaluacionesParaGrafico = window.evaluacionesGlobales;
            console.log(`📊 Usando todas las evaluaciones globales: ${evaluacionesParaGrafico.length}`);
        } 
        else {
            console.error('❌ No hay evaluaciones disponibles');
            const canvas = document.getElementById('chartEvolutivoAtributos');
            if (canvas) {
                mostrarMensajeSinDatosEnCanvas(canvas, '📊 No hay datos disponibles');
            }
            return;
        }

        if (evaluacionesParaGrafico.length === 0) {
            console.warn('⚠️ Las evaluaciones están vacías');
            const canvas = document.getElementById('chartEvolutivoAtributos');
            if (canvas) {
                mostrarMensajeSinDatosEnCanvas(canvas, '📊 No hay datos para mostrar');
            }
            return;
        }

        // 🔴 OBTENER EL PERÍODO SELECCIONADO SIN MODIFICACIONES
        let periodo = filtroPeriodoActual || document.getElementById('filtroPeriodoReportes')?.value || 'mes';
        console.log(`📊 Período para vista atributos: ${periodo}`);
        
        // 🔴 SOLO SI ES 'todos', usar 'mes'
        if (periodo === 'todos') {
            periodo = 'mes';
            console.log('📊 "todos" seleccionado, usando "mes" para atributos');
        }
        
        // 🔴 NO FORZAR 'mes' SI EL USUARIO SELECCIONÓ 'dia'
        console.log(`📊 Usando período: ${periodo} para el gráfico de atributos/submotivos`);
        
        // Recalcular datos agrupados con el período correcto
        const datosAgrupados = agruparEvaluacionesPorPeriodo(evaluacionesParaGrafico, periodo);

        if (datosAgrupados.length === 0) {
            console.warn('⚠️ No hay datos agrupados para el período seleccionado');
            const canvas = document.getElementById('chartEvolutivoAtributos');
            if (canvas) {
                mostrarMensajeSinDatosEnCanvas(canvas, '📊 No hay datos en el período seleccionado');
            }
            return;
        }

        // Generar el gráfico correspondiente según la vista seleccionada
        console.log(`📊 Generando gráfico para vista: ${vistaAtributosActual} con período ${periodo}`);
        
        if (vistaAtributosActual === 'general') {
            generarEvolutivoAtributosAgrupado(evaluacionesParaGrafico, datosAgrupados, periodo);
        } else {
            generarEvolutivoSubmotivosAgrupado(evaluacionesParaGrafico, datosAgrupados, periodo);
        }
    }
    // ===== FIN FUNCIÓN: cambiarVistaAtributos ===============================

    // ===== 20. INICIO FUNCIÓN: mostrarDetalleFechaMejorado ==================
    function mostrarDetalleFechaMejorado(fecha, frenteFiltro = null) {
        const evaluaciones = window.evaluacionesGlobales || [];

        // Mapeo de submotivos a frentes
        const mapaFrentes = {
            // ======================================================
            // FRENTE CLIENTE (ENC)
            // ======================================================
            'Cumple_Speech': 'cliente',
            'Cliente_corta_llamada': 'cliente',
            'Especifica_Motivo_Llamada': 'cliente',
            'Menciona_Numero_Servicio': 'cliente',
            'No_Interrumpe_Dialogo': 'cliente',
            'No_Omite_Preguntas_del_Cliente': 'cliente',
            'No_Deja_en_Espera_al_Cliente': 'cliente',
            'No_Usa_Jergas': 'cliente',
            'Transmite_Seguridad/confianza': 'cliente',
            'Tono_de_Voz/ Vocalizacion': 'cliente',
            // ======================================================
            // FRENTE NEGOCIO (ECUF)
            // ======================================================
            'No_Corta_Llamada': 'negocio',
            'No_Genera_conflicto_con_cliente': 'negocio',
            'Amabilidad': 'negocio',
            'Brinda_informacion_correcta': 'negocio',
            'No_Repite_Información': 'negocio',
            'Informa_Campañas': 'negocio',
            // ======================================================
            // FRENTE PROCESO (ECN)
            // ======================================================
            'Identifica_Responsable_de_Pago': 'proceso',
            'Valida_Pago_de_Deuda': 'proceso',
            'Genera_Compromiso_de_Pago': 'proceso',
            'Maneja_Objeciones': 'proceso',
            'Resuelve_dudas': 'proceso',
            'Pregunta_motivo_no_pago': 'proceso',
            'Prioriza_pagos_APP_Digitales': 'proceso',
            'Prioriza_pagos_Bancos/Agentes': 'proceso',
            'Confirma_Compromiso_de_Pago': 'proceso',
            'Cierre_correcto': 'proceso',
            'No_Perjudica_imagen_Movistar': 'proceso',
            'No_Compara_con_otros_clientes': 'proceso',
            'No_Induce Baja/Reclamo': 'proceso',
            'Tipificacion_correcta': 'proceso'
        };

        // Filtrar evaluaciones de esa fecha
        const evaluacionesFecha = evaluaciones.filter(eval => {
            let fechaEval = eval.fechaOriginal || eval.fecha || '';
            let fechaSolo = fechaEval.includes(' ') ? fechaEval.split(' ')[0] : fechaEval;
            return fechaSolo === fecha;
        });

        const drillDownArea = document.getElementById('drillDownArea');
        const drillDownTitle = document.getElementById('drillDownTitle');
        const drillDownContent = document.getElementById('drillDownContent');

        // Calcular estadísticas de la fecha
        let totalFallas = 0;
        const fallasPorAtributo = {};

        evaluacionesFecha.forEach(eval => {
            if (eval.detalles) {
                eval.detalles.forEach(det => {
                    if (!det.cumple && det.submotivo) {
                        // Determinar frente del submotivo
                        const frente = mapaFrentes[det.submotivo] || 'proceso';

                        // Si hay filtro de frente, solo incluir fallas de ese frente
                        if (frenteFiltro && frente !== frenteFiltro) return;

                        totalFallas++;
                        const atributo = det.atributo || det.bloque || 'Otros';
                        if (!fallasPorAtributo[atributo]) {
                            fallasPorAtributo[atributo] = {
                                nombre: atributo,
                                fallas: [],
                                total: 0,
                                frente: frente
                            };
                        }
                        fallasPorAtributo[atributo].fallas.push({
                            submotivo: det.submotivo,
                            bloque: det.bloque,
                            peso: det.peso,
                            frente: frente
                        });
                        fallasPorAtributo[atributo].total++;
                    }
                });
            }
        });

        const totalEvaluaciones = evaluacionesFecha.length;
        const promedioFecha = totalEvaluaciones > 0
            ? (evaluacionesFecha.reduce((sum, e) => sum + (e.notaFinal || 0), 0) / totalEvaluaciones).toFixed(1)
            : 0;

        // Crear título con indicación del filtro
        let tituloFiltro = '';
        if (frenteFiltro) {
            const nombres = { cliente: 'ENC - Cliente', negocio: 'ECUF - Negocio', proceso: 'ECN - Proceso' };
            tituloFiltro = ` (filtrado: ${nombres[frenteFiltro]})`;
        }
        drillDownTitle.innerHTML = `🔍 Análisis detallado - ${fecha}${tituloFiltro}`;
        drillDownArea.style.display = 'block';

        if (totalFallas === 0) {
            let mensajeSinFallas = `Todas las evaluaciones del ${fecha} cumplieron con los estándares de calidad.`;
            if (frenteFiltro) {
                const nombres = { cliente: 'ENC (Cliente)', negocio: 'ECUF (Negocio)', proceso: 'ECN (Proceso)' };
                mensajeSinFallas = `No hay fallas registradas en el frente ${nombres[frenteFiltro]} para el ${fecha}.`;
            }
            drillDownContent.innerHTML = `
                <div style="text-align: center; padding: 40px; background: linear-gradient(135deg, #e8f5e9, #c8e6c9); border-radius: 16px;">
                    <div style="font-size: 48px; margin-bottom: 10px;">✅</div>
                    <h3 style="color: #2e7d32;">¡Sin fallas registradas!</h3>
                    <p style="color: #1b5e20;">${mensajeSinFallas}</p>
                    <div style="margin-top: 15px; display: flex; gap: 20px; justify-content: center;">
                        <div><strong>📊 Evaluaciones:</strong> ${totalEvaluaciones}</div>
                        <div><strong>⭐ Promedio:</strong> ${promedioFecha}%</div>
                    </div>
                </div>
            `;
            return;
        }

        // Ordenar atributos por cantidad de fallas
        const atributosOrdenados = Object.values(fallasPorAtributo).sort((a, b) => b.total - a.total);

        // Colores por frente
        const frenteColors = { cliente: '#019DF4', negocio: '#7b1fa2', proceso: '#fd7e14' };

        let html = `
            <div style="display: grid; grid-template-columns: repeat(3, 1fr); gap: 15px; margin-bottom: 20px;">
                <div style="background: linear-gradient(135deg, #667eea, #764ba2); border-radius: 12px; padding: 15px; text-align: center; color: white;">
                    <div style="font-size: 28px; font-weight: bold;">${totalEvaluaciones}</div>
                    <div style="font-size: 12px;">📞 Evaluaciones</div>
                </div>
                <div style="background: linear-gradient(135deg, #f093fb, #f5576c); border-radius: 12px; padding: 15px; text-align: center; color: white;">
                    <div style="font-size: 28px; font-weight: bold;">${totalFallas}</div>
                    <div style="font-size: 12px;">❌ Total Fallas</div>
                </div>
                <div style="background: linear-gradient(135deg, ${promedioFecha >= 90 ? '#11998e, #38ef7d' : promedioFecha >= 85 ? '#f2994a, #f2c94c' : '#eb3349, #f45c43'}); border-radius: 12px; padding: 15px; text-align: center; color: white;">
                    <div style="font-size: 28px; font-weight: bold;">${promedioFecha}%</div>
                    <div style="font-size: 12px;">⭐ Promedio del día</div>
                </div>
            </div>
            <div style="margin-top: 10px;">
                <h5 style="margin-bottom: 12px;">📋 Fallas por Atributo (click para ver detalles)</h5>
                <div style="display: flex; flex-direction: column; gap: 10px;">
        `;

        atributosOrdenados.forEach(atributo => {
            // Contar submotivos únicos
            const submotivosUnicos = {};
            atributo.fallas.forEach(f => {
                submotivosUnicos[f.submotivo] = (submotivosUnicos[f.submotivo] || 0) + 1;
            });

            const frenteNombre = atributo.frente === 'cliente' ? 'ENC' : (atributo.frente === 'negocio' ? 'ECUF' : 'ECN');

            html += `
                <div class="atributo-card" onclick="expandirAtributo('${atributo.nombre.replace(/'/g, "\\'")}', '${fecha.replace(/'/g, "\\'")}', '${atributo.frente}')">
                    <div class="atributo-titulo">
                        <span class="atributo-nombre">📌 ${escapeHtml(atributo.nombre)} <span style="font-size: 10px; background: ${frenteColors[atributo.frente]}; color: white; padding: 2px 6px; border-radius: 10px; margin-left: 8px;">${frenteNombre}</span></span>
                        <span class="atributo-badge">${atributo.total} fallas</span>
                    </div>
                    <div class="atributo-preview">
                        <span>📝 ${Object.keys(submotivosUnicos).length} submotivo(s) afectado(s)</span>
                        <span>🔁 ${atributo.fallas.length} incidencia(s)</span>
                    </div>
                </div>
            `;
        });

        html += `
                </div>
            </div>
            <div style="margin-top: 15px; font-size: 12px; color: var(--muted); text-align: center; padding: 10px; background: #f8f9fa; border-radius: 10px;">
                💡 <strong>Consejo:</strong> Haz clic en cualquier atributo para ver los submotivos específicos que fallaron.
            </div>
        `;

        drillDownContent.innerHTML = html;

        // Guardar datos para drill-down adicional
        window.datosFallaFechaMejorado = {
            fecha: fecha,
            fallasPorAtributo: fallasPorAtributo,
            frenteFiltro: frenteFiltro
        };
    }
    // ===== FIN FUNCIÓN: mostrarDetalleFechaMejorado =========================
    
    // ===== 21.  INICIO FUNCIÓN: expandirAtributo ============================
    function expandirAtributo(atributoNombre, fecha, frenteAtributo = null) {
        if (!window.datosFallaFechaMejorado || window.datosFallaFechaMejorado.fecha !== fecha) {
            mostrarDetalleFechaMejorado(fecha, frenteAtributo);
        }

        const atributo = window.datosFallaFechaMejorado?.fallasPorAtributo[atributoNombre];
        if (!atributo) return;

        // Agrupar fallas por submotivo
        const submotivosMap = {};
        atributo.fallas.forEach(f => {
            if (!submotivosMap[f.submotivo]) {
                submotivosMap[f.submotivo] = {
                    count: 0,
                    peso: f.peso,
                    bloque: f.bloque,
                    frente: f.frente
                };
            }
            submotivosMap[f.submotivo].count++;
        });

        // Determinar frente para cada submotivo
        const getFrenteInfo = (frente) => {
            const nombres = { cliente: 'ENC', negocio: 'ECUF', proceso: 'ECN' };
            const colores = { cliente: '#019DF4', negocio: '#7b1fa2', proceso: '#fd7e14' };
            return { nombre: nombres[frente] || 'ECN', color: colores[frente] || '#fd7e14' };
        };

        let html = `
            <div style="margin-bottom: 15px;">
                <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 15px;">
                    <h4 style="margin: 0;">📋 ${escapeHtml(atributoNombre)}</h4>
                    <button onclick="mostrarDetalleFechaMejorado('${fecha}', '${frenteAtributo || ''}')" style="background: var(--accent); color: white; border: none; padding: 6px 12px; border-radius: 8px; cursor: pointer; font-size: 12px;">
                        ← Volver al resumen
                    </button>
                </div>
                <div style="background: #f8f9fa; border-radius: 12px; padding: 15px;">
        `;

        for (const [submotivo, data] of Object.entries(submotivosMap)) {
            const frenteInfo = getFrenteInfo(data.frente);
            html += `
                <div class="submotivo-item">
                    <div style="display: flex; align-items: center; gap: 10px; flex-wrap: wrap;">
                        <span class="submotivo-nombre">❌ ${escapeHtml(submotivo)}</span>
                        <span class="submotivo-frente" style="background: ${frenteInfo.color};">${frenteInfo.nombre}</span>
                    </div>
                    <div style="display: flex; align-items: center; gap: 10px;">
                        <span class="submotivo-count">${data.count} vez/veces</span>
                        ${data.peso ? `<span style="font-size: 11px; color: var(--muted);">Peso: ${data.peso}%</span>` : ''}
                    </div>
                </div>
            `;
        }

        html += `
                </div>
            </div>
        `;

        const drillDownContent = document.getElementById('drillDownContent');
        drillDownContent.innerHTML = html;
    }
    // ===== FIN FUNCIÓN: expandirAtributo ====================================
    
    // ===== 22. INICIO FUNCIÓN: cerrarDrillDown ==============================
    function cerrarDrillDown() {
        const drillDownArea = document.getElementById('drillDownArea');
        if (drillDownArea) {
            drillDownArea.style.display = 'none';
        }
    }
    // ===== FIN FUNCIÓN: cerrarDrillDown =====================================
    
    // ======================================================
    // FUNCIÓN: generarTablaJerarquicaFallas (CORREGIDA)
    // ======================================================
    async function generarTablaJerarquicaFallas(evaluaciones) {
        console.log('📊 generarTablaJerarquicaFallas - INICIO');
        
        const container = document.getElementById('contenedorFallasJerarquicas');
        if (!container) {
            console.error('❌ No se encontró el contenedor "contenedorFallasJerarquicas"');
            return;
        }
        
        // 🔴 VALIDACIÓN
        if (!evaluaciones || evaluaciones.length === 0) {
            console.log('⚠️ No hay evaluaciones para mostrar fallas jerárquicas');
            container.innerHTML = '<div style="text-align: center; padding: 40px; color: var(--muted);">📊 No hay datos de fallas para mostrar</div>';
            return;
        }
        
        console.log(`📊 ${evaluaciones.length} evaluaciones recibidas`);
        
        // Calcular datos evolutivos por mes
        const datosEvolutivos = await calcularDatosEvolutivosJerarquia(evaluaciones);
        
        // 🔴 VALIDACIÓN DE RESULTADO
        if (!datosEvolutivos) {
            console.log('⚠️ datosEvolutivos es null o undefined');
            container.innerHTML = '<div style="text-align: center; padding: 40px; color: var(--muted);">📊 No se pudieron calcular los datos evolutivos</div>';
            return;
        }
        
        const { meses, totalMeses } = datosEvolutivos;
        
        console.log(`📊 datosEvolutivos: ${totalMeses} meses, meses array: ${meses?.length || 0}`);
        
        if (!meses || meses.length === 0) {
            console.log('⚠️ No hay meses con datos para mostrar jerarquía');
            container.innerHTML = '<div style="text-align: center; padding: 40px; color: var(--muted);">📊 No hay datos suficientes para mostrar evolución</div>';
            return;
        }
        
        // 🔴 VERIFICAR QUE CADA MES TENGA LABEL
        const mesesConLabel = meses.filter(m => m && m.label);
        if (mesesConLabel.length === 0) {
            console.log('⚠️ Ningún mes tiene la propiedad label');
            container.innerHTML = '<div style="text-align: center; padding: 40px; color: var(--muted);">📊 No hay datos de meses válidos</div>';
            return;
        }
        
        console.log(`✅ ${mesesConLabel.length} meses con label: ${mesesConLabel.map(m => m.label).join(', ')}`);
        
        // Renderizar la vista evolutiva
        renderizarJerarquiaEvolutiva(container, {
            meses: mesesConLabel,
            totalMeses: mesesConLabel.length
        });
    }
    // ===== FIN FUNCIÓN: generarTablaJerarquicaFallas ========================
    
    // ======================================================
    // NUEVA FUNCIÓN: Calcular datos evolutivos jerarquía (CORREGIDA)
    // ======================================================
    async function calcularDatosEvolutivosJerarquia(evaluaciones) {
        console.log('📊 calcularDatosEvolutivosJerarquia - INICIO');
        
        // 🔴 VALIDACIÓN
        if (!evaluaciones || evaluaciones.length === 0) {
            console.log('⚠️ No hay evaluaciones para calcular jerarquía');
            return { meses: [], totalMeses: 0 };
        }
        
        const rango = obtenerRangoFechasActivo();
        console.log(`   📅 Rango activo: ${rango.tieneFiltro ? 'SÍ' : 'NO'}`);
        if (rango.tieneFiltro) {
            console.log(`   Desde: ${rango.fechaInicio.toLocaleDateString()} Hasta: ${rango.fechaFin.toLocaleDateString()}`);
        }
        
        // 1. Agrupar evaluaciones por mes (CON FILTRO)
        const evaluacionesPorMes = {};
        const mesesOrdenados = [];
        
        for (const evalItem of evaluaciones) {
            const fecha = obtenerFechaEvaluacion(evalItem);
            if (!fecha) continue;
            
            // Filtrar por rango de fechas
            if (rango && rango.tieneFiltro) {
                if (fecha < rango.fechaInicio || fecha > rango.fechaFin) continue;
            }
            
            const anio = fecha.getFullYear();
            const mes = fecha.getMonth() + 1;
            const claveMes = `${anio}-${String(mes).padStart(2, '0')}`;
            const mesesNombresLocal = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
            const labelMes = `${mesesNombresLocal[mes - 1]} ${anio}`;
            
            if (!evaluacionesPorMes[claveMes]) {
                evaluacionesPorMes[claveMes] = {
                    clave: claveMes,
                    label: labelMes,
                    anio: anio,
                    mes: mes,
                    evaluaciones: []
                };
                mesesOrdenados.push(claveMes);
            }
            evaluacionesPorMes[claveMes].evaluaciones.push(evalItem);
        }
        
        // Ordenar meses cronológicamente
        mesesOrdenados.sort();
        
        console.log(`📊 ${mesesOrdenados.length} meses encontrados después del filtro`);
        
        if (mesesOrdenados.length === 0) {
            console.log('⚠️ No hay meses en el rango seleccionado');
            return { meses: [], totalMeses: 0 };
        }
        
        // 2. Para cada mes, calcular estadísticas de fallas
        const datosPorMes = {};
        
        for (const mesClave of mesesOrdenados) {
            const mesData = evaluacionesPorMes[mesClave];
            const evaluacionesMes = mesData.evaluaciones;
            
            // Estructuras para acumular fallas
            const fallasPorBloque = {};
            const fallasPorAtributo = {};
            const fallasPorSubmotivo = {};
            let totalFallasMes = 0;
            
            // Guardar TODAS las ocurrencias por agente
            const ocurrenciasPorAgente = {};
            
            for (const evalItem of evaluacionesMes) {
                const agente = evalItem.agente || 'Sin agente';
                
                if (evalItem.detalles && evalItem.detalles.length > 0) {
                    for (const det of evalItem.detalles) {
                        const cumple = det.cumple === true || det.cumple === 1 || det.cumple === 'true';
                        if (!cumple) {
                            totalFallasMes++;
                            
                            // Por BLOQUE (Motivo)
                            const bloque = det.bloque || 'Sin bloque';
                            if (!fallasPorBloque[bloque]) {
                                fallasPorBloque[bloque] = { 
                                    fallas: 0, 
                                    gestores: new Set(), 
                                    ocurrenciasPorAgente: {} 
                                };
                            }
                            fallasPorBloque[bloque].fallas++;
                            fallasPorBloque[bloque].gestores.add(agente);
                            
                            if (!fallasPorBloque[bloque].ocurrenciasPorAgente[agente]) {
                                fallasPorBloque[bloque].ocurrenciasPorAgente[agente] = 0;
                            }
                            fallasPorBloque[bloque].ocurrenciasPorAgente[agente]++;
                            
                            // Por ATRIBUTO
                            const atributo = det.atributo || 'Sin atributo';
                            const claveAtributo = `${bloque}|${atributo}`;
                            if (!fallasPorAtributo[claveAtributo]) {
                                fallasPorAtributo[claveAtributo] = {
                                    bloque: bloque,
                                    atributo: atributo,
                                    fallas: 0,
                                    gestores: new Set(),
                                    ocurrenciasPorAgente: {}
                                };
                            }
                            fallasPorAtributo[claveAtributo].fallas++;
                            fallasPorAtributo[claveAtributo].gestores.add(agente);
                            
                            if (!fallasPorAtributo[claveAtributo].ocurrenciasPorAgente[agente]) {
                                fallasPorAtributo[claveAtributo].ocurrenciasPorAgente[agente] = 0;
                            }
                            fallasPorAtributo[claveAtributo].ocurrenciasPorAgente[agente]++;
                            
                            // Por SUBMOTIVO
                            const submotivo = det.submotivo || 'Sin submotivo';
                            const claveSubmotivo = `${bloque}|${atributo}|${submotivo}`;
                            if (!fallasPorSubmotivo[claveSubmotivo]) {
                                fallasPorSubmotivo[claveSubmotivo] = {
                                    bloque: bloque,
                                    atributo: atributo,
                                    submotivo: submotivo,
                                    fallas: 0,
                                    gestores: new Set(),
                                    ocurrenciasPorAgente: {}
                                };
                            }
                            fallasPorSubmotivo[claveSubmotivo].fallas++;
                            fallasPorSubmotivo[claveSubmotivo].gestores.add(agente);
                            
                            if (!fallasPorSubmotivo[claveSubmotivo].ocurrenciasPorAgente[agente]) {
                                fallasPorSubmotivo[claveSubmotivo].ocurrenciasPorAgente[agente] = 0;
                            }
                            fallasPorSubmotivo[claveSubmotivo].ocurrenciasPorAgente[agente]++;
                        }
                    }
                }
            }
            
            // Calcular porcentajes y ordenar
            const bloquesArray = Object.entries(fallasPorBloque).map(([nombre, data]) => ({
                nombre: nombre,
                fallas: data.fallas,
                gestores: Array.from(data.gestores),
                cantidadGestores: data.gestores.size,
                porcentaje: totalFallasMes > 0 ? (data.fallas / totalFallasMes) * 100 : 0,
                ocurrenciasPorAgente: data.ocurrenciasPorAgente
            })).sort((a, b) => b.fallas - a.fallas).slice(0, 3);
            
            const atributosArray = Object.values(fallasPorAtributo).map(data => ({
                bloque: data.bloque,
                atributo: data.atributo,
                fallas: data.fallas,
                gestores: Array.from(data.gestores),
                cantidadGestores: data.gestores.size,
                porcentaje: totalFallasMes > 0 ? (data.fallas / totalFallasMes) * 100 : 0,
                ocurrenciasPorAgente: data.ocurrenciasPorAgente
            })).sort((a, b) => b.fallas - a.fallas).slice(0, 10);
            
            const submotivosArray = Object.values(fallasPorSubmotivo).map(data => ({
                bloque: data.bloque,
                atributo: data.atributo,
                submotivo: data.submotivo,
                fallas: data.fallas,
                gestores: Array.from(data.gestores),
                cantidadGestores: data.gestores.size,
                porcentaje: totalFallasMes > 0 ? (data.fallas / totalFallasMes) * 100 : 0,
                ocurrenciasPorAgente: data.ocurrenciasPorAgente
            })).sort((a, b) => b.fallas - a.fallas).slice(0, 10);
            
            datosPorMes[mesClave] = {
                label: mesData.label,
                clave: mesClave,
                totalFallas: totalFallasMes,
                bloques: bloquesArray,
                atributos: atributosArray,
                submotivos: submotivosArray
            };
        }
        
        // Convertir a array ordenado
        const mesesArray = mesesOrdenados.map(clave => datosPorMes[clave]);
        
        // 🔴 DIAGNÓSTICO: Verificar que cada mes tenga label
        for (const m of mesesArray) {
            if (!m.label) {
                console.warn(`⚠️ Mes sin label:`, m);
            }
        }
        
        console.log(`✅ ${mesesArray.length} meses analizados (filtrados por período)`);
        console.log(`   Meses: ${mesesArray.map(m => m.label).join(', ')}`);
        
        return {
            meses: mesesArray,
            totalMeses: mesesArray.length
        };
    }

