    // ===== 28. INICIO FUNCIÓN: mostrarGestoresPopup =========================
    function mostrarGestoresPopup(titulo, gestores) {
        if (!gestores || gestores.length === 0) {
            alert(`📋 ${titulo}\n\nNo hay gestores registrados para este ítem.`);
            return;
        }

        let mensaje = `📋 ${titulo}\n`;
        mensaje += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
        mensaje += `👥 Gestores involucrados (${gestores.length}):\n\n`;

        // Mostrar todos los gestores (sin límite, o con scroll en el alert)
        gestores.forEach((g, idx) => {
            mensaje += `${idx + 1}. ${g}\n`;
        });

        mensaje += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
        alert(mensaje);
    }
