    // ======================================================
// FUNCIÓN CORREGIDA: Cargar Agentes en Q4 por Mes
// ======================================================
async function cargarAgentesQ4PorMes() {
    const mesSeleccionado = document.getElementById('selectorMesQ4')?.value;
    const filtroEstadoPDA = document.getElementById('selectorEstadoPDA')?.value || 'todos';

    if (!mesSeleccionado) {
        const container = document.getElementById('agentesQ4PorMesContainer');
        if (container) container.innerHTML = '<div style="text-align: center; padding: 40px;">📅 Seleccione un mes para ver los agentes en Q4</div>';
        return;
    }

    const [anio, mes] = mesSeleccionado.split('-');
    if (!anio || !mes) {
        console.error('Formato de mes inválido:', mesSeleccionado);
        return;
    }

    const container = document.getElementById('agentesQ4PorMesContainer');
    if (container) container.innerHTML = '<div style="text-align: center; padding: 40px;">⏳ Cargando agentes en Q4...</div>';

    try {
        const todasEvaluaciones = window.evaluacionesGlobales || [];
        if (todasEvaluaciones.length === 0) {
            container.innerHTML = '<div style="text-align: center; padding: 40px;">⚠️ No hay evaluaciones cargadas.</div>';
            return;
        }

        const agentesUnicos = [...new Set(todasEvaluaciones.map(e => e.agente))];
        
        await cargarDatosPDA();
        
        // 🔴 Crear un Set con identificadores únicos de PDA por ciclo
        // Formato: "agente|ciclo|fechaInicio"
        const pdaPorCiclo = new Set();
        (window.datosPDA || []).forEach(pda => {
            if (pda.estado && ['pendiente', 'notificado', 'en_gestion', 'en_seguimiento'].includes(pda.estado)) {
                // Crear clave única para este ciclo
                const clave = `${pda.agente}|${pda.ciclo_basal_numero || ''}|${pda.fecha_inicio_ciclo_basal || ''}`;
                pdaPorCiclo.add(clave);
            }
        });

        const resultados = [];

        for (const agente of agentesUnicos) {
            const ciclos = await agruparEvaluacionesEnCiclos(agente);
            if (ciclos.length === 0) continue;
            
            for (const ciclo of ciclos) {
                if (ciclo.cuartil === 'Q4' && ciclo.esCompleto) {
                    // Extraer fecha de fin del ciclo
                    let fechaFinCiclo = null;
                    if (ciclo.fechaFin && ciclo.fechaFin !== 'N/A') {
                        const partes = ciclo.fechaFin.split('/');
                        if (partes.length === 3) {
                            fechaFinCiclo = new Date(partes[2], partes[1] - 1, partes[0]);
                        }
                    }
                    
                    if (fechaFinCiclo && 
                        fechaFinCiclo.getFullYear() == anio && 
                        (fechaFinCiclo.getMonth() + 1) == mes) {
                        
                        // 🔴 Verificar si ESTE ciclo específico ya tiene un PDA asociado
                        const clavePDA = `${agente}|${ciclo.numero}|${ciclo.fechaInicio}`;
                        const tienePDAactivo = pdaPorCiclo.has(clavePDA);
                        
                        resultados.push({
                            agente: agente,
                            ciclo: ciclo.numero,
                            fechaInicio: ciclo.fechaInicio,
                            fechaFin: ciclo.fechaFin,
                            totalEvaluaciones: ciclo.totalEvaluaciones,
                            promedio: ciclo.promedio,
                            promedioENC: ciclo.promedioENC,
                            promedioECUF: ciclo.promedioECUF,
                            promedioECN: ciclo.promedioECN,
                            cuartil: ciclo.cuartil,
                            tienePDAactivo: tienePDAactivo
                        });
                    }
                }
            }
        }

        // Aplicar filtro de estado de PDA
        let resultadosFiltrados = resultados;
        if (filtroEstadoPDA === 'sin_pda') {
            resultadosFiltrados = resultados.filter(r => !r.tienePDAactivo);
        } else if (filtroEstadoPDA === 'con_pda') {
            resultadosFiltrados = resultados.filter(r => r.tienePDAactivo);
        }

        mostrarResultadosQ4(resultadosFiltrados, mesSeleccionado, resultados.length);

    } catch (error) {
        console.error('Error en cargarAgentesQ4PorMes:', error);
        if (container) container.innerHTML = `<div style="text-align: center; padding: 40px; color: var(--danger);">❌ Error: ${error.message}</div>`;
    }
}
    

    // ======================================================
    // FUNCIÓN AUXILIAR: Mostrar Resultados en HTML
    // ======================================================
    // ===== FUNCIÓN MODIFICADA: mostrarResultadosQ4 =====
function mostrarResultadosQ4(resultados, mesSeleccionado, totalSinFiltrar) {
    const container = document.getElementById('agentesQ4PorMesContainer');
    if (!container) return;

    const [anio, mesNum] = mesSeleccionado.split('-');
    const mesesNombres = ['Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio', 'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre'];
    const nombreMes = mesesNombres[parseInt(mesNum) - 1];

    if (resultados.length === 0) {
        container.innerHTML = `
            <div class="card" style="background: #fff4e5; margin-top: 15px;">
                <div style="display: flex; align-items: center; gap: 12px;">
                    <span style="font-size: 24px;">✅</span>
                    <div>
                        <strong>No hay agentes en Q4 para ${nombreMes} ${anio}</strong>
                        <span style="font-size: 13px;">(Total ciclos evaluados: ${totalSinFiltrar})</span>
                    </div>
                </div>
            </div>
        `;
        return;
    }

    let html = `
        <div style="margin-top: 15px;">
            <div style="background: #f0f7ff; padding: 8px 15px; border-radius: 8px; margin-bottom: 15px;">
                📊 Mostrando ${resultados.length} resultado(s) para ${nombreMes} ${anio} 
                (Total ciclos completos en Q4: ${totalSinFiltrar})
            </div>
            <div style="display: flex; flex-direction: column; gap: 12px;">
    `;

    for (const item of resultados) {
        const infoPDA = obtenerInfoPDA(item.agente, 'Q4');
        const tienePDAactivo = item.tienePDAactivo;

        let estadoBadge = '';
        let botonPDA = '';

        if (tienePDAactivo) {
            estadoBadge = '<span class="badge" style="background: var(--accent);">📋 PDA en curso</span>';
            botonPDA = `
                <button onclick="abrirGestionPDADesdeAlerta('${escapeHtml(item.agente)}')" 
                        style="background: var(--accent); padding: 8px 16px; font-size: 12px; border-radius: 8px; border: none; cursor: pointer;">
                    📝 Ver PDA en curso
                </button>
            `;
        } else {
            estadoBadge = '<span class="badge" style="background: var(--danger);">🔴 Requiere PDA</span>';
            // 🔴 CLAVE: Pasar el número de ciclo a la función generarPDAConDocumento
            botonPDA = `
                <button onclick="generarPDAConDocumento('${escapeHtml(item.agente)}', ${item.ciclo})" 
                        style="background: var(--warning); padding: 8px 16px; font-size: 12px; border-radius: 8px; border: none; cursor: pointer;">
                    📋 Generar PDA
                </button>
            `;
        }

        html += `
            <div class="card" style="border-left: 5px solid var(--danger); padding: 16px;">
                <div style="display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 10px;">
                    <div style="flex: 1;">
                        <div style="display: flex; align-items: center; gap: 10px; flex-wrap: wrap;">
                            <strong style="font-size: 16px;">⚠️ ${escapeHtml(item.agente)}</strong>
                            ${estadoBadge}
                            <span style="font-size: 11px; background: #e9ecef; padding: 2px 8px; border-radius: 12px;">
                                📊 Ciclo #${item.ciclo} (${item.totalEvaluaciones}/5 eval)
                            </span>
                        </div>
                        <div style="display: flex; gap: 15px; margin-top: 8px; flex-wrap: wrap;">
                            <span>📊 Promedio ciclo: <strong style="color: var(--danger);">${item.promedio}%</strong></span>
                            <span>📅 Período: ${item.fechaInicio} → ${item.fechaFin}</span>
                            <span>🎯 ENC: ${item.promedioENC}%</span>
                            <span>⚠️ ECUF: ${item.promedioECUF}%</span>
                            <span>💰 ECN: ${item.promedioECN}%</span>
                        </div>
                        ${infoPDA.total > 0 && infoPDA.total !== '-' ? `
                        <div style="margin-top: 6px; font-size: 11px; color: var(--muted);">
                            📋 PDA aplicados: ${infoPDA.total} | Último PDA: ${infoPDA.ultimaFecha || 'N/A'}
                        </div>
                        ` : ''}
                    </div>
                    <div style="display: flex; gap: 8px;">
                        ${botonPDA}
                        <button onclick="verEvolucionCiclos('${escapeHtml(item.agente)}')" 
                                style="background: var(--accent); padding: 8px 16px; font-size: 12px; border-radius: 8px; border: none; cursor: pointer;">
                            📊 Ver evolución
                        </button>
                        <button onclick="mostrarTimeline('${escapeHtml(item.agente)}')" 
                                style="background: var(--accent); padding: 8px 16px; font-size: 12px; border-radius: 8px; border: none; cursor: pointer;">
                            📅 Ver timeline
                        </button>
                    </div>
                </div>
            </div>
        `;
    }

    html += `</div>`;
    container.innerHTML = html;
}
    
    // ======================================================
    // FUNCIÓN: Cargar Meses Disponibles en el Selector Q4
    // ======================================================
    async function cargarMesesParaSelectorQ4() {
        const select = document.getElementById('selectorMesQ4');
        if (!select) return;

        const evaluaciones = window.evaluacionesGlobales || [];
        if (evaluaciones.length === 0) {
            select.innerHTML = '<option value="">⚠️ Cargue evaluaciones primero</option>';
            return;
        }

        const mesesSet = new Set();
        
        for (const e of evaluaciones) {
            let fechaStr = e.fechaOriginal || e.fecha || '';
            if (fechaStr) {
                // Extraer solo la fecha (sin hora)
                let fechaParte = fechaStr;
                if (fechaStr.includes(' ')) fechaParte = fechaStr.split(' ')[0];
                if (fechaStr.includes('T')) fechaParte = fechaStr.split('T')[0];
                
                const partes = fechaParte.split('/');
                if (partes.length === 3) {
                    const anio = partes[2];
                    const mes = partes[1];
                    if (anio && anio.match(/^\d{4}$/) && mes && mes.match(/^\d{1,2}$/)) {
                        mesesSet.add(`${anio}-${mes.padStart(2, '0')}`);
                    }
                } else {
                    // Formato ISO (YYYY-MM-DD)
                    const partesISO = fechaParte.split('-');
                    if (partesISO.length === 3) {
                        const anio = partesISO[0];
                        const mes = partesISO[1];
                        if (anio && anio.match(/^\d{4}$/) && mes && mes.match(/^\d{1,2}$/)) {
                            mesesSet.add(`${anio}-${mes.padStart(2, '0')}`);
                        }
                    }
                }
            }
        }

        const meses = Array.from(mesesSet).sort();
        const mesesNombres = ['Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio', 'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre'];

        select.innerHTML = '<option value="">-- Seleccionar mes --</option>';
        
        for (const mes of meses) {
            const [anio, mesNum] = mes.split('-');
            const nombreMes = mesesNombres[parseInt(mesNum) - 1];
            select.innerHTML += `<option value="${mes}">${nombreMes} ${anio}</option>`;
        }

        // Seleccionar el último mes disponible por defecto
        if (meses.length > 0) {
            select.value = meses[meses.length - 1];
            await cargarAgentesQ4PorMes();
        }

        console.log(`✅ ${meses.length} meses cargados para el selector Q4:`, meses);
    }

    // ===== 33. INICIO FUNCIÓN: filtrarEvaluacionesPorRangoFechas ============
    function filtrarEvaluacionesPorRangoFechas(evaluaciones, fechaInicio, fechaFin) {
        const inicio = new Date(fechaInicio + 'T00:00:00');
        const fin = new Date(fechaFin + 'T23:59:59');
        
        return evaluaciones.filter(eval => {
            const fecha = obtenerFechaEvaluacion(eval);
            if (!fecha) return false;
            return fecha >= inicio && fecha <= fin;
        });
    }

    // ===== FIN FUNCIÓN: filtrarEvaluacionesPorRangoFechas ===================
    
    // ===== 34. INICIO FUNCIÓN: filtrarEvaluacionesPorCantidadPeriodos =======
    function filtrarEvaluacionesPorCantidadPeriodos(evaluaciones, periodo, cantidad) {
        if (cantidad === 'all') return evaluaciones;

        const hoy = new Date();
        let fechaLimite = new Date();

        switch (periodo) {
            case 'semana':
                fechaLimite.setDate(hoy.getDate() - (parseInt(cantidad) * 7));
                break;
            case 'mes':
                fechaLimite.setMonth(hoy.getMonth() - parseInt(cantidad));
                break;
            case 'trimestre':
                fechaLimite.setMonth(hoy.getMonth() - (parseInt(cantidad) * 3));
                break;
            case 'anio':
                fechaLimite.setFullYear(hoy.getFullYear() - parseInt(cantidad));
                break;
            default:
                return evaluaciones;
        }

        return evaluaciones.filter(e => {
            const fecha = obtenerFechaEvaluacion(e);
            if (!fecha) return false;
            return fecha >= fechaLimite;
        });
    }
    // ===== FIN FUNCIÓN: filtrarEvaluacionesPorCantidadPeriodos ==============

    // ===== 35. INICIO FUNCIÓN: agruparEvaluacionesPorPeriodo ================
    function agruparEvaluacionesPorPeriodo(evaluaciones, periodo) {
        if (evaluaciones.length === 0) return [];

        // 🔴 SOLO SI ES 'todos', usar 'mes' (porque 'todos' no es un período de agrupación)
        if (periodo === 'todos') {
            periodo = 'mes';
            console.log('📊 "todos" en agruparEvaluacionesPorPeriodo, usando "mes"');
        }

        console.log(`📊 agruparEvaluacionesPorPeriodo: ${evaluaciones.length} evaluaciones, período: ${periodo}`);

        const agrupado = {};

        evaluaciones.forEach(e => {
            const fecha = obtenerFechaEvaluacion(e);
            if (!fecha) return;

            let clave = '';

            switch (periodo) {
                case 'dia':
                    clave = `${fecha.getFullYear()}-${String(fecha.getMonth() + 1).padStart(2, '0')}-${String(fecha.getDate()).padStart(2, '0')}`;
                    break;
                case 'semana':
                    const semana = getWeekNumber(fecha);
                    clave = `${fecha.getFullYear()}-S${semana}`;
                    break;
                case 'mes':
                    clave = `${fecha.getFullYear()}-${String(fecha.getMonth() + 1).padStart(2, '0')}`;
                    break;
                case 'trimestre':
                    const trimestre = Math.floor(fecha.getMonth() / 3) + 1;
                    clave = `${fecha.getFullYear()}-T${trimestre}`;
                    break;
                case 'anio':
                    clave = `${fecha.getFullYear()}`;
                    break;
                default:
                    clave = `${fecha.getFullYear()}-${String(fecha.getMonth() + 1).padStart(2, '0')}-${String(fecha.getDate()).padStart(2, '0')}`;
            }

            if (!agrupado[clave]) {
                agrupado[clave] = {
                    clave: clave,
                    evaluaciones: [],
                    sumaNotas: 0,
                    count: 0,
                    totalENC: 0,
                    totalECUF: 0,
                    totalECN: 0,
                    quiebres: 0
                };
            }

            agrupado[clave].evaluaciones.push(e);
            agrupado[clave].sumaNotas += e.notaFinal || 0;
            agrupado[clave].count++;
            agrupado[clave].totalENC += e.totalENC || 0;
            agrupado[clave].totalECUF += e.totalECUF || 0;
            agrupado[clave].totalECN += e.totalECN || 0;
            if ((e.notaFinal || 0) < 85) agrupado[clave].quiebres++;
        });

        // Convertir a array y ordenar por fecha/clave
        let resultados = Object.values(agrupado);
        resultados.sort((a, b) => a.clave.localeCompare(b.clave));

        // Formatear etiquetas para mostrar
        resultados = resultados.map(item => {
            let label = '';
            switch (periodo) {
                case 'dia':
                    const [anioD, mesD, diaD] = item.clave.split('-');
                    label = `${diaD}/${mesD}`;
                    break;
                case 'semana':
                    const [anioS, semana] = item.clave.split('-S');
                    label = `Sem ${semana} (${anioS})`;
                    break;
                case 'mes':
                    const [anioM, mesM] = item.clave.split('-');
                    const meses = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
                    label = `${meses[parseInt(mesM) - 1]} ${anioM}`;
                    break;
                case 'trimestre':
                    const [anioT, trim] = item.clave.split('-T');
                    label = `T${trim} ${anioT}`;
                    break;
                case 'anio':
                    label = item.clave;
                    break;
                default:
                    label = item.clave;
            }

            return {
                ...item,
                label: label,
                promedioNota: item.count > 0 ? (item.sumaNotas / item.count).toFixed(1) : 0,
                promedioENC: item.count > 0 ? (item.totalENC / item.count).toFixed(1) : 0,
                promedioECUF: item.count > 0 ? (item.totalECUF / item.count).toFixed(1) : 0,
                promedioECN: item.count > 0 ? (item.totalECN / item.count).toFixed(1) : 0,
                porcentajeQuiebres: item.count > 0 ? (item.quiebres / item.count) * 100 : 0
            };
        });

        console.log(`✅ Datos agrupados: ${resultados.length} períodos`);
        return resultados;
    }
    // ===== FIN FUNCIÓN: agruparEvaluacionesPorPeriodo =======================

    // ===== 36. INICIO FUNCIÓN: actualizarCardsPromedioMotivosAgrupados ======
    function actualizarCardsPromedioMotivosAgrupados(datosAgrupados) {
        if (!datosAgrupados || datosAgrupados.length === 0) return;

        const totalEvals = datosAgrupados.reduce((sum, d) => sum + d.count, 0);
        if (totalEvals === 0) return;

        const sumENC = datosAgrupados.reduce((sum, d) => sum + (parseFloat(d.promedioENCPct || d.promedioENC) * d.count), 0);
        const sumECUF = datosAgrupados.reduce((sum, d) => sum + (parseFloat(d.promedioECUFPct || d.promedioECUF) * d.count), 0);
        const sumECN = datosAgrupados.reduce((sum, d) => sum + (parseFloat(d.promedioECNPct || d.promedioECN) * d.count), 0);
        const sumRawENC = datosAgrupados.reduce((sum, d) => sum + (parseFloat(d.promedioENC) * d.count), 0);
        const sumRawECUF = datosAgrupados.reduce((sum, d) => sum + (parseFloat(d.promedioECUF) * d.count), 0);
        const sumRawECN = datosAgrupados.reduce((sum, d) => sum + (parseFloat(d.promedioECN) * d.count), 0);

        const promedioENC = (sumENC / totalEvals).toFixed(1);
        const promedioECUF = (sumECUF / totalEvals).toFixed(1);
        const promedioECN = (sumECN / totalEvals).toFixed(1);

        const promedioRawENC = (sumRawENC / totalEvals).toFixed(1);
        const promedioRawECUF = (sumRawECUF / totalEvals).toFixed(1);
        const promedioRawECN = (sumRawECN / totalEvals).toFixed(1);

        const matrizDominante = obtenerMatrizDominante(datosAgrupados.flatMap(d => d.evaluaciones || []));
        const encDetalleText = matrizDominante ? `${promedioRawENC}/${matrizDominante.pesos.ENC} pts` : `${promedioRawENC} pts`;
        const ecufDetalleText = matrizDominante ? `${promedioRawECUF}/${matrizDominante.pesos.ECUF} pts` : `${promedioRawECUF} pts`;
        const ecnDetalleText = matrizDominante ? `${promedioRawECN}/${matrizDominante.pesos.ECN} pts` : `${promedioRawECN} pts`;

        const encElem = document.getElementById('kpiPromedioENC');
        const encDetalle = document.getElementById('kpiPromedioENCDetalle');
        const ecufElem = document.getElementById('kpiPromedioECUF');
        const ecufDetalle = document.getElementById('kpiPromedioECUFDetalle');
        const ecnElem = document.getElementById('kpiPromedioECN');
        const ecnDetalle = document.getElementById('kpiPromedioECNDetalle');

        if (encElem) encElem.textContent = promedioENC + '%';
        if (encDetalle) encDetalle.textContent = encDetalleText;
        if (ecufElem) ecufElem.textContent = promedioECUF + '%';
        if (ecufDetalle) ecufDetalle.textContent = ecufDetalleText;
        if (ecnElem) ecnElem.textContent = promedioECN + '%';
        if (ecnDetalle) ecnDetalle.textContent = ecnDetalleText;
    }
    // ===== FIN FUNCIÓN: actualizarCardsPromedioMotivosAgrupados =============
    
    // ===== 37. INICIO FUNCIÓN: actualizarCardPorcentajeQuiebresAgrupados ====
    function actualizarCardPorcentajeQuiebresAgrupados(datosAgrupados) {
        if (!datosAgrupados || datosAgrupados.length === 0) return;

        const totalEvals = datosAgrupados.reduce((sum, d) => sum + d.count, 0);
        const totalQuiebres = datosAgrupados.reduce((sum, d) => sum + d.quiebres, 0);
        const porcentaje = totalEvals > 0 ? Math.round((totalQuiebres / totalEvals) * 100) : 0;

        const pctElem = document.getElementById('kpiPorcentajeQuiebres');
        const detalleElem = document.getElementById('kpiPorcentajeQuiebresDetalle');

        if (pctElem) pctElem.textContent = porcentaje + '%';
        if (detalleElem) detalleElem.textContent = totalQuiebres + ' de ' + totalEvals + ' evaluaciones';
    }
    // ===== FIN FUNCIÓN: actualizarCardPorcentajeQuiebresAgrupados ===========

    // ===== 38. INICIO FUNCIÓN: formatDateToDisplay ==========================
    function formatDateToDisplay(dateStr) {
        if (!dateStr) return '';
        const [anio, mes, dia] = dateStr.split('-');
        return `${dia}/${mes}/${anio}`;
    }
    // ===== FIN FUNCIÓN: formatDateToDisplay =================================

    // ===== 39. INICIO FUNCIÓN: calcularFrentesImpacto =======================
    function calcularFrentesImpacto() {
        console.log('=== INICIANDO CÁLCULO DE FRENTES DE IMPACTO ===');
        const evaluaciones = window.evaluacionesGlobales || [];
        if (evaluaciones.length === 0) return;

        const mapaFrentes = {
            // ======================================================
            // FRENTE CLIENTE (ENC)
            // ======================================================
            'Cumple_Speech': 'cliente',
            'Cliente_corta_llamada': 'cliente',
            'Especifica_Motivo_Llamada': 'cliente',
            'Menciona_Numero_Servicio': 'cliente',
            'No_Interrumpe_Dialogo': 'cliente',
            'No_Omite_Preguntas_del_Cliente': 'cliente',
            'No_Deja_en_Espera_al_Cliente': 'cliente',
            'No_Usa_Jergas': 'cliente',
            'Transmite_Seguridad/confianza': 'cliente',
            'Tono_de_Voz/ Vocalizacion': 'cliente',
            // ======================================================
            // FRENTE NEGOCIO (ECUF)
            // ======================================================
            'No_Corta_Llamada': 'negocio',
            'No_Genera_conflicto_con_cliente': 'negocio',
            'Amabilidad': 'negocio',
            'Brinda_informacion_correcta': 'negocio',
            'No_Repite_Información': 'negocio',
            'Informa_Campañas': 'negocio',
            // ======================================================
            // FRENTE PROCESO (ECN)
            // ======================================================
            'Identifica_Responsable_de_Pago': 'proceso',
            'Valida_Pago_de_Deuda': 'proceso',
            'Genera_Compromiso_de_Pago': 'proceso',
            'Maneja_Objeciones': 'proceso',
            'Resuelve_dudas': 'proceso',
            'Pregunta_motivo_no_pago': 'proceso',
            'Prioriza_pagos_APP_Digitales': 'proceso',
            'Prioriza_pagos_Bancos/Agentes': 'proceso',
            'Confirma_Compromiso_de_Pago': 'proceso',
            'Cierre_correcto': 'proceso',
            'No_Perjudica_imagen_Movistar': 'proceso',
            'No_Compara_con_otros_clientes': 'proceso',
            'No_Induce Baja/Reclamo': 'proceso',
            'Tipificacion_correcta': 'proceso'
        };

        let acumuladores = { cliente: { pesoTotal: 0, pesoObtenido: 0, submotivos: {} }, negocio: { pesoTotal: 0, pesoObtenido: 0, submotivos: {} }, proceso: { pesoTotal: 0, pesoObtenido: 0, submotivos: {} } };

        evaluaciones.forEach(evaluacion => {
            if (evaluacion.detalles) {
                evaluacion.detalles.forEach(detalle => {
                    const submotivo = detalle.submotivo;
                    const peso = Number(detalle.peso) || 0;
                    const cumple = (detalle.cumple === true || detalle.cumple === 'true' || detalle.cumple === 1 || detalle.cumple === '1');
                    const pesoObtenido = cumple ? peso : 0;
                    const frente = mapaFrentes[submotivo];
                    if (frente) {
                        acumuladores[frente].pesoTotal += peso;
                        acumuladores[frente].pesoObtenido += pesoObtenido;
                        if (!acumuladores[frente].submotivos[submotivo]) {
                            acumuladores[frente].submotivos[submotivo] = { pesoTotal: 0, pesoObtenido: 0, count: 0 };
                        }
                        acumuladores[frente].submotivos[submotivo].pesoTotal += peso;
                        acumuladores[frente].submotivos[submotivo].pesoObtenido += pesoObtenido;
                        acumuladores[frente].submotivos[submotivo].count++;
                    }
                });
            }
        });

        const pctCliente = acumuladores.cliente.pesoTotal > 0 ? ((acumuladores.cliente.pesoObtenido / acumuladores.cliente.pesoTotal) * 100).toFixed(1) : 0;
        const pctNegocio = acumuladores.negocio.pesoTotal > 0 ? ((acumuladores.negocio.pesoObtenido / acumuladores.negocio.pesoTotal) * 100).toFixed(1) : 0;
        const pctProceso = acumuladores.proceso.pesoTotal > 0 ? ((acumuladores.proceso.pesoObtenido / acumuladores.proceso.pesoTotal) * 100).toFixed(1) : 0;

        const rangoCliente = obtenerRango(pctCliente);
        const rangoNegocio = obtenerRango(pctNegocio);
        const rangoProceso = obtenerRango(pctProceso);

        const frenteClientePct = document.getElementById('frenteClientePct');
        const frenteNegocioPct = document.getElementById('frenteNegocioPct');
        const frenteProcesoPct = document.getElementById('frenteProcesoPct');
        if (frenteClientePct) frenteClientePct.textContent = pctCliente + '%';
        if (frenteNegocioPct) frenteNegocioPct.textContent = pctNegocio + '%';
        if (frenteProcesoPct) frenteProcesoPct.textContent = pctProceso + '%';

        const clienteRango = document.getElementById('frenteClienteRango');
        const negocioRango = document.getElementById('frenteNegocioRango');
        const procesoRango = document.getElementById('frenteProcesoRango');
        if (clienteRango) { clienteRango.textContent = rangoCliente.nombre; clienteRango.style.backgroundColor = rangoCliente.color; }
        if (negocioRango) { negocioRango.textContent = rangoNegocio.nombre; negocioRango.style.backgroundColor = rangoNegocio.color; }
        if (procesoRango) { procesoRango.textContent = rangoProceso.nombre; procesoRango.style.backgroundColor = rangoProceso.color; }

        const clienteDetalle = document.getElementById('frenteClienteDetalle');
        const negocioDetalle = document.getElementById('frenteNegocioDetalle');
        const procesoDetalle = document.getElementById('frenteProcesoDetalle');
        if (clienteDetalle) clienteDetalle.textContent = `${acumuladores.cliente.pesoObtenido}/${acumuladores.cliente.pesoTotal} puntos`;
        if (negocioDetalle) negocioDetalle.textContent = `${acumuladores.negocio.pesoObtenido}/${acumuladores.negocio.pesoTotal} puntos`;
        if (procesoDetalle) procesoDetalle.textContent = `${acumuladores.proceso.pesoObtenido}/${acumuladores.proceso.pesoTotal} puntos`;

        console.log('✅ Cálculo de frentes completado');
        return { cliente: { pct: pctCliente }, negocio: { pct: pctNegocio }, proceso: { pct: pctProceso } };
    }
    // ===== FIN FUNCIÓN: calcularFrentesImpacto ==============================

    // ===== 40. INICIO FUNCIÓN: exportarFrentesCSV ===========================
    async function exportarFrentesCSV() {
        try {
            const evaluaciones = window.evaluacionesFiltradasGlobal || window.evaluacionesGlobales || [];
            const datos = await API.exportarFrentes(evaluaciones);
            
            if (!datos || datos.length === 0) {
                alert('No hay datos para exportar');
                return;
            }
            
            const headers = ['Frente', 'Peso Total', 'Peso Obtenido', 'Porcentaje', 'Rango'];
            const csvRows = [headers.join(',')];
            
            for (const row of datos) {
                const values = headers.map(header => `"${row[header] || ''}"`);
                csvRows.push(values.join(','));
            }
            
            const blob = new Blob(["\uFEFF" + csvRows.join('\n')], { type: 'text/csv;charset=utf-8;' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `frentes_${new Date().toISOString().slice(0, 10)}.csv`;
            a.click();
            URL.revokeObjectURL(url);
            
            alert('✅ Exportado análisis por frentes');
            
        } catch (error) {
            console.error('Error exportando frentes:', error);
            alert('❌ Error al exportar: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: exportarFrentesCSV ==================================
    
    // ===== 41. INICIO FUNCIÓN: renderizarGraficoAtributos ===================
    function renderizarGraficoAtributos(canvas, labels, datasets, tituloLeyenda) {
        console.log(`📊 Renderizando gráfico de atributos: ${tituloLeyenda}`);
        console.log('📊 Labels:', labels);
        console.log('📊 Datasets:', datasets.length);

        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Destruir gráfico existente
        if (window.chartEvolutivoAtributos && typeof window.chartEvolutivoAtributos.destroy === 'function') {
            window.chartEvolutivoAtributos.destroy();
            window.chartEvolutivoAtributos = null;
        }

        // Limpiar canvas
        canvas.width = canvas.clientWidth;
        canvas.height = canvas.clientHeight;
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        window.chartEvolutivoAtributos = new Chart(ctx, {
            type: 'bar',
            data: { labels: labels, datasets: datasets },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                interaction: { mode: 'index', intersect: false },
                layout: {
                    padding: {
                        top: 20,
                        bottom: 55,
                        left: 10,
                        right: 10
                    }
                },
                plugins: {
                    tooltip: {
                        callbacks: {
                            label: function (context) {
                                return `${context.dataset.label}: ${context.raw} falla(s)`;
                            }
                        },
                        backgroundColor: 'rgba(0,0,0,0.8)',
                        titleColor: '#fff',
                        bodyColor: '#e9ecef'
                    },
                    legend: {
                        position: 'bottom',
                        align: 'center',
                        labels: {
                            font: { size: 10, weight: 'normal' },
                            usePointStyle: true,
                            boxWidth: 12,
                            padding: 6
                        },
                        maxHeight: 60
                    },
                    datalabels: {
                        anchor: 'end',
                        align: 'top',
                        offset: -5,
                        formatter: function (value) {
                            if (value === 0) return '';
                            return value;
                        },
                        backgroundColor: function (context) {
                            const coloresFondo = ['#d93025', '#f39c12', '#7b1fa2', '#019DF4', '#1a7f37'];
                            return coloresFondo[context.datasetIndex % coloresFondo.length];
                        },
                        borderRadius: 3,
                        padding: { left: 4, right: 4, top: 2, bottom: 2 },
                        color: 'white',
                        font: { weight: 'bold', size: 9 }
                    }
                },
                scales: {
                    y: {
                        beginAtZero: true,
                        title: { display: true, text: 'Número de fallas', font: { weight: 'bold', size: 11 } },
                        grid: { display: false },
                        ticks: { stepSize: 1, font: { size: 10 } }
                    },
                    x: {
                        title: { display: true, text: 'Fecha (Día/Mes)', font: { weight: 'bold', size: 11 } },
                        grid: { display: false },
                        ticks: {
                            maxRotation: 45,
                            minRotation: 45,
                            autoSkip: true,
                            maxTicksLimit: 8,
                            font: { size: 9 }
                        }
                    }
                }
            }
        });

        console.log(`✅ Gráfico de Atributos generado - ${tituloLeyenda}`);
    }
    // ===== FIN FUNCIÓN: renderizarGraficoAtributos ==========================

    // ===== 42. INICIO FUNCIÓN: mostrarMensajeSinDatosEnCanvasGestion =======
    function mostrarMensajeSinDatosEnCanvasGestion(canvas, mensaje) {
        const ctx = canvas.getContext('2d');
        if (ctx) {
            if (chartGestionLlamadas) {
                chartGestionLlamadas.destroy();
                chartGestionLlamadas = null;
            }
            canvas.width = canvas.clientWidth;
            canvas.height = canvas.clientHeight;
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            ctx.font = '14px sans-serif';
            ctx.fillStyle = '#6c757d';
            ctx.textAlign = 'center';
            ctx.fillText(mensaje, canvas.width / 2, canvas.height / 2);
        }
    }
