    // Mostrar elementos múltiples seleccionados
    function mostrarMultiples(tipo) {
        let containerSelector = '';
        let formatoEtiqueta = '';
        
        if (tipo === 'dia') {
            containerSelector = 'filtroMultiplesDiaLista';
            formatoEtiqueta = (item) => formatDateToDisplay(item);
        } else if (tipo === 'mes') {
            containerSelector = 'filtroMultiplesMesLista';
            formatoEtiqueta = (item) => {
                const [anio, mes] = item.split('-');
                const meses = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
                return `${meses[parseInt(mes) - 1]} ${anio}`;
            };
        } else if (tipo === 'trimestre') {
            containerSelector = 'filtroMultiplesTrimLista';
            formatoEtiqueta = (item) => {
                const [anio, trim] = item.split('-Q');
                return `Q${trim} ${anio}`;
            };
        } else if (tipo === 'anio') {
            containerSelector = 'filtroMultiplesAnioLista';
            formatoEtiqueta = (item) => item;
        }
        
        const container = document.getElementById(containerSelector);
        if (!container) return;
        
        container.innerHTML = filtroMultiples.map(item => `
            <div draggable="true" ondragstart="onDragStartMultiple(event, '${item}')" ondragover="onDragOverMultiple(event)" ondrop="onDropMultiple(event, '${item}')" style="background: var(--accent); color: white; padding: 4px 10px; border-radius: 12px; font-size: 11px; display: flex; align-items: center; gap: 6px; white-space: nowrap; cursor: grab;">
                <span>${formatoEtiqueta(item)}</span>
                <button onclick="removerMultiple('${item}')" style="background: transparent; border: none; color: white; cursor: pointer; font-size: 14px; padding: 0; line-height: 1;">✕</button>
            </div>
        `).join('');
    }
    
    // Remover un elemento de la lista de múltiples
    function removerMultiple(valor) {
        filtroMultiples = filtroMultiples.filter(item => item !== valor);
        
        const tipoSelect = document.getElementById('filtroMultiplesTipo');
        const tipo = tipoSelect?.value;
        if (tipo) mostrarMultiples(tipo);
        
        actualizarInfoFiltro();
    }

    // Drag & Drop para reordenar múltiples
    function onDragStartMultiple(ev, valor) {
        ev.dataTransfer.setData('text/plain', valor);
        ev.dataTransfer.effectAllowed = 'move';
    }
    function onDragOverMultiple(ev) { ev.preventDefault(); ev.dataTransfer.dropEffect = 'move'; }
    function onDropMultiple(ev, targetValor) {
        ev.preventDefault();
        const dragged = ev.dataTransfer.getData('text/plain');
        if (!dragged || dragged === targetValor) return;
        const fromIdx = filtroMultiples.indexOf(dragged);
        const toIdx = filtroMultiples.indexOf(targetValor);
        if (fromIdx === -1 || toIdx === -1) return;
        // Reordenar array
        filtroMultiples.splice(fromIdx, 1);
        filtroMultiples.splice(toIdx, 0, dragged);
        const tipoSelect = document.getElementById('filtroMultiplesTipo');
        const tipo = tipoSelect?.value || 'mes';
        mostrarMultiples(tipo);
        actualizarInfoFiltro();
    }

    // Obtener fecha de inicio de una semana (lunes)
    function obtenerFechaInicioSemana(anio, semana) {
        const fecha = new Date(anio, 0, 1);
        const diaSemana = fecha.getDay();
        const diff = (semana - 1) * 7;
        fecha.setDate(fecha.getDate() + diff - diaSemana + (diaSemana === 0 ? -6 : 1));
        return fecha;
    }

    // Inicializar el filtro de período
    function inicializarFiltroPeriodoMejorado() {
        const selectPeriodo = document.getElementById('filtroPeriodoReportes');
        if (!selectPeriodo) return;
        
        // Valores por defecto
        const ahora = new Date();
        filtroSemanaAnio = ahora.getFullYear();
        filtroMesAnio = ahora.getFullYear();
        filtroTrimestreAnio = ahora.getFullYear();
        filtroAnio = ahora.getFullYear();
        
        // Renderizar controles iniciales
        renderizarControlesPeriodo();
        
        // Evento para cambiar los controles según el período
        selectPeriodo.addEventListener('change', () => {
            renderizarControlesPeriodo();
        });
        
        console.log('✅ Filtro de período mejorado inicializado');
    }

