    // ===== 1. INICIO FUNCIÓN: construirRankingAgentes ======================
    let rankingCache = {
        resultado: null,
        hashEvaluaciones: null
    };

    // ===== 1. INICIO FUNCIÓN: construirRankingAgentes (CORREGIDO) =====
async function construirRankingAgentes(evaluaciones) {
    if (!evaluaciones || evaluaciones.length === 0) {
        return [];
    }

    console.log('🔄 Calculando ranking...');

    const agentes = {};

    for (const e of evaluaciones) {
        const nombre = e.agente || 'Sin nombre';

        if (!agentes[nombre]) {
            agentes[nombre] = {
                agente: nombre,
                suma: 0,
                count: 0,
                enc: 0,
                ecuf: 0,
                ecn: 0,
                bajos: 0,
                ultima: e.fecha_formateada || e.fechaOriginal || e.fecha || ''
            };
        }

        const nota = parseFloat(e.notaFinal || e.nota_final || 0);
        const totalENC = parseFloat(e.totalENC || e.total_enc || 0);
        const totalECUF = parseFloat(e.totalECUF || e.total_ecuf || 0);
        const totalECN = parseFloat(e.totalECN || e.total_ecn || 0);

        const fechaActual = e.fecha_formateada || e.fechaOriginal || e.fecha || '';
        if (fechaActual > agentes[nombre].ultima) {
            agentes[nombre].ultima = fechaActual;
        }

        agentes[nombre].suma += nota;
        agentes[nombre].enc += totalENC;
        agentes[nombre].ecuf += totalECUF;
        agentes[nombre].ecn += totalECN;
        agentes[nombre].count++;
        if (nota < 85) agentes[nombre].bajos++;
    }

    // 🔴 🔴 🔴 PARTE CORREGIDA 🔴 🔴 🔴
    const resultado = [];
    
    for (const a of Object.values(agentes)) {
        const promedio = a.count > 0 ? Number((a.suma / a.count).toFixed(1)) : 0;
        const cuartil = await obtenerCuartil(promedio);
        
        resultado.push({
            ...a,
            promedio: promedio,
            promedioENC: a.count > 0 ? Number((a.enc / a.count).toFixed(1)) : 0,
            promedioECUF: a.count > 0 ? Number((a.ecuf / a.count).toFixed(1)) : 0,
            promedioECN: a.count > 0 ? Number((a.ecn / a.count).toFixed(1)) : 0,
            cuartil: cuartil
        });
    }

    resultado.sort((a, b) => b.promedio - a.promedio);

    return resultado;
}
// ===== FIN FUNCIÓN: construirRankingAgentes =============================


    function calcularCuartilesGlobales(ranking) {
        if (!ranking || ranking.length === 0) return ranking;
        
        const promedios = ranking.map(r => r.promedio).sort((a, b) => a - b);
        const q1 = promedios[Math.floor(promedios.length * 0.25)] || 0;
        const q2 = promedios[Math.floor(promedios.length * 0.5)] || 0;
        const q3 = promedios[Math.floor(promedios.length * 0.75)] || 0;
        
        console.log(`📊 Cuartiles globales: Q1≥${q3}, Q2≥${q2}, Q3≥${q1}, Q4<${q1}`);
        
        return ranking.map(r => ({
            ...r,
            cuartil: r.promedio >= q3 ? 'Q1' : (r.promedio >= q2 ? 'Q2' : (r.promedio >= q1 ? 'Q3' : 'Q4'))
        }));
    }

    // ===== 2. INICIO FUNCIÓN: invalidarRankingCache ========================
    function invalidarRankingCache() {
        rankingCache = { resultado: null, hashEvaluaciones: null };
        console.log('🗑️ Caché de ranking invalidado');
    }
    // ===== FIN FUNCIÓN: invalidarRankingCache ===============================

    // ===== 3. INICIO FUNCIÓN: cargarRankingAgentesCompleto =================
async function cargarRankingAgentesCompleto() {
    console.log('📊 Cargando ranking completo de agentes...');

    if (!window.evaluacionesGlobales || window.evaluacionesGlobales.length === 0) {
        await cargarEvaluacionesDesdePostgreSQL();
    }

    await cargarMesesDisponiblesRanking();

    const evaluaciones = window.evaluacionesGlobales || [];
    const rankingSinCuartiles = await construirRankingAgentes(evaluaciones);
    
    // 🔴 🔴 🔴 SOLO AGREGA ESTA LÍNEA 🔴 🔴 🔴
    window.rankingOriginalCompleto = calcularCuartilesGlobales(rankingSinCuartiles);
    window.rankingCompletoGlobal = window.rankingOriginalCompleto;
    
    console.log(`✅ Ranking completo cargado: ${window.rankingOriginalCompleto.length} agentes`);
    
    await aplicarFiltroMesRanking();
    
    const selectPeriodo = document.getElementById('filtroMesRanking');
    if (selectPeriodo && !selectPeriodo._listenerAdded) {
        selectPeriodo.addEventListener('change', () => aplicarFiltroMesRanking());
        selectPeriodo._listenerAdded = true;
    }
}
// ===== FIN FUNCIÓN: cargarRankingAgentesCompleto ========================


    // ===== 4. INICIO FUNCIÓN: Tabla Evolución de Cuartiles por Gestor =======
    // ========== 4.1 Función principal para cargar la tabla evolutiva (CORREGIDO) ==========
// ======================================================
// FUNCIÓN: cargarEvolucionCuartilesPorGestor (VERSIÓN CORREGIDA)
// ======================================================
// 📌 PROPÓSITO: Cargar la tabla evolutiva de cuartiles por gestor
// 📌 🔴 CORREGIDO: Usa await para obtener cuartiles desde BD
// ======================================================

async function cargarEvolucionCuartilesPorGestor() {
    console.log('📊 Cargando evolución de cuartiles por gestor...');
    
    const container = document.getElementById('evolucionCuartilesContainer');
    if (!container) return;
    
    container.innerHTML = '<div style="text-align: center; padding: 40px;">⏳ Calculando evolución de cuartiles...</div>';
    
    // 🔴 VERIFICAR QUE HAY EVALUACIONES
    if (!window.evaluacionesGlobales || window.evaluacionesGlobales.length === 0) {
        console.log('🔄 No hay evaluaciones cargadas. Intentando cargar...');
        try {
            await cargarEvaluacionesDesdePostgreSQL();
        } catch (error) {
            console.error('❌ Error cargando evaluaciones:', error);
        }
    }
    
    const evaluaciones = window.evaluacionesGlobales || [];
    if (evaluaciones.length === 0) {
        container.innerHTML = '<div style="text-align: center; padding: 40px; color: var(--muted);">📊 No hay evaluaciones para mostrar</div>';
        return;
    }
    
    // Obtener período y cantidad
    const periodo = document.getElementById('selectPeriodoEvolucion')?.value || 'mes';
    const cantidadPeriodos = parseInt(document.getElementById('selectCantidadPeriodos')?.value || '6');
    
    // Obtener gestores únicos
    const gestoresSet = new Set();
    evaluaciones.forEach(e => {
        if (e.agente) gestoresSet.add(e.agente);
    });
    const gestores = Array.from(gestoresSet).sort();
    
    // Calcular períodos
    const periodosInfo = calcularPeriodosRango(evaluaciones, periodo, cantidadPeriodos);
    const periodosLabels = periodosInfo.labels;
    const mapaPeriodos = periodosInfo.mapa;
    
    if (periodosLabels.length === 0) {
        container.innerHTML = '<div style="text-align: center; padding: 40px; color: var(--muted);">📊 No hay suficientes datos para mostrar evolución</div>';
        return;
    }
    
    // Construir matriz de cuartiles
    const matrizCuartiles = {};
    
    for (const gestor of gestores) {
        matrizCuartiles[gestor] = {};
        const evalGestor = evaluaciones.filter(e => e.agente === gestor);
        
        for (const periodoLabel of periodosLabels) {
            const periodoKey = mapaPeriodos[periodoLabel];
            const evaluacionesPeriodo = filtrarEvaluacionesPorPeriodo(evalGestor, periodoKey, periodo);
            
            if (evaluacionesPeriodo.length === 0) {
                matrizCuartiles[gestor][periodoLabel] = { cuartil: '-', evaluaciones: 0 };
            } else {
                const sumaNotas = evaluacionesPeriodo.reduce((sum, e) => sum + (e.notaFinal || 0), 0);
                const promedio = sumaNotas / evaluacionesPeriodo.length;
                
                // 🔴 🔴 🔴 CLAVE: await para obtener el cuartil desde BD 🔴 🔴 🔴
                const cuartil = await obtenerCuartil(promedio);
                
                matrizCuartiles[gestor][periodoLabel] = {
                    cuartil: cuartil,
                    evaluaciones: evaluacionesPeriodo.length,
                    promedio: promedio
                };
            }
        }
    }
    
    // Calcular tendencias
    const tendencias = calcularTendenciasGestores(matrizCuartiles, periodosLabels);
    
    // Generar tabla
    generarTablaEvolucionCuartiles(container, matrizCuartiles, periodosLabels, gestores, tendencias);
}

// ======================================================
// FUNCIÓN: getCuartilHTML()
// ======================================================
// 📌 PROPÓSITO: Generar HTML para badge de cuartil
// ======================================================

function getCuartilHTML(cuartil) {
    if (!cuartil || cuartil === '-' || cuartil === 'undefined' || cuartil === 'null') {
        return '<span style="color: #adb5bd;">—</span>';
    }
    
    const config = {
        'Q1': { color: '#1a7f37', texto: '🏆 Q1' },
        'Q2': { color: '#019DF4', texto: '📈 Q2' },
        'Q3': { color: '#f39c12', texto: '⚠️ Q3' },
        'Q4': { color: '#d93025', texto: '🔴 Q4' }
    };
    
    const c = config[cuartil];
    if (!c) {
        return `<span style="background: #6c757d; color: white; padding: 4px 10px; border-radius: 20px; font-size: 12px;">❓ ${cuartil}</span>`;
    }
    
    return `<span style="background: ${c.color}; color: white; padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: bold; display: inline-block; white-space: nowrap;">
        ${c.texto}
    </span>`;
}

// Exponer globalmente
window.getCuartilHTML = getCuartilHTML;

    // ========== 4.2 Calcular períodos disponibles (CORREGIDO) ==========
function calcularPeriodosRango(evaluaciones, periodo, cantidad) {
    console.log(`📅 calcularPeriodosRango: periodo=${periodo}, cantidad=${cantidad}`);
    
    // Obtener todas las fechas únicas de evaluación
    const fechasSet = new Set();
    
    for (const evalItem of evaluaciones) {
        let fechaStr = evalItem.fecha_formateada || evalItem.fechaOriginal || evalItem.fecha;
        if (!fechaStr) continue;
        
        const fechaLimpia = fechaStr.split(' ')[0];
        
        if (fechaLimpia && fechaLimpia.includes('/')) {
            const partes = fechaLimpia.split('/');
            if (partes.length === 3) {
                const mes = partes[1];
                const anio = partes[2];
                
                if (anio && anio.match(/^\d{4}$/) && mes && mes.match(/^\d{1,2}$/)) {
                    let key;
                    if (periodo === 'mes') {
                        key = `${anio}-${mes.padStart(2, '0')}`;
                    } else if (periodo === 'trimestre') {
                        // 🔴 CORRECCIÓN: Usar formato consistente con filtrarEvaluacionesPorPeriodo
                        // filtrarEvaluacionesPorPeriodo espera "YYYY-MM" para trimestres también
                        // Usamos el mes de inicio del trimestre como referencia
                        const trimestre = Math.ceil(parseInt(mes) / 3);
                        const mesInicio = (trimestre - 1) * 3 + 1;
                        key = `${anio}-${String(mesInicio).padStart(2, '0')}`;
                    } else {
                        key = `${anio}-${mes.padStart(2, '0')}`;
                    }
                    fechasSet.add(key);
                }
            }
        }
        else if (fechaStr.includes('-')) {
            const partes = fechaStr.split('-');
            if (partes.length >= 2) {
                let anio = partes[0];
                let mes = partes[1];
                if (mes && mes.includes('-')) mes = mes.split('-')[0];
                if (mes && mes.includes('T')) mes = mes.split('T')[0];
                if (anio && mes && anio.match(/^\d{4}$/) && mes.match(/^\d{1,2}$/)) {
                    let key;
                    if (periodo === 'mes') {
                        key = `${anio}-${mes.padStart(2, '0')}`;
                    } else if (periodo === 'trimestre') {
                        // 🔴 CORRECCIÓN: Usar formato consistente
                        const trimestre = Math.ceil(parseInt(mes) / 3);
                        const mesInicio = (trimestre - 1) * 3 + 1;
                        key = `${anio}-${String(mesInicio).padStart(2, '0')}`;
                    } else {
                        key = `${anio}-${mes.padStart(2, '0')}`;
                    }
                    fechasSet.add(key);
                }
            }
        }
    }
    
    // 🔴 CORRECCIÓN: Agrupar por trimestre usando SET para eliminar duplicados
    let periodosUnicos;
    if (periodo === 'trimestre') {
        // Para trimestres, agrupar por trimestre real
        const trimestresMap = new Map();
        for (const key of fechasSet) {
            const [anio, mes] = key.split('-');
            const trimestre = Math.ceil(parseInt(mes) / 3);
            const mesInicio = (trimestre - 1) * 3 + 1;
            const trimKey = `${anio}-${String(mesInicio).padStart(2, '0')}`;
            trimestresMap.set(trimKey, { anio, trimestre });
        }
        periodosUnicos = Array.from(trimestresMap.keys()).sort();
    } else {
        periodosUnicos = Array.from(fechasSet).sort();
    }
    
    console.log(`   📊 Periodos únicos encontrados: ${periodosUnicos.length}`);
    
    const periodosMostrar = periodosUnicos.slice(-cantidad);
    
    const mesesNombres = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
    const labels = [];
    const mapa = {};
    
    for (const p of periodosMostrar) {
        let label = '';
        if (periodo === 'mes') {
            const [anio, mes] = p.split('-');
            label = `${mesesNombres[parseInt(mes) - 1]} ${anio}`;
        } else if (periodo === 'trimestre') {
            const [anio, mes] = p.split('-');
            const trimestre = Math.ceil(parseInt(mes) / 3);
            label = `T${trimestre} ${anio}`;
        } else {
            const [anio, mes] = p.split('-');
            label = `${mesesNombres[parseInt(mes) - 1]} ${anio}`;
        }
        labels.push(label);
        mapa[label] = p;
    }
    
    console.log(`   ✅ Períodos a mostrar: ${labels.length}`, labels);
    
    return { labels, mapa, periodosRaw: periodosMostrar };
}

    // ========== 4.3 Filtrar evaluaciones por período ========================
    function filtrarEvaluacionesPorPeriodo(evaluaciones, periodoKey, tipoPeriodo) {
        const [anioKey, mesKey] = periodoKey.split('-');
        
        return evaluaciones.filter(e => {
            let fechaStr = e.fecha_descarga || e.fechaOriginal || e.fecha;
            if (!fechaStr) return false;
            
            let anio = '', mes = '';
            if (fechaStr.includes('/')) {
                const partes = fechaStr.split('/');
                if (partes.length >= 3) {
                    anio = partes[2].substring(0, 4);
                    mes = partes[1];
                }
            } else if (fechaStr.includes('-')) {
                const partes = fechaStr.split('-');
                if (partes.length >= 2) {
                    anio = partes[0];
                    mes = partes[1];
                }
            }
            
            if (tipoPeriodo === 'mes') {
                return anio === anioKey && mes === mesKey;
            } else if (tipoPeriodo === 'trimestre') {
                const trimestreKey = Math.ceil(parseInt(mesKey) / 3);
                const trimestreEval = Math.ceil(parseInt(mes) / 3);
                return anio === anioKey && trimestreEval === trimestreKey;
            }
            return anio === anioKey && mes === mesKey;
        });
    }

    // ========== 4.4 Calcular tendencias de gestores =========================
    function calcularTendenciasGestores(matrizCuartiles, periodosLabels) {
        const tendencias = {};
        const ordenCuartil = { 'Q1': 1, 'Q2': 2, 'Q3': 3, 'Q4': 4 };
        
        for (const [gestor, periodos] of Object.entries(matrizCuartiles)) {
            let ultimoCuartil = null;
            let penultimoCuartil = null;
            let mejora = 0;
            
            // Obtener últimos dos períodos con datos
            for (let i = periodosLabels.length - 1; i >= 0; i--) {
                const label = periodosLabels[i];
                const info = periodos[label];
                if (info && info.cuartil !== '-') {
                    if (ultimoCuartil === null) {
                        ultimoCuartil = info.cuartil;
                    } else if (penultimoCuartil === null) {
                        penultimoCuartil = info.cuartil;
                        break;
                    }
                }
            }
            
            if (ultimoCuartil && penultimoCuartil) {
                const diff = ordenCuartil[penultimoCuartil] - ordenCuartil[ultimoCuartil];
                if (diff > 0) {
                    mejora = diff;
                    tendencias[gestor] = { tipo: 'mejora', texto: `▲ Mejoró (${diff} nivel)`, color: '#28a745', icono: '📈' };
                } else if (diff < 0) {
                    mejora = diff;
                    tendencias[gestor] = { tipo: 'empeoro', texto: `▼ Empeoró (${Math.abs(diff)} nivel)`, color: '#d93025', icono: '📉' };
                } else {
                    tendencias[gestor] = { tipo: 'estable', texto: '➡️ Estable', color: '#6c757d', icono: '➡️' };
                }
            } else if (ultimoCuartil) {
                tendencias[gestor] = { tipo: 'primer', texto: '🆕 Primer período', color: '#019DF4', icono: '🆕' };
            } else {
                tendencias[gestor] = { tipo: 'sin_datos', texto: '❓ Sin datos', color: '#6c757d', icono: '❓' };
            }
        }
        
        return tendencias;
    }

    // ========== 4.5 Generar tabla HTML (CORREGIDO) ==========
    function generarTablaEvolucionCuartiles(container, matrizCuartiles, periodosLabels, gestores, tendencias) {
        const ultimoPeriodo = periodosLabels[periodosLabels.length - 1];
        const gestoresOrdenados = [...gestores].sort((a, b) => {
            const cuartilA = matrizCuartiles[a][ultimoPeriodo]?.cuartil || 'Z';
            const cuartilB = matrizCuartiles[b][ultimoPeriodo]?.cuartil || 'Z';
            
            if (cuartilA === 'Q4' && cuartilB !== 'Q4') return -1;
            if (cuartilA !== 'Q4' && cuartilB === 'Q4') return 1;
            return a.localeCompare(b);
        });
        
        // 🔴 🔴 🔴 FUNCIÓN CORREGIDA 🔴 🔴 🔴
        const getCuartilHTML = (cuartil, evaluaciones) => {
            // Si no hay cuartil o es '-', mostrar vacío
            if (!cuartil || cuartil === '-') {
                return '<span style="color: #adb5bd;">—</span>';
            }
            
            const config = {
                'Q1': { color: '#1a7f37', texto: '🏆 Q1' },
                'Q2': { color: '#019DF4', texto: '📈 Q2' },
                'Q3': { color: '#f39c12', texto: '⚠️ Q3' },
                'Q4': { color: '#d93025', texto: '🔴 Q4' }
            };
            
            // 🔴 Verificar si el cuartil existe en la configuración
            const c = config[cuartil];
            if (!c) {
                // Si no existe, mostrar el cuartil con color genérico
                return `<span style="background: #6c757d; color: white; padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: bold; display: inline-block; white-space: nowrap;">❓ ${cuartil}</span>`;
            }
            
            const badge = `<span style="background: ${c.color}; color: white; padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: bold; display: inline-block; white-space: nowrap;">
                ${c.texto}
            </span>`;
            
            if (evaluaciones > 0) {
                return `<div title="${evaluaciones} evaluación(es) en este período">${badge}</div>`;
            }
            return badge;
        };
    
    const minWidth = Math.max(500, 180 + (periodosLabels.length * 85));
    
    const totalQ4 = gestoresOrdenados.filter(g => {
        const info = matrizCuartiles[g][ultimoPeriodo];
        return info?.cuartil === 'Q4';
    }).length;
    
    // 🔴 CORRECCIÓN: Verificar que periodosLabels no tenga duplicados
    const labelsUnicos = [...new Set(periodosLabels)];
    if (labelsUnicos.length !== periodosLabels.length) {
        console.warn('⚠️ Duplicados en labels:', periodosLabels);
    }
    
    let html = `
        <div style="border-radius: 12px; border: 1px solid #e2e8f0; overflow: hidden; background: white;">
            <div style="max-height: 350px; overflow-y: auto; overflow-x: auto;">
                <table style="width: 100%; min-width: ${minWidth}px; border-collapse: collapse; font-size: 13px; border: none;">
                    <thead style="position: sticky; top: 0; z-index: 10;">
                        <tr style="background: linear-gradient(135deg, #019DF4, #00B4F0); color: white;">
                            <th style="padding: 12px 15px; text-align: left; position: sticky; left: 0; background: linear-gradient(135deg, #019DF4, #00B4F0); z-index: 11; min-width: 180px; border: none;">👥 Gestor</th>
                            ${periodosLabels.map(label => `<th style="padding: 12px 10px; text-align: center; border: none;">${escapeHtml(label)}</th>`).join('')}
                            <th style="padding: 12px 15px; text-align: center; min-width: 100px; border: none;">📊 Tendencia</th>
                        </tr>
                    </thead>
                    <tbody>
    `;
    
    for (const gestor of gestoresOrdenados) {
        const tendencia = tendencias[gestor] || { texto: '❓ Sin datos', color: '#6c757d' };
        const cuartilActual = matrizCuartiles[gestor][ultimoPeriodo]?.cuartil;
        const requierePDA = cuartilActual === 'Q4';
        const bgColor = requierePDA ? '#fff5f5' : '#ffffff';
        
        html += `
            <tr style="background: ${bgColor};">
                <td style="padding: 10px 15px; font-weight: 600; position: sticky; left: 0; background: ${bgColor}; z-index: 5; border: none;">
                    ${escapeHtml(gestor)}
                    ${requierePDA ? '<span style="margin-left: 8px; font-size: 10px; background: #d93025; color: white; padding: 2px 8px; border-radius: 12px;">⚠️ Q4</span>' : ''}
                </td>
                ${periodosLabels.map(label => {
                    const info = matrizCuartiles[gestor][label];
                    return `<td style="padding: 8px 10px; text-align: center; border: none;">${getCuartilHTML(info?.cuartil, info?.evaluaciones || 0)}</td>`;
                }).join('')}
                <td style="padding: 10px 15px; text-align: center; border: none;">
                    <span style="color: ${tendencia.color}; font-weight: 500;">
                        ${tendencia.texto}
                    </span>
                </td>
            </tr>
        `;
    }
    
    html += `
                    </tbody>
                </table>
            </div>
        </div>
        <div style="margin-top: 12px; padding: 8px 15px; background: #f8fafc; border-radius: 10px; font-size: 12px; color: #475569; border: 1px solid #e2e8f0;">
            📊 Total gestores: <strong>${gestoresOrdenados.length}</strong> | 
            🔴 En Q4 actual: <strong style="color: #d93025;">${totalQ4}</strong> | 
            📅 Períodos mostrados: <strong>${periodosLabels.length}</strong>
        </div>
    `;
    
    container.innerHTML = html;
}

    // ========== 4.6 Inicializar controles de filtro =========================
    function inicializarFiltrosEvolucionCuartiles() {
        const periodoSelect = document.getElementById('selectPeriodoEvolucion');
        const cantidadSelect = document.getElementById('selectCantidadPeriodos');
        
        if (periodoSelect) {
            periodoSelect.addEventListener('change', () => cargarEvolucionCuartilesPorGestor());
        }
        if (cantidadSelect) {
            cantidadSelect.addEventListener('change', () => cargarEvolucionCuartilesPorGestor());
        }
    }
