    // ======================================================
    // FUNCIÓN: Mostrar resumen agrupado con datos filtrados (SIN columna Quiebres)
    // ======================================================
    async function mostrarResumenAgrupadoConFiltro(evaluacionesFiltradas, campoAgrupacion, titulo, icono) {
        console.log(`📊 mostrando resumen agrupado por: ${campoAgrupacion} con ${evaluacionesFiltradas.length} evaluaciones`);
        
        const container = document.getElementById('resumen-agrupado-container');
        if (!container) {
            console.error('❌ No se encontró el contenedor resumen-agrupado-container');
            return;
        }
        
        if (evaluacionesFiltradas.length === 0) {
            container.innerHTML = `<div class="card" style="text-align: center; padding: 40px; color: var(--muted);">📊 No hay datos en el período seleccionado para este resumen.</div>`;
            return;
        }
        
        container.innerHTML = '<div style="text-align: center; padding: 20px;">⏳ Procesando datos...</div>';
        
        try {
            const token = localStorage.getItem('meca_token');
            let liderPorAgente = {};
            let ubicacionPorAgente = {};
            let localidadPorAgente = {};
            
            try {
                const response = await fetch('/api/agentes/completo', {
                    headers: { 'Authorization': `Bearer ${token}` }
                });
                if (response.ok) {
                    const agentes = await response.json();
                    agentes.forEach(a => {
                        liderPorAgente[a.nombre] = a.lider_2026 || 'Sin líder';
                        ubicacionPorAgente[a.nombre] = a.ubicacion || 'Sin ubicación';
                        localidadPorAgente[a.nombre] = a.localidad || 'Sin localidad';
                    });
                }
            } catch (error) {
                console.warn('Error obteniendo agentes:', error);
            }
            
            const grupos = new Map();
            
            for (const evalItem of evaluacionesFiltradas) {
                const agente = evalItem.agente;
                let grupoNombre = 'Sin grupo';
                
                switch (campoAgrupacion) {
                    case 'lider_2026':
                        grupoNombre = liderPorAgente[agente] || 'Sin líder';
                        break;
                    case 'ubicacion':
                        grupoNombre = ubicacionPorAgente[agente] || 'Sin ubicación';
                        break;
                    case 'localidad':
                        grupoNombre = localidadPorAgente[agente] || 'Sin localidad';
                        break;
                }
                
                if (!grupos.has(grupoNombre)) {
                    grupos.set(grupoNombre, {
                        nombre: grupoNombre,
                        totalEval: 0,
                        sumaNotas: 0,
                        agentesSet: new Set(),
                        sumaENC: 0,
                        sumaECUF: 0,
                        sumaECN: 0
                    });
                }
                
                const grupo = grupos.get(grupoNombre);
                grupo.totalEval++;
                grupo.sumaNotas += evalItem.notaFinal || 0;
                grupo.sumaENC += evalItem.totalENC || 0;
                grupo.sumaECUF += evalItem.totalECUF || 0;
                grupo.sumaECN += evalItem.totalECN || 0;
                grupo.agentesSet.add(agente);
            }
            
            const ranking = await construirRankingAgentes(evaluacionesFiltradas);
            const cuartilPorAgente = {};
            ranking.forEach(r => {
                cuartilPorAgente[r.agente] = r.cuartil;
            });
            
            const resultados = Array.from(grupos.values()).map(grupo => {
                let gestoresQ4 = 0;
                for (const agente of grupo.agentesSet) {
                    if (cuartilPorAgente[agente] === 'Q4') gestoresQ4++;
                }
                
                const totalEval = grupo.totalEval;
                const promedioENC = totalEval > 0 ? (grupo.sumaENC / totalEval).toFixed(1) : 0;
                const promedioECUF = totalEval > 0 ? (grupo.sumaECUF / totalEval).toFixed(1) : 0;
                const promedioECN = totalEval > 0 ? (grupo.sumaECN / totalEval).toFixed(1) : 0;
                
                return {
                    nombre: grupo.nombre,
                    totalAgentes: grupo.agentesSet.size,
                    totalEval: totalEval,
                    promedioGeneral: totalEval > 0 ? Math.round((grupo.sumaNotas / totalEval) * 10) / 10 : 0,
                    promedioENC: Math.round(promedioENC * 10) / 10,
                    promedioECUF: Math.round(promedioECUF * 10) / 10,
                    promedioECN: Math.round(promedioECN * 10) / 10,
                    gestoresQ4: gestoresQ4,
                    pctQ4: grupo.agentesSet.size > 0 ? Math.round((gestoresQ4 / grupo.agentesSet.size) * 100) : 0
                };
            });
            
            resultados.sort((a, b) => b.promedioGeneral - a.promedioGeneral);
            
            console.log(`✅ ${resultados.length} grupos calculados`);
            
            if (resultados.length === 0) {
                container.innerHTML = `<div class="card" style="text-align: center; padding: 40px; color: var(--muted);">📊 No hay datos para agrupar en el período seleccionado.</div>`;
                return;
            }
            
            // 🔴 HTML SIN la columna Quiebres
            let html = `
                <div class="card" style="margin-top: 20px;">
                    <h3>${icono} ${titulo} (${resultados.length} grupos | ${evaluacionesFiltradas.length} evaluaciones)</h3>
                    <div class="table-container">
                        <table style="width: 100%; min-width: 800px;">
                            <thead>
                                <tr>
                                    <th>Grupo</th>
                                    <th>👥 Agentes</th>
                                    <th>📞 Evaluaciones</th>
                                    <th>⭐ Promedio</th>
                                    <th>🎯 ENC</th>
                                    <th>⚠️ ECUF</th>
                                    <th>💰 ECN</th>
                                    <th>🔴 Q4 (%)</th>
                                </tr>
                            </thead>
                            <tbody>
            `;
            
            for (const item of resultados) {
                let promedioColor = 'var(--danger)';
                if (item.promedioGeneral >= 90) promedioColor = 'var(--ok)';
                else if (item.promedioGeneral >= 85) promedioColor = 'var(--warning)';
                
                let q4Color = 'var(--ok)';
                let q4Alerta = '';
                if (item.pctQ4 >= 40) {
                    q4Color = 'var(--danger)';
                    q4Alerta = '🔴';
                } else if (item.pctQ4 >= 20) {
                    q4Color = 'var(--warning)';
                    q4Alerta = '⚠️';
                }
                
                html += `
                    <tr onclick="filtrarPor('${campoAgrupacion}', '${escapeHtml(item.nombre)}')" style="cursor: pointer;">
                        <td><strong>${escapeHtml(item.nombre)}</strong> ${q4Alerta}</td>
                        <td style="text-align: center;">${item.totalAgentes}</td>
                        <td style="text-align: center;">${item.totalEval}</td>
                        <td style="text-align: center; color: ${promedioColor}; font-weight: bold;">${item.promedioGeneral}%</td>
                        <td style="text-align: center;">${item.promedioENC}%</td>
                        <td style="text-align: center;">${item.promedioECUF}%</td>
                        <td style="text-align: center;">${item.promedioECN}%</td>
                        <td style="text-align: center; color: ${q4Color}; font-weight: bold;">${item.pctQ4}% (${item.gestoresQ4})</td>
                    </tr>
                `;
            }
            
            html += `
                            </tbody>
                        </table>
                    </div>
                    <div style="margin-top: 10px; font-size: 11px; color: var(--muted); text-align: center;">
                        💡 Haga clic en cualquier fila para filtrar los gráficos | 📊 Datos del período seleccionado (${evaluacionesFiltradas.length} evaluaciones)
                    </div>
                </div>
            `;
            
            container.innerHTML = html;
            
        } catch (error) {
            console.error('Error:', error);
            container.innerHTML = `<div class="card" style="text-align: center; padding: 40px; color: var(--danger);">❌ Error: ${error.message}</div>`;
        }
    }

