    // ===== 23. INICIO FUNCIÓN: obtenerEstadoPDAporUltimoCiclo ===============
    async function obtenerEstadoPDAporUltimoCiclo(agente) {
        // Obtener ciclos del agente
        const ciclos = await agruparEvaluacionesEnCiclos(agente);

        if (ciclos.length === 0) {
            return {
                estado: '<span style="color: var(--muted);">-</span>',
                requierePDA: false,
                cuartilUltimoCiclo: null
            };
        }

        const ultimoCiclo = ciclos[ciclos.length - 1];
        const esQ4 = ultimoCiclo.cuartil === 'Q4';

        // Verificar si tiene PDA activo
        const tienePDAactivo = (window.datosPDA || []).some(pda =>
            pda.agente === agente &&
            ['pendiente', 'notificado', 'en_gestion', 'en_seguimiento'].includes(pda.estado)
        );

        let estado = '';
        let requierePDA = false;

        if (esQ4 && !tienePDAactivo) {
            estado = '<span class="badge" style="background: var(--danger);">🔴 Requiere PDA</span>';
            requierePDA = true;
        } else if (esQ4 && tienePDAactivo) {
            estado = '<span class="badge" style="background: var(--warning);">⏳ PDA en curso</span>';
            requierePDA = false;
        } else if (!esQ4) {
            // Buscar PDA completado recientemente
            const pdaCompletado = (window.datosPDA || []).find(pda =>
                pda.agente === agente && pda.estado === 'corregido'
            );
            if (pdaCompletado) {
                estado = '<span class="badge" style="background: var(--ok);">✅ Corregido</span>';
            } else {
                estado = '<span style="color: var(--muted);">-</span>';
            }
            requierePDA = false;
        }

        return {
            estado: estado,
            requierePDA: requierePDA,
            cuartilUltimoCiclo: ultimoCiclo.cuartil,
            promedioUltimoCiclo: ultimoCiclo.promedio
        };
    }
    // ===== FIN FUNCIÓN: obtenerEstadoPDAporUltimoCiclo ======================
    
    // ===== 24. INICIO FUNCIÓN: verEvolucionCiclos ===========================
    // ===== FUNCIÓN CORREGIDA: verEvolucionCiclos =====
async function verEvolucionCiclos(agente) {
    console.log(`📊 Mostrando evolución de ciclos para: ${agente}`);

    const modal = document.getElementById('modalEvolucionCiclos');
    const titulo = document.getElementById('modalEvolucionTitulo');
    const contenido = document.getElementById('modalEvolucionContenido');

    if (!modal || !titulo || !contenido) return;

    titulo.innerHTML = `📊 Evolución por Ciclos - ${escapeHtml(agente)}`;
    modal.style.display = 'flex';
    contenido.innerHTML = '<div style="text-align: center; padding: 40px;">⏳ Cargando ciclos...</div>';

    const ciclos = await agruparEvaluacionesEnCiclos(agente);

    if (ciclos.length === 0) {
        contenido.innerHTML = '<div style="text-align: center; padding: 40px; color: var(--muted);">No hay ciclos disponibles para este gestor</div>';
        return;
    }

    // 🔴 CORRECCIÓN: Mostrar en orden ASCENDENTE (Ciclo #1 primero, #5 al final)
    // NO invertir el array, usarlo tal cual viene
    // El array 'ciclos' ya viene ordenado de más antiguo a más reciente
    const ciclosOrdenados = [...ciclos]; // Solo copiar para no modificar el original

    let html = `
        <div class="table-container" style="max-height: 400px;">
            <table style="width: 100%; font-size: 13px;">
                <thead>
                    <tr>
                        <th>Ciclo</th>
                        <th>Período</th>
                        <th>Evaluaciones</th>
                        <th>Promedio</th>
                        <th>Cuartil</th>
                        <th>ENC</th>
                        <th>ECUF</th>
                        <th>ECN</th>
                        <th>PDA</th>
                    </tr>
                </thead>
                <tbody>
    `;

    for (const ciclo of ciclosOrdenados) {
        let cuartilColor = '';
        let cuartilIcono = '';

        switch (ciclo.cuartil) {
            case 'Q1': cuartilColor = '#28a745'; cuartilIcono = '🏆'; break;
            case 'Q2': cuartilColor = '#019DF4'; cuartilIcono = '📈'; break;
            case 'Q3': cuartilColor = '#f39c12'; cuartilIcono = '⚠️'; break;
            case 'Q4': cuartilColor = '#d93025'; cuartilIcono = '🔴'; break;
        }

        // Verificar si este ciclo tuvo un PDA asociado
        const pdaAsociado = (window.datosPDA || []).find(pda =>
            pda.agente === agente &&
            pda.fechaInicioCicloBasal === ciclo.fechaInicio
        );

        const pdaBadge = pdaAsociado ?
            `<span class="badge" style="background: var(--accent);">📋 PDA</span>` :
            '<span style="color: var(--muted);">-</span>';

        // Calcular mejora respecto al ciclo anterior (en orden ascendente)
        const cicloIndex = ciclosOrdenados.indexOf(ciclo);
        const cicloAnterior = cicloIndex > 0 ? ciclosOrdenados[cicloIndex - 1] : null;
        
        let mejoraIcono = '';
        let mejoraTexto = '';
        
        if (cicloAnterior) {
            const orden = { 'Q1': 1, 'Q2': 2, 'Q3': 3, 'Q4': 4 };
            const diferenciaPromedio = ciclo.promedio - cicloAnterior.promedio;
            
            if (orden[ciclo.cuartil] < orden[cicloAnterior.cuartil]) {
                mejoraIcono = '▲';
                mejoraTexto = `Mejoró (${Math.abs(diferenciaPromedio).toFixed(1)}%)`;
                mejoraIcono = `<span style="color: #28a745;">▲ Mejoró</span>`;
            } else if (orden[ciclo.cuartil] > orden[cicloAnterior.cuartil]) {
                mejoraIcono = `<span style="color: #d93025;">▼ Empeoró</span>`;
                mejoraTexto = `Empeoró (${Math.abs(diferenciaPromedio).toFixed(1)}%)`;
            } else {
                mejoraIcono = `<span style="color: var(--muted);">➡️ Estable</span>`;
                mejoraTexto = `Estable (${diferenciaPromedio > 0 ? '+' : ''}${diferenciaPromedio.toFixed(1)}%)`;
            }
        } else {
            mejoraIcono = `<span style="color: var(--muted);">-</span>`;
            mejoraTexto = 'Primer ciclo';
        }

        html += `
            <tr>
                <td style="padding: 8px; text-align: center;">
                    <strong>#${ciclo.numero}</strong>
                    <div style="font-size: 10px; margin-top: 4px;">${mejoraIcono}</div>
                </td>
                <td style="padding: 8px; white-space: nowrap;">${ciclo.fechaInicio} → ${ciclo.fechaFin}</td>
                <td style="padding: 8px; text-align: center;">${ciclo.totalEvaluaciones}/5</td>
                <td style="padding: 8px; text-align: center; font-weight: bold;">${ciclo.promedio}%</td>
                <td style="padding: 8px; text-align: center;">
                    <span class="badge" style="background: ${cuartilColor};">${cuartilIcono} ${ciclo.cuartil}</span>
                </td>
                <td style="padding: 8px; text-align: center;">${ciclo.promedioENC}%</td>
                <td style="padding: 8px; text-align: center;">${ciclo.promedioECUF}%</td>
                <td style="padding: 8px; text-align: center;">${ciclo.promedioECN}%</td>
                <td style="padding: 8px; text-align: center;">${pdaBadge}</td>
            </tr>
        `;
    }

    html += `
                </tbody>
            </table>
        </div>
        <div style="margin-top: 15px; padding: 10px; background: #f8f9fa; border-radius: 10px; font-size: 12px;">
            <strong>📌 Leyenda:</strong>
            <span style="margin-left: 10px;">🏆 Q1: Excelente (≥97%)</span>
            <span style="margin-left: 10px;">📈 Q2: Bueno (90-96%)</span>
            <span style="margin-left: 10px;">⚠️ Q3: Regular (85-89%)</span>
            <span style="margin-left: 10px;">🔴 Q4: Crítico (&lt;85%)</span>
        </div>
    `;

    contenido.innerHTML = html;
}
    // ===== FIN FUNCIÓN: verEvolucionCiclos ==================================

    // ===== 25. INICIO FUNCIÓN: cerrarModalEvolucionCiclos ===================
    function cerrarModalEvolucionCiclos() {
        const modal = document.getElementById('modalEvolucionCiclos');
        if (modal) modal.style.display = 'none';
    }
    // ===== FIN FUNCIÓN: cerrarModalEvolucionCiclos ==========================

    // ===== 26. INICIO FUNCIÓN: cargarListaAgentesParaBusqueda ===============
    let agentesListaCompleta = [];
    let timeoutBusquedaGestor = null;
    let agenteSeleccionadoActual = null;
    let dropdownVisible = false;

    async function cargarListaAgentesParaBusqueda() {
        const evaluaciones = window.evaluacionesGlobales || [];
        const agentesSet = new Set();

        evaluaciones.forEach(eval => {
            if (eval.agente) agentesSet.add(eval.agente);
        });

        // Obtener ranking para ordenar
        const ranking = await construirRankingAgentes(evaluaciones);
        const agentesQ4 = new Set(ranking.filter(a => a.cuartil === 'Q4').map(a => a.agente));
        const rankingMap = {};
        ranking.forEach(r => { rankingMap[r.agente] = r.promedio; });

        agentesListaCompleta = Array.from(agentesSet).map(agente => ({
            nombre: agente,
            esQ4: agentesQ4.has(agente),
            promedio: rankingMap[agente] || 0,
            evaluaciones: evaluaciones.filter(e => e.agente === agente).length
        }));

        // Ordenar: primero Q4, luego por promedio descendente, luego alfabético
        agentesListaCompleta.sort((a, b) => {
            if (a.esQ4 && !b.esQ4) return -1;
            if (!a.esQ4 && b.esQ4) return 1;
            if (b.promedio !== a.promedio) return b.promedio - a.promedio;
            return a.nombre.localeCompare(b.nombre);
        });

        console.log(`✅ ${agentesListaCompleta.length} gestores cargados`);
    }
    // ===== FIN FUNCIÓN: cargarListaAgentesParaBusqueda ======================

    // ===== 27. INICIO FUNCIÓN: inicializarBuscadorGestores ==================
    function inicializarBuscadorGestores() {
        const input = document.getElementById('buscarAgenteHistorial');
        const sugerenciasDiv = document.getElementById('sugerenciasAgentes');
        const hiddenInput = document.getElementById('selectAgenteHistorial');

        if (!input || !sugerenciasDiv) {
            console.warn('⚠️ Elementos del buscador no encontrados');
            return;
        }

        // Cargar lista completa de gestores
        cargarListaAgentesParaBusqueda();

        // ======================================================
        // EVENTO: AL HACER CLIC/FOCUS - Mostrar lista completa
        // ======================================================
        input.addEventListener('focus', function () {
            console.log('📌 Focus - Mostrando lista completa de gestores');
            mostrarListaCompletaGestores();
            dropdownVisible = true;
        });

        // ======================================================
        // EVENTO: AL ESCRIBIR - Filtrar la lista
        // ======================================================
        input.addEventListener('input', function (e) {
            const busqueda = this.value.trim();

            if (timeoutBusquedaGestor) clearTimeout(timeoutBusquedaGestor);

            timeoutBusquedaGestor = setTimeout(() => {
                let filtrados = agentesListaCompleta;

                if (busqueda.length > 0) {
                    const busquedaLower = busqueda.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
                    filtrados = agentesListaCompleta.filter(agente => {
                        const nombreNormalizado = agente.nombre.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
                        return nombreNormalizado.includes(busquedaLower);
                    });
                }

                mostrarSugerencias(filtrados, busqueda);
                dropdownVisible = true;
            }, 200);
        });

        // ======================================================
        // EVENTO: Cerrar dropdown al hacer clic fuera
        // ======================================================
        document.addEventListener('click', function (e) {
            const container = input.closest('div');
            if (container && !container.contains(e.target)) {
                sugerenciasDiv.style.display = 'none';
                dropdownVisible = false;
            }
        });

        // ======================================================
        // EVENTO: Tecla Enter - Seleccionar primer elemento
        // ======================================================
        input.addEventListener('keydown', function (e) {
            if (e.key === 'Enter' && dropdownVisible) {
                e.preventDefault();
                const primerItem = sugerenciasDiv.querySelector('.sugerencia-item');
                if (primerItem) {
                    primerItem.click();
                }
            }

            // Tecla Escape para cerrar dropdown
            if (e.key === 'Escape') {
                sugerenciasDiv.style.display = 'none';
                dropdownVisible = false;
            }
        });

        // ======================================================
        // EVENTO: Flechas para navegación (opcional)
        // ======================================================
        let selectedIndex = -1;

        input.addEventListener('keydown', function (e) {
            const items = sugerenciasDiv.querySelectorAll('.sugerencia-item');
            if (items.length === 0) return;

            if (e.key === 'ArrowDown') {
                e.preventDefault();
                selectedIndex = Math.min(selectedIndex + 1, items.length - 1);
                actualizarSeleccion(items, selectedIndex, input);
            } else if (e.key === 'ArrowUp') {
                e.preventDefault();
                selectedIndex = Math.max(selectedIndex - 1, -1);
                actualizarSeleccion(items, selectedIndex, input);
                if (selectedIndex === -1) {
                    input.value = '';
                }
            }
        });

        function actualizarSeleccion(items, index, input) {
            items.forEach((item, i) => {
                if (i === index) {
                    item.classList.add('selected');
                    const nombre = item.getAttribute('data-nombre');
                    if (nombre && index !== -1) {
                        input.value = nombre;
                    }
                    item.scrollIntoView({ block: 'nearest' });
                } else {
                    item.classList.remove('selected');
                }
            });
        }
    }
    // ===== FIN FUNCIÓN: inicializarBuscadorGestores =========================
    
    // ===== 28. INICIO FUNCIÓN: mostrarListaCompletaGestores =================
    function mostrarListaCompletaGestores() {
        console.log('📋 Mostrando lista completa de gestores...');
        
        // Obtener la lista de agentes como objetos (con sus datos)
        const ranking = rankingCompletoGlobal || [];
        
        if (ranking.length === 0) {
            console.warn('⚠️ No hay ranking de agentes disponible');
            const sugerenciasDiv = document.getElementById('sugerenciasAgentes');
            if (sugerenciasDiv) {
                sugerenciasDiv.innerHTML = `<div style="padding: 20px; text-align: center; color: var(--muted);">
                    ❌ No hay gestores disponibles
                </div>`;
                sugerenciasDiv.style.display = 'block';
            }
            return;
        }
        
        // Convertir ranking a objetos con la estructura que espera mostrarSugerencias
        const agentesFormateados = ranking.map(agente => ({
            nombre: agente.agente,
            esQ4: agente.cuartil === 'Q4',
            evaluaciones: agente.count,
            promedio: agente.promedio
        }));
        
        mostrarSugerencias(agentesFormateados, '');
    }
    // ===== FIN FUNCIÓN: mostrarListaCompletaGestores ========================
    
    // ===== 29. INICIO FUNCIÓN: mostrarSugerencias ===========================
    function mostrarSugerencias(agentes, busqueda) {
        const sugerenciasDiv = document.getElementById('sugerenciasAgentes');
        const input = document.getElementById('buscarAgenteHistorial');

        if (!sugerenciasDiv) return;

        if (!agentes || agentes.length === 0) {
            sugerenciasDiv.innerHTML = `
                <div style="padding: 20px; text-align: center; color: var(--muted);">
                    ❌ No se encontraron gestores ${busqueda ? `para "${escapeHtml(busqueda)}"` : ''}
                </div>
            `;
            sugerenciasDiv.style.display = 'block';
            return;
        }

        // Función para resaltar coincidencias
        const resaltarCoincidencia = (texto, busqueda) => {
            if (!busqueda || busqueda === '') return escapeHtml(texto);
            const busquedaLower = busqueda.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
            const textoNormalizado = texto.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

            if (!textoNormalizado.includes(busquedaLower)) return escapeHtml(texto);

            // Buscar posición de la coincidencia en el texto original
            let regex;
            try {
                regex = new RegExp(`(${busqueda.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})`, 'gi');
            } catch (e) {
                return escapeHtml(texto);
            }
            return escapeHtml(texto).replace(regex, '<span class="sugerencia-resaltado">$1</span>');
        };

        const totalMostrados = Math.min(agentes.length, 20);
        let html = `<div style="padding: 8px 12px; background: #f8f9fa; font-size: 11px; color: var(--muted); border-bottom: 1px solid #e0e0e0; display: flex; justify-content: space-between;">
            <span>🔍 ${agentes.length} gestor${agentes.length !== 1 ? 'es' : ''}</span>
            <span style="font-size: 10px;">⬆️⬇️ para navegar | Enter para seleccionar</span>
        </div>`;

        for (let i = 0; i < totalMostrados; i++) {
            const agente = agentes[i];
            const icono = agente.esQ4 ? '⚠️' : '👤';
            const detalle = `${agente.evaluaciones} eval | Prom: ${agente.promedio}%`;

            html += `
                <div class="sugerencia-item" data-nombre="${escapeHtml(agente.nombre)}" onclick="seleccionarGestor('${escapeHtml(agente.nombre).replace(/'/g, "\\'")}')">
                    <div>
                        <span class="sugerencia-nombre">${icono} ${resaltarCoincidencia(agente.nombre, busqueda)}</span>
                        ${agente.esQ4 ? '<span style="margin-left: 8px; font-size: 10px; background: var(--danger); color: white; padding: 2px 6px; border-radius: 10px;">Q4</span>' : ''}
                        <div class="sugerencia-detalle">${detalle}</div>
                    </div>
                    <span style="color: var(--accent);">→</span>
                </div>
            `;
        }

        if (agentes.length > totalMostrados) {
            html += `<div style="padding: 12px; text-align: center; color: var(--muted); font-size: 12px;">
                ... y ${agentes.length - totalMostrados} más
            </div>`;
        }

        sugerenciasDiv.innerHTML = html;
        sugerenciasDiv.style.display = 'block';
    }
    // ===== FIN FUNCIÓN: mostrarSugerencias ==================================

    // ===== 30. INICIO FUNCIÓN: seleccionarGestor ============================
    function seleccionarGestor(gestor) {
        const input = document.getElementById('buscarAgenteHistorial');
        const hiddenInput = document.getElementById('selectAgenteHistorial');
        const sugerenciasDiv = document.getElementById('sugerenciasAgentes');

        if (input) input.value = gestor;
        if (hiddenInput) hiddenInput.value = gestor;
        if (sugerenciasDiv) sugerenciasDiv.style.display = 'none';

        agenteSeleccionadoActual = gestor;
        dropdownVisible = false;

        console.log(`✅ Gestor seleccionado: ${gestor}`);

        // Opcional: mostrar un pequeño indicador de selección
        const mensajeTemporal = document.createElement('div');
        mensajeTemporal.textContent = `✅ Seleccionado: ${gestor}`;
        mensajeTemporal.style.cssText = 'position: fixed; bottom: 20px; right: 20px; background: var(--ok); color: white; padding: 8px 16px; border-radius: 20px; font-size: 12px; z-index: 1000; animation: fadeOut 2s ease forwards;';
        document.body.appendChild(mensajeTemporal);
        setTimeout(() => mensajeTemporal.remove(), 2000);
    }
    // ===== FIN FUNCIÓN: seleccionarGestor ===================================

    // ===== 31. INICIO FUNCIÓN: cargarHistorialAgente =======================
    function cargarHistorialAgente() {
        const hiddenInput = document.getElementById('selectAgenteHistorial');
        const inputBusqueda = document.getElementById('buscarAgenteHistorial');
        let agente = hiddenInput?.value || inputBusqueda?.value;

        if (!agente || agente.trim() === '') {
            alert('⚠️ Seleccione o escriba un gestor para ver su historial');
            return;
        }

        const evaluaciones = window.evaluacionesGlobales || [];
        const evaluacionesAgente = evaluaciones.filter(e => e.agente === agente);

        if (evaluacionesAgente.length === 0) {
            alert(`⚠️ No hay evaluaciones para el gestor ${agente}`);
            return;
        }

        // Ordenar por fecha (más reciente primero)
        evaluacionesAgente.sort((a, b) => {
            const fechaA = a.fechaOriginal || a.fecha || '';
            const fechaB = b.fechaOriginal || b.fecha || '';
            return fechaB.localeCompare(fechaA);
        });

        // Mostrar resumen
        mostrarResumenAgente(agente, evaluacionesAgente);

        // Mostrar tabla de evaluaciones
        mostrarTablaEvaluacionesAgente(agente, evaluacionesAgente);

        // Mostrar botón de exportar
        const btnExportar = document.getElementById('btnExportarHistorial');
        if (btnExportar) btnExportar.style.display = 'inline-flex';
    }
    // ===== FIN FUNCIÓN: cargarHistorialAgente ===============================

    // ===== 32. INICIO FUNCIÓN: exportarHistorialAgenteCSV ===================
    function exportarHistorialAgenteCSV() {
        const hiddenInput = document.getElementById('selectAgenteHistorial');
        const inputBusqueda = document.getElementById('buscarAgenteHistorial');
        const agente = hiddenInput?.value || inputBusqueda?.value;

        if (!agente || agente.trim() === '') {
            alert('⚠️ Seleccione un gestor primero');
            return;
        }

        const evaluaciones = window.evaluacionesGlobales || [];
        const evaluacionesAgente = evaluaciones.filter(e => e.agente === agente);

        if (evaluacionesAgente.length === 0) {
            alert(`No hay evaluaciones para ${agente}`);
            return;
        }

        // Resto del código de exportación igual...
        const headers = ['Fecha', 'ID Llamada', 'Nota Final', 'Rango', 'ENC', 'ECUF', 'ECN', 'Evaluador', 'Bloque', 'Atributo', 'Submotivo', 'Peso (%)', 'Cumple'];
        const rows = [];

        evaluacionesAgente.forEach(eval => {
            const fecha = eval.fechaOriginal || eval.fecha || '';
            const idLlamada = eval.idLlamada || '';
            const nota = eval.notaFinal || 0;
            const rango = eval.rango || '';
            const enc = eval.totalENC || 0;
            const ecuf = eval.totalECUF || 0;
            const ecn = eval.totalECN || 0;
            const evaluador = eval.evaluador || '';

            if (eval.detalles && eval.detalles.length > 0) {
                eval.detalles.forEach(det => {
                    rows.push([
                        `"${fecha}"`,
                        `"${idLlamada}"`,
                        nota,
                        `"${rango}"`,
                        enc,
                        ecuf,
                        ecn,
                        `"${evaluador}"`,
                        `"${det.bloque || ''}"`,
                        `"${det.atributo || ''}"`,
                        `"${det.submotivo || ''}"`,
                        det.peso || 0,
                        det.cumple ? 'SI' : 'NO'
                    ]);
                });
            } else {
                rows.push([
                    `"${fecha}"`,
                    `"${idLlamada}"`,
                    nota,
                    `"${rango}"`,
                    enc,
                    ecuf,
                    ecn,
                    `"${evaluador}"`,
                    'Sin detalles',
                    '',
                    '',
                    '',
                    ''
                ]);
            }
        });

        const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
        const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `historial_${agente.replace(/\s/g, '_')}_${new Date().toISOString().slice(0, 10)}.csv`;
        a.click();
        URL.revokeObjectURL(url);

        alert(`✅ Exportado historial de ${agente} (${evaluacionesAgente.length} evaluaciones, ${rows.length} filas de detalle)`);
    }
    // ===== FIN FUNCIÓN: exportarHistorialAgenteCSV ==========================

    // ===== 33. INICIO FUNCIÓN: mostrarResumenAgente =======================
    async function mostrarResumenAgente(agente, evaluaciones) {
        const total = evaluaciones.length;
        const sumaNotas = evaluaciones.reduce((sum, e) => sum + numeroSeguro(e.notaFinal), 0);
        const promedio = (sumaNotas / total).toFixed(1);

        // Calcular cuartil
        const ranking = await construirRankingAgentes(evaluaciones);
        const agenteRanking = ranking.find(r => r.agente === agente);
        const cuartil = agenteRanking?.cuartil || calcularCuartilIndividual(promedio);

        // Obtener estado PDA
        const infoPDA = obtenerInfoPDA(agente, cuartil);

        document.getElementById('resumenTotalEval').textContent = total;
        document.getElementById('resumenPromedio').textContent = promedio + '%';
        document.getElementById('resumenCuartil').innerHTML = cuartil === 'Q4'
            ? `<span style="color: var(--danger);">⚠️ ${cuartil} (Riesgo)</span>`
            : `<span style="color: var(--ok);">✅ ${cuartil}</span>`;
        document.getElementById('resumenEstadoPDA').innerHTML = infoPDA.estado || '-';

        document.getElementById('resumenAgente').style.display = 'block';
    }
    // ===== FIN FUNCIÓN: mostrarResumenAgente ================================
    
    // ===== 34. INICIO FUNCIÓN: mostrarTablaEvaluacionesAgente ==============
    function mostrarTablaEvaluacionesAgente(agente, evaluaciones) {
        const tbody = document.getElementById('tablaHistorialAgente');
        if (!tbody) return;

        let html = '';

        evaluaciones.forEach((eval, index) => {
            const fecha = eval.fechaOriginal || eval.fecha || 'Sin fecha';
            const nota = numeroSeguro(eval.notaFinal);
            const rango = eval.rango || obtenerRango(nota).nombre;

            let notaColor = '';
            if (nota >= 90) notaColor = 'var(--ok)';
            else if (nota >= 85) notaColor = 'var(--warning)';
            else notaColor = 'var(--danger)';

            // 🔴 OBTENER FECHA DESCARGA AUDIO
            let fechaDescarga = '-';
            if (eval.fechaDescarga) {
                try {
                    // Si viene en formato ISO (YYYY-MM-DD)
                    if (eval.fechaDescarga.includes('-')) {
                        const [anio, mes, dia] = eval.fechaDescarga.split('T')[0].split('-');
                        fechaDescarga = `${dia}/${mes}/${anio}`;
                    } else {
                        fechaDescarga = eval.fechaDescarga;
                    }
                } catch (e) {
                    fechaDescarga = eval.fechaDescarga || '-';
                }
            }

            const rowId = `eval-${eval.id || index}`;

            // Fila principal (expandible) con NUEVA COLUMNA
            html += `
                <tr class="expandable-row" onclick="toggleDetalleEvaluacion('${rowId}')" style="cursor: pointer;">
                    <td style="text-align: center;">
                        <span class="expand-icon" id="icon-${rowId}">▶</span>
                    </td>
                    <td>${escapeHtml(fecha)}</td>
                    <td>${escapeHtml(fechaDescarga)}</td>  <!-- ✅ NUEVA COLUMNA -->
                    <td>${escapeHtml(eval.idLlamada || '-')}</td>
                    <td style="font-weight: bold; color: ${notaColor};">${nota}%</td>
                    <td><span class="badge" style="background: ${notaColor};">${rango}</span></td>
                    <td>${numeroSeguro(eval.totalENC)}/${obtenerPesosActuales().ENC}</td>
                    <td>${numeroSeguro(eval.totalECUF)}/${obtenerPesosActuales().ECUF}</td>
                    <td>${numeroSeguro(eval.totalECN)}/${obtenerPesosActuales().ECN}</td>
                    <td>${escapeHtml(eval.evaluador || '-')}</td>
                    
                </tr>
                <tr id="${rowId}" class="detail-row" style="display: none;">
                    <td colspan="10">  <!-- 🔴 ACTUALIZAR colspan de 9 a 10 -->
                        <div class="detail-content">
                            <strong>📋 Detalle de ítems evaluados:</strong>
                            <div class="detail-items" id="items-${rowId}">
                                ${generarDetalleItemsHTML(eval.detalles || [])}
                            </div>
                        </div>
                    </td>
                </tr>
            `;
        });

        tbody.innerHTML = html;
        document.getElementById('historialContainer').style.display = 'block';
    }
    // ===== FIN FUNCIÓN: mostrarTablaEvaluacionesAgente ======================
    
    // ===== 35. INICIO FUNCIÓN: toggleDetalleEvaluacion =====================
    function toggleDetalleEvaluacion(rowId) {
        const detailRow = document.getElementById(rowId);
        const icon = document.getElementById(`icon-${rowId}`);

        if (detailRow.style.display === 'none') {
            detailRow.style.display = 'table-row';
            if (icon) icon.innerHTML = '▼';
            icon?.classList.add('expanded');
        } else {
            detailRow.style.display = 'none';
            if (icon) icon.innerHTML = '▶';
            icon?.classList.remove('expanded');
        }
    }
    // ===== FIN FUNCIÓN: toggleDetalleEvaluacion =============================            

    // ===== 36. INICIO FUNCIÓN: generarDetalleItemsHTML =====================
    function generarDetalleItemsHTML(detalles) {
        if (!detalles || detalles.length === 0) {
            return '<div style="padding: 15px; text-align: center; color: var(--muted);">No hay detalles disponibles para esta evaluación</div>';
        }

        let html = '';

        detalles.forEach(det => {
            const cumple = det.cumple === true || det.cumple === 'true' || det.cumple === 1;
            const clase = cumple ? 'cumple' : 'no-cumple';
            const badge = cumple
                ? '<span class="detail-badge ok">✅ CUMPLE</span>'
                : '<span class="detail-badge no">❌ NO CUMPLE</span>';

            const submotivoTexto = det.submotivo || det.atributo || '-';
            const peso = det.peso || 0;

            html += `
                <div class="detail-item ${clase}">
                    <span class="item-bloque">📁 ${escapeHtml(det.bloque || '-')}</span>
                    <span class="item-atributo"><strong>${escapeHtml(det.atributo || '-')}</strong></span>
                    <span class="item-submotivo">📌 ${escapeHtml(submotivoTexto)}</span>
                    <span class="item-peso">⚖️ ${peso}%</span>
                    ${badge}
                </div>
            `;
        });

        return html;
    }
    // ===== FIN FUNCIÓN: generarDetalleItemsHTML =============================
    
    // ===== 37. INICIO FUNCIÓN: exportarTodosLosAgentesCSV ==================
    async function exportarTodosLosAgentesCSV() {
        console.log('📥 Exportando detalle de TODOS los agentes...');

        // Asegurar que tenemos las evaluaciones cargadas
        if (!window.evaluacionesGlobales || window.evaluacionesGlobales.length === 0) {
            await cargarEvaluacionesDesdePostgreSQL();
        }

        const evaluaciones = window.evaluacionesGlobales || [];

        if (evaluaciones.length === 0) {
            alert('⚠️ No hay evaluaciones para exportar');
            return;
        }

        // Headers del CSV
        const headers = [
            'ID Evaluación', 'Fecha', 'Agente', 'Evaluador', 'ID Llamada',
            'Nota Final', 'Rango', 'ENC', 'ECUF', 'ECN',
            'Bloque', 'Atributo', 'Submotivo', 'Peso (%)', 'Cumple (1=Si 0=No)', 'Peso Obtenido'
        ];

        const rows = [];

        for (const evalItem of evaluaciones) {
            const fecha = evalItem.fechaOriginal || evalItem.fecha || '';
            const agente = evalItem.agente || '';
            const evaluador = evalItem.evaluador || '';
            const idLlamada = evalItem.idLlamada || '';
            const notaFinal = evalItem.notaFinal || 0;
            const rango = evalItem.rango || '';
            const enc = evalItem.totalENC || 0;
            const ecuf = evalItem.totalECUF || 0;
            const ecn = evalItem.totalECN || 0;

            // Si tiene detalles, exportar una fila por cada ítem
            if (evalItem.detalles && evalItem.detalles.length > 0) {
                for (const det of evalItem.detalles) {
                    const cumple = (det.cumple === true || det.cumple === 'true' || det.cumple === 1) ? 1 : 0;
                    const pesoObtenido = cumple === 1 ? (det.peso || 0) : 0;

                    rows.push([
                        `"${evalItem.id || ''}"`,
                        `"${fecha}"`,
                        `"${agente.replace(/"/g, '""')}"`,
                        `"${evaluador.replace(/"/g, '""')}"`,
                        `"${idLlamada.replace(/"/g, '""')}"`,
                        notaFinal,
                        `"${rango}"`,
                        enc,
                        ecuf,
                        ecn,
                        `"${(det.bloque || '').replace(/"/g, '""')}"`,
                        `"${(det.atributo || '').replace(/"/g, '""')}"`,
                        `"${(det.submotivo || '').replace(/"/g, '""')}"`,
                        det.peso || 0,
                        cumple,
                        pesoObtenido
                    ]);
                }
            } else {
                // Si no hay detalles, exportar una fila con datos básicos
                rows.push([
                    `"${evalItem.id || ''}"`,
                    `"${fecha}"`,
                    `"${agente.replace(/"/g, '""')}"`,
                    `"${evaluador.replace(/"/g, '""')}"`,
                    `"${idLlamada.replace(/"/g, '""')}"`,
                    notaFinal,
                    `"${rango}"`,
                    enc,
                    ecuf,
                    ecn,
                    'Sin detalles',
                    '',
                    '',
                    '',
                    '',
                    ''
                ]);
            }
        }

        // Crear el archivo CSV
        const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
        const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `todos_los_agentes_detalle_${new Date().toISOString().slice(0, 10)}.csv`;
        a.click();
        URL.revokeObjectURL(url);

        // Mostrar resumen
        let totalFilas = rows.length;
        let totalEvaluaciones = evaluaciones.length;
        alert(`✅ Exportación completada\n\n📊 Total evaluaciones: ${totalEvaluaciones}\n📋 Total filas de detalle: ${totalFilas}\n\nArchivo: todos_los_agentes_detalle_${new Date().toISOString().slice(0, 10)}.csv`);
    }
    // ===== FIN FUNCIÓN: exportarTodosLosAgentesCSV ==========================

    // ===== 38. INICIO FUNCIÓN: calcularCuartilIndividual ====================
    async function calcularCuartilIndividual(promedio) {
        const resultado = await obtenerCuartilPorNota(promedio);
        return resultado.cuartil;
    }
    // ===== FIN FUNCIÓN: calcularCuartilIndividual ===========================
    
    // ===== 39. INICIO FUNCIÓN: cargarHistorialEvaluaciones ==================
    function cargarHistorialEvaluaciones() {
        const tbody = document.getElementById('tablaHistorial');
        if (!tbody) return;

        const evaluaciones = window.evaluacionesGlobales || [];

        if (evaluaciones.length === 0) {
            tbody.innerHTML = '<tr><td colspan="10" style="text-align: center; padding: 50px;">No hay evaluaciones registradas</td></tr>';
            return;
        }

        evaluaciones.sort((a, b) => b.timestamp - a.timestamp);

        let html = '';
        evaluaciones.forEach((eval, index) => {
            let notaColor = '';
            if (eval.notaFinal >= 90) notaColor = 'var(--ok)';
            else if (eval.notaFinal >= 85) notaColor = 'var(--warning)';
            else notaColor = 'var(--danger)';

            html += `<tr>
                <td style="padding: 8px; text-align: center;">${index + 1}</td>
                <td style="padding: 8px;">${mostrarFechaSinT(eval.fechaOriginal || eval.fecha || '')}</td>
                <td style="padding: 8px;">${escapeHtml(eval.agente || '')}</td>
                <td style="padding: 8px;">${escapeHtml(eval.evaluador || '')}</td>
                <td style="padding: 8px;">${eval.idLlamada || ''}</td>
                <td style="padding: 8px; font-weight: bold; color: ${notaColor};">${eval.notaFinal}%</td>
                <td style="padding: 8px;"><span class="badge" style="background: ${notaColor};">${eval.rango || ''}</span></td>
                <td style="padding: 8px; text-align: center;">
                    <button onclick="verDetalleEvaluacion(${eval.id})" style="padding: 4px 8px; background: var(--accent); color: white;">👁️</button>
                    <button onclick="eliminarEvaluacion(${eval.id})" style="padding: 4px 8px; background: #fee; color: var(--danger);">🗑️</button>
                </td>
            </tr>`;
        });

        tbody.innerHTML = html;
    }
    // ===== FIN FUNCIÓN: cargarHistorialEvaluaciones =========================

    // ===== 40. INICIO FUNCIÓN: verDetalleEvaluacion =========================
    function verDetalleEvaluacion(id) {
        const evaluaciones = window.evaluacionesGlobales || [];
        const evaluacion = evaluaciones.find(e => e.id === id);

        if (!evaluacion) return;
        const pesosEval = obtenerPesosPorEvaluacion(evaluacion);

        let detalle = `📋 DETALLE DE EVALUACIÓN\n`;
        detalle += `━━━━━━━━━━━━━━━━━━━━━━━━\n`;
        detalle += `📅 Fecha: ${evaluacion.fecha}\n`;
        detalle += `👤 Agente: ${evaluacion.agente}\n`;
        detalle += `👥 Evaluador: ${evaluacion.evaluador}\n`;
        detalle += `🎫 ID Llamada: ${evaluacion.idLlamada}\n\n`;
        detalle += `📊 RESULTADOS:\n`;
        detalle += `✅ ENC: ${evaluacion.totalENC}/${pesosEval.ENC}%\n`;
        detalle += `⚠️ ECUF: ${evaluacion.totalECUF}/${pesosEval.ECUF}%\n`;
        detalle += `💰 ECN: ${evaluacion.totalECN}/${pesosEval.ECN}%\n`;
        detalle += `━━━━━━━━━━━━━━━━━━━━━━━━\n`;
        detalle += `🎯 NOTA FINAL: ${evaluacion.notaFinal}% (${evaluacion.rango})\n\n`;

        if (evaluacion.detalles && evaluacion.detalles.length > 0) {
            detalle += `📝 DETALLE POR ÍTEM:\n`;
            const noCumple = evaluacion.detalles.filter(d => !d.cumple);
            if (noCumple.length > 0) {
                detalle += `❌ NO CUMPLE:\n`;
                noCumple.forEach(d => {
                    detalle += `   • ${d.bloque} - ${d.atributo}: ${d.submotivo} (${d.peso}%)\n`;
                });
            }
        }

        alert(detalle);
    }
    // ===== FIN FUNCIÓN: verDetalleEvaluacion ================================

    // ===== 41. INICIO FUNCIÓN: filtrarHistorial =============================
    function filtrarHistorial() {
        const busqueda = document.getElementById('buscarHistorial')?.value.toLowerCase();
        const evaluaciones = window.evaluacionesGlobales || [];

        if (!busqueda) {
            historialFiltrado = [...evaluaciones].sort((a, b) => b.timestamp - a.timestamp);
        } else {
            historialFiltrado = evaluaciones.filter(e =>
                (e.agente && e.agente.toLowerCase().includes(busqueda)) ||
                (e.evaluador && e.evaluador.toLowerCase().includes(busqueda)) ||
                (e.idLlamada && e.idLlamada.toLowerCase().includes(busqueda))
            ).sort((a, b) => b.timestamp - a.timestamp);
        }

        actualizarTablaHistorialFiltrada();
    }
    // ===== FIN FUNCIÓN: filtrarHistorial ====================================

    // ===== 42. INICIO FUNCIÓN: actualizarTablaHistorialFiltrada =============
    function actualizarTablaHistorialFiltrada() {
        const tbody = document.getElementById('tablaHistorial');
        if (!tbody) return;

        if (historialFiltrado.length === 0) {
            tbody.innerHTML = '<tr><td colspan="8" style="text-align: center; padding: 50px;">No hay evaluaciones</td></tr>';
            const mostrandoCount = document.getElementById('mostrandoHistorialCount');
            if (mostrandoCount) mostrandoCount.textContent = '0';
            return;
        }

        let html = '';
        historialFiltrado.forEach((eval, index) => {
            let notaColor = '';
            if (eval.notaFinal >= 90) notaColor = 'var(--ok)';
            else if (eval.notaFinal >= 85) notaColor = 'var(--warning)';
            else notaColor = 'var(--danger)';

            html += `<tr>
                <td style="padding: 8px; text-align: center;">${index + 1}</td>                
                <td style="padding: 8px;">${eval.fechaOriginal || eval.fecha || ''}</td>
                <td style="padding: 8px;">${escapeHtml(eval.agente || '')}</td>
                <td style="padding: 8px;">${escapeHtml(eval.evaluador || '')}</td>
                <td style="padding: 8px;">${eval.idLlamada || ''}</td>
                <td style="padding: 8px; font-weight: bold; color: ${notaColor};">${eval.notaFinal}%</td>
                <td style="padding: 8px;"><span class="badge" style="background: ${notaColor};">${eval.rango || ''}</span></td>
                <td style="padding: 8px; text-align: center;">
                    <button onclick="verDetalleEvaluacion(${eval.id})" style="padding: 4px 8px; background: var(--accent); color: white;">👁️</button>
                    <button onclick="eliminarEvaluacion(${eval.id})" style="padding: 4px 8px; background: #fee; color: var(--danger);">🗑️</button>
                </td>
            </tr>`;
        });

        tbody.innerHTML = html;
        const mostrandoCount = document.getElementById('mostrandoHistorialCount');
        if (mostrandoCount) mostrandoCount.textContent = historialFiltrado.length;
        const totalCount = document.getElementById('totalHistorialCount');
        if (totalCount) totalCount.textContent = historialFiltrado.length;
    }
    // ===== FIN FUNCIÓN: actualizarTablaHistorialFiltrada ====================

    // ===== 43. INICIO FUNCIÓN: exportarDetalleCSV ===========================
    function exportarDetalleCSV() {
        const evaluaciones = window.evaluacionesGlobales || [];
        if (evaluaciones.length === 0) {
            alert('No hay datos para exportar');
            return;
        }

        const headersGenerales = [
            'ID Evaluación', 'Fecha Evaluación', 'Agente', 'Evaluador', 'ID Llamada',
            'Nota Final', 'Rango', 'ENC (30%)', 'ECUF (30%)', 'ECN (40%)',
            'Tiempo Auditoría (segundos)', 'Tiempo Auditoría (formateado)'
        ];

        const headersDetalle = [
            'Bloque', 'Atributo', 'Submotivo', 'Peso (%)', 'Cumple (1=Si 0=No)', 'Peso Obtenido (%)'
        ];

        const headersCompletos = [...headersGenerales, ...headersDetalle];
        const rows = [];

        evaluaciones.forEach(eval => {
            const totalENC = numeroSeguro(eval.totalENC);
            const totalECUF = numeroSeguro(eval.totalECUF);
            const totalECN = numeroSeguro(eval.totalECN);
            const notaFinal = numeroSeguro(eval.notaFinal);

            let fechaValida = eval.fechaOriginal || eval.fecha || new Date().toLocaleString();

            if (eval.detalles && eval.detalles.length > 0) {
                eval.detalles.forEach(detalle => {
                    const peso = numeroSeguro(detalle.peso);
                    const cumple = detalle.cumple === true || detalle.cumple === 'true' || detalle.cumple === 1 || detalle.cumple === '1';
                    const pesoObtenido = cumple ? peso : 0;

                    rows.push([
                        eval.id || '', fechaValida,
                        `"${(eval.agente || '').replace(/"/g, '""')}"`,
                        `"${(eval.evaluador || '').replace(/"/g, '""')}"`,
                        `"${(eval.idLlamada || '').replace(/"/g, '""')}"`,
                        notaFinal, `"${eval.rango || ''}"`, totalENC, totalECUF, totalECN,
                        eval.tiempoAuditoria || '', `"${eval.tiempoAuditoriaFormateado || ''}"`,
                        `"${(detalle.bloque || '').replace(/"/g, '""')}"`,
                        `"${(detalle.atributo || '').replace(/"/g, '""')}"`,
                        `"${(detalle.submotivo || '').replace(/"/g, '""')}"`,
                        peso, cumple ? '1' : '0', pesoObtenido
                    ]);
                });
            } else {
                rows.push([
                    eval.id || '', fechaValida,
                    `"${(eval.agente || '').replace(/"/g, '""')}"`,
                    `"${(eval.evaluador || '').replace(/"/g, '""')}"`,
                    `"${(eval.idLlamada || '').replace(/"/g, '""')}"`,
                    notaFinal, `"${eval.rango || ''}"`, totalENC, totalECUF, totalECN,
                    eval.tiempoAuditoria || '', `"${eval.tiempoAuditoriaFormateado || ''}"`,
                    'Sin detalles', '', '', '', '', ''
                ]);
            }
        });

        const csvContent = [headersCompletos.join(','), ...rows.map(row => row.join(','))].join('\n');
        const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `detalle_evaluaciones_${new Date().toISOString().slice(0, 10)}.csv`;
        a.click();
        URL.revokeObjectURL(url);

        alert(`✅ Exportadas ${evaluaciones.length} evaluaciones con ${rows.length} filas de detalle`);
    }
    // ===== FIN FUNCIÓN: exportarDetalleCSV ==================================

    // ===== 44. INICIO FUNCIÓN: exportarResumenCSV ===========================
    function exportarResumenCSV() {
        const evaluaciones = window.evaluacionesGlobales || [];
        if (evaluaciones.length === 0) {
            alert('No hay datos para exportar');
            return;
        }

        const agentes = {};
        evaluaciones.forEach(e => {
            if (!agentes[e.agente]) {
                agentes[e.agente] = { suma: 0, count: 0 };
            }
            agentes[e.agente].suma += parseFloat(e.notaFinal);
            agentes[e.agente].count++;
        });

        const headers = [
            'ID', 'Fecha', 'Agente', 'Evaluador', 'ID Llamada', 'Nota Final', 'Rango',
            'Cuartil del Agente', 'ENC (30%)', 'ECUF (30%)', 'ECN (40%)',
            'Tiempo Auditoría (segundos)', 'Tiempo Auditoría (formateado)',
            'Total Submotivos Evaluados', 'Submotivos OK', 'Submotivos NO OK'
        ];

        const rows = evaluaciones.map(eval => {
            const agenteData = agentes[eval.agente];
            const promedioAgente = agenteData.suma / agenteData.count;
            const cuartil = obtenerCuartil(promedioAgente);

            const totalSubmotivos = eval.detalles ? eval.detalles.length : 0;
            const submotivosOK = eval.detalles ? eval.detalles.filter(d => d.cumple).length : 0;
            const submotivosNO = totalSubmotivos - submotivosOK;

            let fechaValida = eval.fechaOriginal || eval.fecha || new Date().toLocaleDateString();

            return [
                eval.id || '', fechaValida,
                `"${eval.agente || ''}"`, `"${eval.evaluador || ''}"`, `"${eval.idLlamada || ''}"`,
                eval.notaFinal || '', `"${eval.rango || ''}"`, `"${cuartil}"`,
                eval.totalENC || '', eval.totalECUF || '', eval.totalECN || '',
                eval.tiempoAuditoria || '', `"${eval.tiempoAuditoriaFormateado || ''}"`,
                totalSubmotivos, submotivosOK, submotivosNO
            ];
        });

        const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
        const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `resumen_evaluaciones_${new Date().toISOString().slice(0, 10)}.csv`;
        a.click();
        URL.revokeObjectURL(url);

        alert(`✅ Exportado resumen de ${evaluaciones.length} evaluaciones con cuartiles`);
    }
    // ===== FIN FUNCIÓN: exportarResumenCSV ==================================

    // ===== 45. INICIO FUNCIÓN: mostrarTimeline =============================
    function mostrarTimeline(agente) {
        const evaluaciones = window.evaluacionesGlobales || [];
        const evaluacionesAgente = evaluaciones.filter(e => e.agente === agente);
        const pdaAgente = datosPDA.filter(p => p.agente === agente);

        if (evaluacionesAgente.length === 0 && pdaAgente.length === 0) {
            alert(`No hay datos de seguimiento para ${agente}`);
            return;
        }

        // Construir timeline
        let timeline = `📅 TIMELINE DE SEGUIMIENTO - ${agente}\n`;
        timeline += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;

        // Ordenar evaluaciones por fecha
        evaluacionesAgente.sort((a, b) => {
            let fechaA = a.fechaOriginal || a.fecha || '';
            let fechaB = b.fechaOriginal || b.fecha || '';
            return fechaA.localeCompare(fechaB);
        });

        // Mostrar cada evaluación
        evaluacionesAgente.forEach((eval, idx) => {
            const fecha = eval.fechaOriginal || eval.fecha || 'Fecha desconocida';
            const nota = eval.notaFinal;
            const rango = eval.rango;

            timeline += `📞 EVALUACIÓN ${idx + 1}\n`;
            timeline += `   📅 Fecha: ${fecha}\n`;
            timeline += `   📊 Nota: ${nota}% (${rango})\n`;

            // Mostrar fallas si las hay
            if (eval.detalles) {
                const fallas = eval.detalles.filter(d => !d.cumple);
                if (fallas.length > 0) {
                    timeline += `   ❌ Fallas:\n`;
                    fallas.forEach(f => {
                        timeline += `      • ${f.submotivo} (${f.bloque})\n`;
                    });
                } else {
                    timeline += `   ✅ Sin fallas\n`;
                }
            }
            timeline += `\n`;
        });

        // Mostrar PDA aplicados
        if (pdaAgente.length > 0) {
            timeline += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
            timeline += `📋 PLANES DE DESARROLLO Y ACCIÓN (PDA)\n\n`;

            pdaAgente.sort((a, b) => new Date(a.fechaAplicacion) - new Date(b.fechaAplicacion));

            pdaAgente.forEach((pda, idx) => {
                const fechaApp = pda.fechaAplicacion;
                const fechaEscucha = pda.fechaEscucha;
                const estado = pda.estado === 'corregido' ? '✅ CORREGIDO' :
                    (pda.estado === 'persiste' ? '❌ PERSISTE - ESCALAR' : '⏳ PENDIENTE');

                timeline += `📌 PDA ${idx + 1}\n`;
                timeline += `   📅 Aplicación: ${fechaApp}\n`;
                timeline += `   📅 Nueva escucha: ${fechaEscucha}\n`;
                timeline += `   🎯 Resultado: ${estado}\n`;
                timeline += `   📝 Acción: ${pda.accion}\n`;
                if (pda.responsable) {
                    timeline += `   👤 Responsable: ${pda.responsable}\n`;
                }
                timeline += `\n`;
            });
        }

        // Agregar resumen final
        timeline += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
        timeline += `📊 RESUMEN:\n`;
        timeline += `   • Total evaluaciones: ${evaluacionesAgente.length}\n`;
        timeline += `   • Total PDA aplicados: ${pdaAgente.length}\n`;
        timeline += `   • PDA pendientes: ${pdaAgente.filter(p => p.estado === 'pendiente').length}\n`;
        timeline += `   • PDA corregidos: ${pdaAgente.filter(p => p.estado === 'corregido').length}\n`;
        timeline += `   • PDA con persistencia: ${pdaAgente.filter(p => p.estado === 'persiste').length}\n`;

        if (pdaAgente.filter(p => p.estado === 'persiste').length >= 2) {
            timeline += `\n⚠️ ATENCIÓN: El agente requiere escalamiento a supervisor (2+ PDA con persistencia)\n`;
        }

        alert(timeline);
    }
    // ===== FIN FUNCIÓN: mostrarTimeline ====================================

    // ===== 46. INICIO FUNCIÓN: generarPDA ==================================
    async function generarPDA(agente) {
        console.log('🚀 generarPDA llamado para:', agente);

        if (!agente) {
            alert('⚠️ No se especificó el agente');
            return;
        }

        try {
            // 🔴 CAMBIO: Usar API en lugar de PostgreSQL directo
            const resultado = await API.generarPDA(agente);
            
            if (resultado.success) {
                alert(`✅ PDA generado para ${agente}\n\n📌 Ítems: ${resultado.cantidadItems || 0} áreas de mejora`);
                
                // Recargar datos de PDA
                await cargarDatosPDA();
                
                // Preguntar si quiere ir a gestión
                if (confirm('¿Desea ir a la pestaña de Gestión PDA para completar los detalles?')) {
                    showTab('gestionPDA', null);
                }
            } else {
                alert(`❌ Error al generar PDA: ${resultado.error || 'Error desconocido'}`);
            }

        } catch (error) {
            console.error('Error generando PDA:', error);
            alert('❌ Error al generar PDA: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: generarPDA =========================================

