    // ===== 1. INICIO FUNCIÓN: cargarProductividad ========================
    async function cargarProductividad() {
        console.log('🎯 Cargando productividad de auditores OPTIMIZADO...');

        if (!window.evaluacionesGlobales || window.evaluacionesGlobales.length === 0) {
            await obtenerEvaluacionesConCache(false);
        }

        const evaluaciones = getEvaluacionesFiltradas();

        // Crear hash del filtro actual
        const filtroHash = `${filtroActivo.inicio || ''}|${filtroActivo.fin || ''}|${evaluaciones.length}`;

        // Verificar caché
        const ahora = Date.now();
        if (cacheProductividad.datos &&
            cacheProductividad.filtroHash === filtroHash &&
            (ahora - cacheProductividad.timestamp) < CACHE_PRODUCTIVIDAD_DURACION) {
            console.log('✅ Usando caché de productividad');
            const auditoresData = cacheProductividad.datos;
            actualizarKPIsProductividad(evaluaciones, auditoresData);
            generarGraficoAuditoriasPorAuditor(auditoresData);
            generarGraficoEvolutivoAuditorias(evaluaciones, auditoresData);
            actualizarTablaProductividad(auditoresData);
            return;
        }

        console.log('🔄 Calculando productividad (no en caché)...');

        const auditoresData = calcularProductividadAuditores(evaluaciones);

        // Guardar en caché
        cacheProductividad = {
            datos: auditoresData,
            timestamp: ahora,
            filtroHash: filtroHash
        };

        actualizarKPIsProductividad(evaluaciones, auditoresData);
        generarGraficoAuditoriasPorAuditor(auditoresData);
        generarGraficoEvolutivoAuditorias(evaluaciones, auditoresData);
        actualizarTablaProductividad(auditoresData);
        actualizarGraficoErroresAuditores();
    }
    // ===== FIN FUNCIÓN: cargarProductividad ================================

    // ===== 2. INICIO FUNCIÓN: getEvaluacionesFiltradas ===================
    let chartAuditoriasPorAuditor = null;
    let chartEvolutivoAuditorias = null;
    let filtroActivo = { inicio: null, fin: null };
    function getEvaluacionesFiltradas() {
        let evaluaciones = window.evaluacionesGlobales || [];

        if (!filtroActivo.inicio || !filtroActivo.fin) {
            return evaluaciones;
        }

        // Normalizar fecha de inicio y fin a SOLO FECHA (sin hora, sin timezone)
        // Tomar la parte YYYY-MM-DD del input y crear fecha UTC
        const fechaInicioStr = filtroActivo.inicio; // "2026-04-06"
        const fechaFinStr = filtroActivo.fin;       // "2026-04-06"

        // Dividir para comparación como strings YYYYMMDD
        const inicioComparable = fechaInicioStr.replace(/-/g, ''); // "20260406"
        const finComparable = fechaFinStr.replace(/-/g, '');       // "20260406"

        console.log('📅 Filtro - Inicio:', inicioComparable, 'Fin:', finComparable);

        const evaluacionesFiltradas = evaluaciones.filter(eval => {
            // Obtener fecha de la evaluación
            let fechaStr = eval.fechaOriginal || eval.fecha || '';
            if (!fechaStr || fechaStr === 'Sin fecha') return false;

            // Convertir fecha de evaluación a formato YYYYMMDD para comparar
            let fechaEvalComparable = null;

            // Caso 1: "23/03/2026 14:49" o "23/03/2026"
            if (fechaStr.includes('/')) {
                const partesFecha = fechaStr.split(' ')[0].split('/');
                if (partesFecha.length === 3) {
                    // partesFecha = [dia, mes, anio]
                    fechaEvalComparable = `${partesFecha[2]}${partesFecha[1]}${partesFecha[0]}`;
                    // "20260323"
                }
            }

            // Caso 2: "2026-03-23T14:49:00" (ISO)
            if (!fechaEvalComparable && fechaStr.includes('T')) {
                const [fechaParte] = fechaStr.split('T');
                fechaEvalComparable = fechaParte.replace(/-/g, '');
            }

            // Caso 3: "2026-03-23 14:49:00"
            if (!fechaEvalComparable && fechaStr.includes('-') && fechaStr.includes(':')) {
                const [fechaParte] = fechaStr.split(' ');
                fechaEvalComparable = fechaParte.replace(/-/g, '');
            }

            if (!fechaEvalComparable) {
                console.warn('⚠️ Fecha no parseable:', fechaStr);
                return false;
            }

            // Comparar como números
            const fechaNum = parseInt(fechaEvalComparable, 10);
            const inicioNum = parseInt(inicioComparable, 10);
            const finNum = parseInt(finComparable, 10);

            return fechaNum >= inicioNum && fechaNum <= finNum;
        });

        console.log(`✅ Filtradas: ${evaluacionesFiltradas.length} de ${evaluaciones.length} evaluaciones`);
        console.log('📅 Ejemplo fecha evaluación:', evaluaciones[0]?.fechaOriginal, '→',
            evaluacionesFiltradas.length > 0 ? 'INCLUIDA' : 'No aplica');

        return evaluacionesFiltradas;
    }
    // ===== FIN FUNCIÓN: getEvaluacionesFiltradas ===========================

    // ===== 3. INICIO FUNCIÓN: extraerFechaDDMMYYYY =======================
    function extraerFechaDDMMYYYY(fechaStr) {
        if (!fechaStr || fechaStr === 'Sin fecha') return null;

        // Si ya está en formato DD/MM/YYYY
        if (fechaStr.match(/^\d{2}\/\d{2}\/\d{4}$/)) {
            return fechaStr;
        }

        // Si tiene hora: "DD/MM/YYYY HH:MM"
        if (fechaStr.includes(' ') && fechaStr.includes('/')) {
            return fechaStr.split(' ')[0];
        }

        // Si es ISO: "2026-03-23T14:49:00"
        if (fechaStr.includes('T')) {
            const [fechaParte] = fechaStr.split('T');
            const [anio, mes, dia] = fechaParte.split('-');
            return `${dia}/${mes}/${anio}`;
        }

        // Si es ISO sin T: "2026-03-23 14:49:00"
        if (fechaStr.includes('-') && fechaStr.includes(':')) {
            const [fechaParte] = fechaStr.split(' ');
            const [anio, mes, dia] = fechaParte.split('-');
            return `${dia}/${mes}/${anio}`;
        }

        return null;
    }
    // ===== FIN FUNCIÓN: extraerFechaDDMMYYYY ===============================

    // ===== 4. INICIO FUNCIÓN: calcularProductividadAuditores =============
    function calcularProductividadAuditores(evaluaciones) {
        const auditores = {};

        evaluaciones.forEach(eval => {
            const auditor = eval.evaluador || 'Desconocido';
            const fechaStr = eval.fechaOriginal || eval.fecha || '';
            const fechaSolo = fechaStr.split(' ')[0];

            if (!auditores[auditor]) {
                auditores[auditor] = {
                    nombre: auditor,
                    total: 0,
                    fechas: new Set(),
                    ultimaFecha: '',
                    evaluaciones: []
                };
            }

            auditores[auditor].total++;
            if (fechaSolo) {
                auditores[auditor].fechas.add(fechaSolo);
            }

            if (fechaStr > auditores[auditor].ultimaFecha) {
                auditores[auditor].ultimaFecha = fechaStr;
            }

            auditores[auditor].evaluaciones.push({
                fecha: fechaStr,
                nota: eval.notaFinal
            });
        });

        // Calcular promedios y rendimiento
        const resultados = Object.values(auditores).map(auditor => {
            const diasTrabajados = auditor.fechas.size;
            const promedioDiario = diasTrabajados > 0 ? (auditor.total / diasTrabajados).toFixed(1) : 0;

            let rendimiento = '';
            let rendimientoColor = '';
            if (promedioDiario >= 15) {
                rendimiento = '✅ Excelente';
                rendimientoColor = '#28a745';
            } else if (promedioDiario >= 10) {
                rendimiento = '🟡 Bueno';
                rendimientoColor = '#f39c12';
            } else if (promedioDiario >= 5) {
                rendimiento = '⚠️ Regular';
                rendimientoColor = '#fd7e14';
            } else {
                rendimiento = '🔴 Bajo';
                rendimientoColor = '#d93025';
            }

            // Calcular tendencia (comparar últimos 7 días vs anteriores)
            let tendencia = '➡️ Estable';
            let tendenciaColor = '#6c757d';

            const ahora = new Date();
            const hace7Dias = new Date();
            hace7Dias.setDate(ahora.getDate() - 7);

            const evaluacionesRecientes = auditor.evaluaciones.filter(e => {
                const fechaEval = parseFechaDDMMYYYY(e.fecha);
                return fechaEval && fechaEval >= hace7Dias;
            }).length;

            const evaluacionesAnteriores = auditor.evaluaciones.filter(e => {
                const fechaEval = parseFechaDDMMYYYY(e.fecha);
                return fechaEval && fechaEval < hace7Dias;
            }).length;

            const promedioReciente = evaluacionesRecientes / 7;
            const promedioAnterior = evaluacionesAnteriores / Math.max(7, Object.keys(auditor.evaluaciones).length / 7);

            if (promedioReciente > promedioAnterior * 1.2) {
                tendencia = '📈 ↑ Creciente';
                tendenciaColor = '#28a745';
            } else if (promedioReciente < promedioAnterior * 0.8) {
                tendencia = '📉 ↓ Decreciente';
                tendenciaColor = '#d93025';
            }

            return {
                ...auditor,
                diasTrabajados,
                promedioDiario: parseFloat(promedioDiario),
                rendimiento,
                rendimientoColor,
                tendencia,
                tendenciaColor
            };
        });

        // Ordenar por total de evaluaciones (mayor a menor)
        return resultados.sort((a, b) => b.total - a.total);
    }
    // ===== FIN FUNCIÓN: calcularProductividadAuditores =====================

    // ===== 5. INICIO FUNCIÓN: actualizarKPIsProductividad ================
    function actualizarKPIsProductividad(evaluaciones, auditoresData) {
        const totalAuditorias = evaluaciones.length;
        const auditoresActivos = auditoresData.length;
        const promedioGeneral = auditoresData.reduce((sum, a) => sum + a.promedioDiario, 0) / (auditoresActivos || 1);

        const totalElem = document.getElementById('totalAuditoriasPeriodo');
        const auditoresElem = document.getElementById('totalAuditoresActivos');
        const promedioElem = document.getElementById('promedioAuditoriasDia');

        if (totalElem) totalElem.textContent = totalAuditorias;
        if (auditoresElem) auditoresElem.textContent = auditoresActivos;
        if (promedioElem) promedioElem.textContent = promedioGeneral.toFixed(1);
    }
    // ===== FIN FUNCIÓN: actualizarKPIsProductividad ========================

    // ===== 6. INICIO FUNCIÓN: generarGraficoAuditoriasPorAuditor =========
    function generarGraficoAuditoriasPorAuditor(auditoresData) {
        const canvas = document.getElementById('chartAuditoriasPorAuditor');
        if (!canvas) return;

        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Top 10 auditores
        const topAuditores = auditoresData.slice(0, 10);
        const labels = topAuditores.map(a => a.nombre.length > 20 ? a.nombre.substring(0, 17) + '...' : a.nombre);
        const dataTotal = topAuditores.map(a => a.total);
        const dataPromedio = topAuditores.map(a => a.promedioDiario);

        if (chartAuditoriasPorAuditor) {
            chartAuditoriasPorAuditor.destroy();
        }

        chartAuditoriasPorAuditor = new Chart(ctx, {
            type: 'bar',
            data: {
                labels: labels,
                datasets: [
                    {
                        label: '📊 Total Auditorías',
                        data: dataTotal,
                        backgroundColor: 'rgba(1, 157, 244, 0.8)',
                        borderColor: '#019DF4',
                        borderWidth: 1,
                        borderRadius: 6,
                        yAxisID: 'y-total'
                    },
                    {
                        label: '⭐ Promedio por Día',
                        data: dataPromedio,
                        type: 'line',
                        backgroundColor: 'rgba(217, 48, 37, 0.1)',
                        borderColor: '#d93025',
                        borderWidth: 2,
                        tension: 0.3,
                        fill: false,
                        pointBackgroundColor: '#d93025',
                        pointBorderColor: '#fff',
                        pointRadius: 4,
                        pointHoverRadius: 6,
                        yAxisID: 'y-promedio'
                    }
                ]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    tooltip: {
                        callbacks: {
                            label: function (context) {
                                if (context.dataset.label === '📊 Total Auditorías') {
                                    return `📊 Total: ${context.raw} auditorías`;
                                }
                                return `⭐ Promedio: ${context.raw} aud/día`;
                            }
                        }
                    },
                    datalabels: {
                        anchor: function (context) {
                            return context.datasetIndex === 0 ? 'end' : 'end';
                        },
                        align: function (context) {
                            return context.datasetIndex === 0 ? 'top' : 'top';
                        },
                        offset: -5,
                        formatter: function (value, context) {
                            if (context.datasetIndex === 0 && value > 0) return value;
                            if (context.datasetIndex === 1 && value > 0) return value.toFixed(1);
                            return '';
                        },
                        backgroundColor: function (context) {
                            return context.datasetIndex === 0 ? '#019DF4' : '#d93025';
                        },
                        borderRadius: 4,
                        padding: { left: 4, right: 4, top: 2, bottom: 2 },
                        color: 'white',
                        font: { size: 9, weight: 'bold' }
                    }
                },
                scales: {
                    'y-total': {
                        type: 'linear',
                        position: 'left',
                        title: { display: true, text: 'Total Auditorías', color: '#019DF4' },
                        grid: { display: false },
                        beginAtZero: true
                    },
                    'y-promedio': {
                        type: 'linear',
                        position: 'right',
                        title: { display: true, text: 'Promedio por Día', color: '#d93025' },
                        grid: { drawOnChartArea: false },
                        beginAtZero: true,
                        max: 30,
                        ticks: { callback: (v) => v + '/día' }
                    },
                    x: {
                        title: { display: true, text: 'Auditor' },
                        ticks: { maxRotation: 45, minRotation: 45 }
                    }
                }
            }
        });
    }
    // ===== FIN FUNCIÓN: generarGraficoAuditoriasPorAuditor =================

    // ===== 7. INICIO FUNCIÓN: generarGraficoEvolutivoAuditorias ==========
    function generarGraficoEvolutivoAuditorias(evaluaciones, auditoresData) {
        const canvas = document.getElementById('chartEvolutivoAuditorias');
        if (!canvas) return;

        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Agrupar por fecha
        const agrupadoPorFecha = {};
        const auditoresNombres = auditoresData.slice(0, 5).map(a => a.nombre);

        evaluaciones.forEach(eval => {
            const fechaFormateada = formatearFechaDiaMes(eval.fechaOriginal || eval.fecha || '');
            if (!fechaFormateada) return;

            if (!agrupadoPorFecha[fechaFormateada]) {
                agrupadoPorFecha[fechaFormateada] = { fecha: fechaFormateada, total: 0 };
                auditoresNombres.forEach(nombre => {
                    agrupadoPorFecha[fechaFormateada][nombre] = 0;
                });
            }

            const auditor = eval.evaluador || 'Desconocido';
            agrupadoPorFecha[fechaFormateada].total++;
            if (auditoresNombres.includes(auditor)) {
                agrupadoPorFecha[fechaFormateada][auditor]++;
            }
        });

        const fechasArray = Object.values(agrupadoPorFecha);
        fechasArray.sort((a, b) => {
            const [diaA, mesA] = a.fecha.split('/');
            const [diaB, mesB] = b.fecha.split('/');
            return new Date(2024, parseInt(mesA) - 1, parseInt(diaA)) - new Date(2024, parseInt(mesB) - 1, parseInt(diaB));
        });

        const labels = fechasArray.map(item => item.fecha);
        const dataTotal = fechasArray.map(item => item.total);

        // Colores para auditores
        const colores = ['#019DF4', '#7b1fa2', '#fd7e14', '#28a745', '#d93025'];
        const datasetsAuditores = auditoresNombres.map((nombre, idx) => ({
            label: nombre.length > 15 ? nombre.substring(0, 12) + '...' : nombre,
            data: fechasArray.map(item => item[nombre] || 0),
            backgroundColor: colores[idx % colores.length] + '80',
            borderColor: colores[idx % colores.length],
            borderWidth: 1,
            borderRadius: 4,
            barPercentage: 0.7,
            categoryPercentage: 0.8,
            type: 'bar',
            stack: 'auditores'
        }));

        if (chartEvolutivoAuditorias) {
            chartEvolutivoAuditorias.destroy();
        }

        chartEvolutivoAuditorias = new Chart(ctx, {
            type: 'bar',
            data: {
                labels: labels,
                datasets: [
                    {
                        label: '📊 Total Diario',
                        data: dataTotal,
                        type: 'line',
                        borderColor: '#d93025',
                        backgroundColor: 'rgba(217, 48, 37, 0.1)',
                        borderWidth: 3,
                        tension: 0.3,
                        fill: true,
                        pointBackgroundColor: '#d93025',
                        pointBorderColor: '#fff',
                        pointRadius: 5,
                        pointHoverRadius: 7,
                        yAxisID: 'y-total'
                    },
                    ...datasetsAuditores
                ]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                interaction: { mode: 'index', intersect: false },
                plugins: {
                    tooltip: {
                        callbacks: {
                            label: function (context) {
                                if (context.dataset.label === '📊 Total Diario') {
                                    return `📊 Total: ${context.raw} auditorías`;
                                }
                                return `${context.dataset.label}: ${context.raw} audiciones`;
                            }
                        }
                    },
                    legend: {
                        position: 'bottom',
                        labels: { font: { size: 10 }, usePointStyle: true }
                    }
                },
                scales: {
                    'y-total': {
                        type: 'linear',
                        position: 'left',
                        title: { display: true, text: 'Total Auditorías por Día' },
                        grid: { display: false },
                        beginAtZero: true,
                        ticks: { stepSize: 1 }
                    },
                    y: {
                        title: { display: true, text: 'Auditorías por Auditor' },
                        grid: { display: false },
                        beginAtZero: true,
                        stacked: true
                    },
                    x: {
                        title: { display: true, text: 'Fecha (Día/Mes)' },
                        ticks: { maxRotation: 45, minRotation: 45, autoSkip: true, maxTicksLimit: 12 }
                    }
                }
            }
        });
    }
    // ===== FIN FUNCIÓN: generarGraficoEvolutivoAuditorias ==================

    // ===== 8. INICIO FUNCIÓN: actualizarTablaProductividad ===============
    function actualizarTablaProductividad(auditoresData) {
        const tbody = document.getElementById('tablaProductividadAuditores');
        if (!tbody) return;

        if (auditoresData.length === 0) {
            tbody.innerHTML = '<tr><td colspan="8" style="text-align: center;">No hay datos de auditores</td></tr>';
            return;
        }

        let html = '';
        auditoresData.forEach((auditor, idx) => {
            html += `
                <tr>
                    <td style="padding: 8px;">${idx + 1}</td>
                    <td style="padding: 8px;"><strong>${escapeHtml(auditor.nombre)}</strong></td>
                    <td style="padding: 8px; font-weight: bold; color: #019DF4;">${auditor.total}</td>
                    <td style="padding: 8px;">${auditor.diasTrabajados}</td>
                    <td style="padding: 8px; font-weight: bold; color: ${auditor.rendimientoColor};">${auditor.promedioDiario}/día</td>
                    <td style="padding: 8px;"><span style="color: ${auditor.rendimientoColor};">${auditor.rendimiento}</span></td>
                    <td style="padding: 8px;">${mostrarFechaSinT(auditor.ultimaFecha) || '-'}</td>
                    <td style="padding: 8px; color: ${auditor.tendenciaColor};">${auditor.tendencia}</td>
                </tr>
            `;
        });

        tbody.innerHTML = html;
    }
    // ===== FIN FUNCIÓN: actualizarTablaProductividad =======================

    // ===== 9. INICIO FUNCIÓN: aplicarFiltroProductividad =================
    function aplicarFiltroProductividad() {
        const fechaInicio = document.getElementById('filtroFechaInicio').value;
        const fechaFin = document.getElementById('filtroFechaFin').value;

        if (fechaInicio && fechaFin) {
            // Validar que inicio <= fin
            if (fechaInicio > fechaFin) {
                alert('⚠️ La fecha de inicio no puede ser mayor a la fecha fin');
                return;
            }

            // Guardar las fechas como strings YYYY-MM-DD (sin convertir a Date)
            filtroActivo = { inicio: fechaInicio, fin: fechaFin };
            console.log('✅ Filtro aplicado:', filtroActivo);
        } else if (fechaInicio || fechaFin) {
            alert('⚠️ Debe seleccionar ambas fechas (inicio y fin) para filtrar');
            return;
        } else {
            filtroActivo = { inicio: null, fin: null };
            console.log('🔄 Filtro reseteados');
        }

        // Limpiar gráficos anteriores
        if (chartAuditoriasPorAuditor) {
            chartAuditoriasPorAuditor.destroy();
            chartAuditoriasPorAuditor = null;
        }
        if (chartEvolutivoAuditorias) {
            chartEvolutivoAuditorias.destroy();
            chartEvolutivoAuditorias = null;
        }

        cargarProductividad();
    }
    // ===== FIN FUNCIÓN: aplicarFiltroProductividad =========================

    // ===== 10. INICIO FUNCIÓN: resetearFiltroProductividad ================
    function resetearFiltroProductividad() {
        document.getElementById('filtroFechaInicio').value = '';
        document.getElementById('filtroFechaFin').value = '';
        filtroActivo = { inicio: null, fin: null };
        cargarProductividad();
    }
    // ===== FIN FUNCIÓN: resetearFiltroProductividad ========================

    // ===== 11. INICIO FUNCIÓN: exportarProductividadCSV ===================
    function exportarProductividadCSV() {
        const evaluaciones = getEvaluacionesFiltradas();
        const auditoresData = calcularProductividadAuditores(evaluaciones);

        if (auditoresData.length === 0) {
            alert('No hay datos para exportar');
            return;
        }

        const headers = ['Auditor', 'Total Evaluaciones', 'Días Trabajados', 'Promedio/Día', 'Rendimiento', 'Última Evaluación', 'Tendencia'];
        const rows = auditoresData.map(a => [
            `"${a.nombre}"`,
            a.total,
            a.diasTrabajados,
            a.promedioDiario,
            a.rendimiento,
            a.ultimaFecha,
            a.tendencia
        ]);

        const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
        const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `productividad_auditores_${new Date().toISOString().slice(0, 10)}.csv`;
        a.click();
        URL.revokeObjectURL(url);

        alert(`✅ Exportados ${auditoresData.length} auditores`);
    }
    // ===== FIN FUNCIÓN: exportarProductividadCSV ===========================

    // ===== 12. INICIO FUNCIÓN: cargarSelectAuditoresHistorial =============
    function cargarSelectAuditoresHistorial() {
        const evaluaciones = window.evaluacionesGlobales || [];
        const auditoresSet = new Set();

        evaluaciones.forEach(eval => {
            if (eval.evaluador) auditoresSet.add(eval.evaluador);
        });

        const auditores = Array.from(auditoresSet).sort();
        const select = document.getElementById('selectAuditorHistorial');

        if (!select) return;

        select.innerHTML = '<option value="">-- Seleccionar auditor --</option>';

        // Calcular estadísticas para ordenar por productividad
        const productividadAuditores = calcularProductividadAuditores(evaluaciones);
        const productividadMap = {};
        productividadAuditores.forEach(a => {
            productividadMap[a.nombre] = a.promedioDiario;
        });

        // Ordenar por productividad (mayor a menor)
        auditores.sort((a, b) => {
            const prodA = productividadMap[a] || 0;
            const prodB = productividadMap[b] || 0;
            return prodB - prodA;
        });

        auditores.forEach(auditor => {
            const promedio = productividadMap[auditor] || 0;
            let icono = '🎧 ';
            let estilo = '';
            if (promedio >= 15) {
                icono = '✅ ';
                estilo = 'style="color: var(--ok);"';
            } else if (promedio >= 10) {
                icono = '🟡 ';
                estilo = 'style="color: var(--warning);"';
            } else if (promedio >= 5) {
                icono = '⚠️ ';
                estilo = 'style="color: var(--danger);"';
            } else {
                icono = '🔴 ';
                estilo = 'style="color: var(--danger);"';
            }
            select.innerHTML += `<option value="${escapeHtml(auditor)}" ${estilo}>${icono}${escapeHtml(auditor)} (${promedio}/día)</option>`;
        });

        console.log(`✅ ${auditores.length} auditores cargados en el select`);
    }
    // ===== FIN FUNCIÓN: cargarSelectAuditoresHistorial =====================

    // ===== 13. INICIO FUNCIÓN: cargarHistorialAuditor =====================
    function cargarHistorialAuditor() {
        const select = document.getElementById('selectAuditorHistorial');
        const auditor = select?.value;

        if (!auditor) {
            alert('⚠️ Seleccione un auditor');
            return;
        }

        const evaluaciones = window.evaluacionesGlobales || [];
        const evaluacionesAuditor = evaluaciones.filter(e => e.evaluador === auditor);

        if (evaluacionesAuditor.length === 0) {
            alert(`⚠️ No hay evaluaciones realizadas por el auditor ${auditor}`);
            return;
        }

        // Ordenar por fecha (más reciente primero)
        evaluacionesAuditor.sort((a, b) => {
            const fechaA = a.fechaOriginal || a.fecha || '';
            const fechaB = b.fechaOriginal || b.fecha || '';
            return fechaB.localeCompare(fechaA);
        });

        // Mostrar resumen
        mostrarResumenAuditor(auditor, evaluacionesAuditor);

        // Mostrar tabla de evaluaciones
        mostrarTablaEvaluacionesAuditor(auditor, evaluacionesAuditor);

        // Mostrar botón de exportar
        document.getElementById('btnExportarHistorialAuditor').style.display = 'inline-flex';
    }
    // ===== FIN FUNCIÓN: cargarHistorialAuditor =============================

    // ===== 14. INICIO FUNCIÓN: mostrarResumenAuditor ======================
    function mostrarResumenAuditor(auditor, evaluaciones) {
        const total = evaluaciones.length;
        const sumaNotas = evaluaciones.reduce((sum, e) => sum + numeroSeguro(e.notaFinal), 0);
        const promedio = (sumaNotas / total).toFixed(1);

        // Calcular días trabajados
        const fechasUnicas = new Set();
        evaluaciones.forEach(e => {
            let fechaStr = e.fechaOriginal || e.fecha || '';
            let fechaSolo = fechaStr.split(' ')[0];
            if (fechaSolo) fechasUnicas.add(fechaSolo);
        });
        const diasTrabajados = fechasUnicas.size;
        const promedioDia = diasTrabajados > 0 ? (total / diasTrabajados).toFixed(1) : 0;

        document.getElementById('resumenAuditorTotalEval').textContent = total;
        document.getElementById('resumenAuditorPromedio').textContent = promedio + '%';
        document.getElementById('resumenAuditorDias').textContent = diasTrabajados;
        document.getElementById('resumenAuditorPromedioDia').textContent = promedioDia + '/día';

        document.getElementById('resumenAuditor').style.display = 'block';
    }
    // ===== FIN FUNCIÓN: mostrarResumenAuditor ==============================

    // ===== 15. INICIO FUNCIÓN: mostrarTablaEvaluacionesAuditor ============
    function mostrarTablaEvaluacionesAuditor(auditor, evaluaciones) {
        const tbody = document.getElementById('tablaHistorialAuditor');
        if (!tbody) return;

        let html = '';

        evaluaciones.forEach((eval, index) => {
            const fecha = eval.fechaOriginal || eval.fecha || 'Sin fecha';
            const nota = numeroSeguro(eval.notaFinal);
            const rango = eval.rango || obtenerRango(nota).nombre;

            let notaColor = '';
            if (nota >= 90) notaColor = 'var(--ok)';
            else if (nota >= 85) notaColor = 'var(--warning)';
            else notaColor = 'var(--danger)';



            const rowId = `auditor-eval-${eval.id || index}`;

            // Fila principal (expandible)
            html += `
                <tr class="expandable-row" onclick="toggleDetalleEvaluacionAuditor('${rowId}')" style="cursor: pointer;">
                    <td style="text-align: center;">
                        <span class="expand-icon" id="icon-${rowId}">▶</span>
                    </td>
                    <td style="padding: 8px;">${escapeHtml(fecha)}</td>
                    <td style="padding: 8px;"><strong>${escapeHtml(eval.agente || '-')}</strong></td>
                    <td style="padding: 8px;">${escapeHtml(eval.idLlamada || '-')}</td>
                    <td style="padding: 8px; font-weight: bold; color: ${notaColor};">${nota}%</td>
                    <td style="padding: 8px;"><span class="badge" style="background: ${notaColor};">${rango}</span></td>
                    <td style="padding: 8px;">${numeroSeguro(eval.totalENC)}/${obtenerPesosActuales().ENC}</td>
                    <td style="padding: 8px;">${numeroSeguro(eval.totalECUF)}/${obtenerPesosActuales().ECUF}</td>
                    <td style="padding: 8px;">${numeroSeguro(eval.totalECN)}/${obtenerPesosActuales().ECN}</td>
                </tr>
                <tr id="${rowId}" class="detail-row" style="display: none;">
                    <td colspan="9">
                        <div class="detail-content">
                            <strong>📋 Detalle de ítems evaluados:</strong>
                            <div class="detail-items" id="items-${rowId}">
                                ${generarDetalleItemsHTML(eval.detalles || [])}
                            </div>
                        </div>
                    </td>
                </tr>
            `;
        });

        tbody.innerHTML = html;
        document.getElementById('historialAuditorContainer').style.display = 'block';
    }
    // ===== FIN FUNCIÓN: mostrarTablaEvaluacionesAuditor ====================

    // ===== 16. INICIO FUNCIÓN: toggleDetalleEvaluacionAuditor =============
    function toggleDetalleEvaluacionAuditor(rowId) {
        const detailRow = document.getElementById(rowId);
        const icon = document.getElementById(`icon-${rowId}`);

        if (detailRow.style.display === 'none') {
            detailRow.style.display = 'table-row';
            if (icon) {
                icon.innerHTML = '▼';
                icon.classList.add('expanded');
            }
        } else {
            detailRow.style.display = 'none';
            if (icon) {
                icon.innerHTML = '▶';
                icon.classList.remove('expanded');
            }
        }
    }
    // ===== FIN FUNCIÓN: toggleDetalleEvaluacionAuditor =====================

    // ===== 17. INICIO FUNCIÓN: exportarHistorialAuditorCSV ================
    function exportarHistorialAuditorCSV() {
        const select = document.getElementById('selectAuditorHistorial');
        const auditor = select?.value;

        if (!auditor) {
            alert('⚠️ Seleccione un auditor primero');
            return;
        }

        const evaluaciones = window.evaluacionesGlobales || [];
        const evaluacionesAuditor = evaluaciones.filter(e => e.evaluador === auditor);

        if (evaluacionesAuditor.length === 0) {
            alert(`No hay evaluaciones realizadas por ${auditor}`);
            return;
        }

        // Headers para el CSV
        const headers = [
            'Fecha', 'Agente Evaluado', 'ID Llamada', 'Nota Final', 'Rango', 'ENC', 'ECUF', 'ECN',
            'Bloque', 'Atributo', 'Submotivo', 'Peso (%)', 'Cumple'
        ];

        const rows = [];

        evaluacionesAuditor.forEach(eval => {
            const fecha = eval.fechaOriginal || eval.fecha || '';
            const agente = eval.agente || '';
            const idLlamada = eval.idLlamada || '';
            const nota = eval.notaFinal || 0;
            const rango = eval.rango || '';
            const enc = eval.totalENC || 0;
            const ecuf = eval.totalECUF || 0;
            const ecn = eval.totalECN || 0;

            if (eval.detalles && eval.detalles.length > 0) {
                eval.detalles.forEach(det => {
                    rows.push([
                        `"${fecha}"`,
                        `"${agente}"`,
                        `"${idLlamada}"`,
                        nota,
                        `"${rango}"`,
                        enc,
                        ecuf,
                        ecn,
                        `"${det.bloque || ''}"`,
                        `"${det.atributo || ''}"`,
                        `"${det.submotivo || ''}"`,
                        det.peso || 0,
                        det.cumple ? 'SI' : 'NO'
                    ]);
                });
            } else {
                rows.push([
                    `"${fecha}"`,
                    `"${agente}"`,
                    `"${idLlamada}"`,
                    nota,
                    `"${rango}"`,
                    enc,
                    ecuf,
                    ecn,
                    'Sin detalles',
                    '',
                    '',
                    '',
                    ''
                ]);
            }
        });

        const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
        const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `historial_auditor_${auditor.replace(/\s/g, '_')}_${new Date().toISOString().slice(0, 10)}.csv`;
        a.click();
        URL.revokeObjectURL(url);

        alert(`✅ Exportado historial del auditor ${auditor} (${evaluacionesAuditor.length} evaluaciones, ${rows.length} filas de detalle)`);
    }
    // ===== FIN FUNCIÓN: exportarHistorialAuditorCSV ========================
    
    // ===== 18. INICIO FUNCIÓN: actualizarGraficoErroresAuditores ==========
    let chartErroresAuditores = null;
    let datosErroresCache = null;  // ← Caché de datos
    let ultimaActualizacionCache = null;
    
    async function actualizarGraficoErroresAuditores() {
        console.log('📊 actualizarGraficoErroresAuditores - Iniciando...');

        // Obtener filtros actuales
        const periodoDias = document.getElementById('filtroPeriodoErrores')?.value || '30';
        const auditorSeleccionado = document.getElementById('filtroAuditorErrores')?.value || 'todos';

        console.log(`📊 Filtros: periodo=${periodoDias}, auditor=${auditorSeleccionado}`);

        try {
            const resultado = await API.getErroresAuditores(periodoDias, auditorSeleccionado);
            
            if (!resultado || !resultado.erroresPorAuditorPorFecha || Object.keys(resultado.erroresPorAuditorPorFecha).length === 0) {
                mostrarMensajeSinDatosErrores();
                return;
            }

            // Actualizar el selector de auditores con los auditores disponibles
            const selectAuditor = document.getElementById('filtroAuditorErrores');
            if (selectAuditor && resultado.auditores && resultado.auditores.length > 0) {
                const valorActual = selectAuditor.value;
                selectAuditor.innerHTML = '<option value="todos">📊 Todos los auditores</option>';
                resultado.auditores.forEach(auditor => {
                    selectAuditor.innerHTML += `<option value="${escapeHtml(auditor)}" ${valorActual === auditor ? 'selected' : ''}>${escapeHtml(auditor)}</option>`;
                });
            }

            // Renderizar gráfico con los datos
            renderizarGraficoErroresConDatos(
                resultado.erroresPorAuditorPorFecha,
                resultado.fechasOrdenadas,
                resultado.auditores,
                periodoDias,
                auditorSeleccionado
            );
            
            // Actualizar tabla de ranking de errores
            actualizarTablaRankingErrores(resultado.erroresPorAuditorPorFecha, resultado.fechasOrdenadas,resultado.detallesPorAuditorPorFecha);

        } catch (error) {
            console.error('Error en actualizarGraficoErroresAuditores:', error);
            mostrarMensajeSinDatosErrores();
        }
    }
    // ===== FIN FUNCIÓN: actualizarGraficoErroresAuditores ==================

    function renderizarGraficoErroresConDatos(erroresPorAuditorPorFecha, fechasOrdenadas, auditores, periodoDias, auditorSeleccionado) {
        console.log('📊 renderizarGraficoErroresConDatos - INICIO');
        
        // Filtrar fechas por período
        let fechasFiltradas = [...fechasOrdenadas];
        if (periodoDias !== 'all') {
            const dias = parseInt(periodoDias);
            const hoy = new Date();
            fechasFiltradas = fechasOrdenadas.filter(fecha => {
                const [dia, mes, anio] = fecha.split('/');
                const fechaObj = new Date(anio, mes - 1, dia);
                const diffDias = Math.floor((hoy - fechaObj) / (1000 * 60 * 60 * 24));
                return diffDias <= dias;
            });
        }

        if (fechasFiltradas.length === 0) {
            mostrarMensajeSinDatosErrores();
            return;
        }

        // Formatear etiquetas
        const labels = fechasFiltradas.map(f => {
            const partes = f.split('/');
            return `${partes[0]}/${partes[1]}`;
        });

        // Construir datasets
        const coloresAuditores = [
            '#d93025', '#f39c12', '#019DF4', '#28a745', '#7b1fa2',
            '#17a2b8', '#fd7e14', '#6f42c1', '#e83e8c', '#20c997'
        ];

        let datasets = [];
        let auditoresMostrar = auditorSeleccionado === 'todos' ? auditores : [auditorSeleccionado];

        for (let i = 0; i < auditoresMostrar.length; i++) {
            const auditor = auditoresMostrar[i];
            const data = fechasFiltradas.map(fecha => erroresPorAuditorPorFecha[auditor]?.[fecha] || 0);

            if (data.some(v => v > 0)) {
                datasets.push({
                    label: auditor,
                    data: data,
                    borderColor: coloresAuditores[i % coloresAuditores.length],
                    backgroundColor: 'transparent',
                    borderWidth: 2,
                    tension: 0.3,
                    fill: false,
                    pointBackgroundColor: coloresAuditores[i % coloresAuditores.length],
                    pointBorderColor: '#fff',
                    pointRadius: 4,
                    pointHoverRadius: 6,
                    pointBorderWidth: 1
                });
            }
        }

        // Calcular promedio del equipo
        const promedioData = fechasFiltradas.map(fecha => {
            let suma = 0;
            let count = 0;
            for (const auditor of auditores) {
                const valor = erroresPorAuditorPorFecha[auditor]?.[fecha] || 0;
                if (valor > 0) {
                    suma += valor;
                    count++;
                }
            }
            return count > 0 ? Math.round((suma / count) * 10) / 10 : 0;
        });

        datasets.push({
            label: '📊 Promedio equipo',
            data: promedioData,
            borderColor: '#6c757d',
            backgroundColor: 'transparent',
            borderWidth: 2,
            borderDash: [5, 5],
            tension: 0.3,
            fill: false,
            pointRadius: 0,
            pointHoverRadius: 0
        });

        // Destruir gráfico existente
        if (window.chartErroresAuditores) {
            window.chartErroresAuditores.destroy();
            window.chartErroresAuditores = null;
        }

        const canvas = document.getElementById('chartEvolutivoErroresAuditores');
        if (!canvas) {
            console.error('❌ Canvas chartEvolutivoErroresAuditores no encontrado');
            return;
        }

        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        canvas.width = canvas.clientWidth;
        canvas.height = canvas.clientHeight;
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        window.chartErroresAuditores = new Chart(ctx, {
            type: 'line',
            data: { labels: labels, datasets: datasets },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                interaction: { mode: 'index', intersect: false },
                plugins: {
                    tooltip: {
                        callbacks: {
                            label: function(context) {
                                let label = context.dataset.label || '';
                                let value = context.raw;
                                if (label === '📊 Promedio equipo') {
                                    return `📊 Promedio: ${value} errores/día`;
                                }
                                return `${label}: ${value} errores`;
                            }
                        }
                    },
                    legend: {
                        position: 'bottom',
                        labels: { font: { size: 10 }, usePointStyle: true }
                    }
                },
                scales: {
                    y: {
                        beginAtZero: true,
                        title: { display: true, text: 'Cantidad de Errores' },
                        ticks: { stepSize: 1 }
                    },
                    x: {
                        title: { display: true, text: 'Fecha (Día/Mes)' },
                        ticks: { maxRotation: 45, minRotation: 45, autoSkip: true }
                    }
                }
            }
        });
        
        console.log('✅ Gráfico renderizado correctamente');
    }

    // ===== 19. INICIO FUNCIÓN: procesarErroresPorAuditorOptimizado ========
    function procesarErroresPorAuditorOptimizado(evaluacionesConDetalles) {
        const erroresPorAuditorPorFecha = {};
        const auditoresSet = new Set();
        const todasFechasSet = new Set();

        // Guardar también los detalles para drill-down
        const detallesPorAuditorPorFecha = {};

        for (const eval of evaluacionesConDetalles) {
            const auditor = eval.evaluador || 'Sin asignar';
            auditoresSet.add(auditor);

            // Obtener fecha
            let fechaEval = eval.fecha_formateada || eval.fecha || '';
            let fechaSolo = fechaEval.includes(' ') ? fechaEval.split(' ')[0] : fechaEval;
            if (fechaEval.includes('T')) {
                const partes = fechaEval.split('T')[0].split('-');
                if (partes.length === 3) {
                    fechaSolo = `${partes[2]}/${partes[1]}/${partes[0]}`;
                }
            }

            if (!fechaSolo) continue;
            todasFechasSet.add(fechaSolo);

            // Contar errores de esta evaluación
            const detalles = eval.detalles_evaluacion || [];
            const errores = detalles.filter(d => {
                const cumple = d.cumple === true || d.cumple === 1 || d.cumple === 'true';
                return !cumple;
            });

            const cantidadErrores = errores.length;
            if (cantidadErrores === 0) continue;

            // Inicializar estructuras
            if (!erroresPorAuditorPorFecha[auditor]) {
                erroresPorAuditorPorFecha[auditor] = {};
            }
            if (!erroresPorAuditorPorFecha[auditor][fechaSolo]) {
                erroresPorAuditorPorFecha[auditor][fechaSolo] = 0;
            }
            erroresPorAuditorPorFecha[auditor][fechaSolo] += cantidadErrores;

            // Guardar detalles para drill-down
            if (!detallesPorAuditorPorFecha[auditor]) {
                detallesPorAuditorPorFecha[auditor] = {};
            }
            if (!detallesPorAuditorPorFecha[auditor][fechaSolo]) {
                detallesPorAuditorPorFecha[auditor][fechaSolo] = [];
            }
            detallesPorAuditorPorFecha[auditor][fechaSolo].push({
                fecha: fechaSolo,
                agente: eval.agente,
                errores: errores.map(e => ({
                    bloque: e.bloque,
                    atributo: e.atributo,
                    submotivo: e.submotivo,
                    peso: e.peso
                }))
            });
        }

        // Ordenar fechas
        const fechasOrdenadas = Array.from(todasFechasSet).sort((a, b) => {
            const [diaA, mesA, anioA] = a.split('/');
            const [diaB, mesB, anioB] = b.split('/');
            return new Date(anioA, mesA - 1, diaA) - new Date(anioB, mesB - 1, diaB);
        });

        const auditores = Array.from(auditoresSet).sort();

        return {
            erroresPorAuditorPorFecha,
            fechasOrdenadas,
            auditores,
            detallesPorAuditorPorFecha
        };
    }
    // ===== FIN FUNCIÓN: procesarErroresPorAuditorOptimizado ================

