    // ===== 21. INICIO FUNCIÓN: actualizarTablaRankingErroresRapido ========
    function actualizarTablaRankingErroresRapido(erroresPorAuditorPorFecha, fechasFiltradas) {
        const tbody = document.getElementById('tablaRankingErroresAuditores');
        if (!tbody) return;

        const statsPorAuditor = [];
        let totalErroresGeneral = 0;
        let totalDiasConErroresGeneral = 0;

        for (const [auditor, fechas] of Object.entries(erroresPorAuditorPorFecha)) {
            let totalErrores = 0;
            let diasConErrores = 0;

            for (const [fecha, cantidad] of Object.entries(fechas)) {
                if (fechasFiltradas.includes(fecha)) {
                    totalErrores += cantidad;
                    if (cantidad > 0) diasConErrores++;
                }
            }

            const promedioDiario = diasConErrores > 0 ? (totalErrores / diasConErrores).toFixed(1) : 0;

            // Acumular para promedio general
            totalErroresGeneral += totalErrores;
            totalDiasConErroresGeneral += diasConErrores;

            // Obtener top submotivos desde los detalles guardados
            let topSubmotivos = 'Sin datos';
            if (window.detallesErroresPorAuditor && window.detallesErroresPorAuditor[auditor]) {
                const submotivosMap = {};
                for (const [fecha, detalles] of Object.entries(window.detallesErroresPorAuditor[auditor])) {
                    if (fechasFiltradas.includes(fecha)) {
                        for (const det of detalles) {
                            for (const error of det.errores) {
                                if (error.submotivo) {
                                    submotivosMap[error.submotivo] = (submotivosMap[error.submotivo] || 0) + 1;
                                }
                            }
                        }
                    }
                }
                const top = Object.entries(submotivosMap).sort((a, b) => b[1] - a[1]).slice(0, 3);
                topSubmotivos = top.map(([nombre, count]) => `${nombre.substring(0, 25)} (${count})`).join(', ') || 'Sin datos';
            }

            statsPorAuditor.push({ 
                auditor, 
                totalErrores, 
                diasConErrores,
                promedioDiario: parseFloat(promedioDiario), 
                topSubmotivos 
            });
        }

        // 🔴 CORRECCIÓN: Calcular promedio equipo correctamente
        // Promedio equipo = Total errores / Total días con errores (entre todos los auditores)
        const promedioGeneral = totalDiasConErroresGeneral > 0 
            ? (totalErroresGeneral / totalDiasConErroresGeneral).toFixed(1) 
            : 0;

        statsPorAuditor.sort((a, b) => b.totalErrores - a.totalErrores);

        if (statsPorAuditor.length === 0) {
            tbody.innerHTML = '<tr><td colspan="6" style="text-align: center;">No hay datos de errores para mostrar<\/td><\/tr>';
            return;
        }

        let html = '';
        statsPorAuditor.forEach((item, idx) => {
            // Comparar el promedio diario del auditor vs el promedio general del equipo
            const vsPromedio = item.promedioDiario > promedioGeneral ?
                `<span style="color: var(--danger);">⚠️ +${(item.promedioDiario - promedioGeneral).toFixed(1)} sobre media</span>` :
                `<span style="color: var(--ok);">✅ ${(promedioGeneral - item.promedioDiario).toFixed(1)} bajo media</span>`;

            html += `
                <tr onclick="toggleDetalleErroresAuditorRapido('${escapeHtml(item.auditor)}')" style="cursor: pointer;">
                    <td style="padding: 8px; text-align: center;">
                        <span class="expand-icon" id="icon-${idx}">▶</span>
                    </td>
                    <td style="padding: 8px;"><strong>${escapeHtml(item.auditor)}</strong></td>
                    <td style="padding: 8px; text-align: center; font-weight: bold; color: var(--danger);">${item.totalErrores} (${item.diasConErrores} días)</td>
                    <td style="padding: 8px; text-align: center;">${item.promedioDiario}/día</td>
                    <td style="padding: 8px;">${vsPromedio}</td>
                    <td style="padding: 8px; font-size: 12px; max-width: 300px;">${escapeHtml(item.topSubmotivos)}</td>
                </tr>
                <tr id="detail-${idx}" style="display: none;">
                    <td colspan="6">
                        <div class="detail-content" id="detail-content-${idx}">
                            <div style="text-align: center; padding: 20px;">Cargando detalles...</div>
                        </div>
                    </td>
                </tr>
            `;
        });

        // 🔴 CORRECCIÓN: Mostrar el promedio equipo correctamente calculado
        html += `
            <tr style="background: #f0f7ff; font-weight: bold;">
                <td colspan="2" style="padding: 8px; text-align: right;">📊 PROMEDIO EQUIPO:</td>
                <td style="padding: 8px; text-align: center;">${totalErroresGeneral} errores (${totalDiasConErroresGeneral} días aud.)</td>
                <td style="padding: 8px; text-align: center;">${promedioGeneral}/día</td>
                <td colspan="2"></td>
            </tr>
        `;

        tbody.innerHTML = html;
        window.statsErroresAuditores = statsPorAuditor;
    }
    // ===== FIN FUNCIÓN: actualizarTablaRankingErroresRapido ================

    // ===== 22. INICIO FUNCIÓN: toggleDetalleErroresAuditorRapido ==========
    async function toggleDetalleErroresAuditorRapido(auditor) {
        const idx = window.statsErroresAuditores?.findIndex(s => s.auditor === auditor);
        if (idx === undefined || idx === -1) return;

        const detailRow = document.getElementById(`detail-${idx}`);
        const icon = document.getElementById(`icon-${idx}`);

        if (detailRow.style.display === 'none') {
            detailRow.style.display = 'table-row';
            if (icon) {
                icon.innerHTML = '▼';
                icon.classList.add('expanded');
            }

            const detailDiv = document.getElementById(`detail-content-${idx}`);
            if (detailDiv && detailDiv.innerHTML.includes('Cargando detalles')) {
                detailDiv.innerHTML = await generarDetalleErroresAuditorHTML(auditor);
            }
        } else {
            detailRow.style.display = 'none';
            if (icon) {
                icon.innerHTML = '▶';
                icon.classList.remove('expanded');
            }
        }
    }
    // ===== FIN FUNCIÓN: toggleDetalleErroresAuditorRapido ==================

    // ===== 23. INICIO FUNCIÓN: mostrarMensajeSinDatosErrores ==============
    function mostrarMensajeSinDatosErrores() {
        const canvas = document.getElementById('chartEvolutivoErroresAuditores');
        if (canvas) {
            const ctx = canvas.getContext('2d');
            if (ctx) {
                if (window.chartErroresAuditores) {
                    window.chartErroresAuditores.destroy();
                    window.chartErroresAuditores = null;
                }
                canvas.width = canvas.clientWidth;
                canvas.height = canvas.clientHeight;
                ctx.clearRect(0, 0, canvas.width, canvas.height);
                ctx.font = '14px sans-serif';
                ctx.fillStyle = '#6c757d';
                ctx.textAlign = 'center';
                ctx.fillText('📊 No hay datos de errores en el período seleccionado', canvas.width / 2, canvas.height / 2);
            }
        }

        const tbody = document.getElementById('tablaRankingErroresAuditores');
        if (tbody) {
            tbody.innerHTML = '<tr><td colspan="6" style="text-align: center;">📊 No hay datos de errores en el período seleccionado<\/td><\/tr>';
        }
    }
    // ===== FIN FUNCIÓN: mostrarMensajeSinDatosErrores ======================

    // ===== 24. INICIO FUNCIÓN: actualizarTablaRankingErrores ===============⚠️ Redundante
    function actualizarTablaRankingErrores(erroresPorAuditorPorFecha, fechasOrdenadas, detalles) {
        const tbody = document.getElementById('tablaRankingErroresAuditores');
        if (!tbody) return;

        // 🔴 GUARDAR DETALLES EN VARIABLE GLOBAL
        if (detalles) {
            window.detallesErroresPorAuditor = detalles;
            console.log('✅ Detalles guardados en window.detallesErroresPorAuditor');
        }

        // Calcular estadísticas por auditor
        const statsPorAuditor = [];

        for (const [auditor, fechas] of Object.entries(erroresPorAuditorPorFecha)) {
            let totalErrores = 0;
            let diasConErrores = 0;
            let submotivosMap = {};

            for (const [fecha, cantidad] of Object.entries(fechas)) {
                totalErrores += cantidad;
                if (cantidad > 0) diasConErrores++;
            }

            const promedioDiario = diasConErrores > 0 ? (totalErrores / diasConErrores).toFixed(1) : 0;

            // Obtener top submotivos desde window.detallesErroresPorAuditor
            if (window.detallesErroresPorAuditor && window.detallesErroresPorAuditor[auditor]) {
                for (const [fecha, detalles] of Object.entries(window.detallesErroresPorAuditor[auditor])) {
                    for (const det of detalles) {
                        for (const error of det.errores) {
                            if (error.submotivo) {
                                submotivosMap[error.submotivo] = (submotivosMap[error.submotivo] || 0) + 1;
                            }
                        }
                    }
                }
            }

            const topSubmotivos = Object.entries(submotivosMap)
                .sort((a, b) => b[1] - a[1])
                .slice(0, 3)
                .map(([nombre, count]) => `${nombre.substring(0, 25)} (${count})`)
                .join(', ');

            statsPorAuditor.push({
                auditor,
                totalErrores,
                promedioDiario: parseFloat(promedioDiario),
                topSubmotivos: topSubmotivos || 'Sin datos'
            });
        }

        // Ordenar por total de errores (mayor a menor)
        statsPorAuditor.sort((a, b) => b.totalErrores - a.totalErrores);

        // Calcular promedio general del equipo
        const totalErroresGeneral = statsPorAuditor.reduce((sum, a) => sum + a.totalErrores, 0);
        const totalAuditores = statsPorAuditor.length;
        const promedioGeneral = totalAuditores > 0 ? (totalErroresGeneral / totalAuditores).toFixed(1) : 0;

        if (statsPorAuditor.length === 0) {
            tbody.innerHTML = '<tr><td colspan="6" style="text-align: center;">No hay datos de errores para mostrar</td></tr>';
            return;
        }

        let html = '';
        statsPorAuditor.forEach((item, idx) => {
            const vsPromedio = item.promedioDiario > promedioGeneral ?
                `<span style="color: var(--danger);">⚠️ +${(item.promedioDiario - promedioGeneral).toFixed(1)} sobre media</span>` :
                `<span style="color: var(--ok);">✅ ${(promedioGeneral - item.promedioDiario).toFixed(1)} bajo media</span>`;

            const rowId = `auditor-error-${idx}`;

            html += `
                <tr class="expandable-row" onclick="toggleDetalleErroresAuditor('${rowId}', '${escapeHtml(item.auditor)}')" style="cursor: pointer;">
                    <td style="padding: 8px; text-align: center;">
                        <span class="expand-icon" id="icon-${rowId}">▶</span>
                    </td>
                    <td style="padding: 8px;"><strong>${escapeHtml(item.auditor)}</strong></td>
                    <td style="padding: 8px; text-align: center; font-weight: bold; color: var(--danger);">${item.totalErrores}</td>
                    <td style="padding: 8px; text-align: center;">${item.promedioDiario}/día</td>
                    <td style="padding: 8px;">${vsPromedio}</td>
                    <td style="padding: 8px; font-size: 12px; max-width: 300px;">${escapeHtml(item.topSubmotivos)}</td>
                </tr>
                <tr id="${rowId}" class="detail-row" style="display: none;">
                    <td colspan="6">
                        <div class="detail-content" id="detail-${rowId}">
                            <div style="text-align: center; padding: 20px;">⏳ Cargando detalles...</div>
                        </div>
                    </td>
                </tr>
            `;
        });

        // Agregar fila de promedio general
        html += `
            <tr style="background: #f0f7ff; font-weight: bold;">
                <td colspan="2" style="padding: 8px; text-align: right;">📊 PROMEDIO EQUIPO:</td>
                <td style="padding: 8px; text-align: center;">${totalErroresGeneral}</td>
                <td style="padding: 8px; text-align: center;">${promedioGeneral}/día</td>
                <td colspan="2"></td>
            </tr>
        `;

        tbody.innerHTML = html;
        window.statsErroresAuditores = statsPorAuditor;
    }
    // ===== FIN FUNCIÓN: actualizarTablaRankingErrores ======================

    // ===== 25. INICIO FUNCIÓN: mostrarDetalleErroresAuditor ================
    function mostrarDetalleErroresAuditor(auditor, fecha) {
        if (!window.detallesErroresPorAuditor || !window.detallesErroresPorAuditor[auditor]) {
            alert(`No hay detalles disponibles para ${auditor} en ${fecha}`);
            return;
        }

        const detallesFecha = window.detallesErroresPorAuditor[auditor][fecha];
        if (!detallesFecha || detallesFecha.length === 0) {
            alert(`No hay errores registrados para ${auditor} en ${fecha}`);
            return;
        }

        // Agrupar errores por submotivo
        const erroresMap = {};
        for (const det of detallesFecha) {
            for (const error of det.errores) {
                const key = error.submotivo;
                if (!erroresMap[key]) {
                    erroresMap[key] = {
                        submotivo: error.submotivo,
                        bloque: error.bloque,
                        atributo: error.atributo,
                        peso: error.peso,
                        count: 0,
                        agentes: new Set()
                    };
                }
                erroresMap[key].count++;
                if (det.agente) erroresMap[key].agentes.add(det.agente);
            }
        }

        const erroresOrdenados = Object.values(erroresMap).sort((a, b) => b.count - a.count);

        let mensaje = `📋 DETALLE DE ERRORES\n`;
        mensaje += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
        mensaje += `👤 Auditor: ${auditor}\n`;
        mensaje += `📅 Fecha: ${fecha}\n`;
        mensaje += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;
        mensaje += `📌 Submotivos con errores (${erroresOrdenados.length}):\n\n`;

        erroresOrdenados.forEach((err, idx) => {
            mensaje += `${idx + 1}. ${err.submotivo}\n`;
            mensaje += `   📂 Bloque: ${err.bloque || 'N/A'}\n`;
            mensaje += `   🏷️ Atributo: ${err.atributo || 'N/A'}\n`;
            mensaje += `   📊 Ocurrencias: ${err.count}\n`;
            mensaje += `   👥 Agentes afectados: ${err.agentes.size}\n`;
            mensaje += `   ⚖️ Peso: ${err.peso || 0}%\n\n`;
        });

        alert(mensaje);
    }
    // ===== FIN FUNCIÓN: mostrarDetalleErroresAuditor =======================

    // ===== 26. INICIO FUNCIÓN: toggleDetalleErroresAuditor =================⚠️ Redundante
    async function toggleDetalleErroresAuditor(rowId, auditor) {
        const detailRow = document.getElementById(rowId);
        const icon = document.getElementById(`icon-${rowId}`);

        if (detailRow.style.display === 'none') {
            detailRow.style.display = 'table-row';
            if (icon) {
                icon.innerHTML = '▼';
                icon.classList.add('expanded');
            }

            const detailDiv = document.getElementById(`detail-${rowId}`);
            if (detailDiv && detailDiv.innerHTML.includes('Cargando detalles')) {
                const html = await generarDetalleErroresAuditorHTML(auditor);
                detailDiv.innerHTML = html;
            }
        } else {
            detailRow.style.display = 'none';
            if (icon) {
                icon.innerHTML = '▶';
                icon.classList.remove('expanded');
            }
        }
    }
    // ===== FIN FUNCIÓN: toggleDetalleErroresAuditor ========================

    // ===== 27. INICIO FUNCIÓN: generarDetalleErroresAuditorHTML ============
    async function generarDetalleErroresAuditorHTML(auditor) {
        console.log(`📊 Generando detalle para: ${auditor}`);
        
        if (!window.detallesErroresPorAuditor || !window.detallesErroresPorAuditor[auditor]) {
            return '<div style="text-align: center; padding: 20px; color: var(--muted);">📊 No hay detalles de errores disponibles para este auditor</div>';
        }
        
        const detalles = window.detallesErroresPorAuditor[auditor];
        
        // Agrupar por motivo
        const porMotivo = {};
        const porAtributo = {};
        const porSubmotivo = {};
        let totalErrores = 0;
        
        for (const [fecha, items] of Object.entries(detalles)) {
            for (const item of items) {
                for (const error of item.errores) {
                    totalErrores++;
                    
                    const motivo = error.bloque || 'Sin motivo';
                    porMotivo[motivo] = (porMotivo[motivo] || 0) + 1;
                    
                    const atributo = error.atributo || 'Sin atributo';
                    porAtributo[atributo] = (porAtributo[atributo] || 0) + 1;
                    
                    const submotivo = error.submotivo || 'Sin submotivo';
                    porSubmotivo[submotivo] = (porSubmotivo[submotivo] || 0) + 1;
                }
            }
        }
        
        const topMotivos = Object.entries(porMotivo).sort((a, b) => b[1] - a[1]).slice(0, 5);
        const topAtributos = Object.entries(porAtributo).sort((a, b) => b[1] - a[1]).slice(0, 5);
        const topSubmotivos = Object.entries(porSubmotivo).sort((a, b) => b[1] - a[1]).slice(0, 5);
        
        let html = `
            <div style="padding: 10px;">
                <h5 style="margin-bottom: 15px;">📊 Análisis detallado - ${escapeHtml(auditor)}</h5>
                <div style="display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px;">
                    <!-- Por Motivo -->
                    <div style="background: white; border-radius: 10px; padding: 12px; border: 1px solid #e0e0e0;">
                        <div style="font-weight: bold; margin-bottom: 10px; color: #019DF4;">📁 POR MOTIVO</div>
                        <div style="font-size: 13px;">
                            ${topMotivos.map(([nombre, count]) => `
                                <div style="display: flex; justify-content: space-between; margin-bottom: 5px;">
                                    <span>${escapeHtml(nombre)}</span>
                                    <span style="font-weight: bold; color: var(--danger);">${count}</span>
                                </div>
                            `).join('')}
                            ${topMotivos.length === 0 ? '<div style="color: var(--muted);">Sin datos</div>' : ''}
                        </div>
                    </div>
                    
                    <!-- Por Atributo -->
                    <div style="background: white; border-radius: 10px; padding: 12px; border: 1px solid #e0e0e0;">
                        <div style="font-weight: bold; margin-bottom: 10px; color: #7b1fa2;">🏷️ POR ATRIBUTO</div>
                        <div style="font-size: 13px;">
                            ${topAtributos.map(([nombre, count]) => `
                                <div style="display: flex; justify-content: space-between; margin-bottom: 5px;">
                                    <span>${escapeHtml(nombre.length > 25 ? nombre.substring(0, 22) + '...' : nombre)}</span>
                                    <span style="font-weight: bold; color: var(--danger);">${count}</span>
                                </div>
                            `).join('')}
                            ${topAtributos.length === 0 ? '<div style="color: var(--muted);">Sin datos</div>' : ''}
                        </div>
                    </div>
                    
                    <!-- Por Submotivo -->
                    <div style="background: white; border-radius: 10px; padding: 12px; border: 1px solid #e0e0e0;">
                        <div style="font-weight: bold; margin-bottom: 10px; color: #fd7e14;">🔬 POR SUBMOTIVO</div>
                        <div style="font-size: 13px;">
                            ${topSubmotivos.map(([nombre, count]) => `
                                <div style="display: flex; justify-content: space-between; margin-bottom: 5px;">
                                    <span>${escapeHtml(nombre.length > 25 ? nombre.substring(0, 22) + '...' : nombre)}</span>
                                    <span style="font-weight: bold; color: var(--danger);">${count}</span>
                                </div>
                            `).join('')}
                            ${topSubmotivos.length === 0 ? '<div style="color: var(--muted);">Sin datos</div>' : ''}
                        </div>
                    </div>
                </div>
                <div style="margin-top: 15px; font-size: 12px; color: var(--muted); text-align: center;">
                    📊 Total de errores registrados: <strong>${totalErrores}</strong>
                </div>
            </div>
        `;
        
        return html;
    }
    // ===== FIN FUNCIÓN: generarDetalleErroresAuditorHTML ===================

    // ======================================================
// FUNCIÓN: calcularProductividadAuditor (CON TOKEN RENOVADO)
// ======================================================
async function calcularProductividadAuditor(evaluaciones) {
    console.log('📊 calcularProductividadAuditor - INICIO');
    console.log(`   Evaluaciones recibidas: ${evaluaciones?.length || 0}`);
    
    if (!evaluaciones || evaluaciones.length === 0) {
        console.log('⚠️ No hay evaluaciones, retornando 0');
        return { porAuditor: 0, capacidadTotal: 0 };
    }

    try {
        // 🔴 OBTENER TOKEN ACTUAL
        const token = localStorage.getItem('meca_token');
        
        if (!token) {
            console.warn('⚠️ No hay token disponible, usando fallback local');
            return calcularProductividadLocal(evaluaciones);
        }

        // 🔴 OBTENER AUDITORES ACTIVOS DESDE LA BD CON EL TOKEN
        let auditoresActivos = [];
        let errorAutenticacion = false;
        
        try {
            console.log('📡 Solicitando auditores activos a la BD...');
            const response = await fetch('/api/usuarios/auditores-activos', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                }
            });
            
            if (!response.ok) {
                if (response.status === 401) {
                    console.warn('⚠️ Token expirado o inválido. Intentando renovar...');
                    errorAutenticacion = true;
                    
                    // Intentar renovar sesión
                    const renovado = await renovarSesion();
                    if (renovado) {
                        // Reintentar con el nuevo token
                        const nuevoToken = localStorage.getItem('meca_token');
                        const retryResponse = await fetch('/api/usuarios/auditores-activos', {
                            headers: {
                                'Authorization': `Bearer ${nuevoToken}`,
                                'Content-Type': 'application/json'
                            }
                        });
                        if (retryResponse.ok) {
                            auditoresActivos = await retryResponse.json();
                            console.log(`   ✅ ${auditoresActivos.length} auditores activos (después de renovar)`);
                        }
                    }
                } else {
                    console.warn(`⚠️ Error ${response.status} al obtener auditores`);
                }
            } else {
                auditoresActivos = await response.json();
                console.log(`   ✅ ${auditoresActivos.length} auditores activos desde BD`);
            }
        } catch (fetchError) {
            console.warn('⚠️ Error de red al obtener auditores:', fetchError.message);
        }

        // 🔴 FALLBACK: Si no se obtuvieron auditores de la BD, contar de evaluaciones
        if (auditoresActivos.length === 0) {
            console.log('📊 Usando fallback: auditores desde evaluaciones');
            const auditoresSet = new Set();
            evaluaciones.forEach(e => {
                if (e.evaluador) auditoresSet.add(e.evaluador);
            });
            auditoresActivos = Array.from(auditoresSet);
            console.log(`   👥 ${auditoresActivos.length} auditores únicos desde evaluaciones`);
        }

        const numeroAuditores = Math.max(auditoresActivos.length, 1);
        console.log(`   👥 Auditores considerados: ${numeroAuditores}`);

        // Obtener días únicos trabajados
        const fechasUnicas = new Set();
        evaluaciones.forEach(e => {
            let fechaStr = e.fechaOriginal || e.fecha || '';
            if (fechaStr) {
                let fechaSolo = fechaStr.split(' ')[0];
                if (fechaSolo) {
                    fechasUnicas.add(fechaSolo);
                }
            }
        });

        const diasTrabajados = fechasUnicas.size;
        console.log(`   📅 Días trabajados: ${diasTrabajados}`);
        
        if (diasTrabajados === 0) {
            console.log('⚠️ No hay días trabajados, retornando 0');
            return { porAuditor: 0, capacidadTotal: 0 };
        }

        const totalEvaluaciones = evaluaciones.length;
        console.log(`   📊 Total evaluaciones: ${totalEvaluaciones}`);
        
        const productividadReal = totalEvaluaciones / (numeroAuditores * diasTrabajados);
        const capacidadReal = totalEvaluaciones / diasTrabajados;

        const resultado = {
            porAuditor: Math.round(productividadReal * 10) / 10,
            capacidadTotal: Math.round(capacidadReal * 10) / 10
        };
        
        console.log(`   ✅ Resultado: porAuditor=${resultado.porAuditor}, capacidadTotal=${resultado.capacidadTotal}`);
        return resultado;

    } catch (error) {
        console.error('❌ Error calculando productividad:', error);
        // Fallback final
        return calcularProductividadLocal(evaluaciones);
    }
}
    // ===== FIN FUNCIÓN: calcularProductividadAuditor =======================

