    // ===== 3. INICIO FUNCIÓN: procesarArchivoEscuchas ====================
    async function procesarArchivoEscuchas(file) {
        console.log('📁 Iniciando procesamiento del archivo:', file.name);

        return new Promise((resolve, reject) => {
            const reader = new FileReader();

            reader.onload = function (e) {
                try {
                    const data = new Uint8Array(e.target.result);
                    const workbook = XLSX.read(data, { type: 'array' });
                    const firstSheet = workbook.Sheets[workbook.SheetNames[0]];
                    const jsonData = XLSX.utils.sheet_to_json(firstSheet, { raw: true, defval: "" });

                    console.log('📊 Total de filas leídas:', jsonData.length);
                    console.log('📋 Columnas encontradas:', Object.keys(jsonData[0] || {}));
                    console.log('📝 Primera fila de ejemplo:', jsonData[0]);

                    const tickets = [];

                    for (let i = 0; i < jsonData.length; i++) {
                        const row = jsonData[i];

                        // Mapear columnas según la estructura REAL del Excel
                        let ticket = row['Consulta[ticket]'] || row['ticket'] || row['Ticket'] || '';
                        let supervisor = row['Consulta[responsable]'] || row['responsable'] || row['Responsable'] || '';
                        let gestor = row['Consulta[UsuarioMov]'] || row['UsuarioMov'] || row['usuario_mov'] || '';
                        let auditor = row['Auditor'] || row['auditor'] || '';
                        let motivos = row['Consulta[Motivos]'] || row['Motivos'] || row['motivos'] || '';
                        let submotivos = row['Consulta[Submotivos]'] || row['Submotivos'] || row['submotivos'] || '';
                        let subnivel = row['Consulta[SubNivel]'] || row['SubNivel]'] || row['subnivel'] || '';
                        let peticion = row['PETICION'] || row['peticion'] || '';
                        let usuario_dni = row['Consulta[UsuarioDNI]'] || row['UsuarioDNI'] || row['usuario_dni'] || '';
                        let motivo_call = row['Consulta[motivo_call]'] || row['motivo_call'] || '';

                        // CONVERTIR FECHA DE EXCEL A FORMATO VÁLIDO
                        let fecha_descarga_raw = row['Fecha Descarga'] || row['fecha_descarga'] || '';
                        let fecha_descarga = '';

                        if (typeof fecha_descarga_raw === 'number') {
                            // Es número serial de Excel
                            fecha_descarga = excelSerialToDate(fecha_descarga_raw);
                            console.log(`📅 Fecha convertida: ${fecha_descarga_raw} → ${fecha_descarga}`);
                        } else if (typeof fecha_descarga_raw === 'string' && fecha_descarga_raw.match(/^\d{4}-\d{2}-\d{2}/)) {
                            // Ya está en formato ISO
                            fecha_descarga = fecha_descarga_raw.split('T')[0];
                        } else if (typeof fecha_descarga_raw === 'string' && fecha_descarga_raw.includes('/')) {
                            // Formato DD/MM/YYYY
                            const partes = fecha_descarga_raw.split('/');
                            if (partes.length === 3) {
                                fecha_descarga = `${partes[2]}-${partes[1]}-${partes[0]}`;
                            }
                        } else {
                            fecha_descarga = '';
                        }

                        // Validar que el ticket no esté vacío
                        if (!ticket || ticket === '') {
                            console.warn(`⚠️ Fila ${i + 2} omitida: No tiene ticket válido`);
                            continue;
                        }

                        // Validar que el auditor no esté vacío
                        if (!auditor || auditor === '') {
                            console.warn(`⚠️ Ticket ${ticket} no tiene auditor asignado en el Excel`);
                            auditor = 'sin_asignar';
                        }

                        tickets.push({
                            ticket: ticket,
                            supervisor_responsable: supervisor,
                            gestor_auditado: gestor,
                            auditor_asignado: auditor,
                            motivos: motivos,
                            submotivos: submotivos,
                            subnivel: subnivel,
                            peticion: peticion,
                            usuario_dni: usuario_dni,
                            usuario_mov: gestor,
                            motivo_call: motivo_call,
                            fecha_descarga: fecha_descarga,
                            estado: 'pendiente'
                        });
                    }

                    console.log(`✅ Tickets procesados: ${tickets.length}`);

                    // Contar por auditor para diagnóstico
                    const conteoPorAuditor = {};
                    for (const t of tickets) {
                        conteoPorAuditor[t.auditor_asignado] = (conteoPorAuditor[t.auditor_asignado] || 0) + 1;
                    }
                    console.log('📊 Distribución por auditor (desde Excel):', conteoPorAuditor);

                    if (tickets.length === 0) {
                        reject(new Error('No se encontraron tickets válidos en el archivo. Verifique que exista la columna "Consulta[ticket]"'));
                        return;
                    }

                    resolve(tickets);

                } catch (error) {
                    console.error('❌ Error procesando el archivo:', error);
                    reject(new Error('Error al leer el archivo: ' + error.message));
                }
            };

            reader.onerror = function (error) {
                console.error('❌ Error de lectura del archivo:', error);
                reject(new Error('Error al leer el archivo'));
            };

            reader.readAsArrayBuffer(file);
        });
    }
    // ===== FIN FUNCIÓN: procesarArchivoEscuchas ============================
    
    // ===== 3.1 INICIO FUNCIÓN: validarGestoresContraTablaAgentes =================
    async function validarGestoresContraTablaAgentes(tickets) {
        console.log('🔍 Validando gestores (usuario_mov) contra tabla agentes...');
        
        const db = getDB();
        if (!db) {
            return { valido: false, errores: ['Base de datos no disponible'], gestoresNoEncontrados: [] };
        }
        
        // 1. Obtener TODOS los nombres de la tabla agentes (activos e inactivos, para depuración)
        const { data: agentes, error } = await db
            .from('agentes')
            .select('nombre');
        
        if (error) {
            console.error('❌ Error obteniendo agentes:', error);
            return { 
                valido: false, 
                errores: [`Error al consultar agentes: ${error.message}`],
                gestoresNoEncontrados: []
            };
        }
        
        // 2. Crear Set de nombres válidos (exactos en mayúsculas)
        const nombresValidosSet = new Set();
        agentes.forEach(agente => {
            if (agente.nombre) {
                nombresValidosSet.add(agente.nombre.toUpperCase().trim());
            }
        });
        
        console.log(`📋 Nombres válidos en agentes (${nombresValidosSet.size}):`, Array.from(nombresValidosSet).slice(0, 5));
        
        // 3. Extraer gestores únicos del archivo
        const gestoresArchivoMap = new Map(); // key: nombre_original, value: { tickets: [], normalizado }
        
        for (const ticket of tickets) {
            let gestor = ticket.gestor_auditado || ticket.usuario_mov || '';
            if (!gestor) {
                console.warn('⚠️ Ticket sin gestor:', ticket.ticket);
                continue;
            }
            
            gestor = gestor.toUpperCase().trim();
            
            if (!gestoresArchivoMap.has(gestor)) {
                gestoresArchivoMap.set(gestor, {
                    original: gestor,
                    tickets: []
                });
            }
            gestoresArchivoMap.get(gestor).tickets.push(ticket.ticket);
        }
        
        // 4. Verificar cada gestor del archivo
        const gestoresNoEncontrados = [];
        
        for (const [gestorNombre, info] of gestoresArchivoMap.entries()) {
            if (nombresValidosSet.has(gestorNombre)) {
                console.log(`✅ Gestor válido: ${gestorNombre}`);
            } else {
                console.warn(`❌ Gestor NO encontrado: ${gestorNombre}`);
                gestoresNoEncontrados.push({
                    nombre: gestorNombre,
                    tickets: info.tickets,
                    cantidadTickets: info.tickets.length
                });
            }
        }
        
        // 5. Construir resultado
        const tieneErrores = gestoresNoEncontrados.length > 0;
        
        let mensaje = '';
        if (tieneErrores) {
            mensaje = `❌ ERROR: ${gestoresNoEncontrados.length} gestor(es) no están registrados\n\n`;
            mensaje += `Los siguientes nombres NO existen en el sistema:\n`;
            mensaje += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
            
            for (const g of gestoresNoEncontrados) {
                const ejemploTickets = g.tickets.slice(0, 3).join(', ');
                const masTickets = g.tickets.length > 3 ? `... +${g.tickets.length - 3} más` : '';
                mensaje += `\n❌ "${g.nombre}"\n`;
                mensaje += `   📌 Tickets afectados: ${ejemploTickets} ${masTickets}\n`;
                mensaje += `   📊 Total: ${g.cantidadTickets} ticket(s)\n`;
            }
            
            mensaje += `\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
            mensaje += `📌 SOLUCIÓN:\n`;
            mensaje += `   1. Debe colocarse en el archivo Excel/CSV los APELLIDOS y NOMBRES\n`;
            mensaje += `   2. Asegúrese que coincidan EXACTAMENTE con el formato indicado\n`;
            mensaje += `   3. Si el gestor es nuevo, regístrelo primero en la pestaña "👥 FTE"\n`;
            mensaje += `\n⚠️ CARGA RECHAZADA - No se distribuirá ningún ticket.`;
        }
        
        return {
            valido: !tieneErrores,
            gestoresNoEncontrados: gestoresNoEncontrados,
            mensaje: mensaje
        };
    }
    // ===== FIN FUNCIÓN: validarGestoresContraTablaAgentes =================

    // ===== 4. INICIO FUNCIÓN: cargarYDistribuirEscuchas ==================
    async function cargarYDistribuirEscuchas() {
        const fileInput = document.getElementById('fileEscuchas');
        const infoDiv = document.getElementById('infoCargaEscuchas');
        const btnCargar = document.getElementById('btnCargarEscuchas');

        if (!fileInput.files || fileInput.files.length === 0) {
            alert('⚠️ Seleccione un archivo Excel/CSV para cargar');
            return;
        }

        const file = fileInput.files[0];

        infoDiv.style.display = 'block';
        infoDiv.innerHTML = `<div style="background: var(--accent); color: white; padding: 10px; border-radius: 8px;">⏳ Procesando archivo ${file.name}...</div>`;
        btnCargar.disabled = true;

        try {
            // 1. Leer archivo
            const todosLosTickets = await procesarArchivoEscuchas(file);
            console.log(`📊 Total tickets en Excel: ${todosLosTickets.length}`);

            if (todosLosTickets.length === 0) {
                throw new Error('No se encontraron tickets válidos en el archivo');
            }

            const token = localStorage.getItem('meca_token');

            // 2. Validación de gestores (usando API local)
            infoDiv.innerHTML = `<div style="background: var(--accent); color: white; padding: 10px; border-radius: 8px;">🔍 Validando gestores contra base de datos...</div>`;
            
            // Obtener agentes existentes desde API local
            const agentesResponse = await fetch('/api/agentes', {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const agentesExistentes = await agentesResponse.json();
            const nombresValidosSet = new Set(agentesExistentes.map(a => a.nombre?.toUpperCase().trim()));
            
            const gestoresNoEncontrados = [];
            for (const ticket of todosLosTickets) {
                let gestor = ticket.gestor_auditado || ticket.usuario_mov || '';
                if (gestor) {
                    gestor = gestor.toUpperCase().trim();
                    if (!nombresValidosSet.has(gestor)) {
                        gestoresNoEncontrados.push(gestor);
                    }
                }
            }
            
            if (gestoresNoEncontrados.length > 0) {
                const mensaje = `❌ ERROR: ${gestoresNoEncontrados.length} gestor(es) no están registrados\n\n${gestoresNoEncontrados.slice(0, 5).join(', ')}${gestoresNoEncontrados.length > 5 ? '...' : ''}`;
                infoDiv.innerHTML = `<div style="background: var(--danger); color: white; padding: 15px; border-radius: 8px;">${mensaje}</div>`;
                btnCargar.disabled = false;
                fileInput.value = '';
                return;
            }

            // 3. Verificar tickets existentes
            infoDiv.innerHTML = `<div style="background: var(--accent); color: white; padding: 10px; border-radius: 8px;">🔍 Verificando tickets ya existentes...</div>`;
            
            const ticketsExistentes = new Set();
            
            // Evaluaciones existentes
            const evaluacionesResponse = await fetch('/api/evaluaciones', {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const evaluacionesExistentes = await evaluacionesResponse.json();
            evaluacionesExistentes.forEach(eval => {
                if (eval.ticket_psi) ticketsExistentes.add(eval.ticket_psi);
            });
            
            // Asignaciones pendientes
            const asignacionesResponse = await fetch('/api/escuchas/asignaciones', {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const asignacionesPendientes = await asignacionesResponse.json();
            asignacionesPendientes.forEach(asig => {
                if (asig.ticket) ticketsExistentes.add(asig.ticket);
            });
            
            console.log(`📊 Total tickets YA EXISTENTES: ${ticketsExistentes.size}`);

            // 4. Filtrar tickets nuevos
            const ticketsNuevos = [];
            const ticketsOmitidosDetalle = [];
            
            for (const ticket of todosLosTickets) {
                if (ticketsExistentes.has(ticket.ticket)) {
                    ticketsOmitidosDetalle.push(ticket.ticket);
                } else {
                    ticketsNuevos.push(ticket);
                }
            }

            console.log(`📊 Tickets NUEVOS: ${ticketsNuevos.length}, OMITIDOS: ${ticketsOmitidosDetalle.length}`);

            if (ticketsNuevos.length === 0) {
                infoDiv.innerHTML = `<div style="background: var(--warning); color: white; padding: 10px; border-radius: 8px;">⚠️ No hay tickets nuevos para distribuir.</div>`;
                setTimeout(() => { infoDiv.style.display = 'none'; }, 5000);
                btnCargar.disabled = false;
                return;
            }

            // 5. Distribuir tickets
            infoDiv.innerHTML = `<div style="background: var(--accent); color: white; padding: 10px; border-radius: 8px;">✅ ${ticketsNuevos.length} tickets nuevos. Distribuyendo...</div>`;

            const resultadoDistribucion = await distribuirTareasEquitativamenteConExclusion(ticketsNuevos);

            // 🔴 DIAGNÓSTICO
            console.log('📊 resultadoDistribucion:', resultadoDistribucion);
            console.log('📊 distribucion:', resultadoDistribucion?.distribucion);
            console.log('📊 distribucion keys:', Object.keys(resultadoDistribucion?.distribucion || {}));

            // 🔴 VALIDAR QUE LA DISTRIBUCIÓN SEA VÁLIDA
            if (!resultadoDistribucion || !resultadoDistribucion.distribucion || Object.keys(resultadoDistribucion.distribucion).length === 0) {
                console.error('❌ La distribución está vacía');
                throw new Error('No se pudo distribuir los tickets');
            }

            // 6. Crear registro de tarea (lote)
            const tarea = await crearRegistroTarea(file.name, ticketsNuevos.length);

            // 🔴 VERIFICAR QUE LA TAREA SE CREÓ
            if (!tarea || !tarea.id) {
                throw new Error('No se pudo crear la tarea');
            }

            // 7. Guardar asignaciones - 🔴 CORREGIDO: pasar la distribución correcta
            const asignacionesGuardadas = await guardarAsignacionesEnAPI(
                tarea.id, 
                resultadoDistribucion.distribucion  // ← PASAR SOLO LA DISTRIBUCIÓN
            );
            
            // 8. Mostrar resumen
            mostrarResumenDistribucion(resultadoDistribucion, ticketsNuevos.length, ticketsOmitidosDetalle.length);
            
            infoDiv.innerHTML = `<div style="background: var(--ok); color: white; padding: 10px; border-radius: 8px;">✅ Distribución completada: ${asignacionesGuardadas.length} tareas asignadas.</div>`;
            
            await refrescarMonitoreoEscuchas();
            fileInput.value = '';
            
            setTimeout(() => { infoDiv.style.display = 'none'; }, 8000);

        } catch (error) {
            console.error('❌ ERROR:', error);
            infoDiv.innerHTML = `<div style="background: var(--danger); color: white; padding: 10px; border-radius: 8px;">❌ Error: ${error.message}</div>`;
        } finally {
            btnCargar.disabled = false;
        }
    }
    // ===== FIN FUNCIÓN: cargarYDistribuirEscuchas ==========================

    async function guardarAsignacionesEnAPI(tareaId, distribucion) {
    const token = localStorage.getItem('meca_token');
    const registros = [];

    console.log('📊 guardarAsignacionesEnAPI - INICIO');
    console.log(`   tareaId: ${tareaId}`);
    console.log(`   Auditores: ${Object.keys(distribucion || {}).join(', ')}`);

    if (!distribucion || typeof distribucion !== 'object' || Object.keys(distribucion).length === 0) {
        console.error('❌ No hay distribución válida');
        return [];
    }

    // 🔴 OBTENER EL ID MÁXIMO ACTUAL PARA GENERAR IDs ÚNICOS
    let idBase = Date.now();
    let contador = 0;

    for (const [auditor, tickets] of Object.entries(distribucion)) {
        if (!tickets || !Array.isArray(tickets) || tickets.length === 0) continue;

        for (const ticket of tickets) {
            contador++;
            // 🔴 GENERAR ID ÚNICO: timestamp + contador
            const nuevoId = idBase + contador;
            
            registros.push({
                id: nuevoId,  // ← CLAVE: ID generado por el frontend
                tarea_id: tareaId,
                ticket: String(ticket.ticket || ''),
                supervisor_responsable: String(ticket.supervisor_responsable || ''),
                gestor_auditado: String(ticket.gestor_auditado || ''),
                auditor_asignado: String(auditor),
                motivos: String(ticket.motivos || ''),
                submotivos: String(ticket.submotivos || ''),
                subnivel: String(ticket.subnivel || ''),
                peticion: String(ticket.peticion || ''),
                usuario_dni: String(ticket.usuario_dni || ''),
                usuario_mov: String(ticket.usuario_mov || ''),
                motivo_call: String(ticket.motivo_call || ''),
                fecha_descarga: ticket.fecha_descarga || null,
                estado: 'pendiente',
                fecha_asignacion: new Date().toISOString(),
                created_at: new Date().toISOString(),
                updated_at: new Date().toISOString()
            });
        }
    }

    if (registros.length === 0) {
        console.warn('⚠️ No hay registros para guardar');
        return [];
    }

    console.log(`📝 ${registros.length} registros generados con IDs (${registros[0].id} - ${registros[registros.length-1].id})`);

    try {
        const response = await fetch('/api/escuchas/asignaciones', {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${token}`,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ 
                tarea_id: tareaId, 
                asignaciones: registros 
            })
        });

        if (!response.ok) {
            const error = await response.json();
            console.error('❌ Error en API:', error);
            throw new Error(error.error || 'Error guardando asignaciones');
        }

        const data = await response.json();
        console.log(`✅ ${data.total || registros.length} asignaciones guardadas`);
        return data;
        
    } catch (error) {
        console.error('❌ Error guardando asignaciones:', error);
        throw error;
    }
}



    // ===== 5. INICIO FUNCIÓN: excelSerialToDate ==========================
    function excelSerialToDate(serial) {
        if (!serial) return '';
        // Si ya es string, devolverlo
        if (typeof serial === 'string') return serial;
        // Si es número, convertir de serial de Excel a fecha
        // Excel serial: días desde 1/1/1900
        const excelEpoch = new Date(1900, 0, 1);
        const daysOffset = serial - 2; // Ajuste por bug de Excel (1900 es bisiesto)
        const date = new Date(excelEpoch.getTime() + daysOffset * 24 * 60 * 60 * 1000);
        return date.toISOString().split('T')[0]; // YYYY-MM-DD
    }
    // ===== FIN FUNCIÓN: excelSerialToDate ==================================
    
    // ===== 6. INICIO FUNCIÓN: obtenerAuditoresActivos ====================
    async function obtenerAuditoresActivos() {
        const db = getDB();
        if (!db) return [];

        try {
            const { data, error } = await db
                .from('usuarios')
                .select('usuario, nombre_completo')
                .eq('activo', true)
                .eq('rol', 'AUDITOR');

            if (error) throw error;

            return (data || []).map(u => ({
                usuario: u.usuario,
                nombre: u.nombre_completo || u.usuario
            }));
        } catch (error) {
            console.error('Error obteniendo auditores:', error);
            return [];
        }
    }
    // ===== FIN FUNCIÓN: obtenerAuditoresActivos ============================

    // ===== 7. INICIO FUNCIÓN: obtenerCargaActualAuditores ==================
    async function obtenerCargaActualAuditores(auditores) {
        const db = getDB();
        if (!db) return {};

        const cargaMap = {};
        auditores.forEach(a => { cargaMap[a.usuario] = 0; });

        try {
            // Contar tareas pendientes y en proceso
            const { data, error } = await db
                .from('asignaciones_escucha')
                .select('auditor_asignado, estado')
                .in('estado', ['pendiente', 'en_proceso']);

            if (!error && data) {
                data.forEach(asig => {
                    if (cargaMap[asig.auditor_asignado] !== undefined) {
                        cargaMap[asig.auditor_asignado]++;
                    }
                });
            }

            console.log('📊 Carga actual por auditor:', cargaMap);

        } catch (error) {
            console.warn('Error obteniendo carga actual:', error);
        }

        return cargaMap;
    }
    // ===== FIN FUNCIÓN: obtenerCargaActualAuditores ========================

    // ===== 7.1. INICIO FUNCIÓN: obtenerCargaActualAuditores ================= ⚠️ Redundante / Duplicada obtenerCargaActualAuditores
    async function obtenerCargaActualAuditores(auditores) {
        const db = getDB();
        if (!db) return {};

        const cargaMap = {};
        auditores.forEach(a => { cargaMap[a.usuario] = 0; });

        try {
            // 🔴 OBTENER EL LOTE ACTIVO
            const { data: loteActivo, error: loteError } = await db
                .from('tareas_escucha')
                .select('id')
                .eq('estado', 'activo')
                .limit(1);

            if (loteError) {
                console.warn('Error obteniendo lote activo:', loteError);
                return cargaMap;
            }

            if (!loteActivo || loteActivo.length === 0) {
                console.log('📦 No hay lote activo, todos los auditores comienzan con carga 0');
                return cargaMap;
            }

            const loteActivoId = loteActivo[0].id;
            console.log(`📦 Lote activo ID: ${loteActivoId}`);

            // Contar tareas pendientes y en proceso SOLO del lote activo
            const { data, error } = await db
                .from('asignaciones_escucha')
                .select('auditor_asignado, estado')
                .eq('tarea_id', loteActivoId)
                .in('estado', ['pendiente', 'en_proceso']);

            if (!error && data) {
                data.forEach(asig => {
                    if (cargaMap[asig.auditor_asignado] !== undefined) {
                        cargaMap[asig.auditor_asignado]++;
                    }
                });
            }

            console.log('📊 Carga actual por auditor (solo lote activo):', cargaMap);

        } catch (error) {
            console.warn('Error obteniendo carga actual:', error);
        }

        return cargaMap;
    }
    // ===== FIN FUNCIÓN: obtenerCargaActualAuditores =========================

    // ===== 8.INICIO FUNCIÓN: distribuirTareasEquitativamenteConExclusion =
    async function distribuirTareasEquitativamenteConExclusion(tickets) {
    console.log('🔄 distribuirTareasEquitativamenteConExclusion - INICIO');
    console.log(`📊 Total tickets a distribuir: ${tickets?.length || 0}`);

    // 🔴 VALIDACIÓN INICIAL
    if (!tickets || tickets.length === 0) {
        console.warn('⚠️ No hay tickets para distribuir');
        return { distribucion: {}, auditores: [] };
    }

    // Obtener auditores activos desde la base de datos
    const db = getDB();
    if (!db) {
        console.error('❌ Base de datos no disponible');
        return { distribucion: {}, auditores: [] };
    }

    const { data: auditoresData, error } = await db
        .from('usuarios')
        .select('usuario, nombre_completo')
        .eq('activo', true)
        .eq('rol', 'AUDITOR');

    if (error) {
        console.error('❌ Error obteniendo auditores:', error);
        return { distribucion: {}, auditores: [] };
    }

    let auditores = auditoresData || [];
    console.log(`👥 Auditores activos: ${auditores.map(a => a.usuario).join(', ')}`);

    // 🔴 FILTRAR AUDITORES EXCLUIDOS
    const excluidosGlobal = typeof auditoresExcluidosGlobal !== 'undefined' ? auditoresExcluidosGlobal : [];
    console.log(`🚫 Auditores excluidos: ${excluidosGlobal.join(', ') || 'ninguno'}`);

    const auditoresFiltrados = auditores.filter(a => !excluidosGlobal.includes(a.usuario));
    console.log(`✅ Auditores disponibles: ${auditoresFiltrados.length}`);

    if (auditoresFiltrados.length === 0) {
        console.error('❌ No hay auditores disponibles después de excluir');
        alert('⚠️ No hay auditores disponibles. Verifique que haya auditores activos y no excluidos.');
        return { distribucion: {}, auditores: [] };
    }

    // Obtener carga actual
    const cargaActual = await obtenerCargaActualAuditores(auditoresFiltrados);

    // Crear array de auditores con su carga
    let auditoresConCarga = auditoresFiltrados.map(auditor => ({
        usuario: auditor.usuario,
        nombre: auditor.nombre_completo || auditor.usuario,
        carga: cargaActual[auditor.usuario] || 0
    }));

    // Ordenar por carga (menor primero)
    auditoresConCarga.sort((a, b) => a.carga - b.carga);

    console.log('📋 Auditores ordenados por carga:');
    auditoresConCarga.forEach(a => console.log(`   ${a.usuario}: ${a.carga} pendientes`));

    // 🔴 INICIALIZAR DISTRIBUCIÓN
    const distribucion = {};
    auditoresFiltrados.forEach(a => { 
        distribucion[a.usuario] = []; 
    });

    let idx = 0;
    let totalAsignados = 0;

    // 🔴 DISTRIBUIR TICKETS
    for (const ticket of tickets) {
        const auditorSeleccionado = auditoresConCarga[idx % auditoresConCarga.length];
        
        distribucion[auditorSeleccionado.usuario].push({
            ...ticket,
            auditor_asignado: auditorSeleccionado.usuario
        });

        // Incrementar carga virtual
        auditoresConCarga = auditoresConCarga.map(a =>
            a.usuario === auditorSeleccionado.usuario
                ? { ...a, carga: a.carga + 1 }
                : a
        );
        auditoresConCarga.sort((a, b) => a.carga - b.carga);
        idx++;
        totalAsignados++;
    }

    // 🔴 VERIFICAR RESULTADO
    console.log('\n📊 RESUMEN FINAL DE CARGA POR AUDITOR:');
    let totalVerificado = 0;
    for (const auditor of auditoresFiltrados) {
        const asignados = distribucion[auditor.usuario]?.length || 0;
        totalVerificado += asignados;
        console.log(`   ${auditor.usuario}: ${cargaActual[auditor.usuario] || 0} previos + ${asignados} nuevos = ${(cargaActual[auditor.usuario] || 0) + asignados} total`);
    }
    console.log(`📊 Total tickets asignados: ${totalVerificado} (de ${tickets.length})`);

    // 🔴 VERIFICAR QUE NO HAYA TICKETS PERDIDOS
    if (totalVerificado !== tickets.length) {
        console.error(`❌ ERROR: Se perdieron ${tickets.length - totalVerificado} tickets en la distribución`);
    }

    // 🔴 RETORNAR CON LA ESTRUCTURA CORRECTA
    return { distribucion, auditores: auditoresFiltrados };
}
    // ===== FIN FUNCIÓN: distribuirTareasEquitativamenteConExclusion ========
    
    // ===== 9. INICIO FUNCIÓN: crearRegistroTarea =========================
    async function crearRegistroTarea(nombreArchivo, totalRegistros) {
    const token = localStorage.getItem('meca_token');
    
    // 🔴 GENERAR ID ÚNICO
    const nuevoId = Date.now();
    
    const fechaFormateada = new Date().toISOString();
    
    const nuevaTarea = {
        id: nuevoId,  // ← ID generado por el frontend
        fecha_carga: fechaFormateada,
        nombre_archivo: nombreArchivo,
        total_registros: totalRegistros,
        estado: 'activo',
        creado_por: window.usuarioActual?.usuario || 'supervisor'
    };
    
    console.log('📤 Enviando tarea:', nuevaTarea);
    
    const response = await fetch('/api/escuchas/tareas', {
        method: 'POST',
        headers: {
            'Authorization': `Bearer ${token}`,
            'Content-Type': 'application/json'
        },
        body: JSON.stringify(nuevaTarea)
    });
    
    if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || 'Error creando tarea');
    }
    
    return await response.json();
}
    // ===== FIN FUNCIÓN: crearRegistroTarea =================================
    
    // ===== 10. INICIO FUNCIÓN: guardarAsignacionesEnPostgreSQL ==============
    async function guardarAsignacionesEnPostgreSQL(tareaId, asignaciones) {
        const db = getDB();
        if (!db) throw new Error('Base de datos no disponible');

        console.log('💾 Guardando asignaciones en la base de datos...');
        console.log('📊 Estructura de asignaciones:', Object.keys(asignaciones));

        const registros = [];

        // Obtener el ID máximo actual para generar IDs únicos
        const { data: maxIdData, error: maxIdError } = await db
            .from('asignaciones_escucha')
            .select('id')
            .order('id', { ascending: false })
            .limit(1);

        let nextId = 1;
        if (!maxIdError && maxIdData && maxIdData.length > 0) {
            nextId = maxIdData[0].id + 1;
        } else {
            // Usar timestamp como base, pero asegurando unicidad
            nextId = Math.floor(Date.now() * 1000);
        }

        console.log(`📝 Siguiente ID disponible: ${nextId}`);

        // asignaciones tiene estructura: { auditor: [tickets] }
        for (const [auditor, tickets] of Object.entries(asignaciones)) {
            console.log(`   Auditor ${auditor}: ${tickets.length} tickets`);

            for (let i = 0; i < tickets.length; i++) {
                const ticket = tickets[i];

                registros.push({
                    id: nextId++,  // ← Incrementar para cada registro
                    tarea_id: tareaId,
                    ticket: ticket.ticket,
                    supervisor_responsable: ticket.supervisor_responsable || '',
                    gestor_auditado: ticket.gestor_auditado || '',
                    auditor_asignado: auditor,
                    motivos: ticket.motivos || '',
                    submotivos: ticket.submotivos || '',
                    subnivel: ticket.subnivel || '',
                    peticion: ticket.peticion || '',
                    usuario_dni: ticket.usuario_dni || '',
                    usuario_mov: ticket.usuario_mov || '',
                    motivo_call: ticket.motivo_call || '',
                    fecha_descarga: ticket.fecha_descarga || null,
                    estado: 'pendiente',
                    fecha_asignacion: new Date().toISOString(),
                    created_at: new Date().toISOString(),
                    updated_at: new Date().toISOString()
                });
            }
        }

        if (registros.length === 0) {
            console.warn('⚠️ No hay registros para guardar');
            return [];
        }

        console.log(`📝 Total registros a insertar: ${registros.length}`);
        console.log(`📝 Rango de IDs: ${registros[0]?.id} - ${registros[registros.length - 1]?.id}`);

        // Insertar en batches
        const batchSize = 100;
        let todosInsertados = [];

        for (let i = 0; i < registros.length; i += batchSize) {
            const batch = registros.slice(i, i + batchSize);
            console.log(`   Insertando batch ${Math.floor(i / batchSize) + 1} (${batch.length} registros)...`);

            const { data, error } = await db
                .from('asignaciones_escucha')
                .insert(batch)
                .select();

            if (error) {
                console.error('❌ Error insertando batch:', error);
                throw error;
            }
            todosInsertados = [...todosInsertados, ...(data || [])];
            console.log(`   ✅ Batch ${Math.floor(i / batchSize) + 1} insertado`);
        }

        console.log(`✅ Total insertados: ${todosInsertados.length}`);
        return todosInsertados;
    }
    // ===== FIN FUNCIÓN: guardarAsignacionesEnPostgreSQL ======================

    // ===== 11. INICIO FUNCIÓN: mostrarResumenDistribucionConFiltro ========
    function mostrarResumenDistribucionConFiltro(distribucion, auditores, ticketsAsignados, ticketsOmitidos, totalTickets) {
        console.log('📊 mostrarResumenDistribucionConFiltro - Parámetros recibidos:');
        console.log('  - distribucion:', distribucion ? Object.keys(distribucion) : 'undefined');
        console.log('  - auditores:', auditores ? (Array.isArray(auditores) ? auditores.length : 'no es array') : 'undefined');
        console.log('  - ticketsAsignados:', ticketsAsignados);
        console.log('  - ticketsOmitidos:', ticketsOmitidos);
        console.log('  - totalTickets:', totalTickets);

        const resumenDiv = document.getElementById('resumenDistribucion');
        const contentDiv = document.getElementById('resumenDistribucionContent');

        // 🔴 VALIDACIONES ROBUSTAS
        if (!resumenDiv || !contentDiv) {
            console.error('❌ No se encontraron los elementos del DOM para el resumen');
            return;
        }

        // Validar distribucion
        if (!distribucion || typeof distribucion !== 'object') {
            console.error('❌ distribucion no es válida');
            contentDiv.innerHTML = '<div style="color: var(--danger); padding: 15px;">❌ Error: No se pudo obtener la distribución de tickets</div>';
            resumenDiv.style.display = 'block';
            return;
        }

        // Validar auditores (DEBE SER UN ARRAY)
        if (!auditores || !Array.isArray(auditores)) {
            console.error('❌ auditores no es un array válido:', auditores);
            contentDiv.innerHTML = '<div style="color: var(--danger); padding: 15px;">❌ Error: No se pudo obtener la lista de auditores</div>';
            resumenDiv.style.display = 'block';
            return;
        }

        // Si no hay auditores, mostrar mensaje
        if (auditores.length === 0) {
            contentDiv.innerHTML = '<div style="color: var(--warning); padding: 15px;">⚠️ No hay auditores disponibles para la distribución</div>';
            resumenDiv.style.display = 'block';
            return;
        }

        // Contar auditores que recibieron tickets
        const auditoresConTickets = auditores.filter(a => {
            const tickets = distribucion[a.usuario];
            return tickets && Array.isArray(tickets) && tickets.length > 0;
        });

        const auditoresSinTickets = auditores.filter(a => {
            const tickets = distribucion[a.usuario];
            return !tickets || !Array.isArray(tickets) || tickets.length === 0;
        });

        // Valores seguros
        const totalAsignados = ticketsAsignados || 0;
        const totalOmitidos = ticketsOmitidos || 0;
        const totalGeneral = totalTickets || (totalAsignados + totalOmitidos);

        let html = `
            <div style="display: flex; flex-wrap: wrap; gap: 12px; justify-content: space-between; align-items: center;">
                <div style="display: flex; gap: 12px; flex-wrap: wrap;">
                    <div style="background: #e3f2fd; border-radius: 10px; padding: 6px 15px; text-align: center; min-width: 90px;">
                        <div style="font-size: 20px; font-weight: bold;">${totalGeneral}</div>
                        <div style="font-size: 10px; color: var(--muted);">Total Excel</div>
                    </div>
                    <div style="background: #e8f5e9; border-radius: 10px; padding: 6px 15px; text-align: center; min-width: 90px;">
                        <div style="font-size: 20px; font-weight: bold; color: var(--ok);">${totalAsignados}</div>
                        <div style="font-size: 10px; color: var(--muted);">Asignados</div>
                    </div>
                    <div style="background: #fff3e0; border-radius: 10px; padding: 6px 15px; text-align: center; min-width: 90px;">
                        <div style="font-size: 20px; font-weight: bold; color: var(--warning);">${totalOmitidos}</div>
                        <div style="font-size: 10px; color: var(--muted);">Ya auditados</div>
                    </div>
                    <div style="background: #f3e5f5; border-radius: 10px; padding: 6px 15px; text-align: center; min-width: 90px;">
                        <div style="font-size: 20px; font-weight: bold;">${auditores.length}</div>
                        <div style="font-size: 10px; color: var(--muted);">Auditores</div>
                    </div>
                </div>
                
                <div style="display: flex; gap: 8px; flex-wrap: wrap;">
                    ${auditoresConTickets.slice(0, 6).map(a => {
            const ticketsAuditor = distribucion[a.usuario] || [];
            const cantidad = ticketsAuditor.length;
            const porcentaje = totalAsignados > 0 ? Math.round((cantidad / totalAsignados) * 100) : 0;
            const nombreMostrar = (a.nombre_completo || a.usuario).substring(0, 15);
            return `
                            <div style="background: #f8f9fa; border-radius: 8px; padding: 4px 12px; text-align: center; border-left: 3px solid var(--accent);">
                                <div style="font-size: 11px; font-weight: bold;">${escapeHtml(nombreMostrar)}</div>
                                <div style="font-size: 14px; font-weight: bold; color: var(--accent);">${cantidad}</div>
                                <div style="font-size: 9px; color: var(--muted);">${porcentaje}%</div>
                            </div>
                        `;
        }).join('')}
                    ${auditoresConTickets.length > 6 ? `<div style="background: #f8f9fa; border-radius: 8px; padding: 4px 12px; text-align: center;">
                        <div style="font-size: 11px;">+${auditoresConTickets.length - 6} más</div>
                    </div>` : ''}
                </div>
            </div>
        `;

        if (auditoresSinTickets.length > 0 && auditoresSinTickets.length < auditores.length) {
            html += `
                <div style="margin-top: 8px; font-size: 10px; color: var(--warning); text-align: center; border-top: 1px solid var(--line); padding-top: 8px;">
                    ⚠️ ${auditoresSinTickets.map(a => escapeHtml(a.nombre_completo || a.usuario)).join(', ')} no recibieron tickets
                </div>
            `;
        }

        contentDiv.innerHTML = html;
        resumenDiv.style.display = 'block';

        setTimeout(() => {
            resumenDiv.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }, 100);
    }
    // ===== FIN FUNCIÓN: mostrarResumenDistribucionConFiltro ================

    // ===== FUNCIÓN: mostrarResumenDistribucion =====
function mostrarResumenDistribucion(resultadoDistribucion, totalTickets, omitidos) {
    console.log('📊 Mostrando resumen de distribución...');
    
    const resumenDiv = document.getElementById('resumenDistribucion');
    const contentDiv = document.getElementById('resumenDistribucionContent');
    
    if (!resumenDiv || !contentDiv) {
        console.warn('⚠️ Elementos de resumen no encontrados en el DOM');
        return;
    }
    
    const { distribucion, auditores } = resultadoDistribucion;
    
    if (!distribucion || Object.keys(distribucion).length === 0) {
        contentDiv.innerHTML = '<div style="color: var(--danger);">❌ No se pudo realizar la distribución</div>';
        resumenDiv.style.display = 'block';
        return;
    }
    
    // Calcular estadísticas
    const auditoresConTickets = Object.keys(distribucion).filter(a => distribucion[a]?.length > 0);
    const totalAsignados = auditoresConTickets.reduce((sum, a) => sum + distribucion[a].length, 0);
    
    let html = `
        <div style="display: flex; flex-wrap: wrap; gap: 12px; justify-content: space-between; align-items: center;">
            <div style="display: flex; gap: 12px; flex-wrap: wrap;">
                <div style="background: #e3f2fd; border-radius: 10px; padding: 6px 15px; text-align: center; min-width: 90px;">
                    <div style="font-size: 20px; font-weight: bold;">${totalTickets}</div>
                    <div style="font-size: 10px; color: var(--muted);">Total Excel</div>
                </div>
                <div style="background: #e8f5e9; border-radius: 10px; padding: 6px 15px; text-align: center; min-width: 90px;">
                    <div style="font-size: 20px; font-weight: bold; color: var(--ok);">${totalAsignados}</div>
                    <div style="font-size: 10px; color: var(--muted);">Asignados</div>
                </div>
                <div style="background: #fff3e0; border-radius: 10px; padding: 6px 15px; text-align: center; min-width: 90px;">
                    <div style="font-size: 20px; font-weight: bold; color: var(--warning);">${omitidos || 0}</div>
                    <div style="font-size: 10px; color: var(--muted);">Omitidos</div>
                </div>
                <div style="background: #f3e5f5; border-radius: 10px; padding: 6px 15px; text-align: center; min-width: 90px;">
                    <div style="font-size: 20px; font-weight: bold;">${auditores?.length || 0}</div>
                    <div style="font-size: 10px; color: var(--muted);">Auditores</div>
                </div>
            </div>
            
            <div style="display: flex; gap: 8px; flex-wrap: wrap;">
                ${auditoresConTickets.slice(0, 6).map(a => {
                    const cantidad = distribucion[a]?.length || 0;
                    const porcentaje = totalAsignados > 0 ? Math.round((cantidad / totalAsignados) * 100) : 0;
                    const nombreMostrar = a.substring(0, 15);
                    return `
                        <div style="background: #f8f9fa; border-radius: 8px; padding: 4px 12px; text-align: center; border-left: 3px solid var(--accent);">
                            <div style="font-size: 11px; font-weight: bold;">${escapeHtml(nombreMostrar)}</div>
                            <div style="font-size: 14px; font-weight: bold; color: var(--accent);">${cantidad}</div>
                            <div style="font-size: 9px; color: var(--muted);">${porcentaje}%</div>
                        </div>
                    `;
                }).join('')}
                ${auditoresConTickets.length > 6 ? `<div style="background: #f8f9fa; border-radius: 8px; padding: 4px 12px; text-align: center;">
                    <div style="font-size: 11px;">+${auditoresConTickets.length - 6} más</div>
                </div>` : ''}
            </div>
        </div>
    `;
    
    // Auditor sin tickets
    const auditoresSinTickets = (auditores || []).filter(a => !distribucion[a?.usuario || a] || distribucion[a?.usuario || a].length === 0);
    if (auditoresSinTickets.length > 0 && auditoresSinTickets.length < (auditores?.length || 0)) {
        html += `
            <div style="margin-top: 8px; font-size: 10px; color: var(--warning); text-align: center; border-top: 1px solid var(--line); padding-top: 8px;">
                ⚠️ ${auditoresSinTickets.map(a => escapeHtml(a.nombre_completo || a.usuario || a)).join(', ')} no recibieron tickets
            </div>
        `;
    }
    
    contentDiv.innerHTML = html;
    resumenDiv.style.display = 'block';
    
    // Scroll al resumen
    setTimeout(() => {
        resumenDiv.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
}
    
    // ===== 12. INICIO FUNCIÓN: refrescarMonitoreoEscuchas =================
    async function refrescarMonitoreoEscuchas() {
    console.log('🔄 Refrescando monitoreo de escuchas...');
    
    const token = localStorage.getItem('meca_token');
    
    try {
        const response = await fetch('/api/escuchas/asignaciones', {
            headers: { 'Authorization': `Bearer ${token}` }
        });
        
        if (!response.ok) {
            console.warn(`⚠️ Error en API: ${response.status}`);
            window.asignacionesEscuchasGlobales = [];
            actualizarTablaMonitoreo([]);
            await actualizarTarjetasProgreso([]);  // ← PASAR ARRAY VACÍO
            return;
        }
        
        const asignaciones = await response.json();
        
        if (!Array.isArray(asignaciones)) {
            console.warn('⚠️ La respuesta no es un array:', asignaciones);
            window.asignacionesEscuchasGlobales = [];
            actualizarTablaMonitoreo([]);
            await actualizarTarjetasProgreso([]);
            return;
        }
        
        window.asignacionesEscuchasGlobales = asignaciones;
        actualizarTablaMonitoreo(asignaciones);
        await actualizarTarjetasProgreso(asignaciones);  // ← PASAR LAS ASIGNACIONES
        
    } catch (error) {
        console.error('❌ Error refrescando monitoreo:', error);
        window.asignacionesEscuchasGlobales = [];
        actualizarTablaMonitoreo([]);
        await actualizarTarjetasProgreso([]);
    }
}
    // ===== FIN FUNCIÓN: refrescarMonitoreoEscuchas =========================

    // ===== 13. INICIO FUNCIÓN: inicializarFiltroLoteEscuchas ==============
    function inicializarFiltroLoteEscuchas() {
        const filtroLote = document.getElementById('filtroLoteEscuchas');
        if (filtroLote) {
            filtroLote.addEventListener('change', function () {
                console.log(`📦 Filtro de lote cambiado a: ${this.value}`);
                refrescarMonitoreoEscuchas();

            });
        }
    }
    // ===== FIN FUNCIÓN: inicializarFiltroLoteEscuchas ======================
    
    // ===== 14. INICIO FUNCIÓN: mostrarAdvertenciaMultiLote ================
    function mostrarAdvertenciaMultiLote(filtroLote, asignaciones) {
        // Eliminar advertencia anterior si existe
        const existingWarning = document.getElementById('warningMultiLote');
        if (existingWarning) existingWarning.remove();

        // Determinar si hay múltiples lotes
        const tareasUnicas = new Set();
        asignaciones.forEach(asig => {
            if (asig.tarea_id) tareasUnicas.add(asig.tarea_id);
        });

        const hayMultiplesLotes = tareasUnicas.size > 1;

        if (hayMultiplesLotes && filtroLote !== 'activo') {
            const warningDiv = document.createElement('div');
            warningDiv.id = 'warningMultiLote';
            warningDiv.style.cssText = `
                background: #fff3e0; 
                padding: 10px 15px; 
                margin-bottom: 15px; 
                border-radius: 8px; 
                font-size: 12px; 
                border-left: 4px solid #f39c12;
                display: flex;
                justify-content: space-between;
                align-items: center;
                flex-wrap: wrap;
                gap: 10px;
            `;
            warningDiv.innerHTML = `
                <div>
                    <span style="font-weight: bold;">⚠️ Visualizando tickets de ${tareasUnicas.size} lotes diferentes</span>
                    <div style="font-size: 11px; color: var(--muted); margin-top: 3px;">
                        Las acciones (reasignación, gestión) solo afectan al lote correspondiente de cada ticket.
                    </div>
                </div>
                <button onclick="refrescarMonitoreoEscuchas()" style="background: var(--accent); padding: 5px 12px; font-size: 11px;">
                    🔄 Volver a lote activo
                </button>
            `;

            const tablaContainer = document.querySelector('#tablaMonitoreoEscuchas')?.parentElement;
            if (tablaContainer && !tablaContainer.querySelector('#warningMultiLote')) {
                tablaContainer.insertBefore(warningDiv, tablaContainer.firstChild);
            }
        }
    }
    // ===== FIN FUNCIÓN: mostrarAdvertenciaMultiLote ========================
    
    // ===== 15. INICIO FUNCIÓN: mostrarResumenEstadisticoMonitoreo =========
    function mostrarResumenEstadisticoMonitoreo(asignaciones, filtroLote) {
        if (!asignaciones || asignaciones.length === 0) {
            console.log('📊 No hay tickets para mostrar');
            return;
        }

        const total = asignaciones.length;
        const pendientes = asignaciones.filter(a => a.estado === 'pendiente').length;
        const enProceso = asignaciones.filter(a => a.estado === 'en_proceso').length;
        const gestionados = asignaciones.filter(a => a.estado === 'gestionado').length;
        const incidencias = asignaciones.filter(a => a.audio_disponible === false && a.motivo_incidencia).length;

        // Contar lotes distintos
        const lotesUnicos = new Set();
        asignaciones.forEach(a => {
            if (a.tarea_id) lotesUnicos.add(a.tarea_id);
        });

        console.log(`📊 RESUMEN MONITOREO (${filtroLote === 'activo' ? 'Lote Activo' : filtroLote === 'pendientes_totales' ? 'Pendientes Totales' : 'Todos los lotes'}):`);
        console.log(`   • Total tickets: ${total}`);
        console.log(`   • ⏳ Pendientes: ${pendientes}`);
        console.log(`   • 🔄 En proceso: ${enProceso}`);
        console.log(`   • ✅ Gestionados: ${gestionados}`);
        console.log(`   • ⚠️ Incidencias: ${incidencias}`);
        console.log(`   • 📦 Lotes involucrados: ${lotesUnicos.size}`);
    }
    // ===== FIN FUNCIÓN: mostrarResumenEstadisticoMonitoreo =====
    
    // ===== 16. INICIO FUNCIÓN: actualizarTablaMonitoreo ===================
    function actualizarTablaMonitoreo(asignaciones) {
        const tbody = document.getElementById('tablaMonitoreoEscuchas');
        if (!tbody) return;

        if (!asignaciones || asignaciones.length === 0) {
            tbody.innerHTML = `<tr><td colspan="10" style="text-align: center; padding: 40px;">
                📭 No hay asignaciones con los filtros seleccionados
            <\/td><\/tr>`;
            return;
        }

        // Ordenar: primero incidencias, luego pendientes, luego el resto
        const asignacionesOrdenadas = [...asignaciones].sort((a, b) => {
            const aEsIncidencia = a.audio_disponible === false && a.motivo_incidencia;
            const bEsIncidencia = b.audio_disponible === false && b.motivo_incidencia;
            if (aEsIncidencia && !bEsIncidencia) return -1;
            if (!aEsIncidencia && bEsIncidencia) return 1;

            // Luego por estado (pendiente primero)
            const estadoOrder = { 'pendiente': 1, 'en_proceso': 2, 'gestionado': 3 };
            return (estadoOrder[a.estado] || 4) - (estadoOrder[b.estado] || 4);
        });

        let html = '';
        for (const asig of asignacionesOrdenadas) {
            const esIncidencia = asig.audio_disponible === false && asig.motivo_incidencia;

            let estadoBadge = '';
            let estadoClase = '';
            let acciones = '';

            if (esIncidencia) {
                estadoBadge = `<span class="badge" style="background: var(--danger);">⚠️ Incidencia</span>`;
                estadoClase = 'style="background: #fff0f0;"';
                acciones = `
                    <div style="display: flex; gap: 5px; flex-wrap: wrap;">
                        <button onclick="verDetalleIncidenciaEscucha(${asig.id})" 
                            style="background: var(--warning); padding: 4px 8px; font-size: 11px; border: none; border-radius: 6px; cursor: pointer;">
                            🔍 Ver
                        </button>
                        <button onclick="marcarIncidenciaResuelta(${asig.id})" 
                            style="background: var(--ok); padding: 4px 8px; font-size: 11px; border: none; border-radius: 6px; cursor: pointer;">
                            ✅ Resolver
                        </button>
                    </div>
                `;
            } else {
                switch (asig.estado) {
                    case 'pendiente':
                        estadoBadge = '<span class="badge" style="background: var(--warning);">⏳ Pendiente</span>';
                        break;
                    case 'en_proceso':
                        estadoBadge = '<span class="badge" style="background: var(--accent);">🔄 En proceso</span>';
                        break;
                    case 'gestionado':
                        estadoBadge = '<span class="badge" style="background: var(--ok);">✅ Gestionado</span>';
                        break;
                    default:
                        estadoBadge = `<span class="badge">${asig.estado}</span>`;
                }

                // Solo permitir reasignación si no está gestionado
                if (asig.estado !== 'gestionado') {
                    acciones = `
                        <button onclick="abrirModalReasignar(${asig.id}, '${escapeHtml(asig.ticket)}', '${escapeHtml(asig.auditor_asignado)}')" 
                                style="background: var(--warning); padding: 4px 8px; font-size: 11px; border: none; border-radius: 6px; cursor: pointer;">
                            🔄 Reasignar
                        </button>
                    `;
                } else {
                    acciones = `<span style="color: var(--muted); font-size: 11px;">-</span>`;
                }
            }

            // Mostrar motivo de incidencia si existe
            let motivoDisplay = '';
            if (asig.motivo_incidencia) {
                motivoDisplay = `<div style="font-size: 10px; color: var(--danger); margin-top: 3px;">📌 ${escapeHtml(asig.motivo_incidencia.substring(0, 50))}${asig.motivo_incidencia.length > 50 ? '...' : ''}</div>`;
            }

            // Mostrar información de reasignación si existe
            let reasignacionInfo = '';
            if (asig.fecha_reasignacion) {
                reasignacionInfo = `<div style="font-size: 9px; color: var(--accent); margin-top: 2px;">🔄 Reasignado: ${formatearFechaPeru(asig.fecha_reasignacion)}</div>`;
            }

            // 🔴 NUEVO: Mostrar a qué lote pertenece (solo si hay múltiples lotes)
            let loteInfo = '';
            if (asig.tarea_id) {
                loteInfo = `<div style="font-size: 9px; color: var(--muted); margin-top: 2px;">📦 Lote ID: ${asig.tarea_id}</div>`;
            }

            html += `
                <tr ${estadoClase}>
                    <td style="padding: 8px;">
                        <strong>${escapeHtml(asig.ticket || '-')}</strong>
                        ${motivoDisplay}
                        ${reasignacionInfo}
                        ${loteInfo}
                    </td>
                    <td style="padding: 8px;">${escapeHtml(asig.auditor_asignado || '-')}</td>
                    <td style="padding: 8px;">${escapeHtml(asig.supervisor_responsable || '-')}</td>
                    <td style="padding: 8px;">${escapeHtml(asig.gestor_auditado || '-')}</td>
                    <td style="padding: 8px; max-width: 150px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title="${escapeHtml(asig.motivos || '')}">
                        ${escapeHtml((asig.motivos || '-').substring(0, 30))}${(asig.motivos || '').length > 30 ? '...' : ''}
                    </td>
                    <td style="padding: 8px;">${estadoBadge}</td>
                    <td style="padding: 8px; white-space: nowrap;">${formatearFechaPeru(asig.fecha_asignacion)}</td>
                    <td style="padding: 8px; white-space: nowrap;">${formatearFechaPeru(asig.fecha_gestion)}</td>
                    <td style="padding: 8px; text-align: center;">${acciones}</td>
                </tr>
            `;
        }

        // Agregar fila de resumen al final
        const total = asignaciones.length;
        const pendientes = asignaciones.filter(a => a.estado === 'pendiente').length;
        const enProceso = asignaciones.filter(a => a.estado === 'en_proceso').length;
        const gestionados = asignaciones.filter(a => a.estado === 'gestionado').length;

        html += `
            <tr style="background: #f8f9fa; font-weight: bold;">
                <td colspan="9" style="padding: 10px;">
                    📊 Resumen: ${total} tickets totales | 
                    ⏳ ${pendientes} pendientes | 
                    🔄 ${enProceso} en proceso | 
                    ✅ ${gestionados} gestionados
                </td>
            </tr>
        `;

        tbody.innerHTML = html;
    }
    // ===== FIN FUNCIÓN: actualizarTablaMonitoreo ===========================
    
    // ===== 17. INICIO FUNCIÓN: actualizarTarjetasProgreso =================
    async function actualizarTarjetasProgreso(asignaciones) {
    const container = document.getElementById('tarjetasProgresoAuditores');
    if (!container) {
        console.warn('⚠️ tarjetasProgresoAuditores no encontrado');
        return;
    }

    try {
        const db = getDB();
        
        // 🔴 1. OBTENER TODOS LOS LOTES ACTIVOS
        let lotesActivos = [];
        let loteInfo = null;
        
        if (db) {
            try {
                const { data, error } = await db
                    .from('tareas_escucha')
                    .select('*')
                    .eq('estado', 'activo')
                    .order('id', { ascending: false });
                
                if (!error && data && data.length > 0) {
                    lotesActivos = data;
                    console.log(`📦 ${lotesActivos.length} lotes activos encontrados`);
                    lotesActivos.forEach(l => {
                        console.log(`   ID: ${l.id}, Archivo: ${l.nombre_archivo}, Tickets: ${l.total_registros}`);
                    });
                } else {
                    console.log('⚠️ No hay lotes activos');
                }
            } catch (err) {
                console.warn('Error obteniendo lotes activos:', err);
            }
        }

        // 🔴 SI NO HAY LOTES ACTIVOS, MOSTRAR MENSAJE
        if (lotesActivos.length === 0) {
            container.innerHTML = `
                <div style="
                    text-align: center; 
                    padding: 40px; 
                    background: #fff8e0; 
                    border-radius: 12px;
                    border: 1px solid #f39c12;
                ">
                    <div style="font-size: 48px; margin-bottom: 10px;">📦</div>
                    <strong style="font-size: 16px;">No hay lotes activos</strong>
                    <p style="margin-top: 5px; color: var(--muted);">
                        Cargue un archivo de escuchas para iniciar un nuevo lote.
                    </p>
                </div>
            `;
            return;
        }

        // 🔴 2. OBTENER TODAS LAS ASIGNACIONES
        let todasAsignaciones = asignaciones;
        
        if (!todasAsignaciones || todasAsignaciones.length === 0) {
            console.log('🔄 Obteniendo asignaciones de la BD...');
            const token = localStorage.getItem('meca_token');
            const response = await fetch('/api/escuchas/asignaciones', {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            
            if (response.ok) {
                todasAsignaciones = await response.json();
                console.log(`📊 ${todasAsignaciones?.length || 0} asignaciones obtenidas de la BD`);
            } else {
                console.warn('⚠️ Error obteniendo asignaciones:', response.status);
                container.innerHTML = '<div style="text-align: center; padding: 20px; color: var(--muted);">⚠️ No se pudieron cargar los datos</div>';
                return;
            }
        }

        // 🔴 3. FILTRAR ASIGNACIONES DE TODOS LOS LOTES ACTIVOS
        const idsLotesActivos = lotesActivos.map(l => l.id);
        const asignacionesFiltradas = todasAsignaciones.filter(a => idsLotesActivos.includes(a.tarea_id));
        
        console.log(`📊 ${asignacionesFiltradas.length} asignaciones de ${lotesActivos.length} lotes activos`);

        if (asignacionesFiltradas.length === 0) {
            container.innerHTML = `
                <div style="
                    text-align: center; 
                    padding: 40px; 
                    background: #f0f7ff; 
                    border-radius: 12px;
                    border: 1px solid #019DF4;
                ">
                    <div style="font-size: 48px; margin-bottom: 10px;">📭</div>
                    <strong style="font-size: 16px;">Los lotes activos no tienen tickets asignados</strong>
                    <p style="margin-top: 5px; color: var(--muted);">
                        ${lotesActivos.length} lote(s) activo(s) sin asignaciones.
                    </p>
                </div>
            `;
            return;
        }

        // 🔴 4. AGRUPAR POR AUDITOR (ACUMULADO DE TODOS LOS LOTES)
        const progresoPorAuditor = {};

        for (const asig of asignacionesFiltradas) {
            const auditor = asig.auditor_asignado || 'Sin asignar';
            if (!progresoPorAuditor[auditor]) {
                progresoPorAuditor[auditor] = {
                    total: 0,
                    pendiente: 0,
                    en_proceso: 0,
                    gestionado: 0,
                    incidencias: 0,
                    tickets: [],
                    lotes: new Set()
                };
            }

            progresoPorAuditor[auditor].total++;
            progresoPorAuditor[auditor].tickets.push(asig);
            progresoPorAuditor[auditor].lotes.add(asig.tarea_id);

            if (asig.estado === 'pendiente') {
                progresoPorAuditor[auditor].pendiente++;
            } else if (asig.estado === 'en_proceso') {
                progresoPorAuditor[auditor].en_proceso++;
            } else if (asig.estado === 'gestionado' || asig.estado === 'completado') {
                progresoPorAuditor[auditor].gestionado++;
            }

            if (asig.audio_disponible === false && asig.motivo_incidencia) {
                progresoPorAuditor[auditor].incidencias++;
            }
        }

        // 🔴 5. GENERAR HTML - TABLA CON TODOS LOS LOTES
        const auditoresOrdenados = Object.keys(progresoPorAuditor).sort((a, b) => {
            const pctA = (progresoPorAuditor[a].gestionado / progresoPorAuditor[a].total) * 100;
            const pctB = (progresoPorAuditor[b].gestionado / progresoPorAuditor[b].total) * 100;
            return pctB - pctA;
        });

        // Calcular totales generales
        let totalGeneral = 0;
        let pendientesGeneral = 0;
        let enProcesoGeneral = 0;
        let gestionadosGeneral = 0;
        let incidenciasGeneral = 0;

        for (const auditor of auditoresOrdenados) {
            const stats = progresoPorAuditor[auditor];
            totalGeneral += stats.total;
            pendientesGeneral += stats.pendiente;
            enProcesoGeneral += stats.en_proceso;
            gestionadosGeneral += stats.gestionado;
            incidenciasGeneral += stats.incidencias;
        }

        const avanceGeneral = totalGeneral > 0 ? ((gestionadosGeneral / totalGeneral) * 100).toFixed(1) : 0;

        // 🔴 MOSTRAR TODOS LOS LOTES ACTIVOS EN EL ENCABEZADO
        let lotesHtml = lotesActivos.map(l => {
            const nombre = l.nombre_archivo ? l.nombre_archivo.split('/').pop().split('\\').pop() : 'Sin nombre';
            return `<span style="background: rgba(255,255,255,0.15); padding: 2px 10px; border-radius: 12px; font-size: 11px; margin: 2px;">📄 ${escapeHtml(nombre)}</span>`;
        }).join(' ');

        let html = `
            <!-- Encabezado con todos los lotes -->
            <div style="
                background: linear-gradient(135deg, #019DF4, #00B4F0); 
                color: white; 
                padding: 12px 20px; 
                border-radius: 12px 12px 0 0;
                display: flex;
                justify-content: space-between;
                align-items: center;
                flex-wrap: wrap;
                gap: 10px;
            ">
                <div>
                    <strong style="font-size: 16px;">📦 ${lotesActivos.length} Lote(s) Activo(s)</strong>
                    <div style="font-size: 12px; margin-top: 4px; display: flex; gap: 5px; flex-wrap: wrap;">
                        ${lotesHtml}
                    </div>
                </div>
                <div style="display: flex; gap: 15px; font-size: 12px; flex-wrap: wrap;">
                    <span>📊 Total: <strong>${totalGeneral}</strong></span>
                    <span>⏳ Pendientes: <strong>${pendientesGeneral}</strong></span>
                    <span>🔄 En proceso: <strong>${enProcesoGeneral}</strong></span>
                    <span>✅ Gestionados: <strong>${gestionadosGeneral}</strong></span>
                    <span>⚠️ Incidencias: <strong style="color: #ff6b6b;">${incidenciasGeneral}</strong></span>
                    <span>📈 Avance: <strong>${avanceGeneral}%</strong></span>
                </div>
            </div>
            
            <!-- Barra de progreso general -->
            <div style="background: #f8f9fa; padding: 8px 20px; border-bottom: 1px solid #e0e0e0;">
                <div style="display: flex; align-items: center; gap: 10px;">
                    <span style="font-size: 12px; font-weight: 600; min-width: 60px;">Progreso:</span>
                    <div style="flex: 1; background: #e9ecef; border-radius: 10px; height: 12px; max-width: 400px;">
                        <div style="width: ${avanceGeneral}%; height: 100%; background: linear-gradient(90deg, #28a745, #20c997); border-radius: 10px; transition: width 0.5s;"></div>
                    </div>
                    <span style="font-size: 13px; font-weight: bold; color: #28a745;">${avanceGeneral}%</span>
                </div>
            </div>
            
            <!-- Tabla de auditores -->
            <div style="overflow-x: auto; border-radius: 0 0 12px 12px; border: 1px solid #e0e0e0; border-top: none;">
                <table style="width: 100%; border-collapse: collapse; font-size: 13px;">
                    <thead>
                        <tr style="background: #f8f9fa; border-bottom: 2px solid #e0e0e0;">
                            <th style="padding: 10px 12px; text-align: left; min-width: 150px;">👤 Auditor</th>
                            <th style="padding: 10px 12px; text-align: center; min-width: 60px;">📊 Total</th>
                            <th style="padding: 10px 12px; text-align: center; min-width: 60px;">⏳ Pend.</th>
                            <th style="padding: 10px 12px; text-align: center; min-width: 60px;">🔄 Prog.</th>
                            <th style="padding: 10px 12px; text-align: center; min-width: 60px;">✅ Hecho</th>
                            <th style="padding: 10px 12px; text-align: center; min-width: 60px;">⚠️ Inc.</th>
                            <th style="padding: 10px 12px; text-align: center; min-width: 100px;">📈 Avance</th>
                            <th style="padding: 10px 12px; text-align: center; min-width: 80px;">🎯 Estado</th>
                            <th style="padding: 10px 12px; text-align: center; min-width: 80px;">📦 Lotes</th>
                        </tr>
                    </thead>
                    <tbody>
        `;

        for (const auditor of auditoresOrdenados) {
            const stats = progresoPorAuditor[auditor];
            const porcentaje = stats.total > 0 ? ((stats.gestionado / stats.total) * 100).toFixed(1) : 0;
            
            let barColor = '#28a745';
            if (porcentaje < 30) barColor = '#d93025';
            else if (porcentaje < 60) barColor = '#f39c12';
            else if (porcentaje < 85) barColor = '#019DF4';

            let estadoTexto = '🟢 Activo';
            let estadoColor = '#28a745';
            if (stats.pendiente === stats.total && stats.total > 0) {
                estadoTexto = '🟡 Sin iniciar';
                estadoColor = '#f39c12';
            } else if (stats.gestionado === stats.total && stats.total > 0) {
                estadoTexto = '✅ Completado';
                estadoColor = '#28a745';
            } else if (stats.incidencias > 0) {
                estadoTexto = `⚠️ ${stats.incidencias} incidencia(s)`;
                estadoColor = '#d93025';
            }

            const tiempoEstimado = stats.total > 0 ? (stats.total * 15) : 0;
            const tiempoFormateado = tiempoEstimado > 60 ? `${Math.round(tiempoEstimado / 60)}h` : `${tiempoEstimado}min`;

            // 🔴 MOSTRAR CANTIDAD DE LOTES DEL AUDITOR
            const cantidadLotes = stats.lotes.size;

            html += `
                <tr style="border-bottom: 1px solid #f0f0f0;">
                    <td style="padding: 10px 12px;">
                        <strong>${escapeHtml(auditor)}</strong>
                        <div style="font-size: 10px; color: var(--muted);">⏱️ ${tiempoFormateado} estimado</div>
                    </td>
                    <td style="padding: 10px 12px; text-align: center; font-weight: bold;">${stats.total}</td>
                    <td style="padding: 10px 12px; text-align: center; color: var(--warning);">${stats.pendiente}</td>
                    <td style="padding: 10px 12px; text-align: center; color: var(--accent);">${stats.en_proceso}</td>
                    <td style="padding: 10px 12px; text-align: center; color: var(--ok); font-weight: bold;">${stats.gestionado}</td>
                    <td style="padding: 10px 12px; text-align: center; ${stats.incidencias > 0 ? 'color: var(--danger); font-weight: bold;' : 'color: var(--muted);'}">${stats.incidencias}</td>
                    <td style="padding: 10px 12px; text-align: center;">
                        <div style="display: flex; align-items: center; gap: 8px; justify-content: center;">
                            <div style="background: #e9ecef; border-radius: 10px; height: 8px; width: 80px;">
                                <div style="width: ${porcentaje}%; height: 100%; background: ${barColor}; border-radius: 10px; transition: width 0.3s;"></div>
                            </div>
                            <span style="font-size: 12px; font-weight: bold; color: ${barColor};">${porcentaje}%</span>
                        </div>
                    </td>
                    <td style="padding: 10px 12px; text-align: center;">
                        <span style="color: ${estadoColor}; font-weight: 500; font-size: 12px;">${estadoTexto}</span>
                    </td>
                    <td style="padding: 10px 12px; text-align: center; font-size: 12px;">
                        <span style="background: #e3f2fd; padding: 2px 10px; border-radius: 12px;">${cantidadLotes} lote(s)</span>
                    </td>
                </tr>
            `;
        }

        html += `
                    </tbody>
                </table>
            </div>
            
            <!-- Pie de tabla con resumen -->
            <div style="
                background: #f8f9fa; 
                padding: 10px 20px; 
                border-radius: 0 0 12px 12px;
                border: 1px solid #e0e0e0;
                border-top: none;
                display: flex;
                justify-content: space-between;
                align-items: center;
                flex-wrap: wrap;
                gap: 10px;
                font-size: 12px;
                color: var(--muted);
            ">
                <div>
                    📊 ${auditoresOrdenados.length} auditores activos | 
                    📋 ${totalGeneral} tickets totales |
                    📦 ${lotesActivos.length} lotes activos
                </div>
                <div>
                    ⏳ ${pendientesGeneral} pendientes | 
                    🔄 ${enProcesoGeneral} en proceso | 
                    ✅ ${gestionadosGeneral} gestionados
                    ${incidenciasGeneral > 0 ? `| ⚠️ ${incidenciasGeneral} incidencias` : ''}
                </div>
                <div>
                    📈 Avance general: <strong style="color: #28a745;">${avanceGeneral}%</strong>
                </div>
            </div>
        `;

        container.innerHTML = html;
        
        console.log(`✅ ${auditoresOrdenados.length} auditores mostrados - ${lotesActivos.length} lotes activos`);

    } catch (error) {
        console.error('❌ Error en actualizarTarjetasProgreso:', error);
        container.innerHTML = `<div style="text-align: center; padding: 20px; color: var(--danger);">❌ Error al cargar progreso: ${error.message}</div>`;
    }
}
    // ===== FIN FUNCIÓN: actualizarTarjetasProgreso =========================

    // ===== 18. INICIO FUNCIÓN: cargarSelectAuditoresFiltro ================
    async function cargarSelectAuditoresFiltro() {
        const auditores = await obtenerAuditoresActivos();
        const select = document.getElementById('filtroAuditorEscuchas');
        if (!select) return;

        const valorActual = select.value;
        select.innerHTML = '<option value="">Todos los auditores</option>';
        auditores.forEach(auditor => {
            select.innerHTML += `<option value="${escapeHtml(auditor.usuario)}" ${valorActual === auditor.usuario ? 'selected' : ''}>${escapeHtml(auditor.nombre)}</option>`;
        });
    }
    // ===== FIN FUNCIÓN: cargarSelectAuditoresFiltro ========================
    
    // ===== 19. INICIO FUNCIÓN: exportarReporteEscuchas ====================
    async function exportarReporteEscuchas() {
        const db = getDB();
        if (!db) return;

        try {
            const { data, error } = await db
                .from('asignaciones_escucha')
                .select('*')
                .order('fecha_asignacion', { ascending: false });

            if (error) throw error;

            if (!data || data.length === 0) {
                alert('No hay datos para exportar');
                return;
            }

            const headers = [
                'Ticket', 'Auditor Asignado', 'Supervisor Responsable', 'Gestor Auditado',
                'Motivos', 'Submotivos', 'Estado', 'Fecha Asignación', 'Fecha Gestión', 'Comentarios'
            ];

            const rows = data.map(row => [
                `"${(row.ticket || '').replace(/"/g, '""')}"`,
                `"${(row.auditor_asignado || '').replace(/"/g, '""')}"`,
                `"${(row.supervisor_responsable || '').replace(/"/g, '""')}"`,
                `"${(row.gestor_auditado || '').replace(/"/g, '""')}"`,
                `"${(row.motivos || '').replace(/"/g, '""')}"`,
                `"${(row.submotivos || '').replace(/"/g, '""')}"`,
                row.estado || 'pendiente',
                row.fecha_asignacion || '',
                row.fecha_gestion || '',
                `"${(row.comentarios || '').replace(/"/g, '""')}"`
            ]);

            const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
            const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `reporte_escuchas_${new Date().toISOString().slice(0, 10)}.csv`;
            a.click();
            URL.revokeObjectURL(url);

            alert(`✅ Exportadas ${data.length} asignaciones`);

        } catch (error) {
            console.error('Error exportando:', error);
            alert('❌ Error al exportar: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: exportarReporteEscuchas ============================

    // ===== 20. INICIO FUNCIÓN: abrirModalReasignar ========================
    let reasignacionActual = null;  // { id, ticket, auditorOrigen }
    async function abrirModalReasignar(id, ticket, auditorOrigen) {
        console.log(`🔄 Abriendo reasignación para ticket ${ticket} del auditor ${auditorOrigen}`);

        reasignacionActual = { id, ticket, auditorOrigen };

        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }

        try {
            // Obtener auditores disponibles (excluyendo al actual)
            const { data, error } = await db
                .from('usuarios')
                .select('usuario, nombre_completo')
                .eq('activo', true)
                .eq('rol', 'AUDITOR')
                .neq('usuario', auditorOrigen)
                .order('usuario', { ascending: true });

            if (error) throw error;

            // Filtrar auditores excluidos si existe la variable global
            let auditoresDisponibles = data || [];
            if (typeof auditoresExcluidosGlobal !== 'undefined' && auditoresExcluidosGlobal) {
                auditoresDisponibles = auditoresDisponibles.filter(a => !auditoresExcluidosGlobal.includes(a.usuario));
            }

            const select = document.getElementById('selectNuevoAuditor');
            if (select) {
                select.innerHTML = '<option value="">-- Seleccionar auditor --</option>';
                auditoresDisponibles.forEach(a => {
                    const nombreMostrar = a.nombre_completo || a.usuario;
                    select.innerHTML += `<option value="${escapeHtml(a.usuario)}">${escapeHtml(nombreMostrar)} (${escapeHtml(a.usuario)})</option>`;
                });
            }

            // Mostrar información del ticket
            const infoDiv = document.getElementById('reasignarInfo');
            if (infoDiv) {
                infoDiv.innerHTML = `
                    <div style="display: flex; flex-direction: column; gap: 5px;">
                        <div><strong>🎫 Ticket PSI:</strong> <span style="font-family: monospace;">${escapeHtml(ticket)}</span></div>
                        <div><strong>👤 Auditor actual:</strong> ${escapeHtml(auditorOrigen)}</div>
                        <div style="font-size: 12px; color: var(--muted); margin-top: 5px;">⚠️ La reasignación mantendrá el historial original de la escucha</div>
                    </div>
                `;
            }

            document.getElementById('reasignarMotivo').value = '';
            document.getElementById('modalReasignarEscucha').style.display = 'flex';

        } catch (error) {
            console.error('Error cargando auditores:', error);
            alert('❌ Error al cargar auditores: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: abrirModalReasignar ================================
    
    // ===== 21. INICIO FUNCIÓN: cerrarModalReasignar =======================
    function cerrarModalReasignar() {
        document.getElementById('modalReasignarEscucha').style.display = 'none';
        reasignacionActual = null;
        document.getElementById('selectNuevoAuditor').value = '';
        document.getElementById('reasignarMotivo').value = '';
    }
    // ===== FIN FUNCIÓN: cerrarModalReasignar ===============================

    // ===== 22. INICIO FUNCIÓN: confirmarReasignacion ======================
    async function confirmarReasignacion() {
        if (!reasignacionActual) {
            alert('❌ No hay una reasignación activa');
            return;
        }

        const nuevoAuditor = document.getElementById('selectNuevoAuditor').value;
        const motivo = document.getElementById('reasignarMotivo').value.trim();

        if (!nuevoAuditor) {
            alert('⚠️ Seleccione un nuevo auditor');
            return;
        }

        if (nuevoAuditor === reasignacionActual.auditorOrigen) {
            alert('⚠️ El nuevo auditor no puede ser el mismo que el actual');
            return;
        }

        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }

        const confirmar = confirm(
            `⚠️ ¿REASIGNAR TICKET?\n\n` +
            `🎫 Ticket: ${reasignacionActual.ticket}\n` +
            `👤 De: ${reasignacionActual.auditorOrigen}\n` +
            `👤 A: ${nuevoAuditor}\n` +
            `📝 Motivo: ${motivo || 'No especificado'}\n\n` +
            `¿Desea continuar?`
        );

        if (!confirmar) return;

        try {
            // 🔴 SOLO ACTUALIZAR LA ASIGNACIÓN (sin historial)
            const { error: updateError } = await db
                .from('asignaciones_escucha')
                .update({
                    auditor_asignado: nuevoAuditor,
                    fecha_reasignacion: new Date().toISOString(),
                    motivo_reasignacion: motivo || 'Reasignación por supervisor',
                    updated_at: new Date().toISOString()
                })
                .eq('id', reasignacionActual.id);

            if (updateError) throw updateError;

            // ✅ Eliminar o comentar todo el bloque de historial_reasignaciones
            // No es necesario crear ni insertar en historial_reasignaciones

            alert(`✅ Ticket ${reasignacionActual.ticket} reasignado exitosamente a ${nuevoAuditor}`);

            await refrescarMonitoreoEscuchas();
            cerrarModalReasignar();

        } catch (error) {
            console.error('❌ Error en reasignación:', error);
            alert('❌ Error al reasignar: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: confirmarReasignacion ==============================
    
    // ===== 23. INICIO FUNCIÓN: abrirModalReasignarMasiva ==================
    async function abrirModalReasignarMasiva() {
        console.log('🔄 Abriendo modal de reasignación masiva...');

        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }

        try {
            // Obtener auditores activos
            const { data, error } = await db
                .from('usuarios')
                .select('usuario, nombre_completo')
                .eq('activo', true)
                .eq('rol', 'AUDITOR')
                .order('usuario', { ascending: true });

            if (error) throw error;

            const auditores = data || [];

            // Llenar select de auditor origen
            const selectOrigen = document.getElementById('selectAuditorOrigen');
            if (selectOrigen) {
                selectOrigen.innerHTML = '<option value="">-- Seleccionar auditor --</option>';
                auditores.forEach(a => {
                    const nombreMostrar = a.nombre_completo || a.usuario;
                    selectOrigen.innerHTML += `<option value="${escapeHtml(a.usuario)}">${escapeHtml(nombreMostrar)} (${escapeHtml(a.usuario)})</option>`;
                });
            }

            // Llenar select de auditor destino
            const selectDestino = document.getElementById('selectAuditorDestino');
            if (selectDestino) {
                selectDestino.innerHTML = '<option value="">-- Seleccionar auditor --</option>';
                auditores.forEach(a => {
                    const nombreMostrar = a.nombre_completo || a.usuario;
                    selectDestino.innerHTML += `<option value="${escapeHtml(a.usuario)}">${escapeHtml(nombreMostrar)} (${escapeHtml(a.usuario)})</option>`;
                });
            }

            // Resetear valores
            document.getElementById('reasignarMasivaMotivo').value = '';
            document.getElementById('selectEstadoReasignar').value = 'todos';
            document.getElementById('resumenReasignacionMasiva').style.display = 'none';
            document.getElementById('btnConfirmarReasignacionMasiva').disabled = true;

            // Agregar event listeners para calcular resumen
            selectOrigen.addEventListener('change', calcularResumenReasignacionMasiva);
            document.getElementById('selectEstadoReasignar').addEventListener('change', calcularResumenReasignacionMasiva);

            document.getElementById('modalReasignarMasiva').style.display = 'flex';

        } catch (error) {
            console.error('Error cargando auditores:', error);
            alert('❌ Error al cargar auditores: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: abrirModalReasignarMasiva ==========================

    // ===== 24. INICIO FUNCIÓN: calcularResumenReasignacionMasiva ==========
    async function calcularResumenReasignacionMasiva() {
        const auditorOrigen = document.getElementById('selectAuditorOrigen').value;
        const estadoFiltro = document.getElementById('selectEstadoReasignar').value;
        const btnConfirmar = document.getElementById('btnConfirmarReasignacionMasiva');
        const resumenDiv = document.getElementById('resumenReasignacionMasiva');

        if (!auditorOrigen) {
            if (resumenDiv) resumenDiv.style.display = 'none';
            if (btnConfirmar) btnConfirmar.disabled = true;
            return;
        }

        const db = getDB();
        if (!db) return;

        try {
            let query = db
                .from('asignaciones_escucha')
                .select('id, ticket, gestor_auditado, estado')
                .eq('auditor_asignado', auditorOrigen);

            if (estadoFiltro !== 'todos') {
                query = query.eq('estado', estadoFiltro);
            } else {
                query = query.in('estado', ['pendiente', 'en_proceso']);
            }

            const { data, error } = await query;

            if (error) throw error;

            const tickets = data || [];
            const countPendientes = tickets.filter(t => t.estado === 'pendiente').length;
            const countEnProceso = tickets.filter(t => t.estado === 'en_proceso').length;

            if (tickets.length === 0) {
                resumenDiv.innerHTML = `
                    <div style="color: var(--danger);">
                        ⚠️ No hay tickets pendientes o en proceso para el auditor seleccionado.
                    </div>
                `;
                resumenDiv.style.display = 'block';
                btnConfirmar.disabled = true;
                return;
            }

            // Obtener nombre del auditor
            const { data: auditorData } = await db
                .from('usuarios')
                .select('nombre_completo')
                .eq('usuario', auditorOrigen)
                .single();

            const nombreAuditor = auditorData?.nombre_completo || auditorOrigen;

            resumenDiv.innerHTML = `
                <div style="font-weight: bold; margin-bottom: 8px;">📊 Resumen de tickets a reasignar:</div>
                <div style="display: flex; gap: 15px; flex-wrap: wrap;">
                    <div><strong>👤 Auditor origen:</strong> ${escapeHtml(nombreAuditor)}</div>
                    <div><strong>📋 Total tickets:</strong> ${tickets.length}</div>
                    <div><strong>⏳ Pendientes:</strong> ${countPendientes}</div>
                    <div><strong>🔄 En proceso:</strong> ${countEnProceso}</div>
                </div>
                <div style="margin-top: 8px; font-size: 11px; color: var(--muted);">
                    💡 Los tickets gestionados (✅) no serán reasignados.
                </div>
            `;
            resumenDiv.style.display = 'block';
            btnConfirmar.disabled = false;

            // Guardar los tickets en variable global para la confirmación
            window.ticketsReasignarMasiva = tickets;

        } catch (error) {
            console.error('Error calculando resumen:', error);
            resumenDiv.innerHTML = `<div style="color: var(--danger);">❌ Error: ${error.message}</div>`;
            resumenDiv.style.display = 'block';
            btnConfirmar.disabled = true;
        }
    }
    // ===== FIN FUNCIÓN: calcularResumenReasignacionMasiva ==================

    // ===== 25. INICIO FUNCIÓN: confirmarReasignacionMasiva ================
    async function confirmarReasignacionMasiva() {
        const auditorOrigen = document.getElementById('selectAuditorOrigen').value;
        const auditorDestino = document.getElementById('selectAuditorDestino').value;
        const motivo = document.getElementById('reasignarMasivaMotivo').value.trim();
        const estadoFiltro = document.getElementById('selectEstadoReasignar').value;

        if (!auditorOrigen) {
            alert('⚠️ Seleccione un auditor origen');
            return;
        }

        if (!auditorDestino) {
            alert('⚠️ Seleccione un auditor destino');
            return;
        }

        if (auditorOrigen === auditorDestino) {
            alert('⚠️ El auditor origen y destino no pueden ser el mismo');
            return;
        }

        if (!window.ticketsReasignarMasiva || window.ticketsReasignarMasiva.length === 0) {
            alert('⚠️ No hay tickets para reasignar');
            return;
        }

        const totalTickets = window.ticketsReasignarMasiva.length;
        const confirmar = confirm(
            `⚠️ REASIGNACIÓN MASIVA\n\n` +
            `Está a punto de reasignar ${totalTickets} tickets:\n` +
            `👤 De: ${auditorOrigen}\n` +
            `👤 A: ${auditorDestino}\n` +
            `📝 Motivo: ${motivo || 'No especificado'}\n\n` +
            `Esta acción NO se puede deshacer fácilmente.\n\n` +
            `¿Desea continuar?`
        );

        if (!confirmar) return;

        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }

        const btnConfirmar = document.getElementById('btnConfirmarReasignacionMasiva');
        const textoOriginal = btnConfirmar?.innerHTML;
        if (btnConfirmar) {
            btnConfirmar.innerHTML = '⏳ Reasignando...';
            btnConfirmar.disabled = true;
        }

        let exitosos = 0;
        let errores = [];

        for (const ticket of window.ticketsReasignarMasiva) {
            try {
                const { error } = await db
                    .from('asignaciones_escucha')
                    .update({
                        auditor_asignado: auditorDestino,
                        fecha_reasignacion: new Date().toISOString(),
                        motivo_reasignacion: motivo || `Reasignación masiva desde ${auditorOrigen}`,
                        updated_at: new Date().toISOString()
                    })
                    .eq('id', ticket.id);

                if (error) throw error;
                exitosos++;

                // Pequeña pausa para no saturar la BD
                await new Promise(resolve => setTimeout(resolve, 50));

            } catch (error) {
                console.error(`Error reasignando ticket ${ticket.id}:`, error);
                errores.push(`Ticket ${ticket.ticket || ticket.id}: ${error.message}`);
            }
        }

        // Guardar en historial (opcional)
        try {
            await db
                .from('historial_reasignaciones')
                .insert({
                    id: Date.now(),
                    asignacion_id: 0, // Para indicar que es masiva
                    ticket: `MASIVA_${totalTickets}_tickets`,
                    auditor_origen: auditorOrigen,
                    auditor_destino: auditorDestino,
                    motivo: motivo || `Reasignación masiva - ${totalTickets} tickets`,
                    reasignado_por: window.usuarioActual?.usuario || 'supervisor',
                    fecha_reasignacion: new Date().toISOString()
                });
        } catch (logError) {
            console.warn('Historial no guardado:', logError);
        }

        if (btnConfirmar) {
            btnConfirmar.innerHTML = textoOriginal;
            btnConfirmar.disabled = false;
        }

        let mensaje = `✅ REASIGNACIÓN MASIVA COMPLETADA\n\n`;
        mensaje += `📊 Tickets reasignados: ${exitosos} de ${totalTickets}\n`;
        mensaje += `👤 De: ${auditorOrigen}\n`;
        mensaje += `👤 A: ${auditorDestino}\n`;

        if (errores.length > 0) {
            mensaje += `\n⚠️ Errores (${errores.length}):\n${errores.slice(0, 5).join('\n')}`;
            if (errores.length > 5) mensaje += `\n... y ${errores.length - 5} más`;
        }

        alert(mensaje);

        // Cerrar modal y refrescar
        cerrarModalReasignarMasiva();
        await refrescarMonitoreoEscuchas();

        // Limpiar variable global
        window.ticketsReasignarMasiva = null;
    }
    // ===== FIN FUNCIÓN: confirmarReasignacionMasiva ========================

    // ===== 26. INICIO FUNCIÓN: cerrarModalReasignarMasiva =================
    function cerrarModalReasignarMasiva() {
        document.getElementById('modalReasignarMasiva').style.display = 'none';
        document.getElementById('selectAuditorOrigen').value = '';
        document.getElementById('selectAuditorDestino').value = '';
        document.getElementById('reasignarMasivaMotivo').value = '';
        document.getElementById('selectEstadoReasignar').value = 'todos';
        document.getElementById('resumenReasignacionMasiva').style.display = 'none';
        window.ticketsReasignarMasiva = null;
    }
