    // ===== 27. INICIO FUNCIÓN: verDetalleIncidenciaEscucha ================
    async function verDetalleIncidenciaEscucha(id) {
        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }

        try {
            const { data: escucha, error } = await db
                .from('asignaciones_escucha')
                .select('*')
                .eq('id', id)
                .single();

            if (error) throw error;

            let mensaje = `⚠️ DETALLE DE INCIDENCIA DE AUDIO\n`;
            mensaje += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;
            mensaje += `🎫 Ticket PSI: ${escucha.ticket}\n`;
            mensaje += `👤 Gestor auditado: ${escucha.gestor_auditado || '-'}\n`;
            mensaje += `👥 Auditor asignado: ${escucha.auditor_asignado || '-'}\n`;
            mensaje += `📅 Fecha asignación: ${formatearFechaPeru(escucha.fecha_asignacion)}\n`;
            mensaje += `📅 Fecha reporte: ${formatearFechaPeru(escucha.fecha_incidencia)}\n`;
            mensaje += `📌 Motivo: ${escucha.motivo_incidencia || 'No especificado'}\n\n`;

            mensaje += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
            mensaje += `📌 Instrucciones:\n`;
            mensaje += `1. Verificar si el audio ya está disponible en el repositorio\n`;
            mensaje += `2. Si está disponible, marcar como "Resuelto"\n`;
            mensaje += `3. El ticket volverá a la lista de pendientes del auditor\n`;

            alert(mensaje);

        } catch (error) {
            console.error('Error:', error);
            alert('❌ Error al cargar detalle: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: verDetalleIncidenciaEscucha ========================

    // ===== 28. INICIO FUNCIÓN: marcarIncidenciaResuelta ===================
    async function marcarIncidenciaResuelta(id) {
        const confirmar = confirm(`✅ ¿Confirmar que el audio ya está disponible?\n\nEsta acción:\n• Marcará la incidencia como resuelta\n• El ticket volverá a estar disponible para el auditor\n\n¿Desea continuar?`);

        if (!confirmar) return;

        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }

        try {
            // Actualizar: audio disponible, limpiar motivo de incidencia
            const { error } = await db
                .from('asignaciones_escucha')
                .update({
                    audio_disponible: true,
                    motivo_incidencia: null,
                    fecha_incidencia: null,
                    updated_at: new Date().toISOString()
                })
                .eq('id', id);

            if (error) throw error;

            alert('✅ Incidencia resuelta correctamente.\n\nEl ticket ahora está disponible para el auditor.');

            // Refrescar la tabla de monitoreo
            await refrescarMonitoreoEscuchas();

        } catch (error) {
            console.error('Error:', error);
            alert('❌ Error al resolver incidencia: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: marcarIncidenciaResuelta ===========================

    // ===== 29. INICIO FUNCIÓN: cargarHistorialLotes =======================
    let lotesHistorialGlobal = [];
    let loteSeleccionadoId = null;            
    async function cargarHistorialLotes() {
        console.log('📦 Cargando historial de lotes...');

        const tbody = document.getElementById('tablaHistorialLotes');
        if (!tbody) {
            console.error('❌ Tabla historial no encontrada');
            return;
        }

        try {
            // 🔴 CAMBIO: Usar PostgreSQL directo en lugar de API
            const db = getDB();
            if (!db) {
                console.error('❌ Base de datos no disponible');
                tbody.innerHTML = '<tr><td colspan="12" style="text-align: center; color: var(--danger);">❌ Base de datos no disponible</td></tr>';
                return;
            }

            // Obtener lotes desde PostgreSQL
            const { data: lotes, error } = await db
                .from('tareas_escucha')
                .select('*')
                .order('fecha_carga', { ascending: false });

            if (error) {
                console.error('❌ Error obteniendo lotes:', error);
                tbody.innerHTML = `<tr><td colspan="12" style="text-align: center; color: var(--danger);">❌ Error: ${error.message}</td></tr>`;
                return;
            }

            if (!lotes || lotes.length === 0) {
                tbody.innerHTML = '<tr><td colspan="12" style="text-align: center; padding: 40px;">📭 No hay lotes cargados aún. Cargue su primer archivo de escuchas.</td></tr>';
                window.lotesHistorialGlobal = [];
                return;
            }

            // Para cada lote, obtener estadísticas de asignaciones
            const lotesConEstadisticas = [];
            for (const lote of lotes) {
                const { data: asignaciones, error: asigError } = await db
                    .from('asignaciones_escucha')
                    .select('estado')
                    .eq('tarea_id', lote.id);

                if (asigError) {
                    console.warn(`Error obteniendo asignaciones para lote ${lote.id}:`, asigError);
                    lotesConEstadisticas.push({
                        ...lote,
                        total: 0,
                        pendientes: 0,
                        enProceso: 0,
                        gestionados: 0,
                        incidencias: 0,
                        avance: 0
                    });
                    continue;
                }

                const total = asignaciones?.length || 0;
                const pendientes = asignaciones?.filter(a => a.estado === 'pendiente').length || 0;
                const enProceso = asignaciones?.filter(a => a.estado === 'en_proceso').length || 0;
                const gestionados = asignaciones?.filter(a => a.estado === 'gestionado').length || 0;
                const incidencias = asignaciones?.filter(a => a.audio_disponible === false && a.motivo_incidencia).length || 0;
                const avance = total > 0 ? Math.round((gestionados / total) * 100) : 0;

                lotesConEstadisticas.push({
                    ...lote,
                    total,
                    pendientes,
                    enProceso,
                    gestionados,
                    incidencias,
                    avance
                });
            }

            // Guardar globalmente
            window.lotesHistorialGlobal = lotesConEstadisticas;

            // Generar HTML de la tabla
            let html = '';
            for (let i = 0; i < lotesConEstadisticas.length; i++) {
                const lote = lotesConEstadisticas[i];
                
                const fechaStr = lote.fecha_carga ? new Date(lote.fecha_carga).toLocaleString('es-ES') : 'Fecha desconocida';
                const esActivo = lote.estado === 'activo';
                
                let nombreArchivo = '-';
                if (lote.nombre_archivo) {
                    nombreArchivo = lote.nombre_archivo.split('/').pop().split('\\').pop() || lote.nombre_archivo;
                }

                const total = lote.total || 0;
                const pendientes = lote.pendientes || 0;
                const enProceso = lote.enProceso || 0;
                const gestionados = lote.gestionados || 0;
                const incidencias = lote.incidencias || 0;
                const avance = lote.avance || 0;
                
                let colorBarra = '#28a745';
                if (avance < 50) colorBarra = '#d93025';
                else if (avance < 80) colorBarra = '#f39c12';

                const rowStyle = esActivo ? 'style="background: #e8f5e9;"' : '';

                html += `
                    <tr onclick="seleccionarLoteHistorial(${lote.id})" style="cursor: pointer;" ${rowStyle}>
                        <td style="padding: 8px; text-align: center;">${i + 1}</td>
                        <td style="padding: 8px; white-space: nowrap;">${escapeHtml(fechaStr)}</td>
                        <td style="padding: 8px; max-width: 250px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title="${escapeHtml(lote.nombre_archivo || '-')}">
                            ${escapeHtml(nombreArchivo)}
                        </td>
                        <td style="padding: 8px; text-align: center; font-weight: bold;">${total}</td>
                        <td style="padding: 8px; text-align: center; color: var(--warning);">${pendientes}</td>
                        <td style="padding: 8px; text-align: center; color: var(--accent);">${enProceso}</td>
                        <td style="padding: 8px; text-align: center; color: var(--ok);">${gestionados}</td>
                        <td style="padding: 8px; text-align: center; ${incidencias > 0 ? 'color: var(--danger); font-weight: bold;' : 'color: var(--muted);'}">
                            ${incidencias}
                        </td>
                        <td style="padding: 8px; text-align: center;">
                            <div style="display: inline-flex; align-items: center; gap: 5px;">
                                <div style="background: #e9ecef; border-radius: 10px; height: 6px; width: 60px;">
                                    <div style="width: ${avance}%; height: 100%; background: ${colorBarra}; border-radius: 10px;"></div>
                                </div>
                                <span style="font-size: 11px;">${avance}%</span>
                            </div>
                        </td>
                        <td style="padding: 8px; text-align: center;">
                            ${esActivo ? '<span class="badge" style="background: var(--ok);">✅ Activo</span>' : '<span class="badge" style="background: var(--muted);">⏸️ Inactivo</span>'}
                        </td>
                        <td style="padding: 8px; text-align: center; white-space: nowrap;">
                            <button onclick="event.stopPropagation(); verDetalleLote(${lote.id})" 
                                    style="background: var(--accent); padding: 4px 8px; font-size: 11px; border-radius: 6px; border: none; cursor: pointer;">
                                👁️ Ver tickets
                            </button>
                        </td>
                        <td style="padding: 8px; text-align: center;">
                            <button onclick="event.stopPropagation(); eliminarLote(${lote.id})" 
                                    style="background: #dc3545; color: white; padding: 4px 8px; font-size: 11px; border-radius: 6px; border: none; cursor: pointer;">
                                🗑️
                            </button>
                        </td>
                    </tr>
                `;
            }

            tbody.innerHTML = html;
            console.log(`✅ Historial de lotes cargado: ${lotesConEstadisticas.length} lotes`);

        } catch (error) {
            console.error('❌ Error cargando historial:', error);
            tbody.innerHTML = `<tr><td colspan="12" style="text-align: center; color: var(--danger);">❌ Error: ${error.message}</td></tr>`;
        }
    }
    // ===== FIN FUNCIÓN: cargarHistorialLotes ===============================
    
    // ===== 30. INICIO FUNCIÓN: actualizarTablaHistorialLotes ==============
    function actualizarTablaHistorialLotes(lotes) {
        const tbody = document.getElementById('tablaHistorialLotes');
        if (!tbody) return;

        if (!lotes || lotes.length === 0) {
            tbody.innerHTML = '<tr><td colspan="12" style="text-align: center;">📭 No hay lotes cargados<\/td><\/tr>';
            return;
        }

        let html = '';
        lotes.forEach((lote, idx) => {
            const fecha = new Date(lote.fecha_carga).toLocaleString('es-ES');
            const esActivo = lote.estado === 'activo';
            const tieneError = lote.error === true;

            let colorBarra = '#28a745';
            if (lote.avance < 50) colorBarra = '#d93025';
            else if (lote.avance < 80) colorBarra = '#f39c12';

            const rowClass = esActivo ? 'style="background: #e8f5e9;"' : '';
            const rowCursor = 'style="cursor: pointer;"';

            const nombreArchivo = lote.nombre_archivo ? lote.nombre_archivo.split('/').pop().split('\\').pop() : '-';

            html += `
                <tr onclick="seleccionarLoteHistorial(${lote.id})" ${rowClass} ${rowCursor}>
                    <td style="padding: 8px; text-align: center;">${idx + 1}</td>
                    <td style="padding: 8px; white-space: nowrap;">${fecha}</td>
                    <td style="padding: 8px; max-width: 250px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title="${escapeHtml(lote.nombre_archivo || '-')}">
                        ${escapeHtml(nombreArchivo)}
                    </td>
                    <td style="padding: 8px; text-align: center; font-weight: bold;">${tieneError ? '?' : lote.total}</td>
                    <td style="padding: 8px; text-align: center; color: var(--warning);">${tieneError ? '?' : lote.pendientes}</td>
                    <td style="padding: 8px; text-align: center; color: var(--accent);">${tieneError ? '?' : lote.enProceso}</td>
                    <td style="padding: 8px; text-align: center; color: var(--ok);">${tieneError ? '?' : lote.gestionados}</td>
                    <td style="padding: 8px; text-align: center; ${lote.incidencias > 0 ? 'color: var(--danger); font-weight: bold;' : 'color: var(--muted);'}">
                        ${tieneError ? '?' : lote.incidencias}
                    </td>
                    <td style="padding: 8px; text-align: center;">
                        ${tieneError ?
                    '<span style="color: var(--danger);">Error</span>' :
                    `<div style="display: inline-flex; align-items: center; gap: 5px;">
                                <div style="background: #e9ecef; border-radius: 10px; height: 6px; width: 60px;">
                                    <div style="width: ${lote.avance}%; height: 100%; background: ${colorBarra}; border-radius: 10px;"></div>
                                </div>
                                <span style="font-size: 11px;">${lote.avance}%</span>
                            </div>`
                }
                    </td>
                    <td style="padding: 8px; text-align: center;">
                        ${esActivo
                    ? '<span class="badge" style="background: var(--ok);">✅ Activo</span>'
                    : '<span class="badge" style="background: var(--muted);">⏸️ Inactivo</span>'}
                    </td>
                    <td style="padding: 8px; text-align: center; white-space: nowrap;">
                        <button onclick="event.stopPropagation(); verDetalleLote(${lote.id})" 
                                style="background: var(--accent); padding: 4px 8px; font-size: 11px; border-radius: 6px;">
                            👁️ Ver tickets
                        </button>
                        ${!esActivo && !tieneError ? `
                        <button onclick="event.stopPropagation(); activarLote(${lote.id})" 
                                style="background: var(--warning); padding: 4px 8px; font-size: 11px; border-radius: 6px; margin-left: 5px;">
                            📌 Activar
                        </button>
                        ` : ''}
                    </td>
                    <!-- 🔴 BOTÓN DE ELIMINAR - AGREGADO AQUÍ -->
                    <td style="padding: 8px; text-align: center;">
                        <button onclick="event.stopPropagation(); eliminarLote(${lote.id})" 
                                style="background: #dc3545; color: white; padding: 4px 8px; font-size: 11px; border-radius: 6px; border: none; cursor: pointer;"
                                title="Eliminar lote y todos sus tickets">
                            🗑️
                        </button>
                    </td>
                </tr>
            `;
        });

        tbody.innerHTML = html;
    }
    // ===== FIN FUNCIÓN: actualizarTablaHistorialLotes ======================
    
    // ===== 31. INICIO FUNCIÓN: seleccionarLoteHistorial ===================
    async function seleccionarLoteHistorial(loteId) {
        console.log(`📌 Seleccionado lote ID: ${loteId}`);
        loteSeleccionadoId = loteId;

        // Cambiar estilo de la fila seleccionada (remover selección anterior)
        document.querySelectorAll('#tablaHistorialLotes tr').forEach(row => {
            row.style.background = '';
            row.style.fontWeight = 'normal';
        });

        // Resaltar la fila seleccionada
        const filas = document.querySelectorAll('#tablaHistorialLotes tr');
        for (const fila of filas) {
            if (fila.textContent.includes(loteId) || fila.cells?.[0]?.textContent === String(loteId)) {
                fila.style.background = '#e3f2fd';
                fila.style.fontWeight = 'bold';
                break;
            }
        }

        // Cargar los tickets de este lote
        await cargarTicketsPorLote(loteId);
    }
    // ===== FIN FUNCIÓN: seleccionarLoteHistorial ===========================
    
    // ===== 32. INICIO FUNCIÓN: cargarTicketsPorLote =======================
    async function cargarTicketsPorLote(loteId) {
        console.log(`📋 Cargando tickets del lote ${loteId}...`);

        const tbody = document.getElementById('tablaMonitoreoEscuchas');
        if (tbody) {
            tbody.innerHTML = `<tr><td colspan="9" style="text-align: center; padding: 40px;">⏳ Cargando tickets del lote...<\/td><\/tr>`;
        }

        try {
            // 🔴 CAMBIO: Usar API en lugar de PostgreSQL directo
            const tickets = await API.getTicketsPorLote(loteId);
            
            // Buscar información del lote para mostrar contexto
            const lote = window.lotesHistorialGlobal?.find(l => l.id === loteId);

            // Mostrar estos tickets en la tabla de monitoreo
            mostrarTicketsConContextoLote(tickets || [], lote);

            console.log(`✅ ${tickets?.length || 0} tickets cargados del lote ${loteId}`);

        } catch (error) {
            console.error('Error cargando tickets:', error);
            if (tbody) {
                tbody.innerHTML = `<tr><td colspan="9" style="text-align: center; color: var(--danger);">❌ Error: ${error.message}<\/td><\/tr>`;
            }
        }
    }
    // ===== FIN FUNCIÓN: cargarTicketsPorLote ===============================
    
    // ===== 33. INICIO FUNCIÓN: mostrarTicketsConContextoLote ==============
    function mostrarTicketsConContextoLote(asignaciones, lote) {
        const tbody = document.getElementById('tablaMonitoreoEscuchas');
        if (!tbody) return;

        const esLoteActivo = lote?.estado === 'activo';
        const nombreArchivo = lote?.nombre_archivo ? lote.nombre_archivo.split('/').pop().split('\\').pop() : 'Desconocido';
        const fechaLote = lote?.fecha_carga ? new Date(lote.fecha_carga).toLocaleString('es-ES') : 'Fecha desconocida';

        // Mostrar contexto del lote actual
        let html = `
            <div style="background: ${esLoteActivo ? '#e8f5e9' : '#fff3e0'}; padding: 10px 12px; margin-bottom: 15px; border-radius: 8px; border-left: 4px solid ${esLoteActivo ? '#28a745' : '#f39c12'};">
                <div style="display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 10px;">
                    <div>
                        <strong>📦 Lote actual:</strong> ${escapeHtml(nombreArchivo)}
                        <div style="font-size: 11px; color: var(--muted); margin-top: 3px;">
                            📅 Cargado: ${fechaLote} | 
                            🆔 ID: ${lote?.id} | 
                            ${esLoteActivo ? '✅ Este es el LOTE ACTIVO' : '⚠️ Este es un LOTE HISTÓRICO (solo consulta)'}
                        </div>
                    </div>
                    ${!esLoteActivo ? `
                    <button onclick="activarLote(${lote?.id})" style="background: var(--warning); padding: 6px 12px; font-size: 12px;">
                        📌 Activar este lote
                    </button>
                    ` : ''}
                </div>
            </div>
        `;

        if (!asignaciones || asignaciones.length === 0) {
            html += `<div style="text-align: center; padding: 40px; color: var(--muted);">📭 No hay tickets en este lote</div>`;
            tbody.innerHTML = html;
            return;
        }

        // Generar tabla de tickets
        html += `
            <table style="width: 100%; min-width: 800px; font-size: 13px; border-collapse: collapse;">
                <thead>
                    <tr>
                        <th style="padding: 8px;">Ticket</th>
                        <th style="padding: 8px;">Auditor</th>
                        <th style="padding: 8px;">Supervisor</th>
                        <th style="padding: 8px;">Gestor</th>
                        <th style="padding: 8px;">Motivos</th>
                        <th style="padding: 8px;">Estado</th>
                        <th style="padding: 8px;">Fec. Asignación</th>
                        <th style="padding: 8px;">Fec. Gestión</th>
                        <th style="padding: 8px;">Acciones</th>
                    </tr>
                </thead>
                <tbody>
        `;

        for (const asig of asignaciones) {
            const esIncidencia = asig.audio_disponible === false && asig.motivo_incidencia;

            let estadoBadge = '';
            let acciones = '';

            if (esIncidencia) {
                estadoBadge = `<span class="badge" style="background: var(--danger);">⚠️ Incidencia</span>`;
                acciones = `
                    <button onclick="verDetalleIncidenciaEscucha(${asig.id})" 
                            style="background: var(--warning); padding: 4px 8px; font-size: 11px; border-radius: 6px;">
                        🔍 Ver
                    </button>
                `;
            } else {
                switch (asig.estado) {
                    case 'pendiente':
                        estadoBadge = '<span class="badge" style="background: var(--warning);">⏳ Pendiente</span>';
                        break;
                    case 'en_proceso':
                        estadoBadge = '<span class="badge" style="background: var(--accent);">🔄 En proceso</span>';
                        break;
                    case 'gestionado':
                        estadoBadge = '<span class="badge" style="background: var(--ok);">✅ Gestionado</span>';
                        break;
                    default:
                        estadoBadge = `<span class="badge">${asig.estado}</span>`;
                }

                // Solo permitir reasignación si el lote está activo
                if (asig.estado !== 'gestionado' && esLoteActivo) {
                    acciones = `
                        <button onclick="abrirModalReasignar(${asig.id}, '${escapeHtml(asig.ticket)}', '${escapeHtml(asig.auditor_asignado)}')" 
                                style="background: var(--warning); padding: 4px 8px; font-size: 11px; border-radius: 6px;">
                            🔄 Reasignar
                        </button>
                    `;
                } else if (asig.estado !== 'gestionado' && !esLoteActivo) {
                    acciones = `<span style="color: var(--muted); font-size: 11px;" title="Lote histórico - no se puede modificar">🔒 Solo lectura</span>`;
                } else {
                    acciones = `<span style="color: var(--muted); font-size: 11px;">-</span>`;
                }
            }

            html += `
                <tr>
                    <td style="padding: 8px;"><strong>${escapeHtml(asig.ticket || '-')}</strong></td>
                    <td style="padding: 8px;">${escapeHtml(asig.auditor_asignado || '-')}</td>
                    <td style="padding: 8px;">${escapeHtml(asig.supervisor_responsable || '-')}</td>
                    <td style="padding: 8px;">${escapeHtml(asig.gestor_auditado || '-')}</td>
                    <td style="padding: 8px; max-width: 150px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title="${escapeHtml(asig.motivos || '')}">
                        ${escapeHtml((asig.motivos || '-').substring(0, 30))}${(asig.motivos || '').length > 30 ? '...' : ''}
                    </td>
                    <td style="padding: 8px;">${estadoBadge}</td>
                    <td style="padding: 8px; white-space: nowrap;">${formatearFechaPeru(asig.fecha_asignacion)}</td>
                    <td style="padding: 8px; white-space: nowrap;">${formatearFechaPeru(asig.fecha_gestion)}</td>
                    <td style="padding: 8px; text-align: center;">${acciones}</td>
                </tr>
            `;
        }

        html += `
            </tbody>
        </table>
    `;

        tbody.innerHTML = html;
    }
    // ===== FIN FUNCIÓN: mostrarTicketsConContextoLote ======================
    
    // ===== 34.. INICIO FUNCIÓN: verDetalleLote =============================
    async function verDetalleLote(loteId) {
        await cargarTicketsPorLote(loteId);

        // Hacer scroll a la tabla de monitoreo
        const tablaMonitoreo = document.getElementById('tablaMonitoreoEscuchas');
        if (tablaMonitoreo) {
            tablaMonitoreo.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }
    }
    // ===== FIN FUNCIÓN: verDetalleLote =====================================
    
    // ===== 35. INICIO FUNCIÓN: activarLote ================================
    async function activarLote(loteId) {
        const lote = window.lotesHistorialGlobal?.find(l => l.id === loteId);
        if (!lote) {
            alert('❌ No se encontró el lote seleccionado');
            return;
        }

        const nombreArchivo = lote.nombre_archivo ? lote.nombre_archivo.split('/').pop().split('\\').pop() : 'Desconocido';

        if (!confirm(`⚠️ ¿Activar el lote "${nombreArchivo}"?\n\nEsto cambiará el lote activo. Los tickets pendientes de este lote pasarán a ser los visibles en el monitoreo por defecto.\n\n¿Desea continuar?`)) {
            return;
        }

        try {
            // 🔴 CAMBIO: Usar API en lugar de PostgreSQL directo
            await API.activarLote(loteId);
            
            alert(`✅ Lote "${nombreArchivo}" activado correctamente`);

            // Recargar historial
            await cargarHistorialLotes();
            
            // Refrescar monitoreo
            await refrescarMonitoreoEscuchas();
            
            // Limpiar selección
            window.loteSeleccionadoId = null;

        } catch (error) {
            console.error('Error activando lote:', error);
            alert('❌ Error al activar el lote: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: activarLote ========================================

    // ===== 36. INICIO FUNCIÓN: refrescarHistorialLotes ====================
    function refrescarHistorialLotes() {
        console.log('🔄 Refrescando historial de lotes...');
        cargarHistorialLotes();
    }
    // ===== FIN FUNCIÓN: refrescarHistorialLotes ============================

    // ===== 37. INICIO FUNCIÓN: exportarHistorialLotesCSV ==================
    function exportarHistorialLotesCSV() {
        console.log('📥 exportarHistorialLotesCSV - INICIADO');
        
        // 🔴 OBTENER DATOS DE FORMA ROBUSTA
        let lotes = [];
        
        // Intentar 1: Desde window.lotesHistorialGlobal
        if (window.lotesHistorialGlobal && window.lotesHistorialGlobal.length > 0) {
            lotes = window.lotesHistorialGlobal;
            console.log(`📋 Usando window.lotesHistorialGlobal: ${lotes.length} lotes`);
        }
        
        // Intentar 2: Desde la variable global (sin window)
        if (lotes.length === 0 && typeof lotesHistorialGlobal !== 'undefined' && lotesHistorialGlobal.length > 0) {
            lotes = lotesHistorialGlobal;
            console.log(`📋 Usando lotesHistorialGlobal: ${lotes.length} lotes`);
        }
        
        // Intentar 3: Extraer de la tabla del DOM
        if (lotes.length === 0) {
            const tbody = document.getElementById('tablaHistorialLotes');
            if (tbody) {
                console.log('📋 Extrayendo datos desde la tabla del DOM...');
                const filas = tbody.querySelectorAll('tr');
                filas.forEach(fila => {
                    const celdas = fila.querySelectorAll('td');
                    if (celdas.length >= 10) {
                        // Extraer texto limpio de cada celda
                        const idText = celdas[0]?.textContent?.trim() || '0';
                        const fechaText = celdas[1]?.textContent?.trim() || '';
                        const archivoText = celdas[2]?.textContent?.trim() || '';
                        const totalText = celdas[3]?.textContent?.trim() || '0';
                        const pendientesText = celdas[4]?.textContent?.trim() || '0';
                        const enProcesoText = celdas[5]?.textContent?.trim() || '0';
                        const gestionadosText = celdas[6]?.textContent?.trim() || '0';
                        const incidenciasText = celdas[7]?.textContent?.trim() || '0';
                        const avanceText = celdas[8]?.textContent?.trim() || '0';
                        const estadoText = celdas[9]?.textContent?.trim() || '';
                        
                        const lote = {
                            id: parseInt(idText) || 0,
                            fecha_carga: fechaText,
                            nombre_archivo: archivoText,
                            total: parseInt(totalText) || 0,
                            pendientes: parseInt(pendientesText) || 0,
                            enProceso: parseInt(enProcesoText) || 0,
                            gestionados: parseInt(gestionadosText) || 0,
                            incidencias: parseInt(incidenciasText) || 0,
                            avance: parseInt(avanceText) || 0,
                            estado: estadoText.includes('Activo') ? 'activo' : 'inactivo'
                        };
                        if (lote.id > 0) {
                            lotes.push(lote);
                        }
                    }
                });
                console.log(`   📊 ${lotes.length} lotes extraídos de la tabla`);
            }
        }
        
        if (lotes.length === 0) {
            alert('⚠️ No hay datos de lotes para exportar');
            return;
        }

        // Headers del CSV
        const headers = [
            'ID Lote',
            'Fecha Carga',
            'Nombre Archivo',
            'Total Tickets',
            'Pendientes',
            'En Proceso',
            'Gestionados',
            'Incidencias',
            'Avance (%)',
            'Estado'
        ];

        // Construir filas
        const rows = lotes.map(lote => {
            // Formatear fecha si es un objeto Date o string ISO
            let fecha = lote.fecha_carga || '';
            if (fecha && !isNaN(new Date(fecha).getTime())) {
                fecha = new Date(fecha).toLocaleString('es-ES');
            }
            
            const nombreArchivo = lote.nombre_archivo ? lote.nombre_archivo.split('/').pop().split('\\').pop() : '-';

            return [
                lote.id || 0,
                `"${fecha}"`,
                `"${nombreArchivo}"`,
                lote.total || 0,
                lote.pendientes || 0,
                lote.enProceso || 0,
                lote.gestionados || 0,
                lote.incidencias || 0,
                lote.avance || 0,
                lote.estado === 'activo' ? 'ACTIVO' : 'INACTIVO'
            ];
        });

        // Generar CSV
        const csvContent = [
            headers.join(','),
            ...rows.map(row => row.join(','))
        ].join('\n');

        // Descargar
        const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `historial_lotes_${new Date().toISOString().slice(0, 10)}.csv`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);

        alert(`✅ Exportados ${lotes.length} lotes`);
    }
    // ===== FIN FUNCIÓN: exportarHistorialLotesCSV ==========================
    
    // ===== 38. INICIO FUNCIÓN: eliminarLote ===============================
    async function eliminarLote(loteId) {
    console.log(`🗑️ Eliminando lote ID: ${loteId}`);

    // 🔴 PRIMERO: Intentar obtener el lote desde el historial global
    let lote = window.lotesHistorialGlobal?.find(l => l.id === loteId);
    
    // 🔴 SI NO ESTÁ EN EL HISTORIAL, BUSCAR DIRECTAMENTE EN LA BD
    if (!lote) {
        console.log('🔍 Lote no encontrado en historial, consultando BD...');
        try {
            const db = getDB();
            if (db) {
                const { data, error } = await db
                    .from('tareas_escucha')
                    .select('*')
                    .eq('id', loteId)
                    .maybeSingle();
                
                if (!error && data) {
                    lote = data;
                    console.log('✅ Lote encontrado en BD:', lote);
                }
            }
        } catch (error) {
            console.warn('Error consultando BD:', error);
        }
    }
    
    // 🔴 SI AÚN NO SE ENCUENTRA, CREAR UN OBJETO CON LA INFORMACIÓN MÍNIMA
    if (!lote) {
        console.warn(`⚠️ No se encontró información del lote ${loteId}, pero se procederá a eliminar`);
        lote = {
            id: loteId,
            nombre_archivo: 'Lote desconocido',
            estado: 'inactivo'
        };
    }

    const nombreArchivo = lote.nombre_archivo ? lote.nombre_archivo.split('/').pop().split('\\').pop() : 'Desconocido';
    const fechaCarga = lote.fecha_carga ? new Date(lote.fecha_carga).toLocaleString('es-ES') : 'Fecha desconocida';

    const confirmar = confirm(
        `⚠️ ¿ELIMINAR LOTE COMPLETO?\n\n` +
        `📦 Lote ID: ${loteId}\n` +
        `📄 Archivo: ${nombreArchivo}\n` +
        `📅 Fecha carga: ${fechaCarga}\n\n` +
        `⚠️ Esta acción ELIMINARÁ PERMANENTEMENTE todos los tickets asociados.\n\n` +
        `¿Está ABSOLUTAMENTE SEGURO de continuar?`
    );

    if (!confirmar) return;

    const codigo = prompt('Para confirmar, escribe "ELIMINAR LOTE" en mayúsculas:');
    if (codigo !== 'ELIMINAR LOTE') {
        alert('❌ Operación cancelada.');
        return;
    }

    try {
        // 🔴 ELIMINAR USANDO LA API
        const token = localStorage.getItem('meca_token');
        const response = await fetch(`/api/escuchas/lotes/${loteId}`, {
            method: 'DELETE',
            headers: {
                'Authorization': `Bearer ${token}`,
                'Content-Type': 'application/json'
            }
        });

        if (!response.ok) {
            const error = await response.json();
            throw new Error(error.error || 'Error al eliminar lote');
        }

        alert(`✅ LOTE ELIMINADO CORRECTAMENTE\n\n📦 Lote ID: ${loteId}\n📄 Archivo: ${nombreArchivo}`);

        // 🔴 RECARGAR EL HISTORIAL PARA ACTUALIZAR LA TABLA
        await cargarHistorialLotes();
        
        // 🔴 REFRESCAR MONITOREO
        await refrescarMonitoreoEscuchas();
        
        // 🔴 LIMPIAR SELECCIÓN ACTUAL
        if (window.loteSeleccionadoId === loteId) {
            window.loteSeleccionadoId = null;
            const tbody = document.getElementById('tablaMonitoreoEscuchas');
            if (tbody) {
                tbody.innerHTML = `<tr><td colspan="9" style="text-align: center; padding: 40px;">
                    📭 El lote seleccionado ha sido eliminado. Seleccione otro lote para ver sus tickets.
                <\/td><\/tr>`;
            }
        }

    } catch (error) {
        console.error('❌ Error eliminando lote:', error);
        alert(`❌ Error al eliminar el lote:\n\n${error.message}`);
    }
}
    // ===== FIN FUNCIÓN: eliminarLote =======================================
    
    // ===== 39. INICIO FUNCIÓN: cargarExclusionesGuardadas =================
    function cargarExclusionesGuardadas() {
        const guardado = localStorage.getItem('auditores_excluidos_supervisor');
        if (guardado) {
            try {
                auditoresExcluidosGlobal = JSON.parse(guardado);
                console.log(`📋 Cargados ${auditoresExcluidosGlobal.length} auditores excluidos:`, auditoresExcluidosGlobal);
            } catch (e) {
                console.error('Error cargando exclusiones:', e);
                auditoresExcluidosGlobal = [];
            }
        } else {
            auditoresExcluidosGlobal = [];
            console.log('📋 No hay exclusiones guardadas');
        }
    }
    // ===== FIN FUNCIÓN: cargarExclusionesGuardadas =========================

    // ===== 40. INICIO FUNCIÓN: guardarExclusiones =========================
    function guardarExclusiones() {
        localStorage.setItem('auditores_excluidos_supervisor', JSON.stringify(auditoresExcluidosGlobal));
        console.log(`💾 Guardados ${auditoresExcluidosGlobal.length} auditores excluidos`);
    }
    // ===== FIN FUNCIÓN: guardarExclusiones =================================

    // ===== 41. INICIO FUNCIÓN: cargarSelectExclusionAuditores =============
    async function cargarSelectExclusionAuditores() {
        console.log('🔄 Cargando select de auditores para exclusión...');

        const db = getDB();
        if (!db) {
            console.error('❌ Base de datos no disponible');
            return;
        }

        try {
            // Obtener todos los auditores activos
            const { data, error } = await db
                .from('usuarios')
                .select('usuario, nombre_completo')
                .eq('activo', true)
                .eq('rol', 'AUDITOR')
                .order('usuario', { ascending: true });

            if (error) throw error;

            todosLosAuditoresGlobal = data || [];
            console.log(`✅ ${todosLosAuditoresGlobal.length} auditores activos encontrados`);

            // Filtrar los que NO están excluidos
            const auditoresDisponibles = todosLosAuditoresGlobal.filter(a => !auditoresExcluidosGlobal.includes(a.usuario));

            const select = document.getElementById('selectExcluirAuditor');
            if (select) {
                select.innerHTML = '<option value="">-- Seleccionar auditor --</option>';

                if (auditoresDisponibles.length === 0) {
                    select.innerHTML += '<option value="" disabled>✅ No hay auditores disponibles para excluir</option>';
                } else {
                    auditoresDisponibles.forEach(a => {
                        const nombreMostrar = a.nombre_completo || a.usuario;
                        select.innerHTML += `<option value="${escapeHtml(a.usuario)}">${escapeHtml(nombreMostrar)} (${escapeHtml(a.usuario)})</option>`;
                    });
                }
            }

            // Actualizar la lista visual de excluidos
            actualizarListaExcluidos();

        } catch (error) {
            console.error('❌ Error cargando auditores:', error);
            const select = document.getElementById('selectExcluirAuditor');
            if (select) {
                select.innerHTML = '<option value="">❌ Error cargando auditores</option>';
            }
        }
    }
    // ===== FIN FUNCIÓN: cargarSelectExclusionAuditores =====================

    // ===== 42. INICIO FUNCIÓN: actualizarListaExcluidos ===================
    function actualizarListaExcluidos() {
        const container = document.getElementById('listaExcluidos');
        if (!container) return;

        if (auditoresExcluidosGlobal.length === 0) {
            container.innerHTML = '<div style="text-align: center; color: var(--muted); font-size: 12px; padding: 10px;">✅ No hay auditores excluidos</div>';
            return;
        }

        let html = '<div style="display: flex; flex-wrap: wrap; gap: 8px;">';

        for (const auditor of auditoresExcluidosGlobal) {
            // Buscar nombre completo del auditor
            const auditorInfo = todosLosAuditoresGlobal.find(a => a.usuario === auditor);
            const nombreMostrar = auditorInfo?.nombre_completo || auditor;

            html += `
                <div style="background: #fee; border: 1px solid var(--danger); border-radius: 20px; padding: 5px 12px; display: inline-flex; align-items: center; gap: 8px;">
                    <span style="font-size: 13px;">🚫 ${escapeHtml(nombreMostrar)}</span>
                    <button onclick="removerExclusionAuditor('${escapeHtml(auditor)}')" 
                            style="background: none; border: none; color: var(--danger); cursor: pointer; font-size: 14px; font-weight: bold; padding: 0 4px;"
                            title="Quitar exclusión">
                        ✖
                    </button>
                </div>
            `;
        }

        html += '</div>';

        // Agregar contador
        html += `<div style="margin-top: 8px; font-size: 11px; color: var(--muted);">📊 Total excluidos: ${auditoresExcluidosGlobal.length} auditor(es)</div>`;

        container.innerHTML = html;
    }
    // ===== FIN FUNCIÓN: actualizarListaExcluidos ===========================

    // ===== 43. INICIO FUNCIÓN: excluirAuditor =============================
    function excluirAuditor() {
        const select = document.getElementById('selectExcluirAuditor');
        const auditor = select?.value;

        if (!auditor) {
            alert('⚠️ Seleccione un auditor para excluir');
            return;
        }

        if (auditoresExcluidosGlobal.includes(auditor)) {
            alert(`⚠️ El auditor ${auditor} ya está en la lista de excluidos`);
            return;
        }

        // Confirmar exclusión
        const auditorInfo = todosLosAuditoresGlobal.find(a => a.usuario === auditor);
        const nombreMostrar = auditorInfo?.nombre_completo || auditor;

        if (confirm(`🚫 ¿Excluir a ${nombreMostrar} de las futuras distribuciones?\n\nEste auditor no recibirá nuevos tickets hasta que lo remueva de la lista.`)) {
            auditoresExcluidosGlobal.push(auditor);
            guardarExclusiones();

            // Recargar selects y lista
            cargarSelectExclusionAuditores();

            console.log(`✅ Auditor ${auditor} excluido de la distribución`);
            alert(`✅ ${nombreMostrar} ha sido excluido de las futuras distribuciones`);
        }
    }
    // ===== FIN FUNCIÓN: excluirAuditor =====================================
    
    // ===== 44. INICIO FUNCIÓN: removerExclusionAuditor ====================
    function removerExclusionAuditor(auditor) {
        const auditorInfo = todosLosAuditoresGlobal.find(a => a.usuario === auditor);
        const nombreMostrar = auditorInfo?.nombre_completo || auditor;

        if (confirm(`✅ ¿Remover a ${nombreMostrar} de la lista de excluidos?\n\nEste auditor volverá a recibir tickets en futuras distribuciones.`)) {
            auditoresExcluidosGlobal = auditoresExcluidosGlobal.filter(a => a !== auditor);
            guardarExclusiones();

            // Recargar selects y lista
            cargarSelectExclusionAuditores();

            console.log(`✅ Auditor ${auditor} removido de exclusión`);
            alert(`✅ ${nombreMostrar} ha sido removido de la lista de excluidos`);
        }
    }
    // ===== FIN FUNCIÓN: removerExclusionAuditor ============================

    // ===== 45. INICIO FUNCIÓN: limpiarTodasExclusiones ====================
    function limpiarTodasExclusiones() {
        const total = auditoresExcluidosGlobal.length;

        if (total === 0) {
            alert('✅ No hay auditores excluidos para limpiar');
            return;
        }

        if (confirm(`⚠️ ¿Eliminar TODAS las exclusiones (${total} auditor(es))?\n\nTodos los auditores volverán a estar disponibles para futuras distribuciones.`)) {
            auditoresExcluidosGlobal = [];
            guardarExclusiones();
            cargarSelectExclusionAuditores();
            console.log(`✅ Eliminadas ${total} exclusiones`);
            alert(`✅ Se han eliminado ${total} exclusiones. Todos los auditores están disponibles.`);
        }
    }
    // ===== FIN FUNCIÓN: limpiarTodasExclusiones ============================

    // ======================================================
    // APLICAR FILTROS DE MONITOREO DE ESCUCHAS
    // ======================================================
    function aplicarFiltrosEscuchas() {
        console.log('🔍 aplicarFiltrosEscuchas - INICIADO');
        
        // Obtener valores de los filtros
        const filtroAuditor = document.getElementById('filtroAuditorEscuchas')?.value || '';
        const filtroEstado = document.getElementById('filtroEstadoEscuchas')?.value || '';
        const filtroLote = document.getElementById('filtroLoteEscuchas')?.value || '';
        const busquedaTicket = document.getElementById('buscarTicketEscucha')?.value?.toLowerCase() || '';
        
        // 🔴 FILTROS DE FECHA
        const fechaInicio = document.getElementById('filtroFechaInicioEscuchas')?.value || '';
        const fechaFin = document.getElementById('filtroFechaFinEscuchas')?.value || '';
        
        console.log(`   Filtros: Auditor=${filtroAuditor || 'todos'}, Estado=${filtroEstado || 'todos'}, Lote=${filtroLote || 'todos'}`);
        console.log(`   Fechas: ${fechaInicio || 'sin inicio'} → ${fechaFin || 'sin fin'}`);
        console.log(`   Busqueda: ${busquedaTicket || 'ninguna'}`);
        
        // Obtener todas las asignaciones
        let asignaciones = window.asignacionesEscuchasGlobales || [];
        
        if (asignaciones.length === 0) {
            console.log('⚠️ No hay asignaciones para filtrar');
            refrescarMonitoreoEscuchas();
            return;
        }
        
        console.log(`   📊 Total asignaciones disponibles: ${asignaciones.length}`);
        
        // Aplicar filtros
        let filtradas = asignaciones;
        
        // Filtrar por auditor
        if (filtroAuditor) {
            filtradas = filtradas.filter(a => a.auditor_asignado === filtroAuditor);
            console.log(`   👤 Filtro auditor: ${filtradas.length} asignaciones`);
        }
        
        // Filtrar por estado
        if (filtroEstado) {
            filtradas = filtradas.filter(a => a.estado === filtroEstado);
            console.log(`   📌 Filtro estado: ${filtradas.length} asignaciones`);
        }
        
        // Filtrar por lote
        if (filtroLote && filtroLote !== 'activo' && filtroLote !== 'todos') {
            const loteId = parseInt(filtroLote);
            if (!isNaN(loteId)) {
                filtradas = filtradas.filter(a => a.tarea_id === loteId);
                console.log(`   📦 Filtro lote ID ${loteId}: ${filtradas.length} asignaciones`);
            }
        } else if (filtroLote === 'activo') {
            const loteActivo = window.lotesHistorialGlobal?.find(l => l.estado === 'activo');
            if (loteActivo) {
                filtradas = filtradas.filter(a => a.tarea_id === loteActivo.id);
                console.log(`   📦 Filtro lote activo (ID ${loteActivo.id}): ${filtradas.length} asignaciones`);
            }
        }
        
        // 🔴 NUEVO: FILTRAR POR RANGO DE FECHAS
        if (fechaInicio || fechaFin) {
            // Convertir fechas a objetos Date para comparación
            const inicio = fechaInicio ? new Date(fechaInicio) : null;
            const fin = fechaFin ? new Date(fechaFin) : null;
            
            // Ajustar horas para comparación correcta
            if (inicio) inicio.setHours(0, 0, 0, 0);
            if (fin) fin.setHours(23, 59, 59, 999);
            
            const antes = filtradas.length;
            
            filtradas = filtradas.filter(a => {
                if (!a.fecha_asignacion) return false;
                
                const fechaAsig = new Date(a.fecha_asignacion);
                if (isNaN(fechaAsig.getTime())) return false;
                
                if (inicio && fechaAsig < inicio) return false;
                if (fin && fechaAsig > fin) return false;
                
                return true;
            });
            
            console.log(`   📅 Filtro de fechas: ${filtradas.length} asignaciones (de ${antes})`);
        }
        
        // Filtrar por búsqueda de ticket
        if (busquedaTicket) {
            const antes = filtradas.length;
            filtradas = filtradas.filter(a => 
                (a.ticket || '').toLowerCase().includes(busquedaTicket) ||
                (a.gestor_auditado || '').toLowerCase().includes(busquedaTicket) ||
                (a.supervisor_responsable || '').toLowerCase().includes(busquedaTicket) ||
                (a.auditor_asignado || '').toLowerCase().includes(busquedaTicket)
            );
            console.log(`   🔍 Búsqueda: ${filtradas.length} asignaciones (de ${antes})`);
        }
        
        console.log(`   ✅ TOTAL FILTRADAS: ${filtradas.length} asignaciones (de ${asignaciones.length})`);
        
        // Actualizar la tabla con los datos filtrados
        actualizarTablaMonitoreo(filtradas);
        
        // Actualizar contador de resultados
        const contador = document.getElementById('resultadosEscuchasCount');
        if (contador) {
            contador.textContent = filtradas.length;
        }
    }

    // ===== 46. INICIO FUNCIÓN: limpiarTodasLasEscuchas ====================
    async function limpiarTodasLasEscuchas() {
        // Confirmación doble por seguridad
        const confirmar = confirm('⚠️ ¡ADVERTENCIA!\n\nEsta acción ELIMINARÁ TODAS las escuchas asignadas de las tablas:\n\n📋 asignaciones_escucha\n📋 tareas_escucha\n\nEsta operación NO se puede deshacer.\n\n¿Estás ABSOLUTAMENTE SEGURO de continuar?');

        if (!confirmar) return;

        // Segunda confirmación con escritura de código
        const codigo = prompt('⚠️ CONFIRMACIÓN FINAL\n\nPara confirmar la eliminación total de todas las escuchas,\nescribe el código: LIMPIAR TODO\n\n(Código en mayúsculas)');

        if (codigo !== 'LIMPIAR TODO') {
            alert('❌ Operación cancelada. No escribiste el código de confirmación correcto.');
            return;
        }

        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }

        // Mostrar indicador de carga
        const btn = document.getElementById('btnLimpiarEscuchas');
        let textoOriginal = '';
        if (btn) {
            textoOriginal = btn.innerHTML;
            btn.innerHTML = '⏳ Eliminando...';
            btn.disabled = true;
        }

        let resultados = {
            asignaciones: { eliminados: 0, error: null },
            tareas: { eliminados: 0, error: null }
        };

        try {
            // 1. Contar registros antes de eliminar (para feedback)
            const { count: countAsignaciones, error: countAsigError } = await db
                .from('asignaciones_escucha')
                .select('*', { count: 'exact', head: true });

            const { count: countTareas, error: countTareasError } = await db
                .from('tareas_escucha')
                .select('*', { count: 'exact', head: true });

            if (!countAsigError) {
                console.log(`📊 Registros en asignaciones_escucha: ${countAsignaciones}`);
            }
            if (!countTareasError) {
                console.log(`📊 Registros en tareas_escucha: ${countTareas}`);
            }

            // 2. Eliminar registros de tareas_escucha (primero por FK)
            console.log('🗑️ Eliminando tareas_escucha...');
            const { error: errorTareas } = await db
                .from('tareas_escucha')
                .delete()
                .neq('id', 0);

            if (errorTareas) {
                resultados.tareas.error = errorTareas.message;
                console.error('Error eliminando tareas:', errorTareas);
            } else {
                resultados.tareas.eliminados = countTareas || 'todos';
                console.log('✅ tareas_escucha eliminadas');
            }

            // 3. Eliminar registros de asignaciones_escucha
            console.log('🗑️ Eliminando asignaciones_escucha...');
            const { error: errorAsignaciones } = await db
                .from('asignaciones_escucha')
                .delete()
                .neq('id', 0);

            if (errorAsignaciones) {
                resultados.asignaciones.error = errorAsignaciones.message;
                console.error('Error eliminando asignaciones:', errorAsignaciones);
            } else {
                resultados.asignaciones.eliminados = countAsignaciones || 'todos';
                console.log('✅ asignaciones_escucha eliminadas');
            }

            // 4. Mostrar resumen final
            let mensaje = '📋 RESULTADO DE LIMPIEZA DE ESCUCHAS\n\n';
            mensaje += '═══════════════════════════════════════\n';

            if (resultados.asignaciones.error) {
                mensaje += `❌ asignaciones_escucha: ERROR - ${resultados.asignaciones.error}\n`;
            } else {
                mensaje += `✅ asignaciones_escucha: ${resultados.asignaciones.eliminados} registros eliminados\n`;
            }

            if (resultados.tareas.error) {
                mensaje += `❌ tareas_escucha: ERROR - ${resultados.tareas.error}\n`;
            } else {
                mensaje += `✅ tareas_escucha: ${resultados.tareas.eliminados} registros eliminados\n`;
            }

            mensaje += '═══════════════════════════════════════\n';

            if (!resultados.asignaciones.error && !resultados.tareas.error) {
                mensaje += '\n✅ LIMPIEZA COMPLETADA EXITOSAMENTE\n';
                mensaje += 'Todas las escuchas han sido eliminadas de la base de datos.';
            } else {
                mensaje += '\n⚠️ LIMPIEZA PARCIAL: Algunas tablas no pudieron ser limpiadas.\n';
                mensaje += 'Revise los errores y contacte a soporte.';
            }

            alert(mensaje);

            // 5. Refrescar las tablas de monitoreo si están visibles
            if (document.getElementById('tab-gestionEscuchas')?.classList.contains('active')) {
                await refrescarMonitoreoEscuchas();
            }

            // 6. Limpiar variables globales
            asignacionesEscuchasGlobales = [];

        } catch (error) {
            console.error('❌ Error en limpieza:', error);
            alert(`❌ Error durante la limpieza:\n\n${error.message}\n\nPor favor, intente nuevamente o contacte a soporte.`);
        } finally {
            // Restaurar botón
            if (btn) {
                btn.innerHTML = textoOriginal || '🗑️ Limpiar todas las escuchas';
                btn.disabled = false;
            }
        }
    }
