    // ===== 1. INICIO FUNCIÓN: obtenerProximoIdAgente =====================
    async function obtenerProximoIdAgente() {
        const db = getDB();
        if (!db) return 1;

        try {
            const { data, error } = await db
                .from('agentes')
                .select('id')
                .order('id', { ascending: false })
                .limit(1);

            if (error) {
                console.error('Error obteniendo max ID:', error);
                return 1;
            }

            if (!data || data.length === 0) {
                return 1;  // No hay registros, empezar desde 1
            }

            return data[0].id + 1;  // ← CLAVE: último ID + 1

        } catch (error) {
            console.error('Error en obtenerProximoIdAgente:', error);
            return 1;
        }
    }
    // ===== FIN FUNCIÓN: obtenerProximoIdAgente =============================
    
    // ===== 2. INICIO FUNCIÓN: filtrarAgentes =============================
    function filtrarAgentes(busqueda) {
        // Obtener valor del input si no se pasó
        if (busqueda === undefined) {
            const input = document.getElementById('buscarAgente');
            busqueda = input ? input.value : '';
        }
        
        console.log('🔍 Filtrando agentes con búsqueda:', busqueda);
        
        // Si no hay búsqueda, mostrar todos
        if (!busqueda || busqueda.trim() === '') {
            window.agentesFiltrados = [...window.agentesGlobales];
            actualizarTablaAgentes();
            const sugerenciasDiv = document.getElementById('sugerenciasAgentes');
            if (sugerenciasDiv) sugerenciasDiv.style.display = 'none';
            return;
        }
        
        const busquedaLower = busqueda.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
        
        // Filtrar agentesGlobales (todos los agentes de la BD)
        const filtrados = window.agentesGlobales.filter(agente => {
            if (!agente.nombre) return false;
            const nombreNormalizado = agente.nombre.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
            return nombreNormalizado.includes(busquedaLower);
        });
        
        // Actualizar agentesFiltrados y la tabla
        window.agentesFiltrados = filtrados;
        actualizarTablaAgentes();
        
        console.log(`✅ Filtrados: ${filtrados.length} agentes`);
    }
    // ===== FIN FUNCIÓN: filtrarAgentes =====================================

    // ===== 3. INICIO FUNCIÓN: actualizarTablaAgentes =====================
    function actualizarTablaAgentes() {
        const tbody = document.getElementById('tablaAgentes');
        if (!tbody) return;

        // 🔴 USAR window.agentesFiltrados
        const agentes = window.agentesFiltrados || window.agentesGlobales || [];
        
        console.log(`📊 actualizarTablaAgentes - Agentes: ${agentes.length}`);

        if (agentes.length === 0) {
            tbody.innerHTML = '<tr><td colspan="7" style="text-align: center; padding: 50px;">No hay gestores registrados<\/td><\/tr>';
            const totalAgentes = document.getElementById('totalAgentes');
            if (totalAgentes) totalAgentes.textContent = '0';
            return;
        }

        let html = '';
        
        for (let i = 0; i < agentes.length; i++) {
            const agente = agentes[i];
            const agenteId = agente.id || (i + 1);
            
            let estadoRaw = (agente.estado || 'INACTIVO').toString().trim().toUpperCase();
            let estadoBadge = '';
            
            if (estadoRaw === 'ACTIVO') {
                estadoBadge = '<span class="badge" style="background: var(--ok);">ACTIVO</span>';
            } else if (estadoRaw === 'DM PROLONGADO') {
                estadoBadge = '<span class="badge" style="background: var(--warning);">DM PROLONGADO</span>';
            } else {
                estadoBadge = '<span class="badge" style="background: var(--danger);">INACTIVO</span>';
            }

            const fechaRegistro = agente.created_at
                ? new Date(agente.created_at).toLocaleDateString('es-ES')
                : '-';
            
            const lider = agente.lider_2026 || '-';
            const categoria = agente.categoria_label || '-';
            const nombre = agente.nombre || 'Sin nombre';
            
            html += `
                <tr style="border-bottom: 1px solid var(--line);">
                    <td style="padding: 8px; text-align: center;">${agenteId}</td>
                    <td style="padding: 8px;"><strong>${escapeHtml(nombre)}</strong></td>
                    <td style="padding: 8px; text-align: center;">${estadoBadge}</td>
                    <td style="padding: 8px;">${escapeHtml(lider)}</td>
                    <td style="padding: 8px;">${escapeHtml(categoria)}</td>
                    <td style="padding: 8px; text-align: center;">${fechaRegistro}</td>
                    <td style="padding: 8px; text-align: center; white-space: nowrap;">
                        <button onclick="editarAgente(${agenteId})" 
                                style="background: var(--warning); padding: 5px 10px; border-radius: 6px; border: none; cursor: pointer; margin-right: 5px;">
                            ✏️
                        </button>
                        <button onclick="eliminarAgente(${agenteId})" 
                                style="background: #fee; color: var(--danger); padding: 5px 10px; border-radius: 6px; border: none; cursor: pointer;">
                            🗑️
                        </button>
                    </td>
                </tr>
            `;
        }

        tbody.innerHTML = html;
        
        const totalAgentes = document.getElementById('totalAgentes');
        if (totalAgentes) totalAgentes.textContent = agentes.length;
        
        console.log(`✅ Tabla actualizada con ${agentes.length} agentes`);
    }
    // ===== FIN FUNCIÓN: actualizarTablaAgentes =============================

    // ===== 4. INICIO FUNCIÓN: actualizarEstadisticasAgentes ==============
    function actualizarEstadisticasAgentes() {
        const agentes = window.agentesGlobales || [];
        const total = agentes.length;
        
        // 🔴 NORMALIZAR ESTADOS (comparar sin distinción de mayúsculas/minúsculas)
        const gestoresActivos = agentes.filter(a => {
            const estado = (a.estado || '').toString().toUpperCase();
            return estado === 'ACTIVO';
        }).length;
        
        const dmProlongado = agentes.filter(a => {
            const estado = (a.estado || '').toString().toUpperCase();
            return estado === 'DM PROLONGADO';
        }).length;
        
        const inactivos = agentes.filter(a => {
            const estado = (a.estado || '').toString().toUpperCase();
            return estado === 'INACTIVO';
        }).length;
        
        console.log(`📊 Estadísticas: Total=${total}, Activos=${gestoresActivos}, DM=${dmProlongado}, Inactivos=${inactivos}`);
        
        // Actualizar elementos existentes
        const statsTotalAgentes = document.getElementById('statsTotalAgentes');
        if (statsTotalAgentes) statsTotalAgentes.textContent = total;
        
        const statsGestoresActivos = document.getElementById('statsGestoresActivos');
        if (statsGestoresActivos) statsGestoresActivos.textContent = gestoresActivos;
        
        const totalAgentes = document.getElementById('totalAgentes');
        if (totalAgentes) totalAgentes.textContent = window.agentesFiltrados?.length || 0;
        
        // Si existen elementos para DM, actualizarlos
        const statsDM = document.getElementById('statsDM');
        if (statsDM) statsDM.textContent = dmProlongado;
        
        const totalDM = document.getElementById('totalDM');
        if (totalDM) totalDM.textContent = dmProlongado;
        
        const statsInactivos = document.getElementById('statsAgentesInactivos');
        if (statsInactivos) statsInactivos.textContent = inactivos;
    }
    // ===== FIN FUNCIÓN: actualizarEstadisticasAgentes ======================
    
    // ===== 5. INICIO FUNCIÓN: editarAgente ===============================
    async function editarAgente(id) {
        console.log('✏️ Editando agente ID:', id);
        
        const token = localStorage.getItem('meca_token');
        
        try {
            const response = await fetch(`/api/agentes/${id}`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            
            if (!response.ok) throw new Error('Error al cargar agente');
            
            const agente = await response.json();
            
            window.agenteEnEdicion = id;
            
            // Cargar campos
            document.getElementById('agenteId').value = agente.id || '';
            document.getElementById('agenteNombre').value = agente.nombre || '';
            document.getElementById('agenteDni').value = agente.dni || '';
            document.getElementById('agenteCarnet').value = agente.carnet || '';
            document.getElementById('agenteCorreo').value = agente.correo || '';
            document.getElementById('agenteCreatedAt').value = agente.created_at ? new Date(agente.created_at).toLocaleDateString('es-ES') : '';
            document.getElementById('agenteHorarioMarzo').value = agente.horario_marzo || '';
            document.getElementById('agenteHorarioMarzoV1').value = agente.horario_marzo_v1 || '';
            document.getElementById('agenteCanalTobe').value = agente.canal_tobe_1ra_activ_marzo || '';
            document.getElementById('agenteActividadMarzo').value = agente['1ra_actividad_marzo_v1'] || '';
            document.getElementById('agenteEstado').value = agente.estado || 'ACTIVO';
            document.getElementById('agenteLider').value = agente.lider_2026 || '';
            document.getElementById('agenteUbicacion').value = agente.ubicacion || '';
            document.getElementById('agenteLocalidad').value = agente.localidad || '';
            document.getElementById('agenteCategoria').value = agente.categoria_label || '';
            document.getElementById('agenteFunciones').value = agente.funciones || '';
            
            const btnCancelar = document.getElementById('btnCancelarEdicion');
            const btnGuardar = document.getElementById('btnGuardarAgente');
            
            if (btnCancelar) btnCancelar.style.display = 'inline-flex';
            if (btnGuardar) {
                btnGuardar.textContent = '✏️ Actualizar Agente';
                btnGuardar.style.background = 'var(--warning)';
            }
            
            alert(`✏️ Editando agente: ${agente.nombre}`);
            
        } catch (error) {
            console.error('Error:', error);
            alert('Error al cargar el agente: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: editarAgente =======================================
    
    // ===== 6. INICIO FUNCIÓN: eliminarAgente =============================
    async function eliminarAgente(id) {
        const agente = agentesGlobales.find(a => a.id === id);
        if (!agente) return;

        if (!confirm(`⚠️ ¿Eliminar al agente "${agente.nombre}"?\n\nEsta acción no se puede deshacer.`)) return;

        try {
            await API.eliminarAgente(id);

            alert(`✅ Agente "${agente.nombre}" eliminado correctamente`);
            await cargarAgentes();

        } catch (error) {
            console.error('Error eliminando agente:', error);
            alert('❌ Error al eliminar: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: eliminarAgente =====================================

    // ===== 7. INICIO FUNCIÓN: limpiarFormAgente ==========================
    function limpiarFormAgente() {
        console.log('🧹 Limpiando formulario de nuevo agente...');
        
        // Limpiar campos de solo lectura
        const camposLectura = [
            'agenteId', 'agenteNombre', 'agenteDni', 'agenteCarnet',
            'agenteCorreo', 'agenteCreatedAt', 'agenteHorarioMarzo',
            'agenteHorarioMarzoV1', 'agenteCanalTobe', 'agenteActividadMarzo'
        ];
        
        camposLectura.forEach(id => {
            const elemento = document.getElementById(id);
            if (elemento) elemento.value = '';
        });
        
        // Limpiar campos editables
        const camposEdicion = [
            'agenteNombre',  // El nombre también debe limpiarse
            'agenteLider', 'agenteUbicacion',
            'agenteLocalidad', 'agenteCategoria', 'agenteFunciones'
        ];
        
        camposEdicion.forEach(id => {
            const elemento = document.getElementById(id);
            if (elemento) elemento.value = '';
        });
        
        // Resetear estado a valor por defecto (SIN ÍCONOS)
        const estadoSelect = document.getElementById('agenteEstado');
        if (estadoSelect) {
            estadoSelect.value = 'ACTIVO';  // Usa el valor exacto que espera tu BD
        }
        
        // Limpiar variable de edición
        window.agenteEnEdicion = null;
        
        // Restaurar botón guardar a su estado original
        const btnGuardar = document.getElementById('btnGuardarAgente');
        if (btnGuardar) {
            btnGuardar.textContent = '💾 Guardar Agente';
            btnGuardar.style.background = '';
        }
        
        // Ocultar botón de cancelar
        const btnCancelar = document.getElementById('btnCancelarEdicion');
        if (btnCancelar) {
            btnCancelar.style.display = 'none';
        }
        
        // Restaurar título del formulario
        const formTitle = document.querySelector('#tab-gestionAgentes .card:first-child h3');
        if (formTitle) {
            formTitle.innerHTML = '<span>📝 Registrar Nuevo Agente</span>';
        }
        
        console.log('✅ Formulario limpiado correctamente');
    }
    // ===== FIN FUNCIÓN: limpiarFormAgente ==================================

    // ===== 8. INICIO FUNCIÓN: inicializarFormularioAgentes ===============
    function inicializarFormularioAgentes() {
        const formAgente = document.getElementById('formAgente');
        if (!formAgente) {
            console.warn('⚠️ Formulario de gestores no encontrado');
            return;
        }

        // Remover eventos anteriores para evitar duplicados
        const nuevoForm = formAgente.cloneNode(true);
        formAgente.parentNode.replaceChild(nuevoForm, formAgente);

        const formFinal = document.getElementById('formAgente');

        formFinal.addEventListener('submit', async function (e) {
            e.preventDefault();
            e.stopPropagation();

            console.log('📝 Procesando formulario de agente...');

            const db = getDB();
            if (!db) {
                alert('❌ Base de datos no disponible');
                return;
            }

            const nombre = document.getElementById('agenteNombre').value.trim().toUpperCase();
            const estado = document.getElementById('agenteEstado').value;

            if (!nombre) {
                alert('⚠️ Complete el nombre del agente');
                return;
            }

            try {
                if (window.agenteEnEdicion) {
                    // ======================================================
                    // ACTUALIZAR AGENTE EXISTENTE - SOLO CAMPOS EDITABLES
                    // ======================================================
                    console.log(`✏️ Actualizando agente ID: ${window.agenteEnEdicion}`);

                    // Obtener valores actuales del formulario
                    const estado = document.getElementById('agenteEstado').value;
                    const lider = document.getElementById('agenteLider').value;
                    const ubicacion = document.getElementById('agenteUbicacion').value;
                    const localidad = document.getElementById('agenteLocalidad').value;
                    const categoria = document.getElementById('agenteCategoria').value;
                    const funciones = document.getElementById('agenteFunciones').value;

                    const updateData = {
                        estado: estado,
                        lider_2026: lider || null,
                        ubicacion: ubicacion || null,
                        localidad: localidad || null,
                        categoria_label: categoria || null,
                        funciones: funciones || null,
                        updated_at: new Date().toISOString()
                    };

                    const { error } = await db
                        .from('agentes')
                        .update(updateData)
                        .eq('id', window.agenteEnEdicion);

                    if (error) throw error;
                    
                    alert(`✅ Agente actualizado correctamente`);
                    window.agenteEnEdicion = null;
                } else {
                    // ======================================================
                    // CREAR NUEVO AGENTE CON ID INCREMENTAL
                    // ======================================================

                    // 1. Verificar si ya existe un agente con ese nombre
                    const { data: existe } = await db
                        .from('agentes')
                        .select('id')
                        .eq('nombre', nombre)
                        .maybeSingle();

                    if (existe) {
                        alert(`⚠️ Ya existe un agente con el nombre "${nombre}"`);
                        return;
                    }

                    // 2. 🔴 OBTENER EL ID MÁXIMO ACTUAL (DEFINIR nuevoId AQUÍ)
                    const { data: maxIdData, error: maxIdError } = await db
                        .from('agentes')
                        .select('id')
                        .order('id', { ascending: false })
                        .limit(1);

                    if (maxIdError) {
                        console.error('Error obteniendo max ID:', maxIdError);
                    }

                    // 3. 🔴 CALCULAR EL NUEVO ID (DEFINIR LA VARIABLE)
                    let nuevoId = 1;
                    if (maxIdData && maxIdData.length > 0 && maxIdData[0].id) {
                        nuevoId = Number(maxIdData[0].id) + 1;
                    }

                    console.log(`📝 Creando nuevo agente con ID: ${nuevoId}`);

                    // 4. Crear el objeto con el nuevo ID
                    const nuevoAgente = {
                        id: nuevoId,  // ← AHORA nuevoId SÍ ESTÁ DEFINIDO
                        nombre: nombre,
                        estado: estado,
                        created_at: new Date().toISOString(),
                        updated_at: new Date().toISOString()
                    };

                    // 5. Insertar en la base de datos
                    const { error } = await db
                        .from('agentes')
                        .insert(nuevoAgente);

                    if (error) throw error;

                    alert(`✅ Agente "${nombre}" registrado correctamente`);
                }

                // Recargar tabla y limpiar formulario
                await cargarAgentes();
                limpiarFormAgente();

            } catch (error) {
                console.error('❌ Error guardando agente:', error);
                alert('❌ Error al guardar: ' + error.message);
            }
        });


        console.log('✅ Formulario de gestores inicializado');
    }
    // ===== FIN FUNCIÓN: inicializarFormularioAgentes =======================
    
    // ===== 9. INICIO FUNCIÓN: exportarAgentesCSV =========================
    async function exportarAgentesCSV() {
        console.log('📥 Exportando agentes a CSV...');
        
        try {
            const token = localStorage.getItem('meca_token');
            const response = await fetch('/api/agentes/exportar', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                }
            });
            
            if (!response.ok) {
                throw new Error(`HTTP ${response.status}`);
            }
            
            // 🔴 Obtener el CSV directamente como texto
            const csvContent = await response.text();
            
            // Crear el blob y descargar
            const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `agentes_${new Date().toISOString().slice(0, 10)}.csv`;
            a.click();
            URL.revokeObjectURL(url);
            
            // Contar líneas para el mensaje
            const lineas = csvContent.split('\n').length - 1;
            alert(`✅ Exportados ${lineas} agentes`);
            
        } catch (error) {
            console.error('Error exportando agentes:', error);
            alert('❌ Error al exportar: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: exportarAgentesCSV =================================

