    // ===== 12. INICIO FUNCIÓN: guardarAgentesMasivo =======================
    async function guardarAgentesMasivo() {
        console.log('📊 guardarAgentesMasivo - INICIADO');
        console.log('📊 window.agentesPendientesGuardarMasivo?.length:', window.agentesPendientesGuardarMasivo?.length);
        
        if (!window.agentesPendientesGuardarMasivo || window.agentesPendientesGuardarMasivo.length === 0) {
            alert('⚠️ No hay agentes para guardar. Primero cargue un archivo Excel.');
            return;
        }

        const confirmar = confirm(`⚠️ ¿Guardar ${window.agentesPendientesGuardarMasivo.length} agentes?...`);
        if (!confirmar) return;

        const btnGuardar = document.getElementById('btnGuardarAgentesMasivo');
        const textoOriginal = btnGuardar?.innerHTML;
        if (btnGuardar) {
            btnGuardar.innerHTML = '⏳ Guardando...';
            btnGuardar.disabled = true;
        }

        let nuevos = 0;
        let duplicados = 0;
        let errores = [];

        // Obtener agentes existentes para verificar duplicados
        const agentesExistentes = await API.getAgentes();
        const nombresExistentes = new Set(agentesExistentes.map(a => a.nombre));

        for (const agente of window.agentesPendientesGuardarMasivo) {
            try {
                // Verificar si ya existe por nombre
                if (nombresExistentes.has(agente.nombre)) {
                    duplicados++;
                    continue;
                }

                // Crear nuevo agente (sin ID, la API lo generará)
                const nuevoAgente = {
                    estado: agente.estado || '',
                    nombre: agente.nombre || '',
                    dni: agente.dni || '',
                    carnet: agente.carnet || '',
                    correo: agente.correo || '',                    
                    lider_2026: agente.lider_2026 || '',
                    localidad: agente.localidad || '',
                    ubicacion: agente.ubicacion || '',                    
                    funciones: agente.funciones || '',
                    categoria_label: agente.categoria_label || '',                    
                    horario_marzo: agente.horario_marzo || '',
                    horario_marzo_v1: agente.horario_marzo_v1 || '',
                    canal_tobe_1ra_activ_marzo: agente.canal_tobe_1ra_activ_marzo || '',
                    '1ra_actividad_marzo_v1': agente['1ra_actividad_marzo_v1'] || ''
                };

                // Limpiar estado
                if (nuevoAgente.estado) {
                    let estadoLimpio = nuevoAgente.estado.toString().toUpperCase();
                    estadoLimpio = estadoLimpio.replace(/[^A-Z\s]/gi, '').trim();
                    if (estadoLimpio.includes('ACTIV')) estadoLimpio = 'Activo';
                    if (estadoLimpio.includes('INACTIV')) estadoLimpio = 'Inactivo';
                    if (estadoLimpio.includes('DM') || estadoLimpio.includes('PROLONG')) estadoLimpio = 'DM prolongado';
                    nuevoAgente.estado = estadoLimpio;
                }

                // 🔴 Usar API.crearAgente (que ya existe)
                await API.crearAgente(nuevoAgente);
                nuevos++;
                nombresExistentes.add(agente.nombre);

            } catch (error) {
                console.error('Error guardando agente:', agente.nombre, error);
                errores.push(`${agente.nombre || 'Sin nombre'}: ${error.message}`);
            }
        }

        if (btnGuardar) {
            btnGuardar.innerHTML = textoOriginal;
            btnGuardar.disabled = true;
        }

        let mensaje = `📊 RESULTADO DE CARGA MASIVA\n\n`;
        mensaje += `✅ Nuevos agentes: ${nuevos}\n`;
        mensaje += `⚠️ Duplicados omitidos: ${duplicados}\n`;
        mensaje += `❌ Errores: ${errores.length}`;

        if (errores.length > 0) {
            mensaje += `\n\nDetalles de errores:\n${errores.slice(0, 5).join('\n')}`;
            if (errores.length > 5) mensaje += `\n... y ${errores.length - 5} más`;
        }

        alert(mensaje);

        // Limpiar después de guardar
        window.agentesPendientesGuardar = [];
        document.getElementById('vistaPreviaAgentes').style.display = 'none';
        document.getElementById('fileAgentes').value = '';
        cerrarModalCargarAgentes();
        await cargarAgentes();
    }
    // ===== FIN FUNCIÓN: guardarAgentesMasivo ===============================

    // ===== 13. INICIO FUNCIÓN: eliminarTodosAgentes =======================
    async function eliminarTodosAgentes() {
        if (!agentesGlobales || agentesGlobales.length === 0) {
            alert('⚠️ No hay agentes para eliminar');
            return;
        }

        const total = agentesGlobales.length;
        const activos = agentesGlobales.filter(a => a.estado === 'ACTIVO').length;
        const inactivos = total - activos;

        const confirmar = confirm(`⚠️ ¡ADVERTENCIA!\n\nEsta acción ELIMINARÁ TODOS los ${total} agentes:\n\n✅ Activos: ${activos}\n❌ Inactivos: ${inactivos}\n\nEsta operación NO se puede deshacer.\n\n¿Estás ABSOLUTAMENTE SEGURO de continuar?`);
        if (!confirmar) return;

        const codigo = prompt('Para confirmar, escribe "ELIMINAR TODO" en mayúsculas:');
        if (codigo !== 'ELIMINAR TODO') {
            alert('❌ Operación cancelada. No escribiste el código de confirmación correcto.');
            return;
        }

        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }

        const btnEliminar = event?.target;
        const textoOriginal = btnEliminar?.innerHTML;
        if (btnEliminar) {
            btnEliminar.innerHTML = '⏳ Eliminando...';
            btnEliminar.disabled = true;
        }

        try {
            // Eliminar todos los agentes
            const { error } = await db
                .from('agentes')
                .delete()
                .neq('id', 0);

            if (error) throw error;

            alert(`✅ Se eliminaron ${total} agentes correctamente`);

            // Recargar tabla
            await cargarAgentes();

        } catch (error) {
            console.error('❌ Error eliminando agentes:', error);
            alert(`❌ Error al eliminar: ${error.message}`);
        } finally {
            if (btnEliminar) {
                btnEliminar.innerHTML = textoOriginal;
                btnEliminar.disabled = false;
            }
        }
    }
    // ===== FIN FUNCIÓN: eliminarTodosAgentes ===============================
    
    // ===== 14. INICIO FUNCIÓN: cargarCategoriasUnicas =====================
    async function cargarCategoriasUnicas() {
        console.log('📋 Cargando categorías únicas...');
        
        try {
            const token = localStorage.getItem('meca_token');
            const response = await fetch('/api/agentes/categorias', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                }
            });
            
            if (!response.ok) {
                throw new Error(`HTTP ${response.status}`);
            }
            
            const categoriasUnicas = await response.json();
            
            const selectCategoria = document.getElementById('agenteCategoria');
            if (selectCategoria) {
                const valorActual = selectCategoria.value;
                selectCategoria.innerHTML = '<option value="">-- Seleccionar --</option>';
                if (Array.isArray(categoriasUnicas)) {
                    categoriasUnicas.forEach(categoria => {
                        selectCategoria.innerHTML += `<option value="${escapeHtml(categoria)}">${escapeHtml(categoria)}</option>`;
                    });
                }
                if (valorActual && categoriasUnicas.includes(valorActual)) {
                    selectCategoria.value = valorActual;
                }
            }
            
            console.log(`✅ ${categoriasUnicas?.length || 0} categorías cargadas`);
            return categoriasUnicas;
            
        } catch (error) {
            console.error('❌ Error cargando categorías:', error);
            return [];
        }
    }
    // ===== FIN FUNCIÓN: cargarCategoriasUnicas ==============================

    // ===== 15. INICIO FUNCIÓN: convertirFechaParaInput ====================
    function convertirFechaParaInput(fechaStr) {
        if (!fechaStr) return '';
        // Si ya está en formato YYYY-MM-DD, devolver igual
        if (fechaStr.match(/^\d{4}-\d{2}-\d{2}$/)) return fechaStr;
        // Si está en formato DD/MM/YYYY, convertir
        if (fechaStr.match(/^\d{2}\/\d{2}\/\d{4}$/)) {
            const [dia, mes, anio] = fechaStr.split('/');
            return `${anio}-${mes}-${dia}`;
        }
        // Si tiene hora (DD/MM/YYYY HH:MM), extraer solo fecha y convertir
        if (fechaStr.match(/^\d{2}\/\d{2}\/\d{4} \d{2}:\d{2}$/)) {
            const [fechaParte] = fechaStr.split(' ');
            const [dia, mes, anio] = fechaParte.split('/');
            return `${anio}-${mes}-${dia}`;
        }
        return '';
    }
    // ===== FIN FUNCIÓN: convertirFechaParaInput ============================
    
    // ===== 16. INICIO FUNCIÓN: resetearRankingCompleto =====================
    async function resetearRankingCompleto() {
        const evaluaciones = window.evaluacionesGlobales || [];
        if (evaluaciones.length > 0) {
            rankingCompletoGlobal = await construirRankingAgentes(evaluaciones);
            console.log(`✅ Ranking completo actualizado: ${rankingCompletoGlobal.length} gestores`);
        }
    }
    // ===== FIN FUNCIÓN: resetearRankingCompleto ============================

    // ===== 17. INICIO FUNCIÓN: calcularCobertura ===========================
    function calcularCobertura(evaluaciones, ranking) {
        const totalAgentes = ranking.length;
        const agentesAuditados = new Set(evaluaciones.map(e => e.agente)).size;
        const cobertura = totalAgentes > 0 ? ((agentesAuditados / totalAgentes) * 100).toFixed(1) : 0;
        return {
            porcentaje: cobertura,
            auditados: agentesAuditados,
            total: totalAgentes
        };
    }
    // ===== FIN FUNCIÓN: calcularCobertura ==================================

    // ===== 18. INICIO FUNCIÓN: calcularTasaQuiebre =========================
    function calcularTasaQuiebre(ranking) {
        const totalAgentes = ranking.length;
        const agentesConQuiebre = ranking.filter(a => a.cuartil === 'Q4').length;
        const tasa = totalAgentes > 0 ? Math.round((agentesConQuiebre / totalAgentes) * 100) : 0;
        return {
            porcentaje: tasa,
            quiebres: agentesConQuiebre,
            total: totalAgentes
        };
    }
    // ===== FIN FUNCIÓN: calcularTasaQuiebre ================================

    // ===== 19. INICIO Event Listeners: ACTUALIZAR AGENTE EXISTENTE =========
    document.getElementById('formAgente')?.addEventListener('submit', async function (e) {
        e.preventDefault();

        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }

        const nombre = document.getElementById('agenteNombre').value.trim().toUpperCase();
        const estado = document.getElementById('agenteEstado').value; // 'ACTIVO' o 'INACTIVO'

        if (!nombre) {
            alert('⚠️ Complete el nombre del agente');
            return;
        }

        try {
            if (window.agenteEnEdicion) {
                // ======================================================
                // ACTUALIZAR AGENTE EXISTENTE
                // ======================================================
                console.log(`✏️ Actualizando agente ID: ${window.agenteEnEdicion}`);

                const { error } = await db
                    .from('agentes')
                    .update({
                        nombre: nombre,
                        estado: estado,  // 🔴 texto: 'ACTIVO' o 'INACTIVO'
                        updated_at: new Date().toISOString()
                    })
                    .eq('id', window.agenteEnEdicion);

                if (error) throw error;
                alert(`✅ Agente "${nombre}" actualizado correctamente`);
                window.agenteEnEdicion = null;

            } else {
                // ======================================================
                // CREAR NUEVO AGENTE CON ID INCREMENTAL
                // ======================================================

                // 1. Verificar si ya existe un agente con ese nombre
                const { data: existe, error: existeError } = await db
                    .from('agentes')
                    .select('id')
                    .eq('nombre', nombre)
                    .maybeSingle();

                if (existeError) {
                    console.warn('Error verificando existencia:', existeError);
                }

                if (existe) {
                    alert(`⚠️ Ya existe un agente con el nombre "${nombre}"`);
                    return;
                }

                // 2. Obtener el ID máximo actual para generar el siguiente
                const { data: maxIdData, error: maxIdError } = await db
                    .from('agentes')
                    .select('id')
                    .order('id', { ascending: false })
                    .limit(1);

                if (maxIdError) {
                    console.error('Error obteniendo max ID:', maxIdError);
                }

                // 3. Calcular el nuevo ID
                let nuevoId = 1;
                if (maxIdData && maxIdData.length > 0 && maxIdData[0].id) {
                    nuevoId = Number(maxIdData[0].id) + 1;
                }

                console.log(`📝 Creando nuevo agente con ID: ${nuevoId}`);

                // 4. Crear el objeto del nuevo agente
                const nuevoAgente = {
                    id: nuevoId,
                    nombre: nombre,
                    estado: estado,  // 🔴 texto: 'ACTIVO' o 'INACTIVO'
                    created_at: new Date().toISOString(),
                    updated_at: new Date().toISOString()
                };

                // 5. Insertar en la base de datos
                const { error: insertError } = await db
                    .from('agentes')
                    .insert(nuevoAgente);

                if (insertError) throw insertError;

                alert(`✅ Agente "${nombre}" registrado correctamente (ID: ${nuevoId})`);
            }

            // 6. Recargar tabla y limpiar formulario
            await cargarAgentes();
            limpiarFormAgente();

        } catch (error) {
            console.error('❌ Error guardando agente:', error);
            alert('❌ Error al guardar: ' + error.message);
        }
    });
    // ===== FIN Event Listeners: ACTUALIZAR AGENTE EXISTENTE ================

    // ===== 20. INICIO Event Listeners: GUARDAR AGENTE  =====================
    document.getElementById('fileAgentes')?.addEventListener('change', function (e) {
        const file = e.target.files[0];
        console.log('📢 [DEBUG] Archivo seleccionado:', file?.name);
        
        if (!file) {
            console.log('📢 [DEBUG] No hay archivo');
            return;
        }

        const reader = new FileReader();
        reader.onload = function (e) {
            console.log('📢 [DEBUG] Iniciando lectura del archivo...');
            
            const data = new Uint8Array(e.target.result);
            const workbook = XLSX.read(data, { type: 'array' });
            const primeraHoja = workbook.Sheets[workbook.SheetNames[0]];
            const jsonData = XLSX.utils.sheet_to_json(primeraHoja, { defval: "" });

            console.log('📊 Datos cargados:', jsonData.length);
            console.log('📋 Columnas detectadas:', Object.keys(jsonData[0] || {}));

            // Mapeo de columnas (flexible, acepta mayúsculas/minúsculas)
            const mapeoColumnas = {
                id: ['id', 'ID'],
                nombre: ['nombre', 'Nombre', 'NOMBRE', 'Nombre y Apellidos', 'NOMBRE Y APELLIDOS', 'agente', 'Agente'],
                dni: ['dni', 'DNI', 'Dni'],
                carnet: ['carnet', 'CARNET', 'Carnet'],
                correo: ['correo', 'CORREO', 'email', 'Email', 'EMAIL'],
                estado: ['estado', 'Estado', 'ESTADO'],
                lider_2026: ['lider_2026', 'LIDER_2026', 'lider', 'Lider', 'LÍDER', 'líder'],
                ubicacion: ['ubicacion', 'UBICACION', 'ubicación', 'Ubicación'],
                localidad: ['localidad', 'LOCALIDAD', 'Localidad'],
                categoria_label: ['categoria_label', 'CATEGORIA_LABEL', 'categoria', 'Categoria', 'CATEGORÍA', 'categoría'],
                funciones: ['funciones', 'FUNCIONES', 'Funciones'],
                horario_marzo: ['horario_marzo', 'HORARIO_MARZO', 'horarioMarzo'],
                horario_marzo_v1: ['horario_marzo_v1', 'HORARIO_MARZO_V1', 'horarioMarzoV1'],
                canal_tobe_1ra_activ_marzo: ['canal_tobe_1ra_activ_marzo', 'CANAL_TOBE_1RA_ACTIV_MARZO', 'canalTobe'],
                '1ra_actividad_marzo_v1': ['1ra_actividad_marzo_v1', '1RA_ACTIVIDAD_MARZO_V1', 'actividadMarzoV1'],
                created_at: ['created_at', 'CREATED_AT', 'fecha_creacion', 'Fecha Creación'],
                updated_at: ['updated_at', 'UPDATED_AT', 'fecha_actualizacion', 'Fecha Actualización']
            };

            function obtenerValor(row, posiblesNombres) {
                for (const nombre of posiblesNombres) {
                    if (row[nombre] !== undefined && row[nombre] !== null && row[nombre] !== '') {
                        let valor = row[nombre];
                        if (typeof valor === 'string') valor = valor.trim();
                        return valor;
                    }
                }
                return '';
            }

            const agentes = [];
            const errores = [];

            for (let i = 0; i < jsonData.length; i++) {
                const row = jsonData[i];
                const agente = {};
                
                for (const [campo, posibles] of Object.entries(mapeoColumnas)) {
                    agente[campo] = obtenerValor(row, posibles);
                }
                
                if (!agente.nombre || agente.nombre === '') {
                    errores.push(`Fila ${i + 2}: Nombre vacío o no encontrado`);
                    continue;
                }
                
                agente.nombre = agente.nombre.toString().toUpperCase();
                
                if (agente.estado) {
                    let estadoLimpio = agente.estado.toString().toUpperCase();
                    estadoLimpio = estadoLimpio.replace(/[^A-Z\s]/gi, '').trim();
                    if (estadoLimpio.includes('ACTIV')) agente.estado = 'ACTIVO';
                    else if (estadoLimpio.includes('INACTIV')) agente.estado = 'INACTIVO';
                    else if (estadoLimpio.includes('DM') || estadoLimpio.includes('PROLONG')) agente.estado = 'DM PROLONGADO';
                    else agente.estado = 'ACTIVO';
                } else {
                    agente.estado = 'ACTIVO';
                }
                
                if (agente.lider_2026 && typeof agente.lider_2026 === 'string') {
                    agente.lider_2026 = agente.lider_2026.toUpperCase();
                }
                if (agente.ubicacion && typeof agente.ubicacion === 'string') {
                    agente.ubicacion = agente.ubicacion.toUpperCase();
                }
                if (agente.localidad && typeof agente.localidad === 'string') {
                    agente.localidad = agente.localidad.toUpperCase();
                }
                if (agente.categoria_label && typeof agente.categoria_label === 'string') {
                    agente.categoria_label = agente.categoria_label.toUpperCase();
                }
                if (agente.funciones && typeof agente.funciones === 'string') {
                    agente.funciones = agente.funciones.toUpperCase();
                }
                
                agentes.push(agente);
            }

            console.log('📢 [DEBUG] Agentes procesados:', agentes.length);

            if (agentes.length === 0) {
                alert('⚠️ No se encontraron agentes válidos en el archivo.\nAsegúrese de tener una columna llamada "nombre" o "Nombre y Apellidos"');
                return;
            }

            // Mostrar vista previa
            const vistaPrevia = document.getElementById('vistaPreviaContenido');
            let previewHtml = `
                <div style="max-height: 300px; overflow-x: auto;">
                    <table style="width: 100%; font-size: 11px; border-collapse: collapse;">
                        <thead>
                            <tr>
                                <th>#</th>
                                <th>Nombre</th>
                                <th>DNI</th>
                                <th>Carnet</th>
                                <th>Correo</th>
                                <th>Estado</th>
                                <th>Líder</th>
                                <th>Ubicación</th>
                                <th>Localidad</th>
                                <th>Categoría</th>
                            </tr>
                        </thead>
                        <tbody>
            `;

            agentes.slice(0, 10).forEach((a, i) => {
                previewHtml += `<tr>
                    <td>${i + 1}</td>
                    <td>${escapeHtml(a.nombre)}</td>
                    <td>${escapeHtml(a.dni || '-')}</td>
                    <td>${escapeHtml(a.carnet || '-')}</td>
                    <td>${escapeHtml(a.correo || '-')}</td>
                    <td>${a.estado}</td>
                    <td>${escapeHtml(a.lider_2026 || '-')}</td>
                    <td>${escapeHtml(a.ubicacion || '-')}</td>
                    <td>${escapeHtml(a.localidad || '-')}</td>
                    <td>${escapeHtml(a.categoria_label || '-')}</td>
                </tr>`;
            });

            if (agentes.length > 10) {
                previewHtml += `<tr><td colspan="10" style="text-align: center;">... y ${agentes.length - 10} más</td></tr>`;
            }

            previewHtml += `
                        </tbody>
                    </table>
                </div>
            `;

            if (errores.length > 0) {
                previewHtml += `<div style="margin-top: 10px; color: var(--danger); font-size: 11px;">
                    <strong>⚠️ Advertencias:</strong><br>
                    ${errores.slice(0, 5).join('<br>')}
                    ${errores.length > 5 ? `<br>... y ${errores.length - 5} más` : ''}
                </div>`;
            }

            vistaPrevia.innerHTML = previewHtml;
            document.getElementById('vistaPreviaAgentes').style.display = 'block';

            // 🔴 CLAVE: Asignar a variable GLOBAL
            window.agentesPendientesGuardarMasivo = agentes;
            console.log('📢 Asignado a window.agentesPendientesGuardarMasivo:', window.agentesPendientesGuardarMasivo?.length);

            // 🔴 CLAVE: Habilitar botón
            const btnGuardar = document.getElementById('btnGuardarAgentesMasivo');
            console.log('📢 [DEBUG] Botón encontrado?', btnGuardar);
            
            if (btnGuardar) {
                btnGuardar.disabled = false;
                btnGuardar.style.opacity = '1';
                btnGuardar.style.cursor = 'pointer';
                console.log('📢 [DEBUG] Botón habilitado, disabled =', btnGuardar.disabled);
            } else {
                console.error('📢 [ERROR] Botón btnGuardarAgentesMasivo NO encontrado en el DOM');
            }

            console.log(`✅ ${agentes.length} agentes listos para guardar`);
        };
        
        reader.onerror = function(error) {
            console.error('📢 [ERROR] Error leyendo archivo:', error);
            alert('Error al leer el archivo');
        };
        
        reader.readAsArrayBuffer(file);
    });
    // ===== FIN Event Listeners: GUARDAR AGENTE =============================

