    // ===== 1. INICIO FUNCIÓN: guardarUsuario =============================
    async function guardarUsuario(event) {
        event.preventDefault();
        event.stopPropagation();

        const token = localStorage.getItem('meca_token');
        
        // 🔴 DEFINIR TODAS LAS VARIABLES
        const usuario = document.getElementById('usuarioUsername').value.trim().toLowerCase();
        const nombreCompleto = document.getElementById('usuarioNombreCompleto').value.trim().toUpperCase();
        const password = document.getElementById('usuarioPassword').value;
        const passwordConfirm = document.getElementById('usuarioPasswordConfirm').value;
        const rolId = document.getElementById('usuarioRol').value;
        const activo = document.getElementById('usuarioActivo').value === 'true';
        
        const isEditing = window.usuarioEnEdicion;
        
        console.log('isEditing:', isEditing);
        console.log('usuario:', usuario);
        console.log('nombreCompleto:', nombreCompleto);

        if (!usuario || !nombreCompleto || !rolId) {
            alert('⚠️ Complete los campos requeridos');
            return;
        }

        try {
            if (isEditing) {
                // ========== ACTUALIZAR ==========
                console.log(`✏️ ACTUALIZANDO usuario ID: ${isEditing}`);
                
                const updateData = {
                    usuario: usuario,  // 🔴 USAR LA VARIABLE 'usuario'
                    nombre_completo: nombreCompleto,
                    rol_id: parseInt(rolId),
                    activo: activo
                };
                
                if (password) {
                    if (password !== passwordConfirm) {
                        alert('⚠️ Las contraseñas no coinciden');
                        return;
                    }
                    if (password.length < 6) {
                        alert('⚠️ La contraseña debe tener al menos 6 caracteres');
                        return;
                    }
                    updateData.contrasena = password;
                }
                
                console.log('📤 Enviando PUT con datos:', updateData);
                
                const response = await fetch(`/api/usuarios/${isEditing}`, {
                    method: 'PUT',
                    headers: {
                        'Authorization': `Bearer ${token}`,
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify(updateData)
                });
                
                console.log('📥 Response status:', response.status);
                
                if (response.ok) {
                    alert('✅ Usuario actualizado correctamente');
                    window.usuarioEnEdicion = null;
                    limpiarFormUsuario();
                    await cargarUsuarios();
                    await cargarRoles();
                } else {
                    const error = await response.json();
                    console.error('Error:', error);
                    alert('❌ Error: ' + (error.error || 'No se pudo actualizar'));
                }
                
            } else {
                // ========== CREAR NUEVO ==========
                console.log('📝 CREANDO nuevo usuario');
                
                if (!password || password !== passwordConfirm) {
                    alert('⚠️ Las contraseñas no coinciden');
                    return;
                }
                
                if (password.length < 6) {
                    alert('⚠️ La contraseña debe tener al menos 6 caracteres');
                    return;
                }
                
                const response = await fetch('/api/usuarios', {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${token}`,
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify({
                        usuario: usuario,
                        nombre_completo: nombreCompleto,
                        contrasena: password,
                        rol_id: parseInt(rolId),
                        activo: activo
                    })
                });

                if (response.ok) {
                    alert('✅ Usuario creado correctamente');
                    document.getElementById('formUsuario').reset();
                    await cargarUsuarios();
                    await cargarRoles();
                } else {
                    const error = await response.json();
                    alert('❌ Error: ' + (error.error || 'No se pudo crear'));
                }
            }
            
        } catch (error) {
            console.error('Error:', error);
            alert('❌ Error: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: guardarUsuario =====================================

    // ===== 2. INICIO FUNCIÓN: filtrarUsuarios ============================
    function filtrarUsuarios() {
        const busqueda = document.getElementById('buscarUsuario').value.toLowerCase();

        if (!busqueda) {
            usuariosFiltrados = [...usuariosGlobales];
        } else {
            usuariosFiltrados = usuariosGlobales.filter(usuario =>
                usuario.usuario.toLowerCase().includes(busqueda) ||
                (usuario.nombre_completo && usuario.nombre_completo.toLowerCase().includes(busqueda))
            );
        }

        actualizarTablaUsuarios();
    }
    // ===== FIN FUNCIÓN: filtrarUsuarios ====================================

    // ===== 3. INICIO FUNCIÓN: actualizarTablaUsuarios ====================
    function actualizarTablaUsuarios() {
        const tbody = document.getElementById('tablaUsuarios');
        if (!tbody) return;

        // 🔴 CORREGIDO: Usar window.usuariosGlobales
        const usuarios = window.usuariosGlobales || [];
        
        if (usuarios.length === 0) {
            tbody.innerHTML = '<tr><td colspan="7" style="text-align: center; padding: 40px;">No hay usuarios registrados<\/td><\/tr>';
            if (document.getElementById('totalUsuarios')) document.getElementById('totalUsuarios').textContent = '0';
            return;
        }

        let html = '';
        for (const usuario of usuarios) {
            const usuarioId = usuario.id;
            const activo = usuario.activo === true || usuario.activo === 'true' || usuario.activo === 1;
            const estadoBadge = activo
                ? '<span class="badge" style="background: var(--ok);">✅ Activo</span>'
                : '<span class="badge" style="background: var(--danger);">❌ Inactivo</span>';

            const rolNombre = usuario.rol_nombre || usuario.rol || 'Sin rol';
            const rolCodigo = usuario.rol_codigo || '';
            
            let rolBadge = '';
            if (rolCodigo === 'ADMIN') {
                rolBadge = '<span class="badge" style="background: #7b1fa2;">⚙️ ADMIN</span>';
            } else if (rolCodigo === 'SUPERVISOR') {
                rolBadge = '<span class="badge" style="background: #fd7e14;">👔 SUPERVISOR</span>';
            } else {
                rolBadge = `<span class="badge" style="background: #019DF4;">🎧 ${escapeHtml(rolNombre)}</span>`;
            }

            const fechaRegistro = usuario.created_at
                ? new Date(usuario.created_at).toLocaleDateString('es-ES')
                : '-';
            
            html += `
                <tr style="border-bottom: 1px solid var(--line);">
                    <td style="padding: 8px; text-align: center;">${usuarioId}</td>
                    <td style="padding: 8px;"><strong>${escapeHtml(usuario.usuario)}</strong></td>
                    <td style="padding: 8px;">${escapeHtml(usuario.nombre_completo || '-')}</td>
                    <td style="padding: 8px;">${rolBadge}</td>
                    <td style="padding: 8px; text-align: center;">${estadoBadge}</td>
                    <td style="padding: 8px; text-align: center;">${fechaRegistro}</td>
                    <td style="padding: 8px; text-align: center; white-space: nowrap;">
                        <button onclick="editarUsuario(${usuarioId})" 
                                style="background: var(--warning); padding: 5px 10px; border-radius: 6px; border: none; cursor: pointer; margin-right: 5px;">
                            ✏️
                        </button>
                        <button onclick="cambiarPasswordUsuario(${usuarioId})" 
                                style="background: var(--accent); padding: 5px 10px; border-radius: 6px; border: none; cursor: pointer; margin-right: 5px;">
                            🔐
                        </button>
                        <button onclick="eliminarUsuario(${usuarioId})" 
                                style="background: #fee; color: var(--danger); padding: 5px 10px; border-radius: 6px; border: none; cursor: pointer;">
                            🗑️
                        </button>
                    </td>
                </table>
            `;
        }

        tbody.innerHTML = html;
        
        if (document.getElementById('totalUsuarios')) {
            document.getElementById('totalUsuarios').textContent = usuarios.length;
        }
        
        console.log(`✅ Tabla actualizada con ${usuarios.length} usuarios`);
    }
    // ===== FIN FUNCIÓN: actualizarTablaUsuarios ============================

    // ===== 4. INICIO FUNCIÓN: actualizarEstadisticasUsuarios =============
    function actualizarEstadisticasUsuarios() {
        const total = usuariosGlobales.length;
        const activos = usuariosGlobales.filter(u => u.activo === true || u.activo === 'true' || u.activo === 1).length;
        const auditores = usuariosGlobales.filter(u => u.rol === 'AUDITOR').length;
        const supervisores = usuariosGlobales.filter(u => u.rol === 'SUPERVISOR' || u.rol === 'ADMIN').length;

        const statsTotal = document.getElementById('statsTotalUsuarios');
        const statsActivos = document.getElementById('statsUsuariosActivos');
        const statsAuditores = document.getElementById('statsAuditores');
        const statsSupervisores = document.getElementById('statsSupervisores');
        const totalUsuariosActivos = document.getElementById('totalUsuariosActivos');
        const totalAuditores = document.getElementById('totalAuditores');

        if (statsTotal) statsTotal.textContent = total;
        if (statsActivos) statsActivos.textContent = activos;
        if (statsAuditores) statsAuditores.textContent = auditores;
        if (statsSupervisores) statsSupervisores.textContent = supervisores;
        if (totalUsuariosActivos) totalUsuariosActivos.textContent = activos;
        if (totalAuditores) totalAuditores.textContent = auditores;
    }
    // ===== FIN FUNCIÓN: actualizarEstadisticasUsuarios =====================

    // ===== 5. INICIO FUNCIÓN: inicializarFormularioUsuarios ==============
    function inicializarFormularioUsuarios() {
        const formUsuario = document.getElementById('formUsuario');
        if (!formUsuario) {
            console.warn('⚠️ Formulario de usuarios no encontrado');
            return;
        }

        // Remover event listeners anteriores
        const nuevoForm = formUsuario.cloneNode(true);
        formUsuario.parentNode.replaceChild(nuevoForm, formUsuario);

        const formFinal = document.getElementById('formUsuario');

        // ✅ Usar la función guardarUsuario externa, no reescribirla aquí
        formFinal.addEventListener('submit', guardarUsuario);

        console.log('✅ Formulario de usuarios inicializado');
    }
    // ===== FIN FUNCIÓN: inicializarFormularioUsuarios ======================

    // ===== 6. INICIO FUNCIÓN: limpiarFormUsuario =========================
    function limpiarFormUsuario() {
        document.getElementById('usuarioUsername').value = '';
        document.getElementById('usuarioNombreCompleto').value = '';
        document.getElementById('usuarioPassword').value = '';
        document.getElementById('usuarioPasswordConfirm').value = '';
        document.getElementById('usuarioRol').value = '';
        document.getElementById('usuarioActivo').value = 'true';
        
        window.usuarioEnEdicion = null;
        
        const btnSubmit = document.querySelector('#formUsuario button[type="submit"]');
        if (btnSubmit) {
            btnSubmit.textContent = '💾 Guardar Usuario';
            btnSubmit.style.background = '';
        }
        
        const btnCancelar = document.getElementById('btnCancelarEdicion');
        if (btnCancelar) btnCancelar.style.display = 'none';
    }
    // ===== FIN FUNCIÓN: limpiarFormUsuario =================================

    // ===== 7. INICIO FUNCIÓN: editarUsuario ==============================
    async function editarUsuario(id) {
        console.log('✏️ EDITANDO USUARIO - ID recibido:', id);
        
        // 🔴 FORZAR LA ASIGNACIÓN GLOBAL INMEDIATA
        window.usuarioEnEdicion = id;
        console.log('✅ window.usuarioEnEdicion asignado a:', window.usuarioEnEdicion);
        
        const token = localStorage.getItem('meca_token');
        
        try {
            const response = await fetch(`/api/usuarios/${id}`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            
            if (!response.ok) {
                throw new Error(`HTTP ${response.status}`);
            }
            
            const usuario = await response.json();
            
            console.log('📝 Usuario cargado:', usuario);
            
            // Cargar datos en el formulario
            document.getElementById('usuarioUsername').value = usuario.usuario || '';
            document.getElementById('usuarioNombreCompleto').value = usuario.nombre_completo || '';
            document.getElementById('usuarioPassword').value = '';
            document.getElementById('usuarioPasswordConfirm').value = '';
            document.getElementById('usuarioRol').value = usuario.rol_id || '';
            document.getElementById('usuarioActivo').value = usuario.activo ? 'true' : 'false';
            
            // Cambiar el texto del botón
            const btnSubmit = document.querySelector('#formUsuario button[type="submit"]');
            if (btnSubmit) {
                btnSubmit.textContent = '✏️ Actualizar Usuario';
                btnSubmit.style.background = 'var(--warning)';
            }
            
            // Mostrar botón cancelar
            const btnCancelar = document.getElementById('btnCancelarEdicion');
            if (btnCancelar) {
                btnCancelar.style.display = 'inline-flex';
            }
            
            alert(`✏️ Editando usuario: ${usuario.usuario}\n\nDeje la contraseña en blanco para mantener la actual.`);
            
        } catch (error) {
            console.error('Error:', error);
            alert('Error al cargar usuario: ' + error.message);
            window.usuarioEnEdicion = null;
        }
    }
    // ===== FIN FUNCIÓN: editarUsuario ======================================

    // ===== 8. INICIO FUNCIÓN: cambiarPasswordUsuario =====================
    async function cambiarPasswordUsuario(id) {
        const usuario = usuariosGlobales.find(u => u.id === id);
        if (!usuario) return;

        usuarioPasswordId = id;
        document.getElementById('cambiarPasswordUsuario').textContent = usuario.usuario;
        document.getElementById('modalCambiarPassword').style.display = 'flex';
    }           
    
    document.getElementById('formCambiarPassword')?.addEventListener('submit', async function (e) {
        e.preventDefault();

        const nuevaPass = document.getElementById('nuevaPassword').value;
        const confirmPass = document.getElementById('confirmarPassword').value;

        if (!nuevaPass || nuevaPass !== confirmPass) {
            alert('⚠️ Las contraseñas no coinciden');
            return;
        }

        if (nuevaPass.length < 6) {
            alert('⚠️ Mínimo 6 caracteres');
            return;
        }

        const db = getDB();
        const hashed = await hashPassword(nuevaPass);

        const { error } = await db
            .from('usuarios')
            .update({ contrasena: hashed, updated_at: new Date().toISOString() })
            .eq('id', usuarioPasswordId);

        if (error) {
            alert('❌ Error: ' + error.message);
        } else {
            alert('✅ Contraseña actualizada correctamente');
            cerrarModalPassword();
        }
    });
    // ===== FIN FUNCIÓN: cambiarPasswordUsuario =============================

    // ===== 9. INICIO FUNCIÓN: cerrarModalPassword ========================
    function cerrarModalPassword() {
        const modal = document.getElementById('modalCambiarPassword');
        if (modal) {
            modal.style.display = 'none';
        }
        document.getElementById('nuevaPassword').value = '';
        document.getElementById('confirmarPassword').value = '';
        window.usuarioPasswordId = null;
    }
    // ===== FIN FUNCIÓN: cerrarModalPassword ================================

    // ===== 10. INICIO FUNCIÓN: inicializarFormCambioPassword ==============
    function inicializarFormCambioPassword() {
        const form = document.getElementById('formCambiarPassword');
        if (!form) return;

        form.addEventListener('submit', async function (e) {
            e.preventDefault();

            const nuevaPassword = document.getElementById('nuevaPassword').value;
            const confirmarPassword = document.getElementById('confirmarPassword').value;

            if (!nuevaPassword || !confirmarPassword) {
                alert('⚠️ Complete ambos campos');
                return;
            }

            if (nuevaPassword !== confirmarPassword) {
                alert('⚠️ Las contraseñas no coinciden');
                return;
            }

            if (nuevaPassword.length < 6) {
                alert('⚠️ La contraseña debe tener al menos 6 caracteres');
                return;
            }

            const db = getDB();
            if (!db) return;

            try {
                const hashedPassword = await hashPassword(nuevaPassword);

                const { error } = await db
                    .from('usuarios')
                    .update({ contrasena: hashedPassword, updated_at: new Date().toISOString() })
                    .eq('id', usuarioPasswordId);

                if (error) throw error;

                alert('✅ Contraseña actualizada correctamente');
                cerrarModalPassword();

            } catch (error) {
                console.error('Error:', error);
                alert('❌ Error al actualizar contraseña: ' + error.message);
            }
        });
    }
    // ===== FIN FUNCIÓN: inicializarFormCambioPassword ======================

    // ===== 11. INICIO FUNCIÓN: eliminarUsuario ============================
    async function eliminarUsuario(id) {
        console.log(`🗑️ Eliminando usuario ID: ${id} (tipo: ${typeof id})`);
        
        // 🔴 CORREGIDO: Comparar como string o convertir a número
        const usuario = usuariosGlobales.find(u => String(u.id) === String(id));
        
        if (!usuario) {
            console.log('IDs disponibles:', usuariosGlobales.map(u => ({ id: u.id, tipo: typeof u.id })));
            alert('Usuario no encontrado');
            return;
        }

        if (!confirm(`⚠️ ¿Eliminar al usuario "${usuario.usuario}"?\n\nEsta acción no se puede deshacer.`)) return;

        try {
            await API.eliminarUsuario(id);
            alert(`✅ Usuario "${usuario.usuario}" eliminado correctamente`);
            
            // Recargar datos y actualizar tabla
            await cargarUsuarios();
            await cargarRoles();
            
            if (typeof actualizarEstadisticasUsuarios === 'function') {
                actualizarEstadisticasUsuarios();
            }
            
            console.log('✅ Tabla de usuarios recargada');
            
        } catch (error) {
            console.error('Error eliminando usuario:', error);
            alert('❌ Error al eliminar: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: eliminarUsuario ====================================

    // ===== 12. INICIO FUNCIÓN: exportarUsuariosCSV ========================
    async function exportarUsuariosCSV() {
        console.log('📥 Exportando usuarios a CSV...');
        
        try {
            const token = localStorage.getItem('meca_token');
            const response = await fetch('/api/usuarios/exportar', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                }
            });
            
            if (!response.ok) {
                throw new Error(`HTTP ${response.status}`);
            }
            
            // 🔴 Obtener el CSV directamente como texto
            const csvContent = await response.text();
            
            // Crear el blob y descargar
            const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `usuarios_${new Date().toISOString().slice(0, 10)}.csv`;
            a.click();
            URL.revokeObjectURL(url);
            
            // Contar líneas para el mensaje
            const lineas = csvContent.split('\n').length - 1;
            alert(`✅ Exportados ${lineas} usuarios`);
            
        } catch (error) {
            console.error('Error exportando usuarios:', error);
            alert('❌ Error al exportar: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: exportarUsuariosCSV ================================

    // ===== 13. INICIO FUNCIÓN: actualizarSelectRoles ======================
    function actualizarSelectRoles() {
        const selectRol = document.getElementById('usuarioRol');
        if (!selectRol) return;
        
        const valorActual = selectRol.value;
        
        selectRol.innerHTML = '<option value="">-- Seleccionar rol --</option>';
        
        rolesGlobales.forEach(rol => {
            const esActivo = rol.activo === true || rol.activo === 'true';
            if (esActivo) {
                const selected = (valorActual && rol.id == valorActual) ? 'selected' : '';
                selectRol.innerHTML += `<option value="${rol.id}" ${selected}>${escapeHtml(rol.nombre)} (${escapeHtml(rol.codigo)})</option>`;
            }
        });
        
        console.log(`✅ Select de roles actualizado con ${rolesGlobales.length} roles`);
    }
    // ===== FIN FUNCIÓN: actualizarSelectRoles ==============================

    // ===== 14. INICIO FUNCIÓN: actualizarTablaRoles =======================
    async function actualizarTablaRoles() {
        const tbody = document.getElementById('tablaRoles');
        if (!tbody) return;
        
        if (!rolesGlobales || rolesGlobales.length === 0) {
            tbody.innerHTML = '<tr><td colspan="7" style="text-align: center; padding: 40px;">No hay roles registrados<\/td><\/tr>';
            return;
        }
        
        // 🔴 USAR LAS VARIABLES GLOBALES que ya cargamos
        const pestanasMap = {};
        (window.pestanasDisponiblesGlobal || []).forEach(p => {
            pestanasMap[p.codigo] = { icono: p.icono, nombre: p.nombre };
        });
        
        const permisosMap = {};
        (window.permisosPestanasGlobal || []).forEach(p => {
            if (!permisosMap[p.rol_id]) permisosMap[p.rol_id] = new Set();
            permisosMap[p.rol_id].add(p.pestana_codigo);
        });
        
        let html = '';
        
        for (const rol of rolesGlobales) {
            const cantidadUsuarios = (usuariosGlobales?.filter(u => u.rol_id === rol.id).length || 0);
            const estadoBadge = (rol.activo === true || rol.activo === 'true')
                ? '<span class="badge" style="background: var(--ok);">✅ Activo</span>'
                : '<span class="badge" style="background: var(--danger);">❌ Inactivo</span>';
            
            // Obtener pestañas permitidas para este rol
            const pestanasPermitidasSet = permisosMap[rol.id] || new Set();
            const pestanasDelRol = (window.pestanasDisponiblesGlobal || []).filter(p => pestanasPermitidasSet.has(p.codigo));
            
            let pestanasHtml = '';
            if (pestanasDelRol.length > 0) {
                pestanasHtml = pestanasDelRol.map(p => 
                    `<span style="font-size: 16px; cursor: help; margin: 0 2px;" title="${escapeHtml(p.nombre)} (${p.codigo})">${p.icono}</span>`
                ).join(' ');
            } else {
                pestanasHtml = '<span style="color: var(--muted); font-size: 12px;">—</span>';
            }
            
            html += `
                <tr style="border-bottom: 1px solid var(--line);">
                    <td style="padding: 8px; text-align: center;">${rol.id}</td>
                    <td style="padding: 8px;"><strong>${escapeHtml(rol.codigo)}</strong></td>
                    <td style="padding: 8px;">${escapeHtml(rol.nombre)}</td>
                    <td style="padding: 8px; text-align: center; white-space: nowrap;">${pestanasHtml}</td>
                    <td style="padding: 8px; text-align: center;">
                        <span class="badge" style="background: ${cantidadUsuarios > 0 ? '#019DF4' : '#6c757d'};">${cantidadUsuarios}</span>
                    </td>
                    <td style="padding: 8px; text-align: center;">${estadoBadge}</td>
                    <td style="padding: 8px; text-align: center; white-space: nowrap;">
                        <button onclick="administrarPestanasRol(${rol.id}, '${escapeHtml(rol.nombre)}')" 
                                style="background: var(--accent); padding: 5px 10px; font-size: 11px; border-radius: 6px; border: none; cursor: pointer; margin-right: 5px;"
                                title="Administrar pestañas de este rol">
                            📋 Pestañas
                        </button>
                        <button onclick="eliminarRol(${rol.id})" 
                                style="background: var(--danger); padding: 5px 10px; font-size: 11px; border-radius: 6px; border: none; cursor: pointer;"
                                title="Eliminar rol">
                            🗑️
                        </button>
                    </td>
                </tr>
            `;
        }
        
        tbody.innerHTML = html;
        console.log('✅ Tabla de roles actualizada con íconos de pestañas');
    }
    // ===== FIN FUNCIÓN: actualizarTablaRoles ===============================

    // ===== 15. INICIO FUNCIÓN: actualizarEstadisticasRoles ================
    function actualizarEstadisticasRoles() {
        const rolesActivos = rolesGlobales.filter(r => r.activo === true || r.activo === 'true').length;
        
        const statsRolesActivos = document.getElementById('statsRolesActivos');
        const statsTotalRoles = document.getElementById('statsTotalRoles');
        
        if (statsRolesActivos) statsRolesActivos.textContent = rolesActivos;
        if (statsTotalRoles) statsTotalRoles.textContent = rolesGlobales.length;
    }
    // ===== FIN FUNCIÓN: actualizarEstadisticasRoles ========================

    // ===== 16. INICIO FUNCIÓN: mostrarModalNuevoRol =======================
    
    function mostrarModalNuevoRol() {
        // Limpiar modal anterior si existe
        const modalExistente = document.getElementById('modalNuevoRol');
        if (modalExistente) modalExistente.remove();
        
        const modalHtml = `
            <div id="modalNuevoRol" style="position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.6); z-index: 10002; display: flex; justify-content: center; align-items: center;">
                <div style="background: white; border-radius: 16px; width: 90%; max-width: 450px; overflow: hidden; box-shadow: 0 20px 40px rgba(0,0,0,0.3);">
                    <div style="padding: 15px 20px; background: linear-gradient(135deg, var(--accent), var(--accent2)); color: white;">
                        <strong style="font-size: 16px;">➕ Nuevo Rol</strong>
                    </div>
                    <div style="padding: 20px;">
                        <div style="margin-bottom: 15px;">
                            <label style="font-size: 12px; font-weight: 600;">Código del Rol *</label>
                            <input type="text" id="nuevoRolCodigo" placeholder="Ej: GERENTE, COORDINADOR" 
                                style="width: 100%; padding: 10px; margin-top: 5px; border-radius: 8px; border: 1px solid var(--line);">
                            <small style="color: var(--muted);">Identificador único (mayúsculas, sin espacios)</small>
                        </div>
                        <div style="margin-bottom: 15px;">
                            <label style="font-size: 12px; font-weight: 600;">Nombre del Rol *</label>
                            <input type="text" id="nuevoRolNombre" placeholder="Ej: Gerente de Calidad" 
                                style="width: 100%; padding: 10px; margin-top: 5px; border-radius: 8px; border: 1px solid var(--line);">
                        </div>
                        <div style="margin-bottom: 20px;">
                            <label style="font-size: 12px; font-weight: 600;">Estado</label>
                            <select id="nuevoRolActivo" style="width: 100%; padding: 10px; margin-top: 5px; border-radius: 8px; border: 1px solid var(--line);">
                                <option value="true">✅ ACTIVO</option>
                                <option value="false">❌ INACTIVO</option>
                            </select>
                        </div>
                        <div style="display: flex; gap: 10px; justify-content: flex-end;">
                            <button onclick="cerrarModalNuevoRol()" class="secondary" style="padding: 8px 20px;">Cancelar</button>
                            <button onclick="crearNuevoRol()" style="background: var(--ok); padding: 8px 20px;">💾 Crear Rol</button>
                        </div>
                    </div>
                </div>
            </div>
        `;
        
        document.body.insertAdjacentHTML('beforeend', modalHtml);
    }

    function cerrarModalNuevoRol() {
        const modal = document.getElementById('modalNuevoRol');
        if (modal) modal.remove();
    }

    async function crearNuevoRol() {
        const codigo = document.getElementById('nuevoRolCodigo')?.value.trim().toUpperCase();
        const nombre = document.getElementById('nuevoRolNombre')?.value.trim();
        const activo = document.getElementById('nuevoRolActivo')?.value === 'true';
        
        if (!codigo || !nombre) {
            alert('⚠️ Complete todos los campos obligatorios');
            return;
        }
        
        const btn = document.querySelector('#modalNuevoRol button:last-child');
        const textoOriginal = btn?.innerHTML;
        if (btn) {
            btn.innerHTML = '⏳ Creando...';
            btn.disabled = true;
        }
        
        try {
            const token = localStorage.getItem('meca_token');
            const response = await fetch('/api/roles', {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ codigo, nombre, activo })
            });
            
            if (response.ok) {
                alert(`✅ Rol "${nombre}" creado correctamente`);
                cerrarModalNuevoRol();
                await cargarRoles();
            } else {
                const error = await response.json();
                alert('❌ Error: ' + (error.error || 'No se pudo crear'));
            }
        } catch (error) {
            alert('❌ Error: ' + error.message);
        } finally {
            if (btn) {
                btn.innerHTML = textoOriginal;
                btn.disabled = false;
            }
        }
    }
