    // 1. Abrir modal para administrar pestañas de un rol específico
    async function administrarPestanasRol(rolId, rolNombre) {
        console.log(`📋 Administrando pestañas para rol: ${rolNombre} (ID: ${rolId})`);
        
        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }
        
        try {
            // Obtener todas las pestañas del sistema
            const { data: pestanas, error: pestError } = await db
                .from('pestanas_sistema')
                .select('*')
                .order('orden', { ascending: true });
            
            if (pestError) throw pestError;
            
            if (!pestanas || pestanas.length === 0) {
                alert('⚠️ No hay pestañas registradas en el sistema');
                return;
            }
            
            // Obtener pestañas actualmente permitidas para este rol
            const { data: permisos, error: permError } = await db
                .from('rol_pestanas')
                .select('pestana_codigo')
                .eq('rol_id', rolId);
            
            if (permError) throw permError;
            
            const pestanasPermitidasSet = new Set((permisos || []).map(p => p.pestana_codigo));
            
            // Generar modal HTML
            const modalHtml = `
                <div id="modalAdminPestanas" style="position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.6); z-index: 10002; display: flex; justify-content: center; align-items: center;">
                    <div style="background: white; border-radius: 16px; width: 90%; max-width: 550px; max-height: 85vh; overflow: hidden; display: flex; flex-direction: column; box-shadow: 0 20px 40px rgba(0,0,0,0.3);">
                        <!-- Header -->
                        <div style="padding: 15px 20px; background: linear-gradient(135deg, var(--accent), var(--accent2)); color: white; display: flex; justify-content: space-between; align-items: center;">
                            <div>
                                <strong style="font-size: 16px;">📋 Administrar Pestañas</strong>
                                <div style="font-size: 12px; opacity: 0.9;">Rol: ${escapeHtml(rolNombre)}</div>
                            </div>
                            <button onclick="cerrarModalAdminPestanas()" style="background: none; border: none; color: white; font-size: 24px; cursor: pointer; width: 32px; height: 32px; border-radius: 50%;">&times;</button>
                        </div>
                        
                        <!-- Body -->
                        <div style="padding: 20px; overflow-y: auto; flex: 1;">
                            <p style="margin-bottom: 15px; font-size: 13px; color: var(--muted);">
                                Seleccione las pestañas que este rol podrá ver:
                            </p>
                            <div style="display: flex; flex-direction: column; gap: 10px;">
                                ${pestanas.map(p => {
                                    const checked = pestanasPermitidasSet.has(p.codigo);
                                    return `
                                        <label style="display: flex; align-items: center; gap: 12px; padding: 10px 12px; background: ${checked ? '#e8f5e9' : '#f8f9fa'}; border-radius: 10px; cursor: pointer; transition: all 0.2s; border-left: 3px solid ${checked ? 'var(--ok)' : '#e0e0e0'};">
                                            <input type="checkbox" 
                                                class="modal-pestana-checkbox" 
                                                data-pestana-codigo="${p.codigo}"
                                                data-pestana-nombre="${escapeHtml(p.nombre)}"
                                                ${checked ? 'checked' : ''}
                                                style="width: 18px; height: 18px; cursor: pointer;">
                                            <span style="font-size: 24px;">${p.icono}</span>
                                            <div style="flex: 1;">
                                                <div style="font-weight: 600;">${escapeHtml(p.nombre)}</div>
                                                <div style="font-size: 11px; color: var(--muted);">${escapeHtml(p.codigo)}</div>
                                            </div>
                                            ${checked ? '<span style="color: var(--ok); font-size: 14px;">✅</span>' : ''}
                                        </label>
                                    `;
                                }).join('')}
                            </div>
                        </div>
                        
                        <!-- Footer -->
                        <div style="padding: 15px 20px; background: #f8f9fa; display: flex; justify-content: flex-end; gap: 10px; border-top: 1px solid #e0e0e0;">
                            <button onclick="cerrarModalAdminPestanas()" class="secondary" style="padding: 8px 20px;">Cancelar</button>
                            <button id="btnGuardarPestanasRol" onclick="guardarPestanasRol(${rolId})" style="background: var(--ok); padding: 8px 20px;">💾 Guardar Cambios</button>
                        </div>
                    </div>
                </div>
            `;
            
            // Remover modal existente si hay
            const modalExistente = document.getElementById('modalAdminPestanas');
            if (modalExistente) modalExistente.remove();
            
            // Insertar modal
            document.body.insertAdjacentHTML('beforeend', modalHtml);
            
            // Agregar efecto de fade in
            const modal = document.getElementById('modalAdminPestanas');
            if (modal) {
                modal.style.animation = 'fadeIn 0.2s ease';
            }
            
        } catch (error) {
            console.error('Error cargando administración de pestañas:', error);
            alert('❌ Error al cargar: ' + error.message);
        }
    }

    // 2. Cerrar modal
    function cerrarModalAdminPestanas() {
        const modal = document.getElementById('modalAdminPestanas');
        if (modal) {
            modal.style.animation = 'fadeOut 0.2s ease';
            setTimeout(() => modal.remove(), 200);
        }
    }

    // 3. Guardar cambios de pestañas para un rol
    async function guardarPestanasRol(rolId) {
        console.log(`💾 Guardando pestañas para rol ID: ${rolId}`);
        
        const checkboxes = document.querySelectorAll('.modal-pestana-checkbox');
        const nuevasPermitidas = [];
        
        checkboxes.forEach(cb => {
            if (cb.checked) {
                nuevasPermitidas.push(cb.dataset.pestanaCodigo);
            }
        });
        
        // Mostrar resumen antes de guardar
        const rolNombre = document.querySelector('#modalAdminPestanas .modal-gestion-header div div')?.innerText || 'este rol';
        
        if (!confirm(`⚠️ Confirmar cambios para ${rolNombre}\n\nSe habilitarán ${nuevasPermitidas.length} pestañas:\n${nuevasPermitidas.map(p => `  • ${p}`).join('\n')}\n\n¿Desea continuar?`)) {
            return;
        }
        
        const btnGuardar = document.getElementById('btnGuardarPestanasRol');
        const textoOriginal = btnGuardar?.innerHTML;
        if (btnGuardar) {
            btnGuardar.innerHTML = '⏳ Guardando...';
            btnGuardar.disabled = true;
        }
        
        try {
            const token = localStorage.getItem('meca_token');
            
            // 1. Eliminar todos los permisos actuales del rol
            const deleteResponse = await fetch(`/api/rol-pestanas/${rolId}`, {
                method: 'DELETE',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                }
            });
            
            if (!deleteResponse.ok) {
                const error = await deleteResponse.json();
                throw new Error(error.error || 'Error eliminando permisos');
            }
            
            // 2. Insertar los nuevos permisos
            if (nuevasPermitidas.length > 0) {
                const insertResponse = await fetch('/api/rol-pestanas', {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${token}`,
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify({
                        rol_id: rolId,
                        pestanas: nuevasPermitidas
                    })
                });
                
                if (!insertResponse.ok) {
                    const error = await insertResponse.json();
                    throw new Error(error.error || 'Error insertando permisos');
                }
            }
            
            alert(`✅ Permisos actualizados correctamente\n\n📊 Pestañas habilitadas: ${nuevasPermitidas.length}`);
            
            // 3. Cerrar modal
            cerrarModalAdminPestanas();
            
            // 4. Recargar tabla de roles
            await cargarRoles();
            
            // 5. Si el rol modificado es el del usuario actual, regenerar pestañas
            if (usuarioActual && usuarioActual.rol_id === rolId) {
                console.log('🔄 Rol actual modificado, regenerando pestañas...');
                await generarTabsDinamicos();
                const currentTab = document.querySelector('.tab-button.active')?.getAttribute('data-tab');
                if (currentTab && typeof showTab === 'function') {
                    showTab(currentTab, null);
                }
            }
            
        } catch (error) {
            console.error('Error guardando pestañas:', error);
            alert('❌ Error al guardar: ' + error.message);
        } finally {
            if (btnGuardar) {
                btnGuardar.innerHTML = textoOriginal;
                btnGuardar.disabled = false;
            }
        }
    }

    // 4. Función para agregar nueva pestaña (desde el panel de administración)
    async function agregarNuevaPestana() {
        const codigo = prompt('📝 Código de la pestaña (identificador único, ej: "dashboard"):');
        if (!codigo) return;
        
        // Validar formato (solo letras minúsculas, números y guión bajo)
        if (!/^[a-z0-9_]+$/.test(codigo)) {
            alert('⚠️ El código solo puede contener letras minúsculas, números y guión bajo');
            return;
        }
        
        const nombre = prompt('📝 Nombre visible (ej: "Dashboard Ejecutivo"):');
        if (!nombre) return;
        
        const icono = prompt('📝 Ícono (ej: "📊", "🎯", "⚙️"):');
        if (!icono) return;
        
        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }
        
        // Obtener el orden actual máximo
        const { data: maxOrdenData } = await db
            .from('pestanas_sistema')
            .select('orden')
            .order('orden', { ascending: false })
            .limit(1);
        
        const nuevoOrden = (maxOrdenData && maxOrdenData[0]?.orden || 0) + 1;
        
        const { error } = await db
            .from('pestanas_sistema')
            .insert({
                codigo: codigo,
                nombre: nombre,
                icono: icono,
                orden: nuevoOrden,
                visible: true
            });
        
        if (error) {
            console.error('Error creando pestaña:', error);
            alert('❌ Error al crear pestaña: ' + error.message);
            return;
        }
        
        alert(`✅ Pestaña "${nombre}" creada exitosamente\n\nAhora puede asignarla a los roles desde el botón "📋 Pestañas"`);
        
        // Recargar la tabla de roles
        await cargarRoles();
    }

    
    
    // ===== 21. INICIO FUNCIÓN: cerrarModalRol =============================
    function cerrarModalRol() {
        document.getElementById('modalEditarRol').style.display = 'none';
        document.getElementById('formRol').reset();
    }
