    // ===== 22. INICIO FUNCIÓN: construirAlertasOperativas ==================
    function construirAlertasOperativas(evaluaciones, ranking, topSubmotivos) {
        const alertas = [];

        if (topSubmotivos.length > 0) {
            const top = topSubmotivos[0];
            alertas.push(`El submotivo más fallado es <strong>${escapeHtml(top.submotivo)}</strong> (${escapeHtml(top.bloque)} / ${escapeHtml(top.atributo)}) con <strong>${top.fallas}</strong> incidencias.`);
        }

        // 🔴 UNIFORME: Usar matriz dominante para obtener máximos dinámicos
        const matrizDominante = obtenerMatrizDominante(evaluaciones);
        const pesosMaximos = matrizDominante ? matrizDominante.pesos : { ENC: 30, ECUF: 30, ECN: 40 };
        
        const conECUF = evaluaciones.filter(e => numeroSeguro(e.totalECUF) < pesosMaximos.ECUF).length;
        const conECN = evaluaciones.filter(e => numeroSeguro(e.totalECN) < pesosMaximos.ECN).length;

        if (conECUF > 0) {
            alertas.push(`Hay <strong>${conECUF}</strong> evaluaciones con impacto en <strong>ECUF</strong>.`);
        }

        if (conECN > 0) {
            alertas.push(`Hay <strong>${conECN}</strong> evaluaciones con impacto en <strong>ECN</strong>.`);
        }



        return alertas;
    }
    // ===== FIN FUNCIÓN: construirAlertasOperativas =========================

    // ======================================================
    // GESTIÓN DE SESIONES ACTIVAS DESDE PESTAÑA USUARIOS
    // ======================================================
    // Cargar sesiones activas de un usuario específico            
    async function cargarSesionesUsuario(usuarioId, usuarioNombre, mostrarSoloActivas = false) {
        console.log(`🔍 Cargando sesiones ${mostrarSoloActivas ? 'activas' : 'completas (historial)'} para usuario: ${usuarioNombre} (ID: ${usuarioId})`);
        
        try {
            const sesiones = await API.getSesionesUsuario(usuarioId, mostrarSoloActivas);
            
            // Guardar selección
            usuarioSesionesSeleccionado = { id: usuarioId, nombre: usuarioNombre };
            
            // Mostrar modal con las sesiones
            mostrarModalSesionesUsuario(usuarioNombre, sesiones || [], mostrarSoloActivas);
            
        } catch (error) {
            console.error('Error cargando sesiones:', error);
            alert('❌ Error al cargar sesiones: ' + error.message);
        }
    }

    // Mostrar modal con las sesiones del usuario            
