    // Cerrar una sesión específica
    async function cerrarSesionEspecifica(sessionToken, usuarioNombre) {
        if (!confirm(`⚠️ ¿Cerrar esta sesión del usuario ${usuarioNombre}?\n\nEl usuario será desconectado de inmediato.`)) {
            return;
        }
        
        try {
            await API.cerrarSesion(sessionToken);
            
            alert(`✅ Sesión cerrada correctamente para ${usuarioNombre}`);
            
            // Refrescar la vista
            await refrescarSesionesUsuario();
            
        } catch (error) {
            console.error('Error cerrando sesión:', error);
            alert('❌ Error al cerrar sesión: ' + error.message);
        }
    }

    // Cerrar todas las sesiones de un usuario
    async function cerrarTodasSesionesUsuario() {
        if (!usuarioSesionesSeleccionado) return;
        
        if (!confirm(`⚠️ ¿CERRAR TODAS LAS SESIONES ACTIVAS de ${usuarioSesionesSeleccionado.nombre}?\n\nEste usuario será desconectado de TODOS sus dispositivos.\n\n¿Está seguro?`)) {
            return;
        }
        
        try {
            await API.cerrarTodasSesiones(usuarioSesionesSeleccionado.id);
            
            alert(`✅ Se cerraron todas las sesiones de ${usuarioSesionesSeleccionado.nombre}`);
            
            // Refrescar la vista (mostrará 0 sesiones)
            await refrescarSesionesUsuario();
            
        } catch (error) {
            console.error('Error cerrando sesiones:', error);
            alert('❌ Error al cerrar sesiones: ' + error.message);
        }
    }

    // Agregar botón de sesiones en la tabla de usuarios
    function agregarBotonSesionesEnTabla() {
        // Buscar todos los botones de acción en la tabla de usuarios
        const botonesExistentes = document.querySelectorAll('.btn-sesiones');
        botonesExistentes.forEach(btn => btn.remove());
        
        // Agregar botón a cada fila de la tabla
        const filas = document.querySelectorAll('#tablaUsuarios tr');
        filas.forEach(fila => {
            const celdas = fila.querySelectorAll('td');
            if (celdas.length >= 7) {
                const usuarioId = celdas[0]?.innerText;
                const usuarioNombre = celdas[1]?.innerText;
                const accionesCell = celdas[6];
                
                if (usuarioId && usuarioNombre && accionesCell && !accionesCell.querySelector('.btn-sesiones')) {
                    const btnSesiones = document.createElement('button');
                    btnSesiones.className = 'btn-sesiones';
                    btnSesiones.innerHTML = '🔐 Sesiones';
                    btnSesiones.title = 'Ver sesiones activas e historial del usuario';
                    btnSesiones.style.cssText = 'background: #7b1fa2; padding: 5px 8px; font-size: 11px; border-radius: 6px; border: none; cursor: pointer; margin-right: 3px; color: white;';
                    btnSesiones.onclick = () => cargarSesionesUsuario(parseInt(usuarioId), usuarioNombre, true); // Por defecto mostrar activas
                    
                    // Insertar antes de los botones existentes
                    const firstButton = accionesCell.querySelector('button');
                    if (firstButton) {
                        accionesCell.insertBefore(btnSesiones, firstButton);
                    } else {
                        accionesCell.appendChild(btnSesiones);
                    }
                }
            }
        });
    }

    // Modificar actualizarTablaUsuarios para incluir botón de sesiones
    const originalActualizarTablaUsuarios = actualizarTablaUsuarios;
    actualizarTablaUsuarios = function() {
        if (originalActualizarTablaUsuarios) {
            originalActualizarTablaUsuarios();
        }
        // Agregar botones de sesiones después de cargar la tabla
        setTimeout(agregarBotonSesionesEnTabla, 100);
    };

    // Actualizar estadísticas globales de sesiones
    async function actualizarEstadisticasSesiones() {
        const db = getDB();
        if (!db) return;
        
        try {
            // Total de sesiones activas
            const { data: sesionesActivas, error: sesError } = await db
                .from('sesiones_activas')
                .select('usuario_id', { count: 'exact' })
                .eq('estado', 'activa');
            
            if (sesError) throw sesError;
            
            const totalSesiones = sesionesActivas?.length || 0;
            
            // Usuarios únicos con sesión activa
            const usuariosUnicos = new Set();
            sesionesActivas?.forEach(s => usuariosUnicos.add(s.usuario_id));
            const totalUsuariosConSesion = usuariosUnicos.size;
            
            // Promedio de sesiones
            const promedio = totalUsuariosConSesion > 0 
                ? (totalSesiones / totalUsuariosConSesion).toFixed(1)
                : 0;
            
            // Actualizar KPIs
            const totalSesionesElem = document.getElementById('totalSesionesActivas');
            const usuariosConSesionElem = document.getElementById('usuariosConSesion');
            const promedioElem = document.getElementById('promedioSesionesUsuario');
            
            if (totalSesionesElem) totalSesionesElem.textContent = totalSesiones;
            if (usuariosConSesionElem) usuariosConSesionElem.textContent = totalUsuariosConSesion;
            if (promedioElem) promedioElem.textContent = promedio;
            
            console.log(`📊 Sesiones activas: ${totalSesiones} | Usuarios conectados: ${totalUsuariosConSesion} | Promedio: ${promedio}`);
            
        } catch (error) {
            console.error('Error actualizando estadísticas de sesiones:', error);
        }
    }

    // Modificar cargarUsuarios para también actualizar estadísticas de sesiones
    const originalCargarUsuarios = cargarUsuarios;
    cargarUsuarios = async function() {
        if (originalCargarUsuarios) {
            await originalCargarUsuarios();
        }
        await actualizarEstadisticasSesiones();
    };
    
