    // ===== 4. INICIO FUNCIÓN: calcularTamanioDesdeTablas ===================
    async function calcularTamanioDesdeTablas() {
        const db = getDB();
        if (!db) return 0;

        let totalSize = 0;
        const tablasEstimadas = [
            'evaluaciones', 'detalles_evaluacion', 'pda_cabecera', 
            'pda_acciones', 'usuarios', 'agentes', 'asignaciones_escucha', 'tareas_escucha'
        ];

        for (const tabla of tablasEstimadas) {
            try {
                const { count, error } = await db
                    .from(tabla)
                    .select('*', { count: 'exact', head: true });

                if (!error && count) {
                    // Estimación: 1KB por registro
                    totalSize += count * 1024;
                }
            } catch (e) {
                console.warn(`Error estimando tamaño de ${tabla}:`, e);
            }
        }

        return totalSize / (1024 * 1024); // Convertir a MB
    }
    // ===== FIN FUNCIÓN: calcularTamanioDesdeTablas =========================

    // ===== 5. INICIO FUNCIÓN: estimarTamanioTablas =========================
    async function estimarTamanioTablas(nombresTablas) {
        const db = getDB();
        if (!db) return [];

        const resultados = [];

        for (const tabla of nombresTablas) {
            try {
                // Obtener conteo de registros
                const { count, error } = await db
                    .from(tabla)
                    .select('*', { count: 'exact', head: true });

                if (error) {
                    console.warn(`Error estimando tamaño de ${tabla}:`, error.message);
                    continue;
                }

                if (count && count > 0) {
                    // Estimación: ~1KB por registro (conservador)
                    const estimadoMB = (count * 1024) / (1024 * 1024);
                    resultados.push({
                        tablename: tabla,
                        total_size: formatSize(estimadoMB * 1024 * 1024),
                        total_size_mb: estimadoMB,
                        table_size: formatSize(estimadoMB * 1024 * 1024 * 0.7),
                        indexes_size: formatSize(estimadoMB * 1024 * 1024 * 0.3),
                        row_count: count
                    });
                } else {
                    resultados.push({
                        tablename: tabla,
                        total_size: '0 B',
                        total_size_mb: 0,
                        table_size: '0 B',
                        indexes_size: '0 B',
                        row_count: 0
                    });
                }

            } catch (e) {
                console.warn(`Error procesando tabla ${tabla}:`, e);
            }
        }

        return resultados.sort((a, b) => b.total_size_mb - a.total_size_mb);
    }
    // ===== FIN FUNCIÓN: estimarTamanioTablas ===============================

    // ======================================================
    // GRÁFICO - Tamaño por Tablas
    // ======================================================

    async function crearGraficoTamanioTablas() {
        console.log('🔧 Creando gráfico "Tamaño por Tablas"...');
        
        const tabBD = document.getElementById('tab-estadoBD');
        if (!tabBD) {
            console.error('❌ Pestaña BD no encontrada');
            return;
        }
        
        // Verificar si ya existe el gráfico
        if (document.getElementById('chartTamanioTablas')) {
            console.log('✅ El gráfico ya existe, actualizando...');
            await actualizarGraficoTamanioTablas();
            return;
        }
        
        // Obtener datos
        const token = localStorage.getItem('meca_token');
        const response = await fetch('/api/estado-bd', {
            headers: { 'Authorization': `Bearer ${token}` }
        });
        const estado = await response.json();
        const tablas = estado.tablas || [];
        
        if (tablas.length === 0) {
            console.warn('No hay datos de tablas');
            return;
        }
        
        // Crear la estructura del gráfico
        const chartHtml = `
            <div class="card" style="margin-top: 20px;">
                <h3>📊 Tamaño por Tablas</h3>
                <div style="max-height: 400px;">
                    <canvas id="chartTamanioTablas" style="max-height: 350px; width: 100%;"></canvas>
                </div>
                <div style="margin-top: 10px; font-size: 11px; color: var(--muted); text-align: center;">
                    💡 Las 10 tablas más grandes - Pase el mouse sobre las barras para ver detalles
                </div>
            </div>
        `;
        
        // Insertar después de la barra de progreso
        const progressBarContainer = tabBD.querySelector('#progressBar')?.parentElement?.parentElement;
        if (progressBarContainer) {
            progressBarContainer.insertAdjacentHTML('afterend', chartHtml);
            console.log('✅ Gráfico agregado');
        } else {
            tabBD.insertAdjacentHTML('beforeend', chartHtml);
            console.log('✅ Gráfico agregado al final');
        }
        
        await actualizarGraficoTamanioTablas();
    }

    async function actualizarGraficoTamanioTablas() {
        console.log('📊 Actualizando gráfico de tamaño por tablas...');
        
        const token = localStorage.getItem('meca_token');
        const response = await fetch('/api/estado-bd', {
            headers: { 'Authorization': `Bearer ${token}` }
        });
        const estado = await response.json();
        const tablas = estado.tablas || [];
        
        if (tablas.length === 0) {
            console.warn('No hay datos de tablas');
            return;
        }
        
        // Tomar las 10 tablas más grandes
        const topTablas = [...tablas].sort((a, b) => b.total_size_mb - a.total_size_mb).slice(0, 10);
        const labels = topTablas.map(t => {
            let nombre = t.tablename.replace(/_/g, ' ');
            return nombre.length > 20 ? nombre.substring(0, 17) + '...' : nombre;
        });
        const data = topTablas.map(t => t.total_size_mb);
        const colores = ['#019DF4', '#7b1fa2', '#fd7e14', '#28a745', '#d93025', '#f39c12', '#17a2b8', '#6f42c1', '#e83e8c', '#20c997'];
        
        const canvas = document.getElementById('chartTamanioTablas');
        if (!canvas) {
            console.error('❌ Canvas chartTamanioTablas no encontrado');
            return;
        }
        
        // Destruir gráfico existente
        if (window.chartTamanioTablasInstance) {
            window.chartTamanioTablasInstance.destroy();
        }
        
        const ctx = canvas.getContext('2d');
        if (ctx) {
            window.chartTamanioTablasInstance = new Chart(ctx, {
                type: 'bar',
                data: {
                    labels: labels,
                    datasets: [{
                        label: 'Tamaño (MB)',
                        data: data,
                        backgroundColor: colores.slice(0, topTablas.length),
                        borderRadius: 8,
                        barPercentage: 0.7
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: true,
                    plugins: {
                        legend: { display: false },
                        tooltip: {
                            callbacks: {
                                label: function(context) {
                                    const tabla = topTablas[context.dataIndex];
                                    return [
                                        `📊 Tamaño: ${tabla.total_size_formatted}`,
                                        `📝 Registros: ${(tabla.row_count || 0).toLocaleString()}`
                                    ];
                                }
                            }
                        },
                        datalabels: {
                            anchor: 'end',
                            align: 'top',
                            offset: -5,
                            formatter: (value) => value > 0 ? `${value.toFixed(1)} MB` : '',
                            backgroundColor: '#333',
                            borderRadius: 4,
                            padding: { left: 4, right: 4, top: 2, bottom: 2 },
                            color: 'white',
                            font: { size: 9, weight: 'bold' }
                        }
                    },
                    scales: {
                        y: {
                            title: { display: true, text: 'Tamaño (MB)', color: '#666' },
                            beginAtZero: true,
                            grid: { display: false }
                        },
                        x: {
                            title: { display: true, text: 'Tabla', color: '#666' },
                            ticks: { maxRotation: 45, minRotation: 45 }
                        }
                    }
                }
            });
            console.log('✅ Gráfico de tamaño por tablas actualizado');
        }
    }
    
    // ===== 6. INICIO FUNCIÓN: parseSizeToMB ================================
    function parseSizeToMB(sizeStr) {
        if (!sizeStr) return 0;

        const match = sizeStr.match(/(\d+(?:\.\d+)?)\s*(\w+)/i);
        if (!match) return 0;

        const value = parseFloat(match[1]);
        const unit = match[2].toUpperCase();

        switch (unit) {
            case 'BYTES': return value / (1024 * 1024);
            case 'KB': return value / 1024;
            case 'MB': return value;
            case 'GB': return value * 1024;
            default: return value / (1024 * 1024);
        }
    }
    // ===== FIN FUNCIÓN: parseSizeToMB ======================================

    // ===== 7. INICIO FUNCIÓN: formatSize ===================================
    function formatSize(bytes) {
        if (!bytes || bytes === 0) return '0 B';
        
        const mb = bytes / (1024 * 1024);
        if (mb >= 1024) {
            return (mb / 1024).toFixed(2) + ' GB';
        }
        if (mb >= 1) {
            return mb.toFixed(2) + ' MB';
        }
        const kb = bytes / 1024;
        if (kb >= 1) {
            return kb.toFixed(2) + ' KB';
        }
        return bytes.toFixed(0) + ' B';
    }
    // ===== FIN FUNCIÓN: formatSize =========================================

    // ===== 8. INICIO FUNCIÓN: formatSizeFromMB =============================
    function formatSizeFromMB(mb) {
        if (mb >= 1024) {
            return (mb / 1024).toFixed(2) + ' GB';
        }
        if (mb >= 1) {
            return mb.toFixed(2) + ' MB';
        }
        const kb = mb * 1024;
        if (kb >= 1) {
            return kb.toFixed(0) + ' KB';
        }
        return (mb * 1024).toFixed(0) + ' KB';
    }
    // ===== FIN FUNCIÓN: formatSizeFromMB ===================================

    // ===== 9. INICIO FUNCIÓN: actualizarUIEstadoBD =========================
    function actualizarUIEstadoBD(estado) {
        console.log('📊 actualizarUIEstadoBD - Estado recibido:', estado);
        
        if (!estado) {
            mostrarErrorBD('No se pudo obtener el estado de la base de datos');
            return;
        }
        
        // 1. Actualizar tamaño total
        const totalSizeElem = document.getElementById('bdTotalSize');
        if (totalSizeElem) {
            totalSizeElem.textContent = estado.totalSizeFormatted || `${estado.totalSizeMB} MB`;
        }
        
        // 2. Actualizar porcentaje de uso
        const totalSizeMB = estado.totalSizeMB || 0;
        const limiteMB = 500;
        const porcentajeUso = Math.min((totalSizeMB / limiteMB) * 100, 100);
        
        const usagePercentElem = document.getElementById('bdUsagePercent');
        if (usagePercentElem) {
            usagePercentElem.textContent = `${porcentajeUso.toFixed(1)}%`;
        }
        
        // 3. Actualizar barra de progreso
        const progressBar = document.getElementById('progressBar');
        const progressText = document.getElementById('progressText');
        if (progressBar) {
            progressBar.style.width = `${porcentajeUso}%`;
            if (porcentajeUso >= 90) {
                progressBar.style.background = 'linear-gradient(90deg, #d93025, #b71c1c)';
            } else if (porcentajeUso >= 75) {
                progressBar.style.background = 'linear-gradient(90deg, #f39c12, #e67e22)';
            } else {
                progressBar.style.background = 'linear-gradient(90deg, #28a745, #20c997)';
            }
        }
        if (progressText) {
            progressText.textContent = `${porcentajeUso.toFixed(1)}%`;
        }
        
        // 4. Actualizar detalle de uso
        const usageDetailElem = document.getElementById('bdUsageDetail');
        if (usageDetailElem) {
            usageDetailElem.textContent = `${estado.totalSizeFormatted} de ${limiteMB} MB (máximo referencial)`;
        }
        
        // 5. 🔴 ACTUALIZAR ALERTAS (lo que estaba faltando)
        const alertasContent = document.getElementById('bdAlertasContent');
        if (alertasContent) {
            if (porcentajeUso >= 90) {
                alertasContent.innerHTML = `
                    <div style="padding: 12px; background: #fff0f0; border-left: 4px solid #d93025; border-radius: 8px;">
                        <strong>🔴 ALERTA CRÍTICA:</strong> La base de datos está al <strong>${porcentajeUso.toFixed(1)}%</strong> de su capacidad referencial.
                        <div style="margin-top: 5px; font-size: 12px;">📊 ${estado.totalSizeFormatted} de ${limiteMB} MB utilizados</div>
                    </div>
                    <div style="margin-top: 10px; padding: 12px; background: #f8f9fa; border-radius: 8px;">
                        <strong>📌 Recomendación:</strong> Archivar datos antiguos o aumentar el límite de almacenamiento.
                    </div>
                `;
            } else if (porcentajeUso >= 75) {
                alertasContent.innerHTML = `
                    <div style="padding: 12px; background: #fff8e0; border-left: 4px solid #f39c12; border-radius: 8px;">
                        <strong>🟡 ATENCIÓN:</strong> La base de datos está al <strong>${porcentajeUso.toFixed(1)}%</strong> de su capacidad referencial.
                        <div style="margin-top: 5px; font-size: 12px;">📊 ${estado.totalSizeFormatted} de ${limiteMB} MB utilizados</div>
                    </div>
                `;
            } else {
                alertasContent.innerHTML = `
                    <div style="padding: 12px; background: #e8f5e9; border-left: 4px solid #28a745; border-radius: 8px;">
                        <strong>🟢 TODO EN ORDEN:</strong> La base de datos está al <strong>${porcentajeUso.toFixed(1)}%</strong> de su capacidad referencial.
                        <div style="margin-top: 5px; font-size: 12px;">📊 ${estado.totalSizeFormatted} utilizados de ${limiteMB} MB</div>
                        <div style="margin-top: 5px; font-size: 12px;">📝 ${estado.totalRows?.toLocaleString()} registros en ${estado.tablas?.length} tablas</div>
                    </div>
                `;
            }
        }
        
        // 6. Actualizar tabla de tablas
        if (estado.tablas && estado.tablas.length > 0 && typeof actualizarTablaDetalleTablas === 'function') {
            actualizarTablaDetalleTablas(estado.tablas);
        }
        
        console.log('✅ UI de estado BD actualizada correctamente');
    }
