    // ===== 11. INICIO FUNCIÓN: actualizarGraficoTablas =====================
    function actualizarGraficoTablas(tablas) {
        const canvas = document.getElementById('chartTablasSize');
        if (!canvas) return;

        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Tomar TOP 10 tablas por tamaño (o todas si son menos de 10)
        const topTablas = [...tablas]
            .sort((a, b) => (b.total_size_mb || 0) - (a.total_size_mb || 0))
            .slice(0, 10);

        if (topTablas.length === 0) {
            mostrarMensajeSinDatosEnCanvas(canvas, '📊 No hay datos de tablas para mostrar');
            return;
        }

        const labels = topTablas.map(t => {
            // Limpiar nombre para mostrar
            let nombre = t.tablename.replace(/_/g, ' ');
            if (nombre.length > 20) nombre = nombre.substring(0, 17) + '...';
            return nombre;
        });
        
        const data = topTablas.map(t => t.total_size_mb || 0);

        const colores = ['#019DF4', '#7b1fa2', '#fd7e14', '#28a745', '#d93025', 
                        '#f39c12', '#17a2b8', '#6f42c1', '#e83e8c', '#20c997'];

        if (chartTablasSize) {
            chartTablasSize.destroy();
        }

        chartTablasSize = new Chart(ctx, {
            type: 'bar',
            data: {
                labels: labels,
                datasets: [{
                    label: 'Tamaño (MB)',
                    data: data,
                    backgroundColor: colores.slice(0, labels.length),
                    borderRadius: 8,
                    borderWidth: 0
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    legend: { display: false },
                    tooltip: {
                        callbacks: {
                            label: function (context) {
                                const tabla = topTablas[context.dataIndex];
                                return [
                                    `Tamaño: ${context.raw.toFixed(2)} MB`,
                                    `Registros: ${tabla.row_count?.toLocaleString() || 0}`
                                ];
                            }
                        }
                    },
                    datalabels: {
                        anchor: 'end',
                        align: 'top',
                        offset: -5,
                        formatter: function (value) {
                            if (value < 0.01) return '';
                            return value.toFixed(2) + ' MB';
                        },
                        backgroundColor: '#333',
                        borderRadius: 4,
                        padding: { left: 4, right: 4, top: 2, bottom: 2 },
                        color: 'white',
                        font: { size: 9, weight: 'bold' }
                    }
                },
                scales: {
                    y: {
                        title: { display: true, text: 'Tamaño (MB)' },
                        grid: { display: false },
                        beginAtZero: true
                    },
                    x: {
                        title: { display: true, text: 'Tabla' },
                        grid: { display: false },
                        ticks: { maxRotation: 45, minRotation: 45 }
                    }
                }
            }
        });
    }
    // ===== FIN FUNCIÓN: actualizarGraficoTablas ============================

    
    
    
    // ===== 12. INICIO FUNCIÓN: actualizarTablaDetalleTablas ================
    function actualizarTablaDetalleTablas(tablas) {
        console.log('📊 actualizarTablaDetalleTablas - Tablas recibidas:', tablas?.length);
        
        const tbody = document.getElementById('tablaDetalleTablas');
        if (!tbody) {
            console.error('❌ Tabla detalle no encontrada');
            return;
        }
        
        if (!tablas || tablas.length === 0) {
            tbody.innerHTML = '<tr><td colspan="7" style="text-align: center;">No hay datos de tablas<\/td><\/tr>';
            return;
        }
        
        // Calcular tamaño total para porcentajes
        const totalSizeMB = tablas.reduce((sum, t) => sum + (parseFloat(t.total_size_mb) || 0), 0);
        
        let html = '';
        
        for (const tabla of tablas) {
            const totalSize = tabla.total_size_formatted || `${tabla.total_size_mb} MB`;
            const tableSize = tabla.table_size_formatted || `${tabla.table_size_mb} MB`;
            const indexesSize = tabla.indexes_size_formatted || `${tabla.indexes_size_mb} MB`;
            const rowCount = tabla.row_count?.toLocaleString() || '0';
            
            // Calcular porcentaje del total
            const tablaSizeMB = parseFloat(tabla.total_size_mb) || 0;
            const porcentaje = totalSizeMB > 0 ? ((tablaSizeMB / totalSizeMB) * 100).toFixed(1) : 0;
            
            // Color de la barra según porcentaje
            let barColor = '#28a745';
            if (porcentaje > 30) barColor = '#f39c12';
            if (porcentaje > 50) barColor = '#d93025';
            
            // Nombre de la tabla formateado
            const nombreMostrar = tabla.tablename.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
            
            html += `
                <tr style="border-bottom: 1px solid var(--line);">
                    <td style="padding: 10px 8px;">
                        <strong>📊 ${escapeHtml(nombreMostrar)}</strong>
                        <div style="font-size: 10px; color: var(--muted);">${escapeHtml(tabla.tablename)}</div>
                    </td>
                    <td style="padding: 10px 8px; font-family: monospace; font-weight: 500;">${totalSize}</td>
                    <td style="padding: 10px 8px; font-family: monospace;">${tableSize}</td>
                    <td style="padding: 10px 8px; font-family: monospace;">${indexesSize}</td>
                    <td style="padding: 10px 8px; text-align: right; font-family: monospace;">${rowCount}</td>
                    <td style="padding: 10px 8px;">
                        <div style="display: flex; align-items: center; gap: 8px;">
                            <div style="flex: 1; background: #e9ecef; border-radius: 10px; height: 8px; max-width: 80px;">
                                <div style="width: ${Math.min(porcentaje, 100)}%; height: 100%; background: ${barColor}; border-radius: 10px;"></div>
                            </div>
                            <span style="font-size: 11px;">${porcentaje}%</span>
                        </div>
                    </td>
                    <td style="padding: 10px 8px; text-align: center;">
                        <span class="badge" style="background: ${tablaSizeMB > 10 ? '#fd7e14' : '#28a745'};">${totalSize}</span>
                    </td>
                </tr>
            `;
        }
        
        tbody.innerHTML = html;
        console.log(`✅ Tabla de tablas actualizada con ${tablas.length} registros`);
    }
    // ===== FIN FUNCIÓN: actualizarTablaDetalleTablas =======================

    // ===== 13. INICIO FUNCIÓN: mostrarErrorBD ==============================
    function mostrarErrorBD(mensaje) {
        const container = document.getElementById('tablaDetalleTablas');
        const alertContainer = document.getElementById('bdStatusAlert');

        if (container) {
            container.innerHTML = `<tr><td colspan="5" style="text-align: center; color: var(--danger);">❌ ${mensaje}</td></tr>`;
        }
        if (alertContainer) {
            alertContainer.innerHTML = `
                <div style="background: linear-gradient(135deg, #d93025, #b71c1c); color: white; padding: 15px; border-radius: 12px;">
                    <strong>⚠️ Error:</strong> ${mensaje}\n
                    <small>Nota: Para ver estadísticas detalladas, cree las funciones RPC en la base de datos.</small>
                </div>
            `;
        }
    }
    // ===== FIN FUNCIÓN: mostrarErrorBD =====================================

