    // ===== 1. INICIO FUNCIÓN: cargarVersionesTabla =========================
    let versionesData = [];
    async function cargarVersionesTabla(tipo = 'todos') {
        const tbody = document.getElementById('tbodyVersiones');
        if (!tbody) return;

        tbody.innerHTML = '<tr><td colspan="7" style="text-align: center;">⏳ Cargando...</td></tr>';

        try {
            // 🔴 CAMBIO: Usar API en lugar de PostgreSQL directamente
            const versiones = await API.getVersiones(tipo);
            
            if (!versiones || versiones.length === 0) {
                tbody.innerHTML = '<tr><td colspan="7" style="text-align: center;">📭 No hay versiones registradas</td></tr>';
                return;
            }

            let html = '';
            for (const v of versiones) {
                const fecha = new Date(v.fecha_publicacion).toLocaleString('es-ES');
                const tipoTexto = v.tipo === 'auditor' ? '🎧 Auditor' : '👔 Supervisor';
                const estadoTexto = v.es_activo ? '✅ Activa' : '⏸️ Inactiva';
                const estadoClass = v.es_activo ? 'var(--ok)' : 'var(--muted)';
                const tipoClass = v.tipo === 'auditor' ? '#019DF4' : '#fd7e14';

                html += `
                    <tr>
                        <td style="padding: 8px;">${v.id}</td>
                        <td style="padding: 8px;"><strong>${escapeHtml(v.version)}</strong></td>
                        <td style="padding: 8px;"><span class="badge" style="background: ${tipoClass};">${tipoTexto}</span></td>
                        <td style="padding: 8px;">${fecha}</td>
                        <td style="padding: 8px;">${escapeHtml(v.publicado_por || '-')}</td>
                        <td style="padding: 8px;"><span style="color: ${estadoClass};">${estadoTexto}</span></td>
                        <td style="padding: 8px; text-align: center;">
                            <button onclick="descargarVersionArchivo(${v.id}, '${v.nombre_archivo}')" class="btn-icon" style="background: #28a745; padding: 4px 8px; border-radius: 6px; margin-right: 5px;">📥</button>
                            <button onclick="activarVersionSistema(${v.id}, '${v.tipo}', '${v.version}')" class="btn-icon" style="background: #019DF4; padding: 4px 8px; border-radius: 6px; margin-right: 5px;" ${v.es_activo ? 'disabled' : ''}>⭐</button>
                            <button onclick="eliminarVersionSistema(${v.id})" class="btn-icon" style="background: #dc3545; padding: 4px 8px; border-radius: 6px;">🗑️</button>
                        </td>
                    </tr>
                `;
            }

            tbody.innerHTML = html;

        } catch (error) {
            console.error('Error cargando versiones:', error);
            tbody.innerHTML = `<tr><td colspan="7" style="text-align: center; color: var(--danger);">❌ Error: ${error.message}</td></tr>`;
        }
    }
    // ===== FIN FUNCIÓN: cargarVersionesTabla ===============================

    // ===== 2. INICIO FUNCIÓN: descargarVersionArchivo ======================
    async function descargarVersionArchivo(id, nombreArchivo) {
        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }

        try {
            const { data, error } = await db
                .from('versiones_sistema')
                .select('contenido_html')
                .eq('id', id)
                .single();

            if (error) throw error;

            if (!data || !data.contenido_html) {
                alert('❌ No se pudo obtener el contenido del archivo');
                return;
            }

            const blob = new Blob([data.contenido_html], { type: 'text/html' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = nombreArchivo;
            a.click();
            URL.revokeObjectURL(url);

            alert(`📥 Descargando ${nombreArchivo}`);

        } catch (error) {
            console.error('Error descargando:', error);
            alert('❌ Error al descargar: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: descargarVersionArchivo ============================

    // ===== 3. INICIO FUNCIÓN: activarVersionSistema ========================
    async function activarVersionSistema(id, tipo, version) {
        if (!confirm(`⚠️ ¿Activar la versión ${version}?\n\nLos usuarios verán la notificación de actualización la próxima vez que abran el sistema.`)) {
            return;
        }

        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }

        try {
            // Desactivar todas las versiones del mismo tipo
            await db
                .from('versiones_sistema')
                .update({ es_activo: false })
                .eq('tipo', tipo);

            // Activar la versión seleccionada
            const { error } = await db
                .from('versiones_sistema')
                .update({ es_activo: true })
                .eq('id', id);

            if (error) throw error;

            alert(`✅ Versión ${version} activada correctamente`);

            // Recargar la tabla
            cargarVersionesTabla('todos');

        } catch (error) {
            console.error('Error activando versión:', error);
            alert('❌ Error al activar: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: activarVersionSistema ==============================

    // ===== 4. INICIO FUNCIÓN: eliminarVersionSistema =======================
    async function eliminarVersionSistema(id) {
        // 🔴 CORREGIDO: Obtener la versión directamente desde la base de datos
        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }

        try {
            // Obtener los datos de la versión antes de eliminar
            const { data: version, error: fetchError } = await db
                .from('versiones_sistema')
                .select('version, tipo')
                .eq('id', id)
                .single();

            if (fetchError) throw fetchError;

            if (!version) {
                alert('❌ Versión no encontrada');
                return;
            }

            const nombreVersion = version.version;
            const tipoSistema = version.tipo === 'auditor' ? 'Auditor' : 'Supervisor';

            if (!confirm(`⚠️ ¿Eliminar la versión ${nombreVersion} (${tipoSistema})?\n\nEsta acción no se puede deshacer.`)) {
                return;
            }

            const { error } = await db
                .from('versiones_sistema')
                .delete()
                .eq('id', id);

            if (error) throw error;

            alert(`✅ Versión ${nombreVersion} eliminada correctamente`);

            // Recargar la tabla
            cargarVersionesTabla('todos');

        } catch (error) {
            console.error('Error eliminando versión:', error);
            alert('❌ Error al eliminar: ' + error.message);
        }
    }
    // ===== FIN FUNCIÓN: eliminarVersionSistema =============================

    // ===== 5. INICIO FUNCIÓN: publicarNuevaVersion =========================
    async function publicarNuevaVersion(event) {
        event.preventDefault();

        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }

        const tipo = document.getElementById('tipoSistema').value;
        const version = document.getElementById('version').value;
        const archivo = document.getElementById('archivoHtml').files[0];
        const descripcion = document.getElementById('descripcion').value;
        const publicadoPor = document.getElementById('publicadoPor').value || 'Administrador';

        if (!tipo || !version || !archivo) {
            alert('⚠️ Complete todos los campos obligatorios');
            return;
        }

        // Validar formato de versión
        if (!/^v\d+\.\d+\.\d+$/.test(version)) {
            alert('⚠️ Formato inválido. Use: v1.0.0, v2.0.0, etc.');
            return;
        }

        // Validar que el archivo sea HTML
        if (!archivo.name.endsWith('.html')) {
            alert('⚠️ El archivo debe ser de tipo HTML (.html)');
            return;
        }

        const btnSubmit = event.target.querySelector('button[type="submit"]');
        const textoOriginal = btnSubmit?.innerHTML;
        if (btnSubmit) {
            btnSubmit.innerHTML = '⏳ Procesando archivo...';
            btnSubmit.disabled = true;
        }

        const lector = new FileReader();
        lector.onload = async function (e) {
            let contenidoHtml = e.target.result;

            // 🔴 ======================================================
            // 🔴 INYECTAR AUTOMÁTICAMENTE LA VERSIÓN EN EL CÓDIGO HTML
            // 🔴 ======================================================

            // Buscar la línea VERSION_ACTUAL en el código
            // Patrón: const VERSION_ACTUAL = 'v1.0.0';
            const versionPattern = /(const VERSION_ACTUAL\s*=\s*['"])([^'"]*)(['"])/;
            const match = contenidoHtml.match(versionPattern);

            if (match) {
                // Reemplazar la versión encontrada con la nueva
                const nuevaLinea = `${match[1]}${version}${match[3]}`;
                contenidoHtml = contenidoHtml.replace(versionPattern, nuevaLinea);
                console.log(`✅ Versión actualizada en el código: ${match[2]} → ${version}`);
            } else {
                console.warn('⚠️ No se encontró la línea VERSION_ACTUAL en el archivo');
                // Como fallback, insertar la definición después de las variables globales
                const fallbackPattern = /(let evaluacionesGlobales = .*?;)/;
                const fallbackMatch = contenidoHtml.match(fallbackPattern);
                if (fallbackMatch) {
                    const versionLine = `\n        const VERSION_ACTUAL = '${version}'; // AUTO-INYECTADO\n        const TIPO_SISTEMA = '${tipo}';\n`;
                    contenidoHtml = contenidoHtml.replace(fallbackPattern, fallbackMatch[0] + versionLine);
                    console.log(`✅ Versión inyectada como fallback: ${version}`);
                }
            }

            // También asegurar que TIPO_SISTEMA sea correcto
            const tipoPattern = /(const TIPO_SISTEMA\s*=\s*['"])([^'"]*)(['"])/;
            const tipoMatch = contenidoHtml.match(tipoPattern);
            if (tipoMatch && tipoMatch[2] !== tipo) {
                const nuevaLineaTipo = `${tipoMatch[1]}${tipo}${tipoMatch[3]}`;
                contenidoHtml = contenidoHtml.replace(tipoPattern, nuevaLineaTipo);
                console.log(`✅ TIPO_SISTEMA actualizado: ${tipoMatch[2]} → ${tipo}`);
            }

            try {
                // Verificar si ya existe la versión
                const { data: existe, error: existeError } = await db
                    .from('versiones_sistema')
                    .select('id')
                    .eq('version', version)
                    .eq('tipo', tipo)
                    .maybeSingle();

                if (existeError) throw existeError;

                if (existe) {
                    alert(`⚠️ La versión ${version} ya existe para el sistema ${tipo === 'auditor' ? 'Auditor' : 'Supervisor'}`);
                    if (btnSubmit) {
                        btnSubmit.innerHTML = textoOriginal;
                        btnSubmit.disabled = false;
                    }
                    return;
                }

                // Desactivar versión activa anterior del mismo tipo
                await db
                    .from('versiones_sistema')
                    .update({ es_activo: false })
                    .eq('tipo', tipo)
                    .eq('es_activo', true);

                // Insertar nueva versión (con el contenido ya modificado)
                const { error: insertError } = await db
                    .from('versiones_sistema')
                    .insert({
                        version: version,
                        tipo: tipo,
                        nombre_archivo: archivo.name,
                        contenido_html: contenidoHtml,  // ← Contenido con versión actualizada
                        descripcion: descripcion,
                        publicado_por: publicadoPor,
                        tamano_bytes: archivo.size,
                        es_activo: true
                    });

                if (insertError) throw insertError;

                alert(`✅ Versión ${version} publicada correctamente\n\n📌 La versión se ha inyectado automáticamente en el código.\nLos usuarios solo necesitarán descargar y reemplazar el archivo.`);

                // Limpiar formulario y recargar tabla
                limpiarFormVersiones();
                cargarVersionesTabla('todos');

            } catch (error) {
                console.error('Error publicando versión:', error);
                alert('❌ Error al publicar: ' + error.message);
            } finally {
                if (btnSubmit) {
                    btnSubmit.innerHTML = textoOriginal;
                    btnSubmit.disabled = false;
                }
            }
        };

        lector.onerror = function () {
            alert('❌ Error al leer el archivo');
            if (btnSubmit) {
                btnSubmit.innerHTML = textoOriginal;
                btnSubmit.disabled = false;
            }
        };

        lector.readAsText(archivo);
    }
    // ===== FIN FUNCIÓN: publicarNuevaVersion ===============================

    // ===== 6. INICIO FUNCIÓN: limpiarFormVersiones =========================
    function limpiarFormVersiones() {
        document.getElementById('tipoSistema').value = '';
        document.getElementById('version').value = '';
        document.getElementById('archivoHtml').value = '';
        document.getElementById('descripcion').value = '';
        document.getElementById('publicadoPor').value = '';
    }
    // ===== FIN FUNCIÓN: limpiarFormVersiones ===============================

    // ===== 7. INICIO FUNCIÓN: inicializarFormVersiones =====================
    function inicializarFormVersiones() {
        const form = document.getElementById('formPublicarVersion');
        if (form) {
            // Remover eventos anteriores
            const nuevoForm = form.cloneNode(true);
            form.parentNode.replaceChild(nuevoForm, form);

            const formFinal = document.getElementById('formPublicarVersion');
            formFinal.addEventListener('submit', publicarNuevaVersion);
            console.log('✅ Formulario de versiones inicializado');
        }
    }
    // ===== FIN FUNCIÓN: inicializarFormVersiones ===========================

