    // ----------------------------------------------------------------------
    // Cargar MIS solicitudes (para el solicitante)
    // ----------------------------------------------------------------------
    async function cargarMisSolicitudes() {
        console.log('📋 Cargando mis solicitudes...');
        
        const container = document.getElementById('misSolicitudesListado');
        if (!container) return;
        
        const usuarioId = getUsuarioActualId();
        if (!usuarioId) {
            container.innerHTML = '<div style="text-align: center; padding: 40px;">❌ Usuario no identificado</div>';
            return;
        }
        
        const filtroEstado = document.getElementById('filtroEstadoSolicitud')?.value || 'todos';
        const busqueda = document.getElementById('buscarSolicitud')?.value.toLowerCase() || '';
        
        container.innerHTML = '<div style="text-align: center; padding: 40px;">⏳ Cargando...</div>';
        
        try {
            let solicitudes = await API.getSolicitudesPorUsuario(usuarioId);
            
            // 🔴 Validar que sea un array
            if (!Array.isArray(solicitudes)) {
                console.warn('solicitudes no es un array:', solicitudes);
                solicitudes = [];
            }
            
            // Aplicar filtros
            if (filtroEstado !== 'todos') {
                solicitudes = solicitudes.filter(s => s.estado === filtroEstado);
            }
            
            if (busqueda) {
                solicitudes = solicitudes.filter(s => 
                    s.titulo.toLowerCase().includes(busqueda) ||
                    s.id.toString().includes(busqueda)
                );
            }
            
            window.solicitudesData = solicitudes;
            
            actualizarKPIsMisSolicitudes(solicitudes);
            renderizarMisSolicitudes(solicitudes);
            await cargarNotificaciones();
            
        } catch (error) {
            console.error('Error cargando solicitudes:', error);
            container.innerHTML = `<div style="text-align: center; padding: 40px; color: var(--danger);">❌ Error: ${error.message}</div>`;
        }
    }

    // ----------------------------------------------------------------------
    // Actualizar KPIs en pestaña "Mis Solicitudes"
    // ----------------------------------------------------------------------
    function actualizarKPIsMisSolicitudes(solicitudes) {
        const pendientes = solicitudes.filter(s => s.estado === 'creada' || s.estado === 'evaluacion').length;
        const enCurso = solicitudes.filter(s => s.estado === 'desarrollo' || s.estado === 'pruebas').length;
        const completadas = solicitudes.filter(s => s.estado === 'completada').length;
        const verificadas = solicitudes.filter(s => s.estado === 'verificada').length;
        
        const pendientesElem = document.getElementById('misSolicitudesPendientes');
        const enCursoElem = document.getElementById('misSolicitudesEnCurso');
        const completadasElem = document.getElementById('misSolicitudesCompletadas');
        const verificadasElem = document.getElementById('misSolicitudesVerificadas');
        
        if (pendientesElem) pendientesElem.textContent = pendientes;
        if (enCursoElem) enCursoElem.textContent = enCurso;
        if (completadasElem) completadasElem.textContent = completadas;
        if (verificadasElem) verificadasElem.textContent = verificadas;
    }

