    // ----------------------------------------------------------------------
    async function cargarTodasSolicitudes() {
        console.log('⚙️ Cargando todas las solicitudes para admin...');
        
        const container = document.getElementById('todasSolicitudesListado');
        if (!container) return;
        
        const adminRol = getUsuarioActualRol();
        if (adminRol !== 'ADMIN') {
            container.innerHTML = '<div style="text-align: center; padding: 40px; color: var(--danger);">⛔ Acceso denegado. Solo administradores.</div>';
            return;
        }
        
        const filtroEstado = document.getElementById('adminFiltroEstado')?.value || 'todos';
        const filtroPrioridad = document.getElementById('adminFiltroPrioridad')?.value || 'todos';
        const busqueda = document.getElementById('adminBuscarSolicitud')?.value.toLowerCase() || '';
        
        container.innerHTML = '<div style="text-align: center; padding: 40px;">⏳ Cargando...</div>';
        
        try {
            // 🔴 CAMBIO: Usar API en lugar de PostgreSQL directo
            let solicitudes = await API.getTodasSolicitudes();
            
            // Aplicar filtros
            if (filtroEstado !== 'todos') {
                solicitudes = solicitudes.filter(s => s.estado === filtroEstado);
            }
            
            if (filtroPrioridad !== 'todos') {
                solicitudes = solicitudes.filter(s => s.prioridad === filtroPrioridad);
            }
            
            if (busqueda) {
                solicitudes = solicitudes.filter(s => 
                    s.titulo.toLowerCase().includes(busqueda) ||
                    s.id.toString().includes(busqueda) ||
                    s.solicitante_nombre.toLowerCase().includes(busqueda)
                );
            }
            
            window.solicitudesData = solicitudes;
            
            actualizarKPIsGestionSolicitudes(solicitudes);
            renderizarTodasSolicitudes(solicitudes);
            
        } catch (error) {
            console.error('Error cargando solicitudes:', error);
            container.innerHTML = `<div style="text-align: center; padding: 40px; color: var(--danger);">❌ Error: ${error.message}</div>`;
        }
    }

    // ----------------------------------------------------------------------
    // Cargar select de solicitantes (para filtro admin)
    // ----------------------------------------------------------------------
    function cargarSelectSolicitantes(solicitudes) {
        const select = document.getElementById('adminFiltroSolicitante');
        if (!select) return;
        
        const solicitantesUnicos = new Set();
        solicitantesUnicos.add('todos');
        
        solicitudes.forEach(s => {
            if (s.solicitante_nombre) {
                solicitantesUnicos.add(s.solicitante_nombre);
            }
        });
        
        const valorActual = select.value;
        select.innerHTML = '';
        
        for (const nombre of solicitantesUnicos) {
            const value = nombre === 'todos' ? 'todos' : nombre;
            const label = nombre === 'todos' ? '👥 Todos' : `👤 ${escapeHtml(nombre)}`;
            select.innerHTML += `<option value="${value}" ${valorActual === value ? 'selected' : ''}>${label}</option>`;
        }
    }

    // ----------------------------------------------------------------------
    // Actualizar KPIs en pestaña de gestión (admin)
    // ----------------------------------------------------------------------
    function actualizarKPIsGestionSolicitudes(solicitudes) {
        const pendientes = solicitudes.filter(s => s.estado === 'creada' || s.estado === 'evaluacion').length;
        const enCurso = solicitudes.filter(s => s.estado === 'desarrollo' || s.estado === 'pruebas').length;
        
        // Completadas este mes
        const ahora = new Date();
        const mesActual = ahora.getMonth();
        const anioActual = ahora.getFullYear();
        const completadasMes = solicitudes.filter(s => {
            if (s.estado !== 'completada' && s.estado !== 'verificada') return false;
            const fecha = new Date(s.fecha_entrega || s.updated_at);
            return fecha.getMonth() === mesActual && fecha.getFullYear() === anioActual;
        }).length;
        
        // Tiempo promedio desde creación hasta completada
        const completadas = solicitudes.filter(s => s.estado === 'completada' || s.estado === 'verificada');
        let tiempoPromedio = 0;
        if (completadas.length > 0) {
            let sumaHoras = 0;
            for (const s of completadas) {
                if (s.tiempo_estimado_horas) {
                    sumaHoras += s.tiempo_estimado_horas;
                }
            }
            tiempoPromedio = Math.round(sumaHoras / completadas.length);
        }
        
        const pendientesElem = document.getElementById('gestionPendientesTotal');
        const enCursoElem = document.getElementById('gestionEnCursoTotal');
        const completadasElem = document.getElementById('gestionCompletadasMes');
        const tiempoElem = document.getElementById('gestionTiempoPromedio');
        
        if (pendientesElem) pendientesElem.textContent = pendientes;
        if (enCursoElem) enCursoElem.textContent = enCurso;
        if (completadasElem) completadasElem.textContent = completadasMes;
        if (tiempoElem) tiempoElem.textContent = `${tiempoPromedio}h`;
    }

