    // ======================================================
    // APROBAR SOLICITUD
    // ======================================================

    function abrirModalAprobarSolicitud(id) {
        console.log(`📋 Abriendo modal de aprobación para solicitud ${id}`);
        
        const solicitud = window.solicitudesData?.find(s => s.id == id);
        if (!solicitud) {
            alert('Solicitud no encontrada');
            return;
        }
        
        const tiempoActual = solicitud.tiempo_estimado_horas || '';
        
        const modalHtml = `
            <div id="modalAprobarSolicitud" style="position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.6); z-index: 10003; display: flex; justify-content: center; align-items: center;">
                <div style="background: white; border-radius: 16px; width: 90%; max-width: 450px; overflow: hidden; box-shadow: 0 20px 40px rgba(0,0,0,0.3);">
                    <div style="padding: 15px 20px; background: linear-gradient(135deg, #28a745, #1a7f37); color: white;">
                        <strong style="font-size: 16px;">✅ Aprobar Solicitud #${id}</strong>
                    </div>
                    <div style="padding: 20px;">
                        <p style="margin-bottom: 15px;"><strong>Solicitud:</strong> ${escapeHtml(solicitud.titulo)}</p>
                        <div style="margin-bottom: 15px;">
                            <label style="font-size: 12px; font-weight: 600;">⏱️ Tiempo estimado (horas) *</label>
                            <input type="number" id="tiempoEstimadoHoras" value="${tiempoActual}" min="1" step="1" required 
                                style="width: 100%; padding: 8px; margin-top: 5px; border-radius: 8px; border: 1px solid #ddd;">
                        </div>
                        <div style="margin-bottom: 15px;">
                            <label style="font-size: 12px; font-weight: 600;">👨‍💻 Responsable asignado (opcional)</label>
                            <input type="text" id="responsableAprobacion" value="${escapeHtml(solicitud.responsable_asignado || '')}" 
                                placeholder="Nombre del desarrollador"
                                style="width: 100%; padding: 8px; margin-top: 5px; border-radius: 8px; border: 1px solid #ddd;">
                        </div>
                    </div>
                    <div style="padding: 15px 20px; background: #f8f9fa; display: flex; justify-content: flex-end; gap: 10px; border-top: 1px solid #e0e0e0;">
                        <button onclick="cerrarModalAprobarSolicitud()" style="padding: 8px 20px; background: #6c757d; border: none; border-radius: 8px; cursor: pointer; color: white;">Cancelar</button>
                        <button onclick="confirmarAprobarSolicitud(${id})" style="padding: 8px 20px; background: #28a745; border: none; border-radius: 8px; cursor: pointer; color: white;">✅ Aprobar</button>
                    </div>
                </div>
            </div>
        `;
        
        const existing = document.getElementById('modalAprobarSolicitud');
        if (existing) existing.remove();
        
        document.body.insertAdjacentHTML('beforeend', modalHtml);
    }

    function cerrarModalAprobarSolicitud() {
        const modal = document.getElementById('modalAprobarSolicitud');
        if (modal) modal.remove();
    }

    async function confirmarAprobarSolicitud(id) {
        console.log(`✅ Confirmando aprobación de solicitud ${id}`);
        
        const tiempoEstimado = parseInt(document.getElementById('tiempoEstimadoHoras')?.value);
        const responsable = document.getElementById('responsableAprobacion')?.value.trim();
        
        if (!tiempoEstimado || tiempoEstimado < 1) {
            alert('⚠️ Ingrese un tiempo estimado válido (mínimo 1 hora)');
            return;
        }
        
        cerrarModalAprobarSolicitud();
        
        const token = localStorage.getItem('meca_token');
        
        try {
            const response = await fetch(`/api/solicitudes/${id}`, {
                method: 'PUT',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    estado: 'aprobada',
                    tiempo_estimado_horas: tiempoEstimado,
                    responsable_asignado: responsable,
                    fecha_aprobacion: new Date().toISOString()
                })
            });
            
            if (!response.ok) throw new Error('Error al aprobar');
            
            alert(`✅ Solicitud #${id} aprobada correctamente`);
            
            // Actualizar localmente
            const index = window.solicitudesData?.findIndex(s => s.id == id);
            if (index !== -1) {
                window.solicitudesData[index].estado = 'aprobada';
                window.solicitudesData[index].tiempo_estimado_horas = tiempoEstimado;
                window.solicitudesData[index].responsable_asignado = responsable;
            }
            
            cerrarModalDetalleSolicitud();
            await cargarTodasSolicitudes();
            await cargarMisSolicitudes();
            
        } catch (error) {
            console.error('Error:', error);
            alert('❌ Error al aprobar: ' + error.message);
        }
    }

    // ======================================================
    // RECHAZAR SOLICITUD
    // ======================================================

    function abrirModalRechazarSolicitud(id) {
        console.log(`📋 Abriendo modal de rechazo para solicitud ${id}`);
        
        const solicitud = window.solicitudesData?.find(s => s.id == id);
        if (!solicitud) {
            alert('Solicitud no encontrada');
            return;
        }
        
        const modalHtml = `
            <div id="modalRechazarSolicitud" style="position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.6); z-index: 10003; display: flex; justify-content: center; align-items: center;">
                <div style="background: white; border-radius: 16px; width: 90%; max-width: 450px; overflow: hidden; box-shadow: 0 20px 40px rgba(0,0,0,0.3);">
                    <div style="padding: 15px 20px; background: linear-gradient(135deg, #d93025, #b71c1c); color: white;">
                        <strong style="font-size: 16px;">❌ Rechazar Solicitud #${id}</strong>
                    </div>
                    <div style="padding: 20px;">
                        <p style="margin-bottom: 15px;"><strong>Solicitud:</strong> ${escapeHtml(solicitud.titulo)}</p>
                        <div style="margin-bottom: 15px;">
                            <label style="font-size: 12px; font-weight: 600;">📝 Motivo del rechazo *</label>
                            <textarea id="motivoRechazo" rows="3" required placeholder="Explique por qué no se aprueba esta solicitud..." 
                                    style="width: 100%; padding: 8px; margin-top: 5px; border-radius: 8px; border: 1px solid #ddd;"></textarea>
                        </div>
                    </div>
                    <div style="padding: 15px 20px; background: #f8f9fa; display: flex; justify-content: flex-end; gap: 10px; border-top: 1px solid #e0e0e0;">
                        <button onclick="cerrarModalRechazarSolicitud()" style="padding: 8px 20px; background: #6c757d; border: none; border-radius: 8px; cursor: pointer; color: white;">Cancelar</button>
                        <button onclick="confirmarRechazarSolicitud(${id})" style="padding: 8px 20px; background: #d93025; border: none; border-radius: 8px; cursor: pointer; color: white;">❌ Rechazar</button>
                    </div>
                </div>
            </div>
        `;
        
        const existing = document.getElementById('modalRechazarSolicitud');
        if (existing) existing.remove();
        
        document.body.insertAdjacentHTML('beforeend', modalHtml);
    }

    function cerrarModalRechazarSolicitud() {
        const modal = document.getElementById('modalRechazarSolicitud');
        if (modal) modal.remove();
    }

    async function confirmarRechazarSolicitud(id) {
        console.log(`❌ Confirmando rechazo de solicitud ${id}`);
        
        const motivo = document.getElementById('motivoRechazo')?.value.trim();
        
        if (!motivo) {
            alert('⚠️ Debe ingresar un motivo de rechazo');
            return;
        }
        
        cerrarModalRechazarSolicitud();
        
        const token = localStorage.getItem('meca_token');
        
        try {
            const response = await fetch(`/api/solicitudes/${id}`, {
                method: 'PUT',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    estado: 'rechazada',
                    motivo_rechazo: motivo
                })
            });
            
            if (!response.ok) throw new Error('Error al rechazar');
            
            alert(`❌ Solicitud #${id} rechazada`);
            
            // Actualizar localmente
            const index = window.solicitudesData?.findIndex(s => s.id == id);
            if (index !== -1) {
                window.solicitudesData[index].estado = 'rechazada';
                window.solicitudesData[index].motivo_rechazo = motivo;
            }
            
            cerrarModalDetalleSolicitud();
            await cargarTodasSolicitudes();
            await cargarMisSolicitudes();
            
        } catch (error) {
            console.error('Error:', error);
            alert('❌ Error al rechazar: ' + error.message);
        }
    }

    // ----------------------------------------------------------------------
    // Cambiar estado de una solicitud (admin)
    // ----------------------------------------------------------------------
    async function cambiarEstadoSolicitud(id, nuevoEstado, opciones = {}) {
        console.log(`🔄 Cambiando solicitud ${id} a estado: ${nuevoEstado}`);
        
        // Buscar en window.solicitudesData
        const solicitud = window.solicitudesData?.find(s => s.id == id);
        
        if (!solicitud) {
            console.error(`❌ Solicitud ${id} no encontrada en window.solicitudesData`);
            alert('Solicitud no encontrada');
            return;
        }
        
        const token = localStorage.getItem('meca_token');
        
        const updateData = {
            estado: nuevoEstado,
            updated_at: new Date().toISOString()
        };
        
        // Actualizar fechas según el nuevo estado
        const ahora = new Date().toISOString();
        
        if (nuevoEstado === 'aprobada') {
            updateData.fecha_aprobacion = ahora;
            if (opciones.tiempoEstimado) updateData.tiempo_estimado_horas = opciones.tiempoEstimado;
            if (opciones.responsable) updateData.responsable_asignado = opciones.responsable;
        } else if (nuevoEstado === 'desarrollo') {
            updateData.fecha_inicio_desarrollo = ahora;
            if (opciones.responsable) updateData.responsable_asignado = opciones.responsable;
        } else if (nuevoEstado === 'completada') {
            updateData.fecha_entrega = ahora;
        } else if (nuevoEstado === 'rechazada') {
            if (opciones.motivoRechazo) updateData.motivo_rechazo = opciones.motivoRechazo;
        }
        
        try {
            const response = await fetch(`/api/solicitudes/${id}`, {
                method: 'PUT',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(updateData)
            });
            
            if (!response.ok) {
                const error = await response.json();
                throw new Error(error.error || 'Error al actualizar');
            }
            
            console.log(`✅ Solicitud ${id} actualizada a ${nuevoEstado}`);
            
            // Actualizar el objeto en window.solicitudesData
            const index = window.solicitudesData.findIndex(s => s.id == id);
            if (index !== -1) {
                window.solicitudesData[index] = { ...window.solicitudesData[index], ...updateData };
            }
            
            // Cerrar modal y recargar listados
            cerrarModalDetalleSolicitud();
            await cargarTodasSolicitudes();
            await cargarMisSolicitudes();
            
            alert(`✅ Solicitud #${id} actualizada a: ${obtenerTextoEstado(nuevoEstado)}`);
            
        } catch (error) {
            console.error('Error:', error);
            alert('❌ Error al actualizar: ' + error.message);
        }
    }

    // ----------------------------------------------------------------------
    // Iniciar desarrollo (con responsable)
    // ----------------------------------------------------------------------
    async function iniciarDesarrollo(id) {
        const responsable = document.getElementById('responsableAsignado')?.value.trim();
        
        await cambiarEstadoSolicitud(id, 'desarrollo', { responsable });
    }

    // ----------------------------------------------------------------------
    // Agregar comentario interno (solo admin)
    // ----------------------------------------------------------------------
    async function agregarComentarioInterno(solicitudId) {
        const comentario = document.getElementById('nuevoComentarioInterno')?.value.trim();
        if (!comentario) {
            alert('⚠️ Escriba un comentario antes de agregar');
            return;
        }
        
        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }
        
        const solicitud = solicitudesData.find(s => s.id === solicitudId);
        if (!solicitud) return;
        
        // Obtener comentarios actuales
        let comentariosActuales = [];
        try {
            if (solicitud.comentarios_internos) {
                comentariosActuales = typeof solicitud.comentarios_internos === 'string' 
                    ? JSON.parse(solicitud.comentarios_internos) 
                    : solicitud.comentarios_internos;
            }
        } catch(e) { console.warn('Error parseando comentarios:', e); }
        
        // Agregar nuevo comentario
        comentariosActuales.push({
            fecha: new Date().toISOString(),
            admin: getUsuarioActualNombre(),
            comentario: comentario
        });
        
        try {
            const { error } = await db
                .from('solicitudes_requerimientos')
                .update({
                    comentarios_internos: JSON.stringify(comentariosActuales),
                    updated_at: new Date().toISOString()
                })
                .eq('id', solicitudId);
            
            if (error) throw error;
            
            // Limpiar textarea
            document.getElementById('nuevoComentarioInterno').value = '';
            
            // Recargar la vista del modal
            await verDetalleSolicitudAdmin(solicitudId);
            
            // Recargar listados
            await cargarTodasSolicitudes();
            
        } catch (error) {
            console.error('Error agregando comentario:', error);
            alert('❌ Error al agregar comentario: ' + error.message);
        }
    }

    // ----------------------------------------------------------------------
    // Cancelar solicitud (solicitante)
    // ----------------------------------------------------------------------
    async function cancelarSolicitud(id) {
        if (!confirm('⚠️ ¿Está seguro de cancelar esta solicitud?\n\nEsta acción no se puede deshacer.')) {
            return;
        }
        
        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }
        
        try {
            const { error } = await db
                .from('solicitudes_requerimientos')
                .update({
                    estado: 'cancelada',
                    updated_at: new Date().toISOString()
                })
                .eq('id', id);
            
            if (error) throw error;
            
            cerrarModalDetalleSolicitud();
            await cargarMisSolicitudes();
            
            alert('✅ Solicitud cancelada');
            
        } catch (error) {
            console.error('Error cancelando solicitud:', error);
            alert('❌ Error: ' + error.message);
        }
    }

    // ----------------------------------------------------------------------
    // Marcar solicitud como verificada (solicitante)
    // ----------------------------------------------------------------------
    async function marcarSolicitudComoVerificada(id) {
        if (!confirm('⭐ ¿Confirmar que la funcionalidad solicitada funciona correctamente?\n\nEsto cerrará definitivamente la solicitud.')) {
            return;
        }
        
        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }
        
        try {
            const { error } = await db
                .from('solicitudes_requerimientos')
                .update({
                    estado: 'verificada',
                    updated_at: new Date().toISOString()
                })
                .eq('id', id);
            
            if (error) throw error;
            
            cerrarModalDetalleSolicitud();
            await cargarMisSolicitudes();
            
            alert('✅ ¡Gracias por confirmar! La solicitud ha sido cerrada.');
            
        } catch (error) {
            console.error('Error verificando solicitud:', error);
            alert('❌ Error: ' + error.message);
        }
    }

    // ----------------------------------------------------------------------
    // Crear notificación interna
    // ----------------------------------------------------------------------
    async function crearNotificacionInterna(usuarioId, solicitudId, mensaje) {
        const db = getDB();
        if (!db) return;
        
        try {
            // Obtener el próximo ID
            const { data: maxIdData } = await db
                .from('notificaciones_internas')
                .select('id')
                .order('id', { ascending: false })
                .limit(1);
            
            const nuevoId = (maxIdData && maxIdData[0]?.id) ? maxIdData[0].id + 1 : 1;
            
            const { error } = await db
                .from('notificaciones_internas')
                .insert({
                    id: nuevoId,
                    usuario_id: usuarioId,
                    solicitud_id: solicitudId,
                    mensaje: mensaje,
                    leida: false,
                    created_at: new Date().toISOString()
                });
            
            if (error) throw error;
            
            // Actualizar badge en la UI
            await cargarNotificaciones();
            
        } catch (error) {
            console.warn('Error creando notificación:', error);
        }
    }

    // ----------------------------------------------------------------------
    // Cargar notificaciones del usuario actual
    // ----------------------------------------------------------------------
    async function cargarNotificaciones() {
        const db = getDB();
        if (!db) return;
        
        const usuarioId = getUsuarioActualId();
        if (!usuarioId) return;
        
        try {
            const { data, error } = await db
                .from('notificaciones_internas')
                .select('*')
                .eq('usuario_id', usuarioId)
                .eq('leida', false)
                .order('created_at', { ascending: false });
            
            if (error) throw error;
            
            const notificacionesNoLeidas = data || [];
            const count = notificacionesNoLeidas.length;
            
            const container = document.getElementById('notificacionesSolicitudes');
            const countSpan = document.getElementById('notificacionesCount');
            
            if (container && countSpan) {
                if (count > 0) {
                    container.style.display = 'block';
                    countSpan.textContent = count;
                    
                    // Opcional: mostrar un badge en el tab
                    const tabButton = document.querySelector('.tab-button[data-tab="misSolicitudes"]');
                    if (tabButton) {
                        let badge = tabButton.querySelector('.notificacion-badge');
                        if (!badge) {
                            badge = document.createElement('span');
                            badge.className = 'notificacion-badge';
                            badge.style.cssText = 'background: red; color: white; border-radius: 50%; padding: 2px 6px; font-size: 10px; margin-left: 5px;';
                            tabButton.appendChild(badge);
                        }
                        badge.textContent = count;
                        badge.style.display = count > 0 ? 'inline-block' : 'none';
                    }
                } else {
                    container.style.display = 'none';
                    const tabButton = document.querySelector('.tab-button[data-tab="misSolicitudes"]');
                    if (tabButton) {
                        const badge = tabButton.querySelector('.notificacion-badge');
                        if (badge) badge.style.display = 'none';
                    }
                }
            }
            
        } catch (error) {
            console.error('Error cargando notificaciones:', error);
        }
    }

    // ----------------------------------------------------------------------
    // Marcar todas las notificaciones como leídas
    // ----------------------------------------------------------------------
    async function marcarTodasNotificacionesLeidas() {
        const db = getDB();
        if (!db) return;
        
        const usuarioId = getUsuarioActualId();
        if (!usuarioId) return;
        
        try {
            const { error } = await db
                .from('notificaciones_internas')
                .update({ leida: true })
                .eq('usuario_id', usuarioId)
                .eq('leida', false);
            
            if (error) throw error;
            
            await cargarNotificaciones();
            
        } catch (error) {
            console.error('Error marcando notificaciones:', error);
        }
    }

    // ----------------------------------------------------------------------
    // Enviar nueva solicitud
    // ----------------------------------------------------------------------
    async function enviarNuevaSolicitud() {
        const titulo = document.getElementById('solicitudTitulo')?.value.trim();
        const tipo = document.getElementById('solicitudTipo')?.value;
        const prioridad = document.getElementById('solicitudPrioridad')?.value;
        const descripcion = document.getElementById('solicitudDescripcion')?.value.trim();
        
        if (!titulo || !tipo || !prioridad || !descripcion) {
            alert('⚠️ Complete todos los campos obligatorios');
            return;
        }
        
        const db = getDB();
        if (!db) {
            alert('❌ Base de datos no disponible');
            return;
        }
        
        const usuarioId = getUsuarioActualId();
        const usuarioNombre = getUsuarioActualNombre();
        const usuarioRol = getUsuarioActualRol();
        
        if (!usuarioId) {
            alert('❌ Usuario no identificado');
            return;
        }
        
        // Obtener el próximo ID
        const { data: maxIdData } = await db
            .from('solicitudes_requerimientos')
            .select('id')
            .order('id', { ascending: false })
            .limit(1);
        
        const nuevoId = (maxIdData && maxIdData[0]?.id) ? maxIdData[0].id + 1 : 1;
        
        const nuevaSolicitud = {
            id: nuevoId,
            titulo: titulo,
            descripcion: descripcion,
            tipo: tipo,
            prioridad: prioridad,
            solicitante_id: usuarioId,
            solicitante_nombre: usuarioNombre,
            solicitante_rol: usuarioRol,
            estado: 'creada',
            fecha_creacion: new Date().toISOString(),
            created_at: new Date().toISOString(),
            updated_at: new Date().toISOString(),
            comentarios_internos: JSON.stringify([])
        };
        
        try {
            const { error } = await db
                .from('solicitudes_requerimientos')
                .insert(nuevaSolicitud);
            
            if (error) throw error;
            
            cerrarModalNuevaSolicitud();
            await cargarMisSolicitudes();
            
            alert(`✅ Solicitud #${nuevoId} creada correctamente\n\nUn administrador la evaluará en breve.`);
            
        } catch (error) {
            console.error('Error creando solicitud:', error);
            alert('❌ Error al crear la solicitud: ' + error.message);
        }
    }

