    function cerrarModalNuevaSolicitud() {
        document.getElementById('modalNuevaSolicitud').style.display = 'none';
    }

    function cerrarModalDetalleSolicitud() {
        const modal = document.getElementById('modalDetalleSolicitud');
        if (modal) modal.style.display = 'none';
    }

    function obtenerTextoEstado(estado) {
        const estados = {
            'creada': '📝 Creada',
            'evaluacion': '⏳ En evaluación',
            'aprobada': '✅ Aprobada',
            'rechazada': '❌ Rechazada',
            'desarrollo': '🔄 En desarrollo',
            'pruebas': '🧪 En pruebas',
            'completada': '✅ Completada',
            'verificada': '⭐ Verificada',
            'cancelada': '⏸️ Cancelada'
        };
        return estados[estado] || estado;
    }

    function obtenerTipoTexto(tipo) {
        const tipos = {
            'grafico': '📊 Gráfico',
            'tabla': '📋 Tabla',
            'vista': '🖥️ Vista',
            'modificacion': '✏️ Modificación',
            'informe': '📄 Informe'
        };
        return tipos[tipo] || tipo;
    }

    function formatearFechaSimple(fechaIso) {
        if (!fechaIso) return '-';
        try {
            const fecha = new Date(fechaIso);
            return `${fecha.getDate().toString().padStart(2, '0')}/${(fecha.getMonth() + 1).toString().padStart(2, '0')}/${fecha.getFullYear()}`;
        } catch(e) {
            return '-';
        }
    }


