// BLOQUE 13: INFORMES MENSUALES
// ====================================================================================== 

    // ======================================================
    // Cargar historial de informes desde la base de datos
    // ======================================================
    async function cargarHistorialInformes() {
        console.log('📋 Cargando historial de informes mensuales...');
        
        const db = getDB();
        if (!db) {
            console.error('❌ Base de datos no disponible');
            return;
        }
        
        const filtroAgente = document.getElementById('filtroAgenteInformes')?.value || '';
        const filtroPeriodo = document.getElementById('filtroPeriodoInformes')?.value || '';
        const filtroPersistencia = document.getElementById('filtroPersistenciaInformes')?.value || '';
        
        try {
            let query = db
                .from('cierres_mensuales')
                .select('*')
                .order('anio', { ascending: false })
                .order('mes', { ascending: false });
            
            if (filtroAgente) {
                query = query.ilike('agente', `%${filtroAgente}%`);
            }
            
            if (filtroPeriodo) {
                const [anio, mes] = filtroPeriodo.split('-');
                query = query.eq('anio', parseInt(anio)).eq('mes', parseInt(mes));
            }
            
            if (filtroPersistencia === 'si') {
                query = query.eq('persistencia', true);
            } else if (filtroPersistencia === 'no') {
                query = query.eq('persistencia', false);
            }
            
            const { data, error } = await query;
            
            if (error) throw error;
            
            // 🔴 CORRECCIÓN: Usar window.informesGlobales
            window.informesGlobales = data || [];
            
            console.log(`✅ ${window.informesGlobales.length} informes cargados en window.informesGlobales`);
            
            if (window.informesGlobales.length > 0) {
                console.log(`   IDs: ${window.informesGlobales.map(i => i.id).join(', ')}`);
            }
            
            // Actualizar la tabla y KPIs
            if (typeof actualizarTablaInformesMensuales === 'function') {
                actualizarTablaInformesMensuales(window.informesGlobales);
            }
            
            if (typeof actualizarKPIsInformes === 'function') {
                actualizarKPIsInformes(window.informesGlobales);
            }
            
        } catch (error) {
            console.error('Error cargando informes:', error);
            window.informesGlobales = [];
            const tbody = document.getElementById('tablaInformesMensuales');
            if (tbody) {
                tbody.innerHTML = `<tr><td colspan="8" style="text-align: center; color: var(--danger);">❌ Error: ${error.message}</td></tr>`;
            }
        }
    }

    // ======================================================
    // Actualizar tabla de informes
    // ======================================================
    function actualizarTablaInformesMensuales(informes) {
        const tbody = document.getElementById('tablaInformesMensuales');
        if (!tbody) return;
        
        // Si no se pasa parámetro, usar la variable global
        const datos = informes || window.informesGlobales || [];
        
        if (datos.length === 0) {
            tbody.innerHTML = '<tr><td colspan="8" style="text-align: center; padding: 40px;">📭 No hay informes generados<\/td><\/tr>';
            return;
        }
        
        const meses = ['Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio', 'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre'];
        
        let html = '';
        
        for (let i = 0; i < datos.length; i++) {
            const inf = datos[i];
            const nombreMes = meses[inf.mes - 1];
            
            let colorPromedio = '#d93025';
            if (inf.promedio_mensual >= 90) colorPromedio = '#28a745';
            else if (inf.promedio_mensual >= 85) colorPromedio = '#f39c12';
            
            let persistenciaBadge = '';
            if (inf.persistencia) {
                persistenciaBadge = `<span class="badge" style="background: #d93025;" title="${inf.meses_consecutivos_q4} meses consecutivos">⚠️ ${inf.meses_consecutivos_q4} meses</span>`;
            } else {
                persistenciaBadge = '<span class="badge" style="background: #6c757d;">-</span>';
            }
            
            const rowId = `informe-row-${inf.id}`;
            
            html += `
                <tr class="expandable-row" onclick="toggleDetalleInforme('${rowId}')" style="cursor: pointer;">
                    <td style="text-align: center;">
                        <span class="expand-icon" id="icon-${rowId}">▶</span>
                    </td>
                    <td><strong>${escapeHtml(inf.agente)}</strong></td>
                    <td>${nombreMes} ${inf.anio}</td>
                    <td style="color: ${colorPromedio}; font-weight: bold;">${inf.promedio_mensual}%</td>
                    <td style="text-align: center;">${inf.total_ciclos}</td>
                    <td style="text-align: center;">${inf.pda_aplicados_en_mes || 0}</td>
                    <td style="text-align: center;">${persistenciaBadge}</td>
                    <td style="text-align: center;">
                        <button onclick="event.stopPropagation(); verInformeCompleto(${inf.id})" 
                                style="background: var(--accent); padding: 4px 10px; font-size: 11px; border-radius: 6px;">
                            👁️ Ver
                        </button>
                        <button onclick="event.stopPropagation(); descargarInformeHTML(${inf.id})" 
                                style="background: var(--ok); padding: 4px 10px; font-size: 11px; border-radius: 6px; margin-left: 5px;">
                            📥
                        </button>
                    </td>
                </tr>
                <tr id="${rowId}" class="detail-row" style="display: none;">
                    <td colspan="8">
                        <div class="detail-content" style="padding: 12px;">
                            <div style="display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px; font-size: 12px;">
                                <div><strong>📊 Promedio:</strong> ${inf.promedio_mensual}%</div>
                                <div><strong>🔄 Ciclos:</strong> ${inf.total_ciclos} de 4</div>
                                <div><strong>📞 Evaluaciones:</strong> ${inf.total_evaluaciones}</div>
                                <div><strong>📋 PDA aplicados:</strong> ${inf.pda_aplicados_en_mes || 0}</div>
                                ${inf.mejora_respecto_mes_anterior ? `<div><strong>📈 Tendencia:</strong> ${inf.mejora_respecto_mes_anterior > 0 ? '✅ Mejoró' : '📉 Empeoró'} ${Math.abs(inf.mejora_respecto_mes_anterior)}%</div>` : ''}
                                ${inf.meses_consecutivos_q4 > 1 ? `<div><strong>⚠️ Persistencia:</strong> ${inf.meses_consecutivos_q4} meses consecutivos en Q4</div>` : ''}
                            </div>
                        </div>
                    </td>
                </tr>
            `;
        }
        
        tbody.innerHTML = html;
        console.log(`✅ Tabla actualizada con ${datos.length} informes`);
    }

    // ======================================================
    // Alternar detalle expandible
    // ======================================================
    function toggleDetalleInforme(rowId) {
        const detailRow = document.getElementById(rowId);
        const icon = document.getElementById(`icon-${rowId}`);
        
        if (detailRow.style.display === 'none') {
            detailRow.style.display = 'table-row';
            if (icon) {
                icon.innerHTML = '▼';
                icon.classList.add('expanded');
            }
        } else {
            detailRow.style.display = 'none';
            if (icon) {
                icon.innerHTML = '▶';
                icon.classList.remove('expanded');
            }
        }
    }

    // ======================================================
    // Actualizar KPIs de la pestaña
    // ======================================================
    function actualizarKPIsInformes(informes) {
        const totalInformes = informes.length;
        const totalPersistencia = informes.filter(i => i.persistencia === true).length;
        
        // Último mes disponible
        let ultimoMesQ4 = 0;
        if (informes.length > 0) {
            const fechaActual = new Date();
            const ultimosInformes = informes.filter(i => i.anio === 2026);
            if (ultimosInformes.length > 0) {
                const ultimoMes = Math.max(...ultimosInformes.map(i => i.mes));
                ultimoMesQ4 = ultimosInformes.filter(i => i.mes === ultimoMes).length;
            }
        }
        
        const totalElem = document.getElementById('totalInformesKPI');
        const persistenciaElem = document.getElementById('totalPersistenciaKPI');
        const q4Elem = document.getElementById('totalQ4UltimoMes');
        
        if (totalElem) totalElem.textContent = totalInformes;
        if (persistenciaElem) persistenciaElem.textContent = totalPersistencia;
        if (q4Elem) q4Elem.textContent = ultimoMesQ4;
    }

    // ======================================================
    // Ver informe completo (abre nueva ventana)
    // ======================================================
    function verInformeCompleto(id) {
        console.log(`🔍 verInformeCompleto llamado con ID: ${id}`);
        
        const idNumero = parseInt(id);
        const informe = window.informesGlobales?.find(i => parseInt(i.id) === idNumero);
        
        if (!informe) {
            console.error(`❌ Informe con ID ${id} no encontrado`);
            alert(`No se pudo encontrar el informe ID: ${id}`);
            return;
        }
        
        if (!informe.documento_html) {
            console.error('❌ El informe no tiene contenido HTML');
            alert('El informe no tiene contenido para mostrar');
            return;
        }
        
        try {
            const ventana = window.open();
            if (!ventana) {
                alert('El navegador bloqueó la ventana emergente. Permita ventanas emergentes para este sitio.');
                return;
            }
            ventana.document.write(informe.documento_html);
            ventana.document.close();
            console.log('✅ Ventana abierta correctamente');
        } catch (error) {
            console.error('❌ Error:', error);
            alert('Error al abrir el informe: ' + error.message);
        }
    }

    // ======================================================
    // Descargar informe como archivo HTML
    // ======================================================
    function descargarInformeHTML(id) {
        console.log(`📥 descargarInformeHTML llamado con ID: ${id}`);
        
        const idNumero = parseInt(id);
        const informe = window.informesGlobales?.find(i => parseInt(i.id) === idNumero);
        
        if (!informe) {
            console.error(`❌ Informe con ID ${id} no encontrado`);
            alert('No se pudo encontrar el informe');
            return;
        }
        
        if (!informe.documento_html) {
            console.error('❌ El informe no tiene contenido HTML');
            alert('El informe no tiene contenido para descargar');
            return;
        }
        
        try {
            const meses = ['Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio', 'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre'];
            const nombreMes = meses[informe.mes - 1];
            const nombreArchivo = `Informe_${informe.agente}_${nombreMes}_${informe.anio}.html`;
            
            const blob = new Blob([informe.documento_html], { type: 'text/html' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = nombreArchivo;
            a.click();
            URL.revokeObjectURL(url);
            
            console.log(`✅ Informe descargado: ${nombreArchivo}`);
        } catch (error) {
            console.error('❌ Error:', error);
            alert('Error al descargar: ' + error.message);
        }
    }

    // ======================================================
    // Exportar todos los informes a CSV
    // ======================================================
