// ======================================================
// FUNCIÓN CORREGIDA - cargarGestionPersonasGP
// ======================================================
async function cargarGestionPersonasGP() {
    console.log('📊 Cargando Gestión de Personas...');
    
    const tbody = document.getElementById('tablaGestionPersonasGP');
    if (!tbody) return;
    
    tbody.innerHTML = '<tr><td colspan="10" style="text-align: center; padding: 40px;">⏳ Cargando gestores...</td></tr>';
    
    try {
        const evaluaciones = window.evaluacionesGlobales || [];
        if (evaluaciones.length === 0) {
            await cargarEvaluacionesDesdePostgreSQL();
        }
        
        await cargarDatosPDA();
        await cargarAgentes();
        
        const selectMes = document.getElementById('filtroMesGP');
        let mesFiltro = 'todos';
        if (selectMes) {
            mesFiltro = selectMes.value;
        }
        console.log(`📅 Mes filtrado en Gestión de Personas: ${mesFiltro}`);
        
        // 🔴 NUEVO: Función para recalcular promedio solo con evaluaciones del mes filtrado
        async function recalcularPromedioPorMes(evaluacionesAgente, mesFiltro) {
            if (!mesFiltro || mesFiltro === 'todos') return null;
            
            const [anioFiltro, mesFiltroNum] = mesFiltro.split('-');
            const anio = parseInt(anioFiltro);
            const mes = parseInt(mesFiltroNum);
            
            // Filtrar evaluaciones del mes
            const evalMes = evaluacionesAgente.filter(e => {
                const fecha = obtenerFechaEvaluacion(e);
                if (!fecha) return false;
                return fecha.getFullYear() === anio && (fecha.getMonth() + 1) === mes;
            });
            
            if (evalMes.length === 0) return null;
            
            // Calcular promedios
            const sumaNotas = evalMes.reduce((sum, e) => sum + (e.notaFinal || e.nota_final || 0), 0);
            const sumaENC = evalMes.reduce((sum, e) => sum + (e.totalENC || e.total_enc || 0), 0);
            const sumaECUF = evalMes.reduce((sum, e) => sum + (e.totalECUF || e.total_ecuf || 0), 0);
            const sumaECN = evalMes.reduce((sum, e) => sum + (e.totalECN || e.total_ecn || 0), 0);
            
            const promedio = sumaNotas / evalMes.length;
            
            // 🔴 🔴 🔴 DINÁMICO: Obtener criterios desde el sistema
            // Usar obtenerCriteriosCuartiles() que es async y lee desde BD o caché
            const criterios = await obtenerCriteriosCuartiles(false);
            
            // Determinar cuartil según el promedio usando los criterios dinámicos
            let cuartil = 'Q4';
            for (const c of criterios) {
                if (promedio >= c.limite_inferior && promedio <= c.limite_superior) {
                    cuartil = c.cuartil;
                    break;
                }
            }
            
            return {
                promedio: promedio.toFixed(1),
                promedioENC: (sumaENC / evalMes.length).toFixed(1),
                promedioECUF: (sumaECUF / evalMes.length).toFixed(1),
                promedioECN: (sumaECN / evalMes.length).toFixed(1),
                cuartil: cuartil,
                evaluaciones: evalMes.length,
                totalEvaluaciones: evalMes.length,
                sumaNotas: sumaNotas,
                sumaENC: sumaENC,
                sumaECUF: sumaECUF,
                sumaECN: sumaECN
            };
        }
        
        // 🔴 NUEVO: Obtener TODAS las evaluaciones (sin filtro de mes) para el ranking
        // El ranking se usa solo para obtener el cuartil global y la lista de agentes
        const ranking = await construirRankingAgentes(evaluaciones);
        
        const liderPorAgente = {};
        const ubicacionPorAgente = {};
        (window.agentesGlobales || []).forEach(agente => {
            liderPorAgente[agente.nombre] = agente.lider_2026 || 'Sin líder';
            ubicacionPorAgente[agente.nombre] = agente.ubicacion || 'Sin ubicación';
        });
        
        datosGestoresGP = [];
        
        for (const gestor of ranking) {
            const ciclos = await agruparEvaluacionesEnCiclos(gestor.agente);
            const ciclosCompletos = ciclos.filter(c => c.esCompleto);
            
            // Obtener TODAS las evaluaciones del agente (sin filtrar por mes)
            const todasEvaluacionesAgente = evaluaciones.filter(e => e.agente === gestor.agente);
            
            // 🔴 NUEVO: Recalcular promedio con el mes filtrado
            const promedioMes = await recalcularPromedioPorMes(todasEvaluacionesAgente, mesFiltro);
            
            // Si no tiene ciclos completos, usar datos del ranking
            if (ciclosCompletos.length === 0) {
                // Si hay filtro de mes y el agente tiene evaluaciones en ese mes, usar promedio del mes
                let promedioGlobal = gestor.promedio;
                let cuartilGlobal = gestor.cuartil;
                let encGlobal = gestor.promedioENC;
                let ecufGlobal = gestor.promedioECUF;
                let ecnGlobal = gestor.promedioECN;
                let totalEvals = 0;
                
                if (promedioMes && mesFiltro !== 'todos') {
                    promedioGlobal = parseFloat(promedioMes.promedio);
                    cuartilGlobal = promedioMes.cuartil;
                    encGlobal = parseFloat(promedioMes.promedioENC);
                    ecufGlobal = parseFloat(promedioMes.promedioECUF);
                    ecnGlobal = parseFloat(promedioMes.promedioECN);
                    totalEvals = promedioMes.totalEvaluaciones;
                }
                
                datosGestoresGP.push({
                    id: gestor.agente,
                    lider: liderPorAgente[gestor.agente] || 'Sin líder',
                    ubicacion: ubicacionPorAgente[gestor.agente] || 'Sin ubicación',
                    nombre: gestor.agente,
                    promedioGlobal: promedioGlobal.toFixed(1),
                    cuartilGlobal: cuartilGlobal,
                    encGlobal: encGlobal.toFixed(1),
                    ecufGlobal: ecufGlobal.toFixed(1),
                    ecnGlobal: ecnGlobal.toFixed(1),
                    totalErrores: 0,
                    reincidencia: 0,
                    tendencia: { icono: '➡️', texto: 'Sin ciclos', color: '#6c757d', valor: 0 },
                    ciclos: [],
                    totalCiclos: 0,
                    // 🔴 NUEVO: Guardar información del mes filtrado para depuración
                    _debug: {
                        mesFiltro: mesFiltro,
                        evaluacionesMes: promedioMes ? promedioMes.totalEvaluaciones : 0,
                        promedioMes: promedioMes ? promedioMes.promedio : null
                    }
                });
                
            }
            
            // Código original para gestores CON ciclos
            let sumaPromedios = 0;
            let sumaENC = 0, sumaECUF = 0, sumaECN = 0;
            let totalErrores = 0;
            const erroresPorCiclo = {};
            
            for (const ciclo of ciclosCompletos) {
                // 🔴 MODIFICADO: Usar TODAS las evaluaciones del ciclo (sin filtrar por mes)
                // porque el filtro de mes se aplica al promedio final
                const evalCiclo = ciclo.evaluaciones;
                
                if (evalCiclo.length === 0) continue;
                
                sumaPromedios += ciclo.promedio;
                sumaENC += ciclo.promedioENC;
                sumaECUF += ciclo.promedioECUF;
                sumaECN += ciclo.promedioECN;
                
                let erroresCiclo = 0;
                for (const evalItem of evalCiclo) {
                    if (evalItem.detalles) {
                        for (const detalle of evalItem.detalles) {
                            const cumple = detalle.cumple === true || detalle.cumple === 1 || detalle.cumple === 'true';
                            if (!cumple) erroresCiclo++;
                        }
                    }
                }
                totalErrores += erroresCiclo;
                
                const erroresUnicos = new Set();
                for (const evalItem of evalCiclo) {
                    if (evalItem.detalles) {
                        for (const detalle of evalItem.detalles) {
                            const cumple = detalle.cumple === true || detalle.cumple === 1 || detalle.cumple === 'true';
                            if (!cumple && detalle.submotivo) {
                                erroresUnicos.add(detalle.submotivo);
                            }
                        }
                    }
                }
                erroresPorCiclo[ciclo.numero] = erroresUnicos;
            }
            
            const todosErrores = {};
            for (const [cicloNum, erroresSet] of Object.entries(erroresPorCiclo)) {
                for (const error of erroresSet) {
                    todosErrores[error] = (todosErrores[error] || 0) + 1;
                }
            }
            const erroresReincidentes = Object.values(todosErrores).filter(count => count >= 2).length;
            const totalTiposErrores = Object.keys(todosErrores).length;
            const reincidencia = totalTiposErrores > 0 ? Math.round((erroresReincidentes / totalTiposErrores) * 100) : 0;
            
            const ultimoCiclo = ciclosCompletos[ciclosCompletos.length - 1];
            const primerCiclo = ciclosCompletos[0];
            const tendenciaValor = ultimoCiclo.promedio - primerCiclo.promedio;
            let tendencia = { icono: '➡️', texto: 'Estable', color: '#6c757d', valor: 0 };
            if (tendenciaValor > 2) {
                tendencia = { icono: '📈', texto: `+${tendenciaValor.toFixed(1)}%`, color: '#28a745', valor: tendenciaValor };
            } else if (tendenciaValor < -2) {
                tendencia = { icono: '📉', texto: `${tendenciaValor.toFixed(1)}%`, color: '#d93025', valor: tendenciaValor };
            }
            
            const totalCiclos = ciclosCompletos.length;
            
            // 🔴 NUEVO: Si hay filtro de mes, recalcular promedios SOLO con evaluaciones del mes
            let promedioGlobal, promedioENC, promedioECUF, promedioECN;
            let cuartilGlobal;
            let totalEvals = 0;
            
            if (promedioMes && mesFiltro !== 'todos') {
                // Usar promedio del mes filtrado
                promedioGlobal = parseFloat(promedioMes.promedio);
                promedioENC = parseFloat(promedioMes.promedioENC);
                promedioECUF = parseFloat(promedioMes.promedioECUF);
                promedioECN = parseFloat(promedioMes.promedioECN);
                cuartilGlobal = promedioMes.cuartil;
                totalEvals = promedioMes.totalEvaluaciones;
                console.log(`📊 ${gestor.agente}: Usando promedio del mes ${mesFiltro} = ${promedioGlobal}% (${totalEvals} eval)`);
            } else {
                // Sin filtro, usar promedio de todos los ciclos
                promedioGlobal = sumaPromedios / totalCiclos;
                promedioENC = sumaENC / totalCiclos;
                promedioECUF = sumaECUF / totalCiclos;
                promedioECN = sumaECN / totalCiclos;
                cuartilGlobal = gestor.cuartil;
                totalEvals = todasEvaluacionesAgente.length;
            }
            
            datosGestoresGP.push({
                id: gestor.agente,
                lider: liderPorAgente[gestor.agente] || 'Sin líder',
                ubicacion: ubicacionPorAgente[gestor.agente] || 'Sin ubicación',
                nombre: gestor.agente,
                promedioGlobal: promedioGlobal.toFixed(1),
                cuartilGlobal: cuartilGlobal,
                encGlobal: promedioENC.toFixed(1),
                ecufGlobal: promedioECUF.toFixed(1),
                ecnGlobal: promedioECN.toFixed(1),
                totalErrores: totalErrores,
                reincidencia: reincidencia,
                tendencia: tendencia,
                ciclos: ciclosCompletos,
                totalCiclos: totalCiclos,
                // 🔴 NUEVO: Guardar información del mes filtrado para depuración
                _debug: {
                    mesFiltro: mesFiltro,
                    evaluacionesMes: promedioMes ? promedioMes.totalEvaluaciones : 0,
                    promedioMes: promedioMes ? promedioMes.promedio : null,
                    totalEvaluacionesHistoricas: todasEvaluacionesAgente.length
                }
            });
        }
        
        if (typeof cargarFiltrosGestionPersonasGP === 'function') {
            await cargarFiltrosGestionPersonasGP();
        }
        
        if (typeof aplicarFiltrosGestionPersonasGP === 'function') {
            aplicarFiltrosGestionPersonasGP();
        }
        
        console.log(`✅ Gestión de Personas cargada: ${datosGestoresGP.length} gestores`);
        
        // 🔴 NUEVO: Mostrar resumen de cuántos agentes están en Q4 según el mes filtrado
        const q4Count = datosGestoresGP.filter(g => g.cuartilGlobal === 'Q4').length;
        console.log(`📊 Agentes en Q4 (${mesFiltro === 'todos' ? 'todos los períodos' : mesFiltro}): ${q4Count}`);
        
    } catch (error) {
        console.error('Error cargando Gestión de Personas:', error);
        tbody.innerHTML = `<tr><td colspan="10" style="text-align: center; color: var(--danger); padding: 40px;">❌ Error: ${error.message}</td></tr>`;
    }
}

// ======================================================
// RECALCULAR PROMEDIO POR MES FILTRADO
// ======================================================
function recalcularPromedioPorMes(evaluaciones, mesFiltro) {
    if (!mesFiltro || mesFiltro === 'todos') return null;
    
    const [anioFiltro, mesFiltroNum] = mesFiltro.split('-');
    const anio = parseInt(anioFiltro);
    const mes = parseInt(mesFiltroNum);
    
    // Filtrar evaluaciones del mes
    const evalMes = evaluaciones.filter(e => {
        const fecha = obtenerFechaEvaluacion(e);
        if (!fecha) return false;
        return fecha.getFullYear() === anio && (fecha.getMonth() + 1) === mes;
    });
    
    if (evalMes.length === 0) return null;
    
    // Calcular promedios
    const sumaNotas = evalMes.reduce((sum, e) => sum + (e.notaFinal || 0), 0);
    const sumaENC = evalMes.reduce((sum, e) => sum + (e.totalENC || 0), 0);
    const sumaECUF = evalMes.reduce((sum, e) => sum + (e.totalECUF || 0), 0);
    const sumaECN = evalMes.reduce((sum, e) => sum + (e.totalECN || 0), 0);
    
    return {
        promedio: (sumaNotas / evalMes.length).toFixed(1),
        promedioENC: (sumaENC / evalMes.length).toFixed(1),
        promedioECUF: (sumaECUF / evalMes.length).toFixed(1),
        promedioECN: (sumaECN / evalMes.length).toFixed(1),
        evaluaciones: evalMes.length,
        totalEvaluaciones: evalMes.length
    };
}

// ======================================================
// Cargar opciones de filtros
// ======================================================
async function cargarFiltrosGestionPersonasGP() {
    // Cargar líderes
    const lideresSet = new Set();
    const ubicacionesSet = new Set();
    
    datosGestoresGP.forEach(g => {
        if (g.lider && g.lider !== 'Sin líder') lideresSet.add(g.lider);
        if (g.ubicacion && g.ubicacion !== 'Sin ubicación') ubicacionesSet.add(g.ubicacion);
    });
    
    const lideres = Array.from(lideresSet).sort();
    const ubicaciones = Array.from(ubicacionesSet).sort();
    
    const selectLider = document.getElementById('filtroLiderGP');
    if (selectLider) {
        const valorActual = selectLider.value;
        selectLider.innerHTML = '<option value="todos">Todos los líderes</option>';
        lideres.forEach(lider => {
            selectLider.innerHTML += `<option value="${escapeHtml(lider)}">${escapeHtml(lider)}</option>`;
        });
        if (valorActual !== 'todos' && lideres.includes(valorActual)) selectLider.value = valorActual;
    }
    
    const selectUbicacion = document.getElementById('filtroUbicacionGP');
    if (selectUbicacion) {
        selectUbicacion.innerHTML = '<option value="todos">Todas las ubicaciones</option>';
        ubicaciones.forEach(ubic => {
            selectUbicacion.innerHTML += `<option value="${escapeHtml(ubic)}">${escapeHtml(ubic)}</option>`;
        });
    }
    
    // 🔴 NUEVO: Cargar meses disponibles
    await cargarMesesDisponiblesGP();
}

async function cargarMesesDisponiblesGP() {
    const selectMes = document.getElementById('filtroMesGP');
    if (!selectMes) return;
    
    const evaluaciones = window.evaluacionesGlobales || [];
    if (evaluaciones.length === 0) {
        selectMes.innerHTML = '<option value="todos">Todos los períodos</option><option disabled>⚠️ Cargue evaluaciones</option>';
        return;
    }
    
    const mesesSet = new Set();
    
    for (const e of evaluaciones) {
        let fechaStr = e.fechaOriginal || e.fecha || '';
        if (fechaStr) {
            let fechaParte = fechaStr;
            if (fechaStr.includes(' ')) fechaParte = fechaStr.split(' ')[0];
            if (fechaStr.includes('T')) fechaParte = fechaStr.split('T')[0];
            
            const partes = fechaParte.split('/');
            if (partes.length === 3) {
                const anio = partes[2];
                const mes = partes[1];
                if (anio && anio.match(/^\d{4}$/) && mes && mes.match(/^\d{1,2}$/)) {
                    mesesSet.add(`${anio}-${mes.padStart(2, '0')}`);
                }
            } else {
                const partesISO = fechaParte.split('-');
                if (partesISO.length === 3) {
                    const anio = partesISO[0];
                    const mes = partesISO[1];
                    if (anio && anio.match(/^\d{4}$/) && mes && mes.match(/^\d{1,2}$/)) {
                        mesesSet.add(`${anio}-${mes.padStart(2, '0')}`);
                    }
                }
            }
        }
    }
    
    const meses = Array.from(mesesSet).sort();
    const mesesNombres = ['Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio', 'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre'];
    
    const valorActual = selectMes.value;
    selectMes.innerHTML = '<option value="todos">📅 Todos los períodos</option>';
    
    for (const mes of meses) {
        const [anio, mesNum] = mes.split('-');
        const nombreMes = mesesNombres[parseInt(mesNum) - 1];
        selectMes.innerHTML += `<option value="${mes}" ${valorActual === mes ? 'selected' : ''}>${nombreMes} ${anio}</option>`;
    }
    
    console.log(`✅ ${meses.length} meses cargados para el filtro`);
}

// ======================================================
// Aplicar filtros (incluyendo mes)
// ======================================================
function aplicarFiltrosGestionPersonasGP() {
    const filtroMes = document.getElementById('filtroMesGP')?.value || 'todos';
    const filtroLider = document.getElementById('filtroLiderGP')?.value || 'todos';
    const filtroUbicacion = document.getElementById('filtroUbicacionGP')?.value || 'todos';
    const filtroCuartil = document.getElementById('filtroCuartilGP')?.value || 'todos';
    const busqueda = document.getElementById('buscarGestorGP')?.value.toLowerCase() || '';
    
    mesFiltroGP = filtroMes;
    
    gestoresFiltradosGP = datosGestoresGP.filter(gestor => {
        // Filtro por mes (basado en los ciclos del gestor)
        if (filtroMes !== 'todos') {
            const [anioFiltro, mesFiltroNum] = filtroMes.split('-');
            const mesFiltro = mesFiltroNum.padStart(2, '0');
            
            // Verificar si el gestor tiene algún ciclo que termine en el mes seleccionado
            const tieneCicloEnMes = gestor.ciclos.some(ciclo => {
                if (ciclo.fechaFin && ciclo.fechaFin !== 'N/A') {
                    const partes = ciclo.fechaFin.split('/');
                    if (partes.length === 3) {
                        const anioCiclo = partes[2];
                        const mesCiclo = partes[1].padStart(2, '0');
                        return anioCiclo === anioFiltro && mesCiclo === mesFiltro;
                    }
                }
                return false;
            });
            if (!tieneCicloEnMes) return false;
        }
        
        if (filtroLider !== 'todos' && gestor.lider !== filtroLider) return false;
        if (filtroUbicacion !== 'todos' && gestor.ubicacion !== filtroUbicacion) return false;
        if (filtroCuartil !== 'todos' && gestor.cuartilGlobal !== filtroCuartil) return false;
        if (busqueda && !gestor.nombre.toLowerCase().includes(busqueda)) return false;
        return true;
    });
    
    // Actualizar el contador de resultados
    const totalResultados = gestoresFiltradosGP.length;
    const infoFiltro = document.getElementById('infoFiltroGP');
    if (infoFiltro) {
        const selectMes = document.getElementById('filtroMesGP');
        const nombreMes = selectMes?.options[selectMes.selectedIndex]?.text || 'todos';
        if (filtroMes !== 'todos') {
            infoFiltro.innerHTML = `<span style="background: #e3f2fd; padding: 4px 12px; border-radius: 20px; font-size: 12px;">📅 ${nombreMes} | ${totalResultados} gestor(es)</span>`;
        } else {
            infoFiltro.innerHTML = `<span style="background: #e3f2fd; padding: 4px 12px; border-radius: 20px; font-size: 12px;">📅 Todos los períodos | ${totalResultados} gestor(es)</span>`;
        }
    }
    
    paginaActualGP = 1;
    actualizarTablaGestionPersonasGP();
    actualizarPaginacionGP();
}

// ======================================================
// Actualizar tabla Nivel 0
// ======================================================
function actualizarTablaGestionPersonasGP() {
    const tbody = document.getElementById('tablaGestionPersonasGP');
    if (!tbody) return;
    
    const inicio = (paginaActualGP - 1) * registrosPorPaginaGP;
    const fin = inicio + registrosPorPaginaGP;
    const paginaGestores = gestoresFiltradosGP.slice(inicio, fin);
    
    if (paginaGestores.length === 0) {
        tbody.innerHTML = '<tr><td colspan="10" style="text-align: center; padding: 40px;">📭 No hay gestores que coincidan con los filtros<\/td><\/tr>';
        return;
    }
    
    let html = '';
    
    // 🔴 Obtener criterios para colores de cuartiles
    const criterios = obtenerCriteriosPorDefecto();
    const cuartilColors = {};
    criterios.forEach(c => {
        cuartilColors[c.cuartil] = c.color_hex;
    });
    const cuartilIcons = {};
    criterios.forEach(c => {
        cuartilIcons[c.cuartil] = c.icono || '📊';
    });
    
    for (const gestor of paginaGestores) {
        const estaExpandido = gestoresExpandidosGP.has(gestor.id);
        const expandIcon = estaExpandido ? '▼' : '▶';
        
        // 🔴 Usar colores dinámicos
        const cuartilColor = cuartilColors[gestor.cuartilGlobal] || '#6c757d';
        const cuartilIcono = cuartilIcons[gestor.cuartilGlobal] || '📊';
        
        let cuartilHtml = `<span style="background: ${cuartilColor}; color: white; padding: 4px 10px; border-radius: 20px; font-size: 12px;">${cuartilIcono} ${gestor.cuartilGlobal}</span>`;
        
        // Barras de progreso
        const pctENC = Math.min(100, gestor.encGlobal);
        const pctECUF = Math.min(100, gestor.ecufGlobal);
        const pctECN = Math.min(100, gestor.ecnGlobal);
        
        const encColor = pctENC >= 90 ? '#28a745' : (pctENC >= 85 ? '#f39c12' : '#d93025');
        const ecufColor = pctECUF >= 90 ? '#28a745' : (pctECUF >= 85 ? '#f39c12' : '#d93025');
        const ecnColor = pctECN >= 90 ? '#28a745' : (pctECN >= 85 ? '#f39c12' : '#d93025');
        
        let reincidenciaColor = '#28a745';
        if (gestor.reincidencia > 50) reincidenciaColor = '#d93025';
        else if (gestor.reincidencia > 25) reincidenciaColor = '#f39c12';
        
        html += `
            <tr id="fila-gestor-${gestor.id.replace(/\s/g, '_')}" style="border-bottom: 1px solid #e0e0e0;">
                <td style="padding: 12px; text-align: center;">
                    <span class="expand-icon" onclick="toggleExpandirGestorGP('${escapeHtml(gestor.id)}')" style="cursor: pointer;">${expandIcon}</span>
                </td>
                <td style="padding: 12px;"><strong>${escapeHtml(gestor.nombre)}</strong></td>
                <td style="padding: 12px; text-align: center; font-weight: bold;">${gestor.promedioGlobal}%</td>
                <td style="padding: 12px; text-align: center;">${cuartilHtml}</td>
                <td style="padding: 12px;">
                    ${gestor.encGlobal}%
                    <div class="barra-progreso-gp" style="margin-top: 4px; width: 80px;">
                        <div class="barra-progreso-fill-gp" style="width: ${pctENC}%; background: ${encColor};"></div>
                    </div>
                </td>
                <td style="padding: 12px;">
                    ${gestor.ecufGlobal}%
                    <div class="barra-progreso-gp" style="margin-top: 4px; width: 80px;">
                        <div class="barra-progreso-fill-gp" style="width: ${pctECUF}%; background: ${ecufColor};"></div>
                    </div>
                </td>
                <td style="padding: 12px;">
                    ${gestor.ecnGlobal}%
                    <div class="barra-progreso-gp" style="margin-top: 4px; width: 80px;">
                        <div class="barra-progreso-fill-gp" style="width: ${pctECN}%; background: ${ecnColor};"></div>
                    </div>
                </td>
                <td style="padding: 12px; text-align: center; font-weight: bold; color: var(--danger);">${gestor.totalErrores}</td>
                <td style="padding: 12px; text-align: center; color: ${reincidenciaColor}; font-weight: bold;">${gestor.reincidencia}%</td>
                <td style="padding: 12px;"><span style="color: ${gestor.tendencia.color};">${gestor.tendencia.icono} ${gestor.tendencia.texto}</span></td>
            </tr>
        `;
        
        if (estaExpandido && gestor.ciclos && gestor.ciclos.length > 0) {
            html += generarNivel1CiclosHistoricosGP(gestor);
        }
    }
    
    tbody.innerHTML = html;
    
    document.getElementById('gpTotal').textContent = gestoresFiltradosGP.length;
    const desde = (paginaActualGP - 1) * registrosPorPaginaGP + 1;
    const hasta = Math.min(paginaActualGP * registrosPorPaginaGP, gestoresFiltradosGP.length);
    document.getElementById('gpDesde').textContent = desde;
    document.getElementById('gpHasta').textContent = hasta;
}

// ======================================================
// NIVEL 1: Generar tabla de ciclos históricos (CON FILTRO POR MES)
// ======================================================
function generarNivel1CiclosHistoricosGP(gestor) {
    const filtroMes = document.getElementById('filtroMesGP')?.value || 'todos';
    const selectMes = document.getElementById('filtroMesGP');
    const nombreMesFiltro = selectMes?.options[selectMes.selectedIndex]?.text || 'Todos los períodos';
    
    let ciclosMostrar = [...gestor.ciclos].sort((a, b) => b.numero - a.numero);
    
    if (filtroMes !== 'todos') {
        const [anioFiltro, mesFiltro] = filtroMes.split('-');
        ciclosMostrar = ciclosMostrar.filter(ciclo => {
            if (ciclo.fechaFin && ciclo.fechaFin !== 'N/A') {
                const partes = ciclo.fechaFin.split('/');
                if (partes.length === 3) {
                    const anioCiclo = partes[2];
                    const mesCiclo = partes[1];
                    return anioCiclo === anioFiltro && mesCiclo === mesFiltro;
                }
            }
            return false;
        });
    }
    
    if (ciclosMostrar.length === 0) {
        return `
            <tr class="fila-gestor-expandida-gp">
                <td colspan="10" style="padding: 0;">
                    <div style="padding: 30px; text-align: center; background: #f8f9fa;">
                        📭 No hay ciclos completos en el período seleccionado (${nombreMesFiltro})
                    </div>
                </td>
            </tr>
        `;
    }
    
    // 🔴 Obtener criterios para colores de cuartiles
    const criterios = obtenerCriteriosPorDefecto();
    const cuartilColors = {};
    const cuartilIcons = {};
    criterios.forEach(c => {
        cuartilColors[c.cuartil] = c.color_hex;
        cuartilIcons[c.cuartil] = c.icono || '📊';
    });
    
    let sumaPromedios = 0;
    let totalErroresFiltrado = 0;
    let sumaENC = 0, sumaECUF = 0, sumaECN = 0;
    
    for (const ciclo of ciclosMostrar) {
        sumaPromedios += ciclo.promedio;
        sumaENC += ciclo.promedioENC;
        sumaECUF += ciclo.promedioECUF;
        sumaECN += ciclo.promedioECN;
        
        for (const evalItem of ciclo.evaluaciones) {
            if (evalItem.detalles) {
                for (const detalle of evalItem.detalles) {
                    const cumple = detalle.cumple === true || detalle.cumple === 1 || detalle.cumple === 'true';
                    if (!cumple) totalErroresFiltrado++;
                }
            }
        }
    }
    
    const totalCiclosMostrados = ciclosMostrar.length;
    const promedioGlobalFiltrado = totalCiclosMostrados > 0 ? (sumaPromedios / totalCiclosMostrados).toFixed(1) : 0;
    const promedioENCFiltrado = totalCiclosMostrados > 0 ? (sumaENC / totalCiclosMostrados).toFixed(1) : 0;
    const promedioECUFFiltrado = totalCiclosMostrados > 0 ? (sumaECUF / totalCiclosMostrados).toFixed(1) : 0;
    const promedioECNFiltrado = totalCiclosMostrados > 0 ? (sumaECN / totalCiclosMostrados).toFixed(1) : 0;
    
    let html = `
        <tr class="fila-gestor-expandida-gp">
            <td colspan="10" style="padding: 0;">
                <div class="detalle-ciclos-gp" style="padding: 20px; background: #f8f9fa;">
                    <div style="margin-bottom: 15px; display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 10px;">
                        <div>
                            <strong>📋 HISTORIAL DE CICLOS COMPLETOS</strong>
                            <span style="margin-left: 15px; font-size: 12px; color: var(--muted);">
                                ${filtroMes !== 'todos' ? `Período: ${nombreMesFiltro}` : 'Todos los períodos'}
                            </span>
                        </div>
                        <div style="font-size: 12px; background: white; padding: 6px 12px; border-radius: 20px;">
                            📊 ${totalCiclosMostrados} ciclo(s) | Promedio: ${promedioGlobalFiltrado}% | Errores: ${totalErroresFiltrado}
                        </div>
                    </div>
                    
                    <div style="margin-bottom: 15px; display: flex; gap: 20px; flex-wrap: wrap; font-size: 12px; background: white; padding: 10px 15px; border-radius: 10px;">
                        <div><strong>🎯 ENC:</strong> ${promedioENCFiltrado}%</div>
                        <div><strong>⚠️ ECUF:</strong> ${promedioECUFFiltrado}%</div>
                        <div><strong>💰 ECN:</strong> ${promedioECNFiltrado}%</div>
                    </div>
                    
                    <div class="table-container" style="max-height: 400px; overflow-y: auto;">
                        <table style="width: 100%; font-size: 12px; border-collapse: collapse;">
                            <thead>
                                <tr style="background: #e9ecef; position: sticky; top: 0;">
                                    <th style="padding: 10px;">Ciclo</th>
                                    <th style="padding: 10px;">Período</th>
                                    <th style="padding: 10px;">Promedio</th>
                                    <th style="padding: 10px;">Cuartil</th>
                                    <th style="padding: 10px;">ENC</th>
                                    <th style="padding: 10px;">ECUF</th>
                                    <th style="padding: 10px;">ECN</th>
                                    <th style="padding: 10px;">#Errores</th>
                                    <th style="padding: 10px;">Acción</th>
                                 </tr>
                            </thead>
                            <tbody>
    `;
    
    for (const ciclo of ciclosMostrar) {
        // 🔴 Usar colores dinámicos
        const cuartilColor = cuartilColors[ciclo.cuartil] || '#6c757d';
        const cuartilIcono = cuartilIcons[ciclo.cuartil] || '📊';
        
        let erroresCiclo = 0;
        for (const evalItem of ciclo.evaluaciones) {
            if (evalItem.detalles) {
                for (const detalle of evalItem.detalles) {
                    const cumple = detalle.cumple === true || detalle.cumple === 1 || detalle.cumple === 'true';
                    if (!cumple) erroresCiclo++;
                }
            }
        }
        
        const promedioColor = ciclo.promedio >= 90 ? '#28a745' : (ciclo.promedio >= 85 ? '#f39c12' : '#d93025');
        
        html += `
            <tr style="border-bottom: 1px solid #e0e0e0;">
                <td style="padding: 10px; text-align: center;"><strong>#${ciclo.numero}</strong></td>
                <td style="padding: 10px; white-space: nowrap;">${ciclo.fechaInicio} → ${ciclo.fechaFin}</td>
                <td style="padding: 10px; text-align: center; color: ${promedioColor}; font-weight: bold;">${ciclo.promedio}%</td>
                <td style="padding: 10px; text-align: center;">
                    <span style="background: ${cuartilColor}; color: white; padding: 4px 10px; border-radius: 20px; font-size: 11px;">${cuartilIcono} ${ciclo.cuartil}</span>
                </td>
                <td style="padding: 10px; text-align: center;">${ciclo.promedioENC}%</td>
                <td style="padding: 10px; text-align: center;">${ciclo.promedioECUF}%</td>
                <td style="padding: 10px; text-align: center;">${ciclo.promedioECN}%</td>
                <td style="padding: 10px; text-align: center; color: ${erroresCiclo > 0 ? '#d93025' : '#28a745'}; font-weight: bold;">${erroresCiclo}</td>
                <td style="padding: 10px; text-align: center;">
                    <button onclick="verDetalleCicloGP('${escapeHtml(gestor.id)}', ${ciclo.numero})" 
                            style="background: var(--accent); padding: 4px 10px; font-size: 11px; border-radius: 6px; border: none; cursor: pointer;">
                        🔍 Ver detalles
                    </button>
                </td>
            </tr>
        `;
    }
    
    html += `
                            </tbody>
                        </table>
                    </div>
                    ${generarResumenErroresFrecuentesGP(ciclosMostrar, filtroMes !== 'todos' ? nombreMesFiltro : null)}
                </div>
            </td>
        </tr>
    `;
    
    return html;
}

// ======================================================
// Generar resumen de errores frecuentes en el período
// ======================================================
function generarResumenErroresFrecuentesGP(ciclos, nombrePeriodo) {
    // Agrupar errores de todos los ciclos mostrados
    const erroresAgrupados = {};
    
    for (const ciclo of ciclos) {
        for (const evalItem of ciclo.evaluaciones) {
            if (evalItem.detalles) {
                for (const detalle of evalItem.detalles) {
                    const cumple = detalle.cumple === true || detalle.cumple === 1 || detalle.cumple === 'true';
                    if (!cumple && detalle.submotivo) {
                        const key = detalle.submotivo;
                        if (!erroresAgrupados[key]) {
                            erroresAgrupados[key] = {
                                submotivo: detalle.submotivo,
                                bloque: detalle.bloque || '',
                                ocurrencias: 0,
                                ciclosAfectados: new Set()
                            };
                        }
                        erroresAgrupados[key].ocurrencias++;
                        erroresAgrupados[key].ciclosAfectados.add(ciclo.numero);
                    }
                }
            }
        }
    }
    
    const erroresList = Object.values(erroresAgrupados)
        .sort((a, b) => b.ocurrencias - a.ocurrencias)
        .slice(0, 5); // Top 5 errores
    
    if (erroresList.length === 0) {
        return `
            <div style="margin-top: 15px; padding: 10px; background: #e8f5e9; border-radius: 8px; text-align: center;">
                ✅ No se detectaron errores en ${nombrePeriodo ? 'el período ' + nombrePeriodo : 'los ciclos mostrados'}
            </div>
        `;
    }
    
    return `
        <div style="margin-top: 15px; padding: 12px; background: white; border-radius: 10px;">
            <div style="font-weight: bold; margin-bottom: 10px;">🔥 Errores más frecuentes ${nombrePeriodo ? `en ${nombrePeriodo}` : 'en el historial'}:</div>
            <div style="display: flex; flex-direction: column; gap: 8px;">
                ${erroresList.map(e => `
                    <div style="display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; padding: 6px 0; border-bottom: 1px solid #e0e0e0;">
                        <div>
                            <span style="font-weight: bold;">❌ ${escapeHtml(e.submotivo)}</span>
                            <span style="font-size: 11px; color: var(--muted); margin-left: 10px;">(${escapeHtml(e.bloque)})</span>
                        </div>
                        <div>
                            <span style="background: #f39c12; color: white; padding: 2px 8px; border-radius: 12px; font-size: 11px;">
                                ${e.ocurrencias} vez/veces
                            </span>
                            <span style="font-size: 11px; color: var(--muted); margin-left: 8px;">
                                en ciclos: ${Array.from(e.ciclosAfectados).sort((a,b) => a-b).join(', ')}
                            </span>
                        </div>
                    </div>
                `).join('')}
            </div>
        </div>
    `;
}

// ======================================================
// NIVEL 2: Ver detalle completo de un ciclo (modal)
// ======================================================
async function verDetalleCicloGP(gestorNombre, cicloNumero) {
    console.log(`🔍 Abriendo detalle del ciclo #${cicloNumero} para: ${gestorNombre}`);
    
    // Obtener los ciclos del gestor
    const gestorData = datosGestoresGP.find(g => g.id === gestorNombre);
    if (!gestorData) {
        alert('No se encontró el gestor');
        return;
    }
    
    const ciclo = gestorData.ciclos.find(c => c.numero === cicloNumero);
    if (!ciclo) {
        alert(`No se encontró el ciclo #${cicloNumero}`);
        return;
    }
    
    cicloActualDetalleGP = {
        gestor: gestorNombre,
        ciclo: ciclo,
        cicloNumero: cicloNumero
    };
    
    // Configurar modal
    const modal = document.getElementById('modalDetalleCicloGP');
    const subtitle = document.getElementById('modalDetalleCicloSubtitleGP');
    
    let cuartilTexto = '';
    switch (ciclo.cuartil) {
        case 'Q1': cuartilTexto = '🏆 Q1'; break;
        case 'Q2': cuartilTexto = '📈 Q2'; break;
        case 'Q3': cuartilTexto = '⚠️ Q3'; break;
        case 'Q4': cuartilTexto = '🔴 Q4'; break;
    }
    
    subtitle.innerHTML = `${escapeHtml(gestorNombre)} | Ciclo #${cicloNumero} | ${ciclo.fechaInicio} → ${ciclo.fechaFin} | Promedio: ${ciclo.promedio}% | ${cuartilTexto}`;
    
    modal.style.display = 'flex';
    
    // Cargar pestaña de evaluaciones por defecto
    mostrarTabDetalleCicloGP('evaluaciones');
}

// ======================================================
// Mostrar tabs del modal (Nivel 2)
// ======================================================
function mostrarTabDetalleCicloGP(tab) {
    if (!cicloActualDetalleGP) return;
    
    const ciclo = cicloActualDetalleGP.ciclo;
    const gestor = cicloActualDetalleGP.gestor;
    
    // Actualizar estilos de tabs
    const tabs = ['evaluaciones', 'errores', 'analisis'];
    tabs.forEach(t => {
        const btn = document.getElementById(`tab${t.charAt(0).toUpperCase() + t.slice(1)}BtnGP`);
        if (btn) {
            if (t === tab) {
                btn.classList.add('tab-active-gp');
                btn.classList.remove('tab-inactive-gp');
            } else {
                btn.classList.add('tab-inactive-gp');
                btn.classList.remove('tab-active-gp');
            }
        }
    });
    
    const contenido = document.getElementById('contenidoDetalleCicloGP');
    
    if (tab === 'evaluaciones') {
        contenido.innerHTML = generarTabEvaluacionesGP(ciclo);
    } else if (tab === 'errores') {
        contenido.innerHTML = generarTabErroresAgrupadosGP(ciclo);
    } else if (tab === 'analisis') {
        contenido.innerHTML = generarTabAnalisisGP(ciclo, gestor);
    }
}

// ======================================================
// TAB: Evaluaciones (con expandibles)
// ======================================================
function generarTabEvaluacionesGP(ciclo) {
    // 🔴 Obtener criterios para colores de cuartiles
    const criterios = obtenerCriteriosPorDefecto();
    const cuartilColors = {};
    const cuartilIcons = {};
    criterios.forEach(c => {
        cuartilColors[c.cuartil] = c.color_hex;
        cuartilIcons[c.cuartil] = c.icono || '📊';
    });
    
    let html = `
        <div style="max-height: 500px; overflow-y: auto;">
            <div style="margin-bottom: 15px;">
                <strong>📞 EVALUACIONES DEL CICLO #${ciclo.numero}</strong>
                <span style="margin-left: 10px; font-size: 12px; color: var(--muted);">${ciclo.evaluaciones.length} evaluaciones</span>
            </div>
    `;
    
    for (let i = 0; i < ciclo.evaluaciones.length; i++) {
        const evalItem = ciclo.evaluaciones[i];
        const fecha = evalItem.fechaOriginal || evalItem.fecha || 'Sin fecha';
        const nota = evalItem.notaFinal || 0;
        const notaColor = nota >= 85 ? '#28a745' : '#d93025';
        
        const errores = [];
        if (evalItem.detalles) {
            for (const detalle of evalItem.detalles) {
                const cumple = detalle.cumple === true || detalle.cumple === 1 || detalle.cumple === 'true';
                if (!cumple && detalle.submotivo) {
                    errores.push({
                        submotivo: detalle.submotivo,
                        bloque: detalle.bloque || '',
                        atributo: detalle.atributo || '',
                        peso: detalle.peso || 0
                    });
                }
            }
        }
        
        html += `
            <div class="evaluacion-item-gp">
                <div class="evaluacion-header-gp" onclick="toggleEvaluacionGP(this)">
                    <div style="display: flex; gap: 20px; align-items: center; flex-wrap: wrap;">
                        <strong>📞 Evaluación #${i + 1}</strong>
                        <span>📅 ${fecha}</span>
                        <span>📊 Nota: <strong style="color: ${notaColor};">${nota}%</strong></span>
                        <span class="badge" style="background: ${errores.length > 0 ? '#d93025' : '#28a745'}">
                            ${errores.length} errores
                        </span>
                    </div>
                    <span class="expand-icon">▼</span>
                </div>
                <div class="evaluacion-contenido-gp" style="display: none;">
                    ${errores.length > 0 ? `
                        <div style="margin-bottom: 10px;"><strong>❌ Errores detectados:</strong></div>
                        ${errores.map(e => `
                            <div class="error-item-gp">
                                <strong>${escapeHtml(e.submotivo)}</strong><br>
                                <span style="font-size: 11px; color: var(--muted);">
                                    📂 ${escapeHtml(e.bloque)} / ${escapeHtml(e.atributo)} | ⚖️ Peso: ${e.peso}%
                                </span>
                            </div>
                        `).join('')}
                    ` : '<div style="color: #28a745;">✅ Sin errores en esta evaluación</div>'}
                </div>
            </div>
        `;
    }
    
    html += `</div>`;
    return html;
}

// ======================================================
// TAB: Errores Agrupados
// ======================================================
function generarTabErroresAgrupadosGP(ciclo) {
    // Agrupar errores por submotivo
    const erroresAgrupados = {};
    
    for (const evalItem of ciclo.evaluaciones) {
        if (evalItem.detalles) {
            for (const detalle of evalItem.detalles) {
                const cumple = detalle.cumple === true || detalle.cumple === 1 || detalle.cumple === 'true';
                if (!cumple && detalle.submotivo) {
                    const key = detalle.submotivo;
                    if (!erroresAgrupados[key]) {
                        erroresAgrupados[key] = {
                            submotivo: detalle.submotivo,
                            bloque: detalle.bloque || '',
                            atributo: detalle.atributo || '',
                            peso: detalle.peso || 0,
                            ocurrencias: 0,
                            evaluaciones: []
                        };
                    }
                    erroresAgrupados[key].ocurrencias++;
                    erroresAgrupados[key].evaluaciones.push(`#${erroresAgrupados[key].evaluaciones.length + 1}`);
                }
            }
        }
    }
    
    const erroresList = Object.values(erroresAgrupados).sort((a, b) => b.ocurrencias - a.ocurrencias);
    
    if (erroresList.length === 0) {
        return '<div style="text-align: center; padding: 40px; color: #28a745;">✅ No hay errores en este ciclo</div>';
    }
    
    let html = `
        <div class="scrollable-table" style="max-height: 500px; overflow-y: auto;">
            <table style="width: 100%; font-size: 13px; border-collapse: collapse;">
                <thead>
                    <tr style="background: #f8f9fa; position: sticky; top: 0;">
                        <th style="padding: 10px;">Submotivo</th>
                        <th style="padding: 10px;">Bloque</th>
                        <th style="padding: 10px;">Atributo</th>
                        <th style="padding: 10px;">Ocurrencias</th>
                        <th style="padding: 10px;">Peso</th>
                        <th style="padding: 10px;">Evaluaciones</th>
                    </tr>
                </thead>
                <tbody>
    `;
    
    for (const error of erroresList) {
        const ocurrenciasColor = error.ocurrencias > 3 ? '#d93025' : (error.ocurrencias > 1 ? '#f39c12' : '#6c757d');
        const evaluacionesUnicas = [...new Set(error.evaluaciones)];
        
        html += `
            <tr class="error-agrupado-row">
                <td style="padding: 10px;"><strong>❌ ${escapeHtml(error.submotivo)}</strong></td>
                <td style="padding: 10px;">${escapeHtml(error.bloque)}</td>
                <td style="padding: 10px;">${escapeHtml(error.atributo)}</td>
                <td style="padding: 10px; text-align: center; color: ${ocurrenciasColor}; font-weight: bold;">${error.ocurrencias}</td>
                <td style="padding: 10px; text-align: center;">${error.peso}%</td>
                <td style="padding: 10px;">${evaluacionesUnicas.join(', ')}</td>
            </tr>
        `;
    }
    
    html += `
                </tbody>
            </table>
        </div>
        <div style="margin-top: 15px; padding: 10px; background: #f8f9fa; border-radius: 8px; font-size: 12px;">
            📊 Total de errores: ${erroresList.reduce((sum, e) => sum + e.ocurrencias, 0)} | Tipos de error: ${erroresList.length}
        </div>
    `;
    
    return html;
}

// ======================================================
// TAB: Análisis del ciclo
// ======================================================
async function generarTabAnalisisGP(ciclo, gestor) {
    // Recolectar estadísticas
    let totalErrores = 0;
    let erroresPorBloque = { ENC: 0, ECUF: 0, ECN: 0 };
    const erroresPorSubmotivo = {};
    
    for (const evalItem of ciclo.evaluaciones) {
        if (evalItem.detalles) {
            for (const detalle of evalItem.detalles) {
                const cumple = detalle.cumple === true || detalle.cumple === 1 || detalle.cumple === 'true';
                if (!cumple && detalle.submotivo) {
                    totalErrores++;
                    erroresPorSubmotivo[detalle.submotivo] = (erroresPorSubmotivo[detalle.submotivo] || 0) + 1;
                    
                    const bloque = detalle.bloque || '';
                    if (bloque === 'ENC' || bloque === 'Cliente') erroresPorBloque.ENC++;
                    else if (bloque === 'ECUF' || bloque === 'Negocio') erroresPorBloque.ECUF++;
                    else erroresPorBloque.ECN++;
                }
            }
        }
    }
    
    const errorCritico = Object.entries(erroresPorSubmotivo).sort((a, b) => b[1] - a[1])[0];
    const bloqueMasAfectado = Object.entries(erroresPorBloque).sort((a, b) => b[1] - a[1])[0];
    
    // 🔴 CORREGIDO: Usar obtenerCriteriosPorDefecto() SÍNCRONO (sin await)
    const criterios = obtenerCriteriosPorDefecto();
    let resultadoCuartil = null;
    for (const c of criterios) {
        if (ciclo.promedio >= c.limite_inferior && ciclo.promedio <= c.limite_superior) {
            resultadoCuartil = c;
            break;
        }
    }
    if (!resultadoCuartil) resultadoCuartil = criterios[3];
    
    let recomendaciones = [];
    if (errorCritico) {
        recomendaciones.push(`⚠️ Error más crítico: "${errorCritico[0]}" (${errorCritico[1]} ocurrencias)`);
    }
    if (bloqueMasAfectado) {
        recomendaciones.push(`📂 Bloque más afectado: ${bloqueMasAfectado[0]} (${bloqueMasAfectado[1]} errores)`);
    }
    
    if (resultadoCuartil.cuartil === 'Q4') {
        recomendaciones.push(`🔴 Ciclo en Q4 (${resultadoCuartil.nombre}) - Requiere PDA inmediato`);
    } else if (ciclo.promedio < 85) {
        recomendaciones.push('⚠️ Promedio por debajo de 85% - Requiere seguimiento');
    } else if (ciclo.promedio >= 90) {
        recomendaciones.push('✅ Buen desempeño - Mantener estrategia actual');
    }
    
    let html = `
        <div style="max-height: 500px; overflow-y: auto;">
            <div class="grid-2" style="display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-bottom: 20px;">
                <div class="card" style="padding: 15px;">
                    <h4 style="margin-bottom: 10px;">📊 Estadísticas del Ciclo</h4>
                    <div><strong>Total evaluaciones:</strong> ${ciclo.evaluaciones.length}</div>
                    <div><strong>Total errores:</strong> <span style="color: var(--danger);">${totalErrores}</span></div>
                    <div><strong>Promedio general:</strong> ${ciclo.promedio}%</div>
                    <div><strong>Cuartil:</strong> ${resultadoCuartil.cuartil} (${resultadoCuartil.nombre})</div>
                </div>
                <div class="card" style="padding: 15px;">
                    <h4 style="margin-bottom: 10px;">📈 Desempeño por Bloque</h4>
                    <div><strong>🎯 ENC (Cliente):</strong> ${ciclo.promedioENC}%</div>
                    <div><strong>⚠️ ECUF (Negocio):</strong> ${ciclo.promedioECUF}%</div>
                    <div><strong>💰 ECN (Proceso):</strong> ${ciclo.promedioECN}%</div>
                </div>
            </div>
            
            <div class="card" style="padding: 15px; margin-bottom: 20px;">
                <h4 style="margin-bottom: 10px;">❌ Distribución de Errores por Bloque</h4>
                <div style="display: flex; gap: 20px; margin-top: 10px;">
                    <div><strong>🎯 ENC:</strong> ${erroresPorBloque.ENC} errores</div>
                    <div><strong>⚠️ ECUF:</strong> ${erroresPorBloque.ECUF} errores</div>
                    <div><strong>💰 ECN:</strong> ${erroresPorBloque.ECN} errores</div>
                </div>
                <div class="barra-progreso-gp" style="margin-top: 10px; height: 20px;">
                    <div style="display: flex; height: 100%; border-radius: 10px; overflow: hidden;">
                        <div style="width: ${(erroresPorBloque.ENC / totalErrores) * 100 || 0}%; background: #019DF4; text-align: center; color: white; font-size: 11px;">ENC</div>
                        <div style="width: ${(erroresPorBloque.ECUF / totalErrores) * 100 || 0}%; background: #7b1fa2; text-align: center; color: white; font-size: 11px;">ECUF</div>
                        <div style="width: ${(erroresPorBloque.ECN / totalErrores) * 100 || 0}%; background: #fd7e14; text-align: center; color: white; font-size: 11px;">ECN</div>
                    </div>
                </div>
            </div>
            
            <div class="card" style="padding: 15px; background: #e8f5e9;">
                <h4 style="margin-bottom: 10px;">💡 Recomendaciones</h4>
                <ul style="margin-left: 20px;">
                    ${recomendaciones.map(r => `<li>${r}</li>`).join('')}
                </ul>
                ${resultadoCuartil.cuartil === 'Q4' ? `
                    <div style="margin-top: 15px;">
                        <button onclick="cerrarModalDetalleCicloGP(); generarPDAConDocumento('${escapeHtml(gestor)}', ${ciclo.numero})" 
                                style="background: var(--warning); padding: 8px 16px; border: none; border-radius: 8px; cursor: pointer;">
                            📋 Generar PDA para este ciclo
                        </button>
                    </div>
                ` : ''}
            </div>
        </div>
    `;
    
    return html;
}

// ======================================================
// Funciones auxiliares
// ======================================================
function toggleExpandirGestorGP(gestorId) {
    if (gestoresExpandidosGP.has(gestorId)) {
        gestoresExpandidosGP.delete(gestorId);
    } else {
        gestoresExpandidosGP.add(gestorId);
    }
    actualizarTablaGestionPersonasGP();
}

function toggleEvaluacionGP(header) {
    const content = header.nextElementSibling;
    const icon = header.querySelector('.expand-icon');
    
    if (content.style.display === 'none' || !content.style.display) {
        content.style.display = 'block';
        if (icon) icon.innerHTML = '▲';
        header.classList.add('expanded');
    } else {
        content.style.display = 'none';
        if (icon) icon.innerHTML = '▼';
        header.classList.remove('expanded');
    }
}

function cerrarModalDetalleCicloGP() {
    document.getElementById('modalDetalleCicloGP').style.display = 'none';
    cicloActualDetalleGP = null;
}

function cerrarModalDetalleEvaluacionGP() {
    document.getElementById('modalDetalleEvaluacionGP').style.display = 'none';
    evaluacionActualDetalleGP = null;
}

function exportarDetalleCicloGP() {
    if (!cicloActualDetalleGP) return;
    
    const ciclo = cicloActualDetalleGP.ciclo;
    const gestor = cicloActualDetalleGP.gestor;
    
    const headers = ['Evaluación', 'Fecha', 'Nota', 'Submotivo', 'Bloque', 'Atributo', 'Peso (%)'];
    const rows = [];
    
    for (let i = 0; i < ciclo.evaluaciones.length; i++) {
        const evalItem = ciclo.evaluaciones[i];
        const fecha = evalItem.fechaOriginal || evalItem.fecha || 'Sin fecha';
        const nota = evalItem.notaFinal || 0;
        
        if (evalItem.detalles && evalItem.detalles.length > 0) {
            for (const detalle of evalItem.detalles) {
                const cumple = detalle.cumple === true || detalle.cumple === 1 || detalle.cumple === 'true';
                if (!cumple && detalle.submotivo) {
                    rows.push([
                        i + 1,
                        `"${fecha}"`,
                        nota,
                        `"${detalle.submotivo}"`,
                        `"${detalle.bloque || ''}"`,
                        `"${detalle.atributo || ''}"`,
                        detalle.peso || 0
                    ]);
                }
            }
        } else {
            rows.push([i + 1, `"${fecha}"`, nota, 'SIN ERRORES', '', '', '']);
        }
    }
    
    const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
    const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `detalle_ciclo_${gestor.replace(/\s/g, '_')}_${ciclo.numero}_${new Date().toISOString().slice(0, 10)}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    
    alert(`✅ Exportados ${rows.length} errores del Ciclo #${ciclo.numero}`);
}

function exportarGestionPersonasGP() {
    if (gestoresFiltradosGP.length === 0) {
        alert('⚠️ No hay datos para exportar');
        return;
    }
    
    const headers = ['Gestor', 'Promedio Global', 'Cuartil', 'ENC', 'ECUF', 'ECN', 'Total Errores', 'Reincidencia', 'Tendencia'];
    const matrizDominante = obtenerMatrizDominante(window.evaluacionesFiltradasGlobal || window.evaluacionesGlobales || []);
    const pesos = matrizDominante ? matrizDominante.pesos : { ENC: 30, ECUF: 30, ECN: 40 };

    const rows = gestoresFiltradosGP.map(g => [
        `"${g.nombre}"`,
        g.promedioGlobal,
        g.cuartilGlobal,
        `${g.encGlobal}/${pesos.ENC}`,
        `${g.ecufGlobal}/${pesos.ECUF}`,
        `${g.ecnGlobal}/${pesos.ECN}`,
        g.totalErrores,
        `${g.reincidencia}%`,
        `${g.tendencia.icono} ${g.tendencia.texto}`
    ]);
    
    const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
    const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `gestion_personas_${new Date().toISOString().slice(0, 10)}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    
    alert(`✅ Exportados ${gestoresFiltradosGP.length} gestores`);
}

async function refrescarGestionPersonasGP() {
    await cargarGestionPersonasGP();
}

function actualizarPaginacionGP() {
    const totalPaginas = Math.ceil(gestoresFiltradosGP.length / registrosPorPaginaGP);
    const btnAnterior = document.getElementById('btnPaginaAnteriorGP');
    const btnSiguiente = document.getElementById('btnPaginaSiguienteGP');
    const paginaInfo = document.getElementById('gpPaginaInfo');
    const paginaSelect = document.getElementById('gpPaginaSelect');
    
    if (btnAnterior) btnAnterior.disabled = paginaActualGP <= 1;
    if (btnSiguiente) btnSiguiente.disabled = paginaActualGP >= totalPaginas;
    if (paginaInfo) paginaInfo.textContent = `Página ${paginaActualGP} de ${totalPaginas || 1}`;
    
    if (paginaSelect) {
        paginaSelect.innerHTML = '';
        for (let i = 1; i <= totalPaginas; i++) {
            paginaSelect.innerHTML += `<option value="${i}" ${i === paginaActualGP ? 'selected' : ''}>Página ${i}</option>`;
        }
    }
}

function cambiarPaginaGP(delta) {
    const totalPaginas = Math.ceil(gestoresFiltradosGP.length / registrosPorPaginaGP);
    const nuevaPagina = paginaActualGP + delta;
    if (nuevaPagina >= 1 && nuevaPagina <= totalPaginas) {
        paginaActualGP = nuevaPagina;
        actualizarTablaGestionPersonasGP();
        actualizarPaginacionGP();
    }
}

function irAPaginaGP(pagina) {
    paginaActualGP = parseInt(pagina);
    actualizarTablaGestionPersonasGP();
    actualizarPaginacionGP();
}

function inicializarFiltrosGestionPersonasGP() {
    // Conectar filtro de mes
    const selectMes = document.getElementById('filtroMesGP');
    if (selectMes) {
        selectMes.addEventListener('change', function() {
            console.log(`📅 Cambiando filtro de mes a: ${this.value}`);
            // 🔴 RECARGAR GESTIÓN DE PERSONAS CON EL NUEVO MES
            if (typeof cargarGestionPersonasGP === 'function') {
                cargarGestionPersonasGP();
            }
        });
    }
    
    // Conectar otros filtros
    const filtros = ['filtroLiderGP', 'filtroUbicacionGP', 'filtroCuartilGP', 'buscarGestorGP'];
    filtros.forEach(id => {
        const elemento = document.getElementById(id);
        if (elemento) {
            // Eliminar event listeners anteriores
            const nuevoElemento = elemento.cloneNode(true);
            elemento.parentNode.replaceChild(nuevoElemento, elemento);
            
            const elFinal = document.getElementById(id);
            if (id === 'buscarGestorGP') {
                elFinal.addEventListener('input', () => aplicarFiltrosGestionPersonasGP());
            } else {
                elFinal.addEventListener('change', () => aplicarFiltrosGestionPersonasGP());
            }
        }
    });
    
    console.log("✅ Filtros de Gestión de Personas inicializados");
}

// ======================================================
// EJECUTAR TAREA AHORA (DESDE LA TABLA)
// ======================================================

async function ejecutarTareaAhora(tareaId) {
    if (!confirm(`⚠️ ¿Ejecutar la tarea ID ${tareaId} ahora?\n\nEsto iniciará el proceso de transcripción inmediatamente.`)) {
        return;
    }
    
    try {
        const token = localStorage.getItem('meca_token');
        
        // Mostrar indicador en el botón
        const buttons = document.querySelectorAll(`button[onclick*="ejecutarTareaAhora(${tareaId})"]`);
        buttons.forEach(btn => {
            btn.textContent = '⏳';
            btn.disabled = true;
        });
        
        const response = await fetch(`http://localhost:5001/api/transcripcion/tareas/${tareaId}/ejecutar`, {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${token}`,
                'Content-Type': 'application/json'
            }
        });
        
        const result = await response.json();
        
        if (result.success) {
            alert(`✅ Tarea ${tareaId} iniciada correctamente`);
            
            // Recargar la tabla de tareas y transcripciones después de unos segundos
            setTimeout(() => {
                if (typeof cargarTareasProgramadas === 'function') {
                    cargarTareasProgramadas();
                }
                if (typeof cargarTranscripciones === 'function') {
                    cargarTranscripciones();
                }
            }, 3000);
            
        } else {
            alert(`❌ Error al ejecutar la tarea:\n${result.error || 'Error desconocido'}`);
        }
        
    } catch (error) {
        console.error('Error ejecutando tarea:', error);
        alert(`❌ Error: ${error.message}`);
    } finally {
        // Restaurar botones
        const buttons = document.querySelectorAll(`button[onclick*="ejecutarTareaAhora(${tareaId})"]`);
        buttons.forEach(btn => {
            btn.textContent = '▶️';
            btn.disabled = false;
        });
    }
}

// ======================================================
// VER LOGS DE TAREA (DESDE LA TABLA)
// ======================================================

async function verLogsTarea(tareaId) {
    try {
        const token = localStorage.getItem('meca_token');
        
        const response = await fetch(`http://localhost:5001/api/transcripcion/logs/${tareaId}`, {
            headers: { 'Authorization': `Bearer ${token}` }
        });
        
        const result = await response.json();
        
        if (!result.logs || result.logs.length === 0) {
            alert(`📋 TAREA #${tareaId}\n\n⏳ No hay logs disponibles. La tarea aún no se ha ejecutado.`);
            return;
        }
        
        // Generar mensaje con los logs
        let mensaje = `📋 LOGS DE TAREA #${tareaId}\n`;
        mensaje += `${'═'.repeat(50)}\n\n`;
        
        result.logs.forEach(log => {
            mensaje += `  ${log}\n`;
        });
        
        mensaje += `\n${'═'.repeat(50)}`;
        mensaje += `\n📌 Total logs: ${result.logs.length}`;
        
        alert(mensaje);
        
    } catch (error) {
        console.error('Error obteniendo logs:', error);
        alert(`❌ Error al obtener logs:\n${error.message}`);
    }
}

// ======================================================
// EXPORTAR TAREAS A CSV
// ======================================================

function exportarTareasCSV() {
    if (!tareasDataGlobal || tareasDataGlobal.length === 0) {
        alert('⚠️ No hay datos de tareas para exportar');
        return;
    }
    
    // Headers
    const headers = [
        'ID',
        'Nombre',
        'Estado',
        'Frecuencia',
        'Origen',
        'Carpeta/URL',
        'Fecha Creación',
        'Última Ejecución',
        'Estado Ejecución',
        'Archivos Procesados'
    ];
    
    // Construir filas
    const rows = tareasDataGlobal.map(t => [
        t.id,
        `"${t.nombre || ''}"`,
        t.estado || '',
        t.frecuencia || '',
        t.tipo_origen || 'local',
        `"${t.carpeta_origen || t.sftp_host || t.sharepoint_site || ''}"`,
        t.fecha_creacion ? new Date(t.fecha_creacion).toLocaleString('es-ES') : '',
        t.ultima_ejecucion ? new Date(t.ultima_ejecucion).toLocaleString('es-ES') : '',
        t.ultima_ejecucion_estado || 'sin_ejecutar',
        `${t.ultima_ejecucion_correctos || 0}/${t.ultima_ejecucion_total || 0}`
    ]);
    
    // Generar CSV
    const csvContent = [
        headers.join(','),
        ...rows.map(row => row.join(','))
    ].join('\n');
    
    // Descargar
    const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `tareas_programadas_${new Date().toISOString().slice(0, 10)}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    
    alert(`✅ Exportadas ${tareasDataGlobal.length} tareas`);
}

// ======================================================
// ELIMINAR TAREA PROGRAMADA
// ======================================================

async function eliminarTarea(tareaId, nombreTarea) {
    // Confirmación con información detallada
    const confirmar = confirm(
        `⚠️ ¿ELIMINAR TAREA PROGRAMADA?\n\n` +
        `🆔 ID: ${tareaId}\n` +
        `📌 Nombre: ${nombreTarea || 'Sin nombre'}\n\n` +
        `Esta acción eliminará:\n` +
        `   • La tarea programada\n` +
        `   • Todos los logs de ejecución asociados\n` +
        `   • Todas las transcripciones generadas por esta tarea\n\n` +
        `⚠️ Esta acción NO se puede deshacer.\n\n` +
        `¿Está seguro de continuar?`
    );
    
    if (!confirmar) return;
    
    // Confirmación adicional con código
    const codigo = prompt('Para confirmar, escribe "ELIMINAR TAREA" en mayúsculas:');
    if (codigo !== 'ELIMINAR TAREA') {
        alert('❌ Operación cancelada.');
        return;
    }
    
    try {
        const token = localStorage.getItem('meca_token');
        
        // Mostrar indicador en el botón
        const buttons = document.querySelectorAll(`button[onclick*="eliminarTarea(${tareaId},"]`);
        buttons.forEach(btn => {
            btn.textContent = '⏳';
            btn.disabled = true;
        });
        
        const response = await fetch(`http://localhost:5001/api/transcripcion/tareas/${tareaId}`, {
            method: 'DELETE',
            headers: {
                'Authorization': `Bearer ${token}`,
                'Content-Type': 'application/json'
            }
        });
        
        const result = await response.json();
        
        if (!response.ok) {
            throw new Error(result.error || 'Error al eliminar tarea');
        }
        
        alert(`✅ Tarea "${nombreTarea || tareaId}" eliminada correctamente`);
        
        // Recargar la tabla de tareas
        if (typeof cargarTareasProgramadas === 'function') {
            cargarTareasProgramadas();
        }
        
        // También recargar transcripciones si es necesario
        if (typeof cargarTranscripciones === 'function') {
            cargarTranscripciones();
        }
        
    } catch (error) {
        console.error('Error eliminando tarea:', error);
        alert(`❌ Error al eliminar la tarea:\n${error.message}`);
    } finally {
        // Restaurar botones
        const buttons = document.querySelectorAll(`button[onclick*="eliminarTarea(${tareaId},"]`);
        buttons.forEach(btn => {
            btn.textContent = '🗑️';
            btn.disabled = false;
        });
    }
}




