    function actualizarResumenCarga() {
        if (datosEvaluaciones.length === 0) return;

        const total = datosEvaluaciones.length;
        const promedio = (datosEvaluaciones.reduce((sum, e) => sum + e.notaFinal, 0) / total).toFixed(1);

        document.getElementById('totalEvalCargadas').textContent = total;
        document.getElementById('promedioGeneralCargado').textContent = promedio + '%';
        document.getElementById('fechaUltimaCarga').textContent = new Date().toLocaleString();
        document.getElementById('resumenCarga').style.display = 'block';

        // Mostrar nombres de archivos
        const fileDetalle = document.getElementById('fileDetalle').files[0];

        if (fileDetalle) {
            document.getElementById('nombreDetalle').textContent = `📄 ${fileDetalle.name}`;
        }


        // Generar reportes automáticamente
        generarReportes();
        showTab('reportes', null);
    }
