    // ===== 29. INICIO FUNCIÓN: generarDocumentoId ==========================
    function generarDocumentoId() {
        const ahora = new Date();
        const anio = ahora.getFullYear();
        const mes = String(ahora.getMonth() + 1).padStart(2, '0');
        const dia = String(ahora.getDate()).padStart(2, '0');
        const aleatorio = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
        return `PDA-${anio}${mes}${dia}-${aleatorio}`;
    }
    // ===== FIN FUNCIÓN: generarDocumentoId =================================
    
    // ===== 30. INICIO FUNCIÓN: convertirFechaDDMMYYYYaISO ==================
    function convertirFechaDDMMYYYYaISO(fechaDDMMYYYY) {
        if (!fechaDDMMYYYY || fechaDDMMYYYY === 'N/A') return null;
        const partes = fechaDDMMYYYY.split('/');
        if (partes.length !== 3) return null;
        return `${partes[2]}-${partes[1]}-${partes[0]}`;
    }
    // ===== FIN FUNCIÓN: convertirFechaDDMMYYYYaISO =========================
    
    // ===== 31. INICIO FUNCIÓN: formatearFechaParaDocumento =================
    function formatearFechaParaDocumento(fechaStr) {
        if (!fechaStr) return 'N/A';

        if (fechaStr.includes('/')) {
            return fechaStr.split(' ')[0];
        }

        if (fechaStr.includes('-')) {
            const [anio, mes, dia] = fechaStr.split('T')[0].split('-');
            return `${dia}/${mes}/${anio}`;
        }

        return fechaStr;
    }
    // ===== FIN FUNCIÓN: formatearFechaParaDocumento ========================
    
    // ===== 32. INICIO FUNCIÓN: crearPDAEnPostgreSQL ==========================
    async function crearPDAEnPostgreSQL(data) {
        const db = getDB();
        if (!db) return null;

        try {
            // Obtener el siguiente ID
            const { data: maxIdData } = await db
                .from('pda_cabecera')
                .select('id')
                .order('id', { ascending: false })
                .limit(1);

            let nuevoId = 1;
            if (maxIdData && maxIdData.length > 0) {
                nuevoId = maxIdData[0].id + 1;
            } else {
                nuevoId = Date.now();
            }

            const nuevoPDA = {
                id: nuevoId,
                agente: data.agente,
                fecha_deteccion: data.fechaDeteccion,
                fecha_inicio_ciclo_basal: data.fechaInicioCicloBasal,
                fecha_fin_ciclo_basal: data.fechaFinCicloBasal,
                ciclo_basal_numero: data.cicloBasalNumero, // ← NUEVO CAMPO
                cuartil_basal: data.cuartilBasal,
                promedio_basal: data.promedioBasal,
                estado: data.estado,
                created_at: new Date().toISOString(),
                updated_at: new Date().toISOString()
            };

            const { error } = await db
                .from('pda_cabecera')
                .insert(nuevoPDA);

            if (error) throw error;

            console.log(`✅ PDA creado: ID ${nuevoId}`);
            return nuevoId;

        } catch (error) {
            console.error('Error creando PDA:', error);
            return null;
        }
    }
