    // ===== FIN FUNCIÓN: actualizarAgentesQ4ConFiltro =======================
    
    // ===== 39. INICIO FUNCIÓN: parseFechaDeString =========================⚠️ Redundante
    function parseFechaDeString(fechaStr) {
        if (!fechaStr) return new Date();

        // Formato: "15/04/2026 14:30" o "15/04/2026"
        if (fechaStr.includes('/')) {
            const partes = fechaStr.split(' ')[0].split('/');
            if (partes.length === 3) {
                return new Date(partes[2], partes[1] - 1, partes[0]);
            }
        }

        // Formato ISO: "2026-04-15T14:30:00"
        if (fechaStr.includes('-')) {
            return new Date(fechaStr);
        }

        return new Date();
    }
    // ===== FIN FUNCIÓN: parseFechaDeString =================================

