    // ===== 45. INICIO FUNCIÓN: actualizarTodosLosGraficosConFiltroMejorado==
    async function actualizarTodosLosGraficosConFiltroMejorado() {
        console.log('🔄 Actualizando gráficos con filtro mejorado...');

        // Destruir todos los gráficos existentes primero
        destruirTodosLosGraficosCompleto();

        let evaluaciones = window.evaluacionesGlobales || [];
        if (evaluaciones.length === 0) {
            console.warn('⚠️ No hay evaluaciones para generar gráficos');
            mostrarMensajeSinDatosEnGraficos();
            return;
        }

        const periodo = filtroPeriodoActual;

        // Aplicar filtros según el período
        let evaluacionesFiltradas = [...evaluaciones];

        if (periodo === 'dia') {
            if (!filtroFechaInicioActual || !filtroFechaFinActual) {
                console.log('📅 Sin filtro de fechas - mostrando TODOS los datos');
            } else {
                evaluacionesFiltradas = filtrarEvaluacionesPorRangoFechas(
                    evaluaciones,
                    filtroFechaInicioActual,
                    filtroFechaFinActual
                );
            }

            const infoSpan = document.getElementById('infoRangoSeleccionado');
            if (infoSpan) {
                if (filtroFechaInicioActual && filtroFechaFinActual) {
                    infoSpan.innerHTML = `📅 Mostrando datos del ${formatDateToDisplay(filtroFechaInicioActual)} al ${formatDateToDisplay(filtroFechaFinActual)} | Período: Día`;
                } else {
                    infoSpan.innerHTML = `📅 Mostrando TODOS los datos (sin filtro de fechas)`;
                }
            }
        } else {
            evaluacionesFiltradas = filtrarEvaluacionesPorCantidadPeriodos(evaluaciones, periodo, filtroCantidadActual);

            const infoSpan = document.getElementById('infoRangoSeleccionado');
            if (infoSpan) {
                const unidad = periodo === 'semana' ? 'semanas' : (periodo === 'mes' ? 'meses' : (periodo === 'trimestre' ? 'trimestres' : 'años'));
                const texto = filtroCantidadActual === 'all' ? 'Todo el histórico' : `Últimas ${filtroCantidadActual} ${unidad}`;
                infoSpan.innerHTML = `📅 Mostrando: ${texto} | Período: ${periodo === 'semana' ? 'Semana' : periodo === 'mes' ? 'Mes' : periodo === 'trimestre' ? 'Trimestre' : 'Año'}`;
            }
        }

        if (evaluacionesFiltradas.length === 0) {
            console.warn('⚠️ No hay datos en el período seleccionado');
            mostrarMensajeSinDatosEnGraficos();

            // 🔴 NUEVO: Limpiar tablas cuando no hay datos
            const tablaRanking = document.getElementById('tablaRanking');
            if (tablaRanking) tablaRanking.innerHTML = '<tr><td colspan="13" style="text-align: center;">📊 No hay datos en el período seleccionado</td></tr>';

            const agentesQ4Container = document.getElementById('agentesQ4Container');
            if (agentesQ4Container) {
                agentesQ4Container.innerHTML = `<div class="card" style="background: #fff4e5;">
                    <div style="display: flex; align-items: center; gap: 12px;">
                        <span style="font-size: 24px;">📊</span>
                        <div>
                            <strong>No hay datos en el período seleccionado</strong>\n
                            <span style="font-size: 13px;">Ajuste los filtros para ver más datos.</span>
                        </div>
                    </div>
                </div>`;
            }

            const contenedorFallas = document.getElementById('contenedorFallasJerarquicas');
            if (contenedorFallas) {
                contenedorFallas.innerHTML = '<div style="text-align: center; padding: 40px; color: var(--muted);">📊 No hay datos de fallas en el período seleccionado</div>';
            }

            return;
        }

        const datosAgrupados = agruparEvaluacionesPorPeriodo(evaluacionesFiltradas, periodo);
        datosAgrupadosActualesGlobal = datosAgrupados;

        if (datosAgrupados.length === 0) {
            mostrarMensajeSinDatosEnGraficos();
            return;
        }

        console.log(`✅ ${datosAgrupados.length} períodos agrupados, ${evaluacionesFiltradas.length} evaluaciones totales`);

        // Actualizar KPIs
        actualizarCardsPromedioMotivosAgrupados(datosAgrupados);
        actualizarCardPorcentajeQuiebresAgrupados(datosAgrupados);

        // 🔴 NUEVO: Actualizar Análisis Jerárquico de Fallas con datos filtrados
        generarTablaJerarquicaFallas(evaluacionesFiltradas);

        // Actualizar el gráfico "Evolutivo diario de notas por motivos de impacto"
        await renderizarEvolutivoConDatosFiltrados(evaluacionesFiltradas);


        // Generar otros gráficos
        setTimeout(() => {
            generarEvolutivoAudiosAgrupado(datosAgrupados, periodo);
            generarDistribucionRangosAgrupado(evaluacionesFiltradas);
            generarEvolutivoAtributosAgrupado(evaluacionesFiltradas, datosAgrupados, periodo);
            generarEvolutivoQuiebresAgrupado(datosAgrupados);
            generarGraficoComparativaAgrupado(evaluacionesFiltradas);
            generarGraficoGestionLlamadas(evaluacionesFiltradas);
            generarEvolutivoCuartiles(evaluacionesFiltradas, datosAgrupados, periodo);

        }, 50);
    }
