    // ===== 46. INICIO FUNCIÓN: cargarItemsSubmotivos =======================⚠️ Redundante
    function cargarItemsSubmotivos() {
        const evaluaciones = window.evaluacionesGlobales || [];
        const submotivosSet = new Set();

        evaluaciones.forEach(eval => {
            if (eval.detalles) {
                eval.detalles.forEach(det => {
                    if (det.submotivo) submotivosSet.add(det.submotivo);
                });
            }
        });

        const select = document.getElementById('pdaItem');
        if (select) {
            select.innerHTML = '<option value="">Seleccionar ítem</option>';
            Array.from(submotivosSet).sort().forEach(submotivo => {
                select.innerHTML += `<option value="${escapeHtml(submotivo)}">${escapeHtml(submotivo)}</option>`;
            });
        }
    }
    // ===== FIN FUNCIÓN: cargarItemsSubmotivos ==============================
    
    // ===== 47. INICIO FUNCIÓN: cargarItemsQuiebreAgente ====================
    function cargarItemsQuiebreAgente(agente) {
        console.log('🔍 Cargando items para agente:', agente);

        const evaluaciones = window.evaluacionesGlobales || [];
        const evaluacionesAgente = evaluaciones.filter(e => e.agente === agente);

        console.log('📊 Evaluaciones del agente:', evaluacionesAgente.length);

        // Mostrar un ejemplo de los detalles para depuración
        if (evaluacionesAgente.length > 0 && evaluacionesAgente[0].detalles) {
            console.log('📝 Ejemplo de detalle (primer evaluación):', evaluacionesAgente[0].detalles[0]);
        }

        const fallasPorSubmotivo = {};

        evaluacionesAgente.forEach(eval => {
            if (eval.detalles && eval.detalles.length > 0) {
                eval.detalles.forEach(det => {
                    // Usar la misma comparación robusta que en procesarArchivoDetalleAcumulativo
                    const cumpleVal = det.cumple;
                    const cumple = cumpleVal === '1' || cumpleVal === 1 || cumpleVal === 'true' || cumpleVal === true;

                    if (!cumple && det.submotivo) {
                        const key = det.submotivo;
                        if (!fallasPorSubmotivo[key]) {
                            fallasPorSubmotivo[key] = {
                                submotivo: det.submotivo,
                                bloque: det.bloque || '',
                                atributo: det.atributo || '',
                                ocurrencias: 0,
                                peso: det.peso || 0
                            };
                        }
                        fallasPorSubmotivo[key].ocurrencias++;
                    }
                });
            }
        });

        console.log('📋 Fallas encontradas (agrupadas):', fallasPorSubmotivo);
        console.log('📋 Cantidad de ítems con falla:', Object.keys(fallasPorSubmotivo).length);

        const container = document.getElementById('pdaItemsContainer');
        const itemsCountSpan = document.getElementById('itemsSeleccionadosCount');

        if (Object.keys(fallasPorSubmotivo).length === 0) {
            if (container) container.innerHTML = '<div style="text-align: center; padding: 20px; color: var(--muted);">✅ No hay ítems con quiebre para este agente</div>';
            if (itemsCountSpan) itemsCountSpan.textContent = '0 items seleccionados';
            return;
        }

        const itemsOrdenados = Object.values(fallasPorSubmotivo).sort((a, b) => b.ocurrencias - a.ocurrencias);

        let html = '<div style="display: flex; flex-direction: column; gap: 8px;">';

        itemsOrdenados.forEach(item => {
            const tipo = obtenerTipoQuiebre(item.submotivo);
            const tipoColor = tipo === 'critico' ? '#d93025' : '#f39c12';
            const tipoTexto = tipo === 'critico' ? '🔴 Crítico' : '🟡 No crítico';
            const frente = determinarFrenteSubmotivo(item.submotivo);
            const frenteColor = frente === 'cliente' ? '#019DF4' : (frente === 'negocio' ? '#7b1fa2' : '#fd7e14');
            const frenteTexto = frente === 'cliente' ? 'ENC' : (frente === 'negocio' ? 'ECUF' : 'ECN');

            html += `
                <label style="display: flex; align-items: center; gap: 12px; padding: 10px; background: #f8f9fa; border-radius: 8px; cursor: pointer; border-left: 3px solid ${frenteColor};">
                    <input type="checkbox" name="pdaItems" value="${escapeHtml(item.submotivo)}" 
                        data-bloque="${escapeHtml(item.bloque)}"
                        data-atributo="${escapeHtml(item.atributo)}"
                        data-tipo="${tipo}"
                        data-frente="${frente}"
                        data-ocurrencias="${item.ocurrencias}"
                        data-peso="${item.peso}"
                        style="width: 18px; height: 18px; cursor: pointer;">
                    <div style="flex: 1;">
                        <div style="display: flex; align-items: center; gap: 8px; flex-wrap: wrap;">
                            <strong style="font-size: 14px;">❌ ${escapeHtml(item.submotivo)}</strong>
                            <span style="font-size: 10px; background: ${frenteColor}; color: white; padding: 2px 6px; border-radius: 10px;">${frenteTexto}</span>
                            <span style="font-size: 10px; background: ${tipoColor}; color: white; padding: 2px 6px; border-radius: 10px;">${tipoTexto}</span>
                        </div>
                        <div style="font-size: 11px; color: var(--muted); margin-top: 4px;">
                            📂 ${escapeHtml(item.bloque || 'Sin bloque')} / ${escapeHtml(item.atributo || 'Sin atributo')}
                        </div>
                    </div>
                    <div style="display: flex; gap: 8px;">
                        <span style="background: var(--warning); color: white; padding: 4px 10px; border-radius: 20px; font-size: 11px; font-weight: bold;">
                            📊 ${item.ocurrencias} falla(s)
                        </span>
                        ${item.peso ? `<span style="background: var(--accent); color: white; padding: 4px 10px; border-radius: 20px; font-size: 11px;">⚖️ ${item.peso}%</span>` : ''}
                    </div>
                </label>
            `;
        });

        html += '</div>';

        if (container) {
            container.innerHTML = html;
            console.log('✅ Checkboxes generados:', document.querySelectorAll('input[name="pdaItems"]').length);
            const checkboxes = document.querySelectorAll('input[name="pdaItems"]');
            checkboxes.forEach(cb => {
                cb.addEventListener('change', actualizarContadorItems);
            });
            actualizarContadorItems();
        } else {
            console.error('❌ Container pdaItemsContainer no encontrado');
        }
    }
    // ===== FIN FUNCIÓN: cargarItemsQuiebreAgente ===========================

    // ===== 48. INICIO FUNCIÓN: actualizarContadorItems =====================
    function actualizarContadorItems() {
        const checkboxes = document.querySelectorAll('input[name="pdaItems"]');
        const seleccionados = Array.from(checkboxes).filter(cb => cb.checked).length;
        const itemsCountSpan = document.getElementById('itemsSeleccionadosCount');
        const btnSeleccionarTodos = document.getElementById('btnSeleccionarTodos');

        if (itemsCountSpan) {
            itemsCountSpan.innerHTML = `📌 ${seleccionados} de ${checkboxes.length} items seleccionados`;
            itemsCountSpan.style.color = seleccionados > 0 ? 'var(--ok)' : 'var(--muted)';
            itemsCountSpan.style.fontWeight = seleccionados > 0 ? 'bold' : 'normal';
        }

        if (btnSeleccionarTodos && checkboxes.length > 0) {
            const todosSeleccionados = seleccionados === checkboxes.length;
            btnSeleccionarTodos.innerHTML = todosSeleccionados ? '⬜ Deseleccionar todos' : '✅ Seleccionar todos';
            btnSeleccionarTodos.style.background = todosSeleccionados ? 'var(--warning)' : 'var(--accent)';
        }
    }
    // ===== FIN FUNCIÓN: actualizarContadorItems ============================

    // ===== 49. INICIO FUNCIÓN: toggleSeleccionarTodos ======================
    function toggleSeleccionarTodos() {
        const checkboxes = document.querySelectorAll('input[name="pdaItems"]');
        if (checkboxes.length === 0) return;

        const todosSeleccionados = Array.from(checkboxes).every(cb => cb.checked);
        checkboxes.forEach(cb => cb.checked = !todosSeleccionados);
        actualizarContadorItems();
    }
    // ===== FIN FUNCIÓN: toggleSeleccionarTodos =============================
    
    // ===== 50. INICIO FUNCIÓN: parseFechaString ============================⚠️ Redundante
    function parseFechaString(fechaStr) {
        if (!fechaStr) return null;
        try {
            if (fechaStr.includes('/')) {
                const [dia, mes, anio] = fechaStr.split('/');
                return new Date(anio, mes - 1, dia);
            }
            return new Date(fechaStr);
        } catch (e) {
            return null;
        }
    }
    // ===== FIN FUNCIÓN: parseFechaString ===================================

