// ABRIR MODAL PARA CREAR NUEVA VERSIÓN
// ======================================================
function abrirModalNuevaVersion() {
    // Limpiar modal anterior
    const modalExistente = document.getElementById('modalNuevaVersion');
    if (modalExistente) modalExistente.remove();
    
    const modalHtml = `
        <div id="modalNuevaVersion" style="position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.6); z-index: 10002; display: flex; justify-content: center; align-items: center;">
            <div style="background: white; border-radius: 16px; width: 90%; max-width: 500px; overflow: hidden; box-shadow: 0 20px 40px rgba(0,0,0,0.3);">
                <div style="padding: 15px 20px; background: linear-gradient(135deg, #7b1fa2, #9c27b0); color: white;">
                    <strong style="font-size: 16px;">📦 Crear Nueva Versión de Matriz</strong>
                </div>
                <div style="padding: 20px;">
                    <p style="margin-bottom: 15px; font-size: 13px; color: var(--muted);">
                        Esta acción creará un "snapshot" de la versión actual. 
                        La nueva versión será una copia exacta que podrás modificar sin afectar la versión activa.
                    </p>
                    <div style="margin-bottom: 15px;">
                        <label style="font-size: 12px; font-weight: 600;">📌 Nombre de la versión *</label>
                        <input type="text" id="nuevaVersionNombre" placeholder="Ej: v2.0.0" 
                            style="width: 100%; padding: 10px; margin-top: 5px; border-radius: 8px; border: 1px solid var(--line);">
                        <small style="color: var(--muted);">Formato: vX.X.X</small>
                    </div>
                    <div style="margin-bottom: 15px;">
                        <label style="font-size: 12px; font-weight: 600;">📅 Fecha de vigencia *</label>
                        <input type="date" id="nuevaVersionFecha" value="${new Date().toISOString().split('T')[0]}"
                            style="width: 100%; padding: 10px; margin-top: 5px; border-radius: 8px; border: 1px solid var(--line);">
                    </div>
                    <div style="margin-bottom: 15px;">
                        <label style="font-size: 12px; font-weight: 600;">📝 Descripción</label>
                        <textarea id="nuevaVersionDescripcion" rows="2" placeholder="Describe los cambios de esta versión..."
                            style="width: 100%; padding: 10px; margin-top: 5px; border-radius: 8px; border: 1px solid var(--line);"></textarea>
                    </div>
                    <div style="background: #fff3e0; padding: 12px; border-radius: 8px; font-size: 12px; border-left: 4px solid #f39c12;">
                        ⚠️ La nueva versión se creará como <strong>INACTIVA</strong>. 
                        Deberás activarla manualmente después de hacer los cambios necesarios.
                    </div>
                </div>
                <div style="padding: 15px 20px; background: #f8f9fa; display: flex; justify-content: flex-end; gap: 10px; border-top: 1px solid #e0e0e0;">
                    <button onclick="cerrarModalNuevaVersion()" style="padding: 8px 20px; background: #6c757d; border: none; border-radius: 8px; cursor: pointer; color: white;">Cancelar</button>
                    <button onclick="crearNuevaVersion()" style="padding: 8px 20px; background: #7b1fa2; border: none; border-radius: 8px; cursor: pointer; color: white;">
                        📦 Crear Snapshot
                    </button>
                </div>
            </div>
        </div>
    `;
    
    document.body.insertAdjacentHTML('beforeend', modalHtml);
}

function cerrarModalNuevaVersion() {
    const modal = document.getElementById('modalNuevaVersion');
    if (modal) modal.remove();
}

async function crearNuevaVersion() {
    const nombre = document.getElementById('nuevaVersionNombre').value.trim();
    const fecha = document.getElementById('nuevaVersionFecha').value;
    const descripcion = document.getElementById('nuevaVersionDescripcion').value.trim();
    
    if (!nombre) {
        alert('⚠️ Ingrese un nombre para la versión');
        return;
    }
    
    if (!fecha) {
        alert('⚠️ Seleccione una fecha de vigencia');
        return;
    }
    
    // Validar formato de versión
    if (!/^v\d+\.\d+\.\d+$/.test(nombre)) {
        alert('⚠️ Formato inválido. Use: v1.0.0, v2.0.0, etc.');
        return;
    }
    
    const btn = document.querySelector('#modalNuevaVersion button:last-child');
    const textoOriginal = btn?.innerHTML;
    if (btn) {
        btn.innerHTML = '⏳ Creando...';
        btn.disabled = true;
    }
    
    try {
        const result = await API.congelarVersionActual({
            version: nombre,
            fecha_vigencia: fecha,
            descripcion: descripcion || `Snapshot de versión ${nombre}`
        });
        
        alert(`✅ Versión "${nombre}" creada exitosamente como snapshot.\n\nAhora puedes modificarla y luego activarla.`);
        
        cerrarModalNuevaVersion();
        await cargarMatrizCompleta();
        
    } catch (error) {
        console.error('Error creando versión:', error);
        alert('❌ Error al crear versión: ' + error.message);
    } finally {
        if (btn) {
            btn.innerHTML = textoOriginal;
            btn.disabled = false;
        }
    }
}

async function crearVersion() {
    const data = {
        version: document.getElementById('versionNombre').value,
        descripcion: document.getElementById('versionDescripcion').value
    };
    
    if (!data.version) {
        alert('⚠️ Ingrese un nombre para la versión');
        return;
    }
    
    try {
        await API.crearVersionMatriz(data);
        cerrarModalVersion();
        cargarMatrizCompleta();
        alert('✅ Versión creada correctamente');
    } catch (error) {
        alert('❌ Error: ' + error.message);
    }
}

async function cambiarVersionActiva() {
    const select = document.getElementById('versionSelect');
    const versionId = select.value;
    
    if (!versionId) return;
    
    if (!confirm('⚠️ ¿Activar esta versión? La matriz se actualizará para todos los auditores.')) {
        select.value = await getVersionActivaId();
        return;
    }
    
    try {
        await API.activarVersionMatriz(versionId);
        alert('✅ Versión activada correctamente');
        cargarMatrizCompleta();
        // Limpiar caché del auditor
        localStorage.removeItem('estructura_evaluacion_v2');
        localStorage.removeItem('estructura_evaluacion_v2_time');
    } catch (error) {
        alert('❌ Error: ' + error.message);
    }
}

function cerrarModalVersion() {
    document.getElementById('modalVersion').style.display = 'none';
}

// ========== RECALCULAR EVALUACIONES ==========
async function recalcularTodasEvaluaciones() {
    if (!confirm('⚠️ ¿RECALCULAR TODAS LAS EVALUACIONES?\n\nEsta acción actualizará las notas de todas las evaluaciones según la matriz actual.\n\n¿Desea continuar?')) return;
    
    try {
        const result = await API.recalcularTodasEvaluaciones();
        alert('✅ ' + (result.message || 'Evaluaciones recalculadas correctamente'));
    } catch (error) {
        alert('❌ Error: ' + error.message);
    }
}

async function getVersionActivaId() {
    try {
        const versiones = await API.getVersionesMatriz();
        const activa = versiones.find(v => v.activa);
        return activa ? activa.id : '';
    } catch {
        return '';
    }
}

// ======================================================
// CRUD: CRITERIOS DE CUARTILES
// ======================================================

// =============================================
// 1. CARGAR CRITERIOS EN TABLA
// =============================================
async function cargarCriteriosCuartilesTabla() {
    console.log('📋 Cargando criterios de cuartiles...');
    
    const tbody = document.getElementById('tbodyCriteriosCuartiles');
    if (!tbody) return;
    
    tbody.innerHTML = '<tr><td colspan="9" style="text-align: center; padding: 40px;">⏳ Cargando...</td></tr>';
    
    try {
        const token = localStorage.getItem('meca_token');
        const response = await fetch('/api/criterios-cuartiles', {
            headers: { 'Authorization': `Bearer ${token}` }
        });
        
        if (!response.ok) throw new Error('Error al cargar criterios');
        
        const result = await response.json();
        const criterios = result.data || [];
        
        if (criterios.length === 0) {
            tbody.innerHTML = '<tr><td colspan="9" style="text-align: center; padding: 40px;">📭 No hay criterios registrados</td></tr>';
            return;
        }
        
        let html = '';
        for (const c of criterios) {
            const estadoBadge = c.activo 
                ? '<span class="badge" style="background: var(--ok);">✅ Activo</span>'
                : '<span class="badge" style="background: var(--danger);">❌ Inactivo</span>';
            
            const vigencia = c.fecha_vigencia_hasta 
                ? `${formatDate(c.fecha_vigencia_desde)} → ${formatDate(c.fecha_vigencia_hasta)}`
                : `${formatDate(c.fecha_vigencia_desde)} → ∞`;
            
            html += `
                <tr>
                    <td style="padding: 8px; text-align: center;">${c.id}</td>
                    <td style="padding: 8px;">
                        <span style="background: ${c.color_hex}; color: white; padding: 4px 10px; border-radius: 20px; font-size: 12px;">
                            ${c.icono || '📊'} ${c.cuartil}
                        </span>
                    </td>
                    <td style="padding: 8px;">${escapeHtml(c.nombre)}</td>
                    <td style="padding: 8px; text-align: center;">${c.limite_inferior}%</td>
                    <td style="padding: 8px; text-align: center;">${c.limite_superior}%</td>
                    <td style="padding: 8px; text-align: center;">${c.orden}</td>
                    <td style="padding: 8px; font-size: 12px;">${vigencia}</td>
                    <td style="padding: 8px; text-align: center;">${estadoBadge}</td>
                    <td style="padding: 8px; text-align: center; white-space: nowrap;">
                        <button onclick="editarCriterioCuartil(${c.id})" 
                                style="background: var(--warning); padding: 4px 10px; border: none; border-radius: 6px; cursor: pointer; margin-right: 5px;">
                            ✏️
                        </button>
                        ${c.activo ? `
                            <button onclick="desactivarCriterioCuartil(${c.id})" 
                                    style="background: var(--danger); padding: 4px 10px; border: none; border-radius: 6px; cursor: pointer; color: white;">
                                🗑️
                            </button>
                        ` : `
                            <button onclick="activarCriterioCuartil(${c.id})" 
                                    style="background: var(--ok); padding: 4px 10px; border: none; border-radius: 6px; cursor: pointer; color: white;">
                                ✅ Activar
                            </button>
                        `}
                    </td>
                </tr>
            `;
        }
        
        tbody.innerHTML = html;
        actualizarEstadisticasCriterios(criterios);
        
    } catch (error) {
        console.error('Error:', error);
        tbody.innerHTML = `<tr><td colspan="9" style="text-align: center; color: var(--danger); padding: 40px;">❌ Error: ${error.message}</td></tr>`;
    }
}

// =============================================
// 2. ACTUALIZAR ESTADÍSTICAS
// =============================================
function actualizarEstadisticasCriterios(criterios) {
    const total = criterios.length;
    const activos = criterios.filter(c => c.activo).length;
    const vigentes = criterios.filter(c => {
        if (!c.activo) return false;
        const hoy = new Date().toISOString().split('T')[0];
        if (!c.fecha_vigencia_hasta) return true;
        return c.fecha_vigencia_hasta >= hoy;
    }).length;
    
    document.getElementById('statsTotalCriterios').textContent = total;
    document.getElementById('statsActivosCriterios').textContent = activos;
    document.getElementById('statsVigentesCriterios').textContent = vigentes;
}

// =============================================
// 3. ABRIR MODAL NUEVO CRITERIO
// =============================================
function abrirModalNuevoCriterio() {
    document.getElementById('modalCriterioTitulo').textContent = '➕ Nuevo Criterio de Cuartil';
    document.getElementById('criterioId').value = '';
    document.getElementById('criterioCuartil').value = '';
    document.getElementById('criterioNombre').value = '';
    document.getElementById('criterioLimiteInferior').value = '';
    document.getElementById('criterioLimiteSuperior').value = '';
    document.getElementById('criterioColor').value = '#019DF4';
    document.getElementById('criterioIcono').value = '📊';
    document.getElementById('criterioOrden').value = '';
    document.getElementById('criterioFechaDesde').value = new Date().toISOString().split('T')[0];
    document.getElementById('criterioFechaHasta').value = '';
    document.getElementById('criterioActivo').value = 'true';
    
    document.getElementById('modalCriterioCuartil').style.display = 'flex';
}

// =============================================
// 4. EDITAR CRITERIO
// =============================================
async function editarCriterioCuartil(id) {
    try {
        const token = localStorage.getItem('meca_token');
        const response = await fetch(`/api/criterios-cuartiles`, {
            headers: { 'Authorization': `Bearer ${token}` }
        });
        const result = await response.json();
        const criterio = result.data.find(c => c.id === id);
        
        if (!criterio) {
            alert('❌ Criterio no encontrado');
            return;
        }
        
        document.getElementById('modalCriterioTitulo').textContent = `✏️ Editar ${criterio.cuartil} - ${criterio.nombre}`;
        document.getElementById('criterioId').value = criterio.id;
        document.getElementById('criterioCuartil').value = criterio.cuartil;
        document.getElementById('criterioNombre').value = criterio.nombre;
        document.getElementById('criterioLimiteInferior').value = criterio.limite_inferior;
        document.getElementById('criterioLimiteSuperior').value = criterio.limite_superior;
        document.getElementById('criterioColor').value = criterio.color_hex || '#019DF4';
        document.getElementById('criterioIcono').value = criterio.icono || '📊';
        document.getElementById('criterioOrden').value = criterio.orden;
        document.getElementById('criterioFechaDesde').value = criterio.fecha_vigencia_desde;
        document.getElementById('criterioFechaHasta').value = criterio.fecha_vigencia_hasta || '';
        document.getElementById('criterioActivo').value = criterio.activo ? 'true' : 'false';
        
        document.getElementById('modalCriterioCuartil').style.display = 'flex';
    } catch (error) {
        alert('❌ Error: ' + error.message);
    }
}

// =============================================
// 5. GUARDAR CRITERIO
// =============================================
async function guardarCriterioCuartil() {
    const id = document.getElementById('criterioId').value;
    const cuartil = document.getElementById('criterioCuartil').value;
    const nombre = document.getElementById('criterioNombre').value.trim();
    const limiteInferior = parseFloat(document.getElementById('criterioLimiteInferior').value);
    const limiteSuperior = parseFloat(document.getElementById('criterioLimiteSuperior').value);
    const color = document.getElementById('criterioColor').value;
    const icono = document.getElementById('criterioIcono').value || '📊';
    const orden = parseInt(document.getElementById('criterioOrden').value) || 0;
    const fechaDesde = document.getElementById('criterioFechaDesde').value;
    const fechaHasta = document.getElementById('criterioFechaHasta').value || null;
    const activo = document.getElementById('criterioActivo').value === 'true';
    
    // Validaciones
    if (!cuartil || !nombre) {
        alert('⚠️ Complete los campos obligatorios: Cuartil y Nombre');
        return;
    }
    
    if (isNaN(limiteInferior) || isNaN(limiteSuperior)) {
        alert('⚠️ Los límites deben ser números válidos');
        return;
    }
    
    if (limiteInferior >= limiteSuperior) {
        alert('⚠️ El límite inferior debe ser menor que el límite superior');
        return;
    }
    
    if (limiteInferior < 0 || limiteSuperior > 100) {
        alert('⚠️ Los límites deben estar entre 0 y 100');
        return;
    }
    
    if (!fechaDesde) {
        alert('⚠️ Seleccione una fecha de vigencia');
        return;
    }
    
    // 🔴 🔴 🔴 CONSTRUIR DATOS EXACTAMENTE COMO LA PRUEBA 🔴 🔴 🔴
    const data = {
        cuartil: cuartil,
        nombre: nombre,
        limite_inferior: limiteInferior,
        limite_superior: limiteSuperior,
        color_hex: color,
        icono: icono,
        orden: orden,
        fecha_vigencia_desde: fechaDesde,
        fecha_vigencia_hasta: fechaHasta,
        activo: activo
    };
    
    console.log('📤 Enviando datos:', data);
    
    const token = localStorage.getItem('meca_token');
    const method = id ? 'PUT' : 'POST';
    const url = id ? `/api/criterios-cuartiles/${id}` : '/api/criterios-cuartiles';
    
    try {
        const response = await fetch(url, {
            method: method,
            headers: {
                'Authorization': `Bearer ${token}`,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(data)  // ← Enviar el objeto directamente
        });
        
        if (!response.ok) {
            const error = await response.json();
            throw new Error(error.error || 'Error al guardar');
        }
        
        const result = await response.json();
        console.log('✅ Guardado:', result);
        
        alert('✅ Criterio guardado correctamente');
        cerrarModalCriterio();
        await cargarCriteriosCuartilesTabla();
        invalidarCacheCuartiles();
        
    } catch (error) {
        console.error('❌ Error:', error);
        alert('❌ Error: ' + error.message);
    }
}
// =============================================
// 6. DESACTIVAR CRITERIO
// =============================================
async function desactivarCriterioCuartil(id) {
    if (!confirm('⚠️ ¿Desactivar este criterio?\n\nNo se eliminará, solo quedará inactivo.')) return;
    
    try {
        const token = localStorage.getItem('meca_token');
        const response = await fetch(`/api/criterios-cuartiles/${id}`, {
            method: 'DELETE',
            headers: { 'Authorization': `Bearer ${token}` }
        });
        
        if (!response.ok) throw new Error('Error al desactivar');
        
        alert('✅ Criterio desactivado');
        await cargarCriteriosCuartilesTabla();
        invalidarCacheCuartiles();
        
    } catch (error) {
        alert('❌ Error: ' + error.message);
    }
}

// =============================================
// 7. ACTIVAR CRITERIO
// =============================================
async function activarCriterioCuartil(id) {
    if (!confirm('⚠️ ¿Activar este criterio?')) return;
    
    try {
        const token = localStorage.getItem('meca_token');
        const response = await fetch(`/api/criterios-cuartiles/${id}/activar`, {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${token}` }
        });
        
        if (!response.ok) throw new Error('Error al activar');
        
        alert('✅ Criterio activado');
        await cargarCriteriosCuartilesTabla();
        invalidarCacheCuartiles();
        
    } catch (error) {
        alert('❌ Error: ' + error.message);
    }
}

// =============================================
// 8. CERRAR MODAL
// =============================================
function cerrarModalCriterio() {
    document.getElementById('modalCriterioCuartil').style.display = 'none';
}

// =============================================
// 9. FORMATO DE FECHA
// =============================================
function formatDate(dateStr) {
    if (!dateStr) return '-';
    const d = new Date(dateStr);
    return `${d.getDate().toString().padStart(2, '0')}/${(d.getMonth()+1).toString().padStart(2, '0')}/${d.getFullYear()}`;
}

// ======================================================
// VARIABLES DE PROGRESO
// ======================================================

let progresoActivo = false;
let progresoInterval = null;
let tareaEnProgreso = null;

// ======================================================
// FUNCIÓN: subirYTranscribirConProgreso
// ======================================================

async function subirYTranscribirConProgreso() {
    const fileInput = document.getElementById('audioFileInput');
    const status = document.getElementById('uploadStatus');
    
    if (!fileInput || !fileInput.files || fileInput.files.length === 0) {
        alert('⚠️ Seleccione un archivo de audio');
        return;
    }
    
    const file = fileInput.files[0];
    const crearTarea = document.getElementById('crearTareaAuto')?.checked !== false;
    
    // Mostrar barra de progreso
    mostrarProgreso('📤 Subiendo audio...', 5);
    agregarLogProgreso('📤 Iniciando subida del archivo: ' + file.name);
    
    try {
        // ======================================================
        // PASO 1: SUBIR AUDIO
        // ======================================================
        const formData = new FormData();
        formData.append('audio', file);
        formData.append('crear_tarea', crearTarea ? 'true' : 'false');
        formData.append('creado_por', usuarioActual?.nombre_completo || 'MECA');
        
        const token = localStorage.getItem('meca_token');
        
        const uploadResponse = await fetch('http://localhost:5001/api/transcripcion/subir', {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${token}` },
            body: formData
        });
        
        const uploadData = await uploadResponse.json();
        
        if (!uploadData.success) {
            throw new Error(uploadData.error || 'Error al subir archivo');
        }
        
        agregarLogProgreso('✅ Audio subido: ' + uploadData.archivo);
        actualizarProgreso('📝 Preparando transcripción...', 20);
        
        // ======================================================
        // PASO 2: INICIAR TRANSCRIPCIÓN
        // ======================================================
        
        if (uploadData.tarea_id) {
            agregarLogProgreso('📋 Tarea creada con ID: ' + uploadData.tarea_id);
            
            // Verificar si la tarea ya tiene transcripciones previas
            const transCheck = await fetch(`http://localhost:5001/api/transcripcion/listar?tarea_id=${uploadData.tarea_id}&limit=1`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const transCheckData = await transCheck.json();
            
            if (transCheckData.data && transCheckData.data.length > 0) {
                const existente = transCheckData.data[0];
                if (existente.estado === 'analizado') {
                    agregarLogProgreso('✅ Ya existe una transcripción analizada para este audio');
                    actualizarProgreso('✅ Transcripción ya completada', 100);
                    setTimeout(() => {
                        ocultarProgreso();
                        cargarTranscripciones();
                        if (status) {
                            status.innerHTML = '<span style="color: var(--ok);">✅ Transcripción ya existente</span>';
                        }
                    }, 2000);
                    return;
                }
            }
            
            // Iniciar la tarea
            const ejecutarResponse = await fetch(`http://localhost:5001/api/transcripcion/tareas/${uploadData.tarea_id}/ejecutar`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                }
            });
            
            const ejecutarData = await ejecutarResponse.json();
            
            if (!ejecutarData.success) {
                throw new Error(ejecutarData.error || 'Error al iniciar tarea');
            }
            
            agregarLogProgreso('🚀 Tarea iniciada');
            tareaEnProgreso = uploadData.tarea_id;
            
            // ======================================================
            // PASO 3: MONITOREAR PROGRESO
            // ======================================================
            actualizarProgreso('🔄 Transcribiendo audio...', 40);
            await monitorearProgreso(uploadData.tarea_id);
            
        } else {
            // Si no hay tarea, transcribir directamente
            agregarLogProgreso('🎤 Transcribiendo directamente...');
            actualizarProgreso('🎤 Transcribiendo audio...', 40);
            
            const transcribeResponse = await fetch('http://localhost:5001/api/transcripcion/transcribir', {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    audio_path: uploadData.ruta,
                    modelo: 'small',
                    idioma: 'Spanish',
                    analizar_con_ollama: true
                })
            });
            
            const transcribeData = await transcribeResponse.json();
            
            if (!transcribeData.success) {
                throw new Error(transcribeData.error || 'Error en transcripción');
            }
            
            agregarLogProgreso('✅ Transcripción completada');
            actualizarProgreso('✅ Transcripción completada', 100);
        }
        
        // ======================================================
        // COMPLETADO
        // ======================================================
        agregarLogProgreso('✅ Proceso completado exitosamente');
        actualizarProgreso('✅ Transcripción completada', 100);
        
        setTimeout(() => {
            ocultarProgreso();
            cargarTranscripciones();
            if (status) {
                status.innerHTML = '<span style="color: var(--ok);">✅ Transcripción completada exitosamente</span>';
            }
        }, 3000);
        
    } catch (error) {
        console.error('❌ Error:', error);
        agregarLogProgreso('❌ Error: ' + error.message);
        actualizarProgreso('❌ Error: ' + error.message, 0, true);
        
        if (status) {
            status.innerHTML = `<span style="color: var(--danger);">❌ ${error.message}</span>`;
        }
        
        setTimeout(ocultarProgreso, 5000);
    }
}

// ======================================================
// FUNCIÓN: MONITOREAR PROGRESO
// ======================================================

async function monitorearProgreso(tareaId) {
    const token = localStorage.getItem('meca_token');
    let intentos = 0;
    const maxIntentos = 300; // 5 minutos (cada 1 segundo)
    let transcripcionCompletada = false;
    let ultimoEstado = '';
    
    return new Promise((resolve, reject) => {
        if (progresoInterval) {
            clearInterval(progresoInterval);
        }
        
        progresoInterval = setInterval(async () => {
            intentos++;
            
            try {
                // ======================================================
                // 1. VERIFICAR TRANSCRIPCIONES COMPLETADAS (LO MÁS IMPORTANTE)
                // ======================================================
                const transResponse = await fetch(`http://localhost:5001/api/transcripcion/listar?tarea_id=${tareaId}&limit=5`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                });
                
                if (transResponse.ok) {
                    const transData = await transResponse.json();
                    
                    if (transData.data && transData.data.length > 0) {
                        // Buscar la transcripción más reciente de esta tarea
                        const trans = transData.data[0];
                        
                        // ✅ CASO 1: Transcripción ya analizada (completa)
                        if (trans.estado === 'analizado') {
                            if (!transcripcionCompletada) {
                                agregarLogProgreso(`🧠 Análisis completado - Calificación: ${trans.calificacion || 0}%`);
                                actualizarProgreso('✅ Transcripción y análisis completados', 100);
                                transcripcionCompletada = true;
                                clearInterval(progresoInterval);
                                resolve();
                                return;
                            }
                        }
                        
                        // 📝 CASO 2: Transcripción transcrita pero no analizada
                        if (trans.estado === 'transcrito' && !transcripcionCompletada) {
                            if (ultimoEstado !== 'transcrito') {
                                agregarLogProgreso('📝 Transcripción completada. Iniciando análisis con Ollama...');
                                actualizarProgreso('🧠 Analizando con Ollama...', 85);
                                ultimoEstado = 'transcrito';
                            }
                        }
                        
                        // ⏳ CASO 3: En proceso (transcribiendo)
                        if (trans.estado === 'en_proceso' && !transcripcionCompletada) {
                            if (ultimoEstado !== 'en_proceso') {
                                agregarLogProgreso('🔄 Transcribiendo audio...');
                                actualizarProgreso('🔄 Transcribiendo audio...', 60);
                                ultimoEstado = 'en_proceso';
                            }
                        }
                    }
                }
                
                // ======================================================
                // 2. VERIFICAR EL ESTADO DE LA TAREA (LOGS DE EJECUCIÓN)
                // ======================================================
                const estadoResponse = await fetch(`http://localhost:5001/api/transcripcion/estado/${tareaId}`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                });
                
                if (estadoResponse.ok) {
                    const estadoData = await estadoResponse.json();
                    
                    // Si la tarea está en error
                    if (estadoData.estado === 'error') {
                        agregarLogProgreso('❌ Error en la transcripción: ' + (estadoData.error || 'Error desconocido'));
                        actualizarProgreso('❌ Error en la transcripción', 0, true);
                        clearInterval(progresoInterval);
                        reject(new Error(estadoData.error || 'Error en la transcripción'));
                        return;
                    }
                    
                    // Si la tarea está completada pero no hay transcripción (caso borde)
                    if (estadoData.estado === 'completado' && !transcripcionCompletada) {
                        // Esperar un poco más por si la transcripción está por llegar
                        if (intentos > 10) {
                            agregarLogProgreso('⚠️ La tarea se completó pero no se encontró transcripción');
                            actualizarProgreso('⚠️ Verificando transcripción...', 95);
                        }
                    }
                }
                
                // ======================================================
                // 3. TIMEOUT
                // ======================================================
                if (intentos >= maxIntentos) {
                    clearInterval(progresoInterval);
                    if (transcripcionCompletada) {
                        resolve();
                    } else {
                        agregarLogProgreso('⏰ Tiempo de espera agotado');
                        actualizarProgreso('⏰ Tiempo de espera agotado', 95);
                        resolve(); // No rechazamos, solo terminamos
                    }
                }
                
            } catch (error) {
                console.error('Error monitoreando:', error);
                if (intentos > 10) {
                    agregarLogProgreso('⚠️ Error monitoreando: ' + error.message);
                }
            }
        }, 1000);
    });
}

// ======================================================
// FUNCIONES DE UI PARA PROGRESO
// ======================================================

function mostrarProgreso(mensaje, porcentaje) {
    const container = document.getElementById('progressContainer');
    const minimizado = document.getElementById('progressMinimizado');
    
    if (container) {
        container.style.display = 'block';
    }
    if (minimizado) {
        minimizado.style.display = 'none';
    }
    
    progresoActivo = true;
    actualizarProgreso(mensaje, porcentaje);
    
    // Limpiar logs anteriores
    const logsContainer = document.getElementById('progressLogs');
    if (logsContainer) {
        logsContainer.innerHTML = '';
    }
}

function actualizarProgreso(mensaje, porcentaje, esError = false) {
    const status = document.getElementById('progressStatus');
    const bar = document.getElementById('progressBar');
    const text = document.getElementById('progressText');
    const pct = document.getElementById('progressPercentage');
    
    if (status) {
        status.textContent = mensaje;
        if (esError) {
            status.style.color = 'var(--danger)';
        } else {
            status.style.color = '';
        }
    }
    
    const pctValue = Math.min(100, Math.max(0, porcentaje || 0));
    
    if (bar) {
        bar.style.width = pctValue + '%';
        if (esError) {
            bar.style.background = 'linear-gradient(90deg, #d93025, #b71c1c)';
        } else if (pctValue >= 90) {
            bar.style.background = 'linear-gradient(90deg, #28a745, #20c997)';
        } else {
            bar.style.background = 'linear-gradient(90deg, #019DF4, #00B4F0)';
        }
    }
    
    if (text) {
        text.textContent = Math.round(pctValue) + '%';
    }
    
    if (pct) {
        pct.textContent = Math.round(pctValue) + '%';
    }
}

function agregarLogProgreso(mensaje) {
    const container = document.getElementById('progressLogs');
    if (!container) return;
    
    const timestamp = new Date().toLocaleTimeString();
    const div = document.createElement('div');
    div.className = 'log-entry';
    
    // Determinar icono y color según el mensaje
    let color = '#333';
    let icono = 'ℹ️';
    
    if (mensaje.includes('✅') || mensaje.includes('completada') || mensaje.includes('exitosa') || mensaje.includes('Completado')) {
        color = '#28a745';
        icono = '✅';
    } else if (mensaje.includes('❌') || mensaje.includes('Error') || mensaje.includes('error')) {
        color = '#d93025';
        icono = '❌';
    } else if (mensaje.includes('⏳') || mensaje.includes('🔄') || mensaje.includes('📤') || mensaje.includes('Iniciando')) {
        color = '#019DF4';
        icono = '⏳';
    } else if (mensaje.includes('🧠') || mensaje.includes('Analizando') || mensaje.includes('Ollama')) {
        color = '#7b1fa2';
        icono = '🧠';
    } else if (mensaje.includes('📋') || mensaje.includes('Tarea') || mensaje.includes('tarea')) {
        color = '#f39c12';
        icono = '📋';
    } else if (mensaje.includes('🎤') || mensaje.includes('Transcribiendo') || mensaje.includes('transcribiendo')) {
        color = '#fd7e14';
        icono = '🎤';
    }
    
    // Limpiar emojis para el texto
    let textoLimpio = mensaje;
    const emojis = ['✅', '❌', '⏳', '🔄', '📤', '🧠', '📋', '🚀', '🎤', '📝', '⚠️', '⏰'];
    emojis.forEach(emoji => {
        textoLimpio = textoLimpio.replace(emoji, '').trim();
    });
    
    div.innerHTML = `
        <span style="color: #6c757d; font-size: 10px;">[${timestamp}]</span>
        <span style="color: ${color};">${icono} ${textoLimpio}</span>
    `;
    
    container.appendChild(div);
    container.scrollTop = container.scrollHeight;
    
    // Limitar logs a 50
    while (container.children.length > 50) {
        container.removeChild(container.firstChild);
    }
}

function ocultarProgreso() {
    const container = document.getElementById('progressContainer');
    const minimizado = document.getElementById('progressMinimizado');
    
    if (container) {
        container.style.display = 'none';
    }
    if (minimizado) {
        minimizado.style.display = 'none';
    }
    
    progresoActivo = false;
    if (progresoInterval) {
        clearInterval(progresoInterval);
        progresoInterval = null;
    }
}

function cancelarTranscripcion() {
    if (confirm('⚠️ ¿Cancelar la transcripción en curso?')) {
        ocultarProgreso();
        agregarLogProgreso('⏹️ Transcripción cancelada por el usuario');
        // Aquí podrías agregar lógica para cancelar la tarea en la BD
    }
}

// ======================================================
// FUNCIONES DE MINIMIZAR/EXPANDIR
// ======================================================

function minimizarProgreso() {
    const container = document.getElementById('progressContainer');
    const minimizado = document.getElementById('progressMinimizado');
    
    if (container) {
        container.style.display = 'none';
    }
    if (minimizado) {
        minimizado.style.display = 'flex';
        // Actualizar el ícono con el progreso actual
        const bar = document.getElementById('progressBar');
        const pct = bar ? parseInt(bar.style.width) || 0 : 0;
        const icon = document.getElementById('progressMinimizadoIcon');
        if (icon) {
            if (pct >= 100) {
                icon.textContent = '✅';
            } else if (pct >= 50) {
                icon.textContent = '🔄';
            } else {
                icon.textContent = '📊';
            }
        }
    }
}

function expandirProgreso() {
    const container = document.getElementById('progressContainer');
    const minimizado = document.getElementById('progressMinimizado');
    
    if (container) {
        container.style.display = 'block';
    }
    if (minimizado) {
        minimizado.style.display = 'none';
    }
}

