                    submotivo: item,
                    bloque: cb?.dataset.bloque || '',
                    atributo: cb?.dataset.atributo || '',
                    tipo: cb?.dataset.tipo || 'no_critico',
                    frente: cb?.dataset.frente || 'proceso',
