// Sobrescribir showTab para cargar reportes al abrir la pestaña
const originalShowTab = window.showTab || function() {};

window.showTab = function(tabName, event) {
    // Llamar a la función original
    if (typeof originalShowTab === 'function') {
        originalShowTab(tabName, event);
    }
    
    // Si es la pestaña de reportes automáticos, cargar estado
    if (tabName === 'reportesAuto') {
        setTimeout(cargarEstadoReportes, 300);
    }
};

// Cargar estado al iniciar si la pestaña está visible
document.addEventListener('DOMContentLoaded', function() {
    setTimeout(() => {
        const tabReportesAuto = document.getElementById('tab-reportesAuto');
        if (tabReportesAuto && tabReportesAuto.classList.contains('active')) {
            cargarEstadoReportes();
        }
    }, 500);
});

// ======================================================
// FUNCIÓN PARA ACTUALIZAR HEADER CON DATOS DEL USUARIO
// ======================================================

window.actualizarHeaderSupervisor = function() {
    console.log('🔄 actualizarHeaderSupervisor - EJECUTADA');
    
    // Obtener datos del usuario
    let nombreCompleto = null;
    let rol = null;
    
    // 1. Intentar desde usuarioActual (global)
    if (window.usuarioActual && window.usuarioActual.nombre_completo) {
        nombreCompleto = window.usuarioActual.nombre_completo;
        rol = window.usuarioActual.rol;
        console.log('📦 usuarioActual:', nombreCompleto);
    }
    
    // 2. Intentar desde localStorage
    if (!nombreCompleto) {
        try {
            const guardado = localStorage.getItem('meca_usuario');
            if (guardado) {
                const data = JSON.parse(guardado);
                nombreCompleto = data.nombre_completo || data.usuario;
                rol = data.rol;
                console.log('📦 localStorage:', nombreCompleto);
            }
        } catch (e) {}
    }
    
    // 3. Intentar desde sessionStorage
    if (!nombreCompleto) {
        try {
            const guardado = sessionStorage.getItem('usuario_actual');
            if (guardado) {
                const data = JSON.parse(guardado);
                nombreCompleto = data.nombre_completo || data.usuario;
                rol = data.rol;
                console.log('📦 sessionStorage:', nombreCompleto);
            }
        } catch (e) {}
    }
    
    // 4. Actualizar el DOM
    if (nombreCompleto) {
        const userNameEl = document.getElementById('userName');
        const userRolEl = document.getElementById('userRol');
        const userInfoEl = document.getElementById('userInfo');
        
        if (userNameEl) {
            userNameEl.textContent = nombreCompleto;
            console.log('✅ userName actualizado:', nombreCompleto);
        }
        if (userRolEl) {
            userRolEl.textContent = rol || 'SUPERVISOR';
            console.log('✅ userRol actualizado:', rol || 'SUPERVISOR');
        }
        if (userInfoEl) {
            userInfoEl.style.display = 'flex';
        }
    } else {
        console.warn('⚠️ No se encontraron datos de usuario');
        const userNameEl = document.getElementById('userName');
        if (userNameEl) {
            userNameEl.textContent = '👤 No autenticado';
        }
    }
};

